(855, 1, 13, 'FLEET_GRASPED', 'В сражении на планете {@coords_from} удалось захватить флот противника ({@fleet}). Командование уже отдало приказ восстановить поврежденные системы жизнеобеспечения и вооружения, захваченный флот прибудет совместно с Вашим флотом на планету {@planet} {@coords}.', 1),
(856, 1, 13, 'FLEET_GRASPED_SUBJECT', 'Захват флота противника', 1),
(857, 1, 1, 'MENU_REPAIR', 'Ремонт', 1),
(858, 1, 4, 'REPAIR_FACTORY_DESC', 'Ремонтный ангар необходим для ремонта поврежденных и утилизации ненужных юнитов.', 1),
(859, 1, 4, 'REPAIR_FACTORY_FULL_DESC', 'Ремонтный ангар необходим для выполнения двух операций: 1 - ремонт поврежденных кораблей и оборонительных сооружений, 2 - утилизация ненужных кораблей и обороны для получения ресурсов.', 1),
