(922, 1, 5, 'DISASSEMBLE', 'Утилизировать', 1),
(923, 1, 4, 'LANCER_SHIP', 'Лансер', 1),
(924, 1, 4, 'LANCER_SHIP_DESC', 'Быстрый и эффективный военный корабль, построенный на самых современных технологиях. Оснащен мощнейшим вооружением для нанесения катастрофических разрушений противнику.', 1),
(925, 1, 4, 'LANCER_SHIP_FULL_DESC', 'Быстрый и эффективный военный корабль, построенный на самых современных технологиях. Оснащен мощнейшим вооружением, которое способно наносить катастрофические разрушения противнику. Для перезарядки энергетической пушки корабля требуется некоторое время, поэтому корабль обладает плохой скорострельностью. Корабль спроектирован учеными, как вспомогательное оружие при нанесении масштабного удара врагу, поэтому наиболее эффективен в сочетании с остальным флотом.', 1),
(926, 1, 17, 'FRONT', 'Фронт', 1),
(927, 1, 18, 'FRONT', 'Фронт', 1),
(928, 1, 18, 'ATTACKER_LOST_RES', 'Потери атакующего: %s (%s металла, %s кремния).', 1),
(929, 1, 18, 'DEFENDER_LOST_RES', 'Потери обороняющегося: %s (%s металла, %s кремния).', 1),
(930, 1, 18, 'ATTACKER_LOST_RES_4', 'Потери атакующего: %s (%s металла, %s кремния, %s водорода).', 1),
(931, 1, 18, 'DEFENDER_LOST_RES_4', 'Потери обороняющегося: %s (%s металла, %s кремния, %s водорода).', 1),
(932, 1, 18, 'HIDE_BATTLE_TEXT', 'Информация не доступна для просмотра.', 1),
(933, 1, 18, 'ROCKET_ATTACK_TIME', 'Ракетная атака в %s часов:', 1),
(934, 1, 11, 'ROCKET_ATTACK_REPORT', 'Отчет о ракетной атаке', 1),
(935, 1, 11, 'ASSAULT_REPORT_TURNS', 'Раундов', 1),
(936, 1, 12, 'BS_USER_FILTER', 'Имя игрока', 1),
(937, 1, 12, 'BS_USER_FILTER_INFO', '', 1),
(938, 1, 6, 'DAILY_PRODUCTION', 'За день', 1),
(939, 1, 6, 'MONTHLY_PRODUCTION', 'За месяц', 1),
(940, 1, 6, 'WEEKLY_PRODUCTION', 'За неделю', 1),
(941, 1, 1, 'PREV', 'Пред.', 1),
(942, 1, 1, 'NEXT', 'След.', 1),
(943, 1, 1, 'RELATED_MSG', 'Сообщения, связанные с этим игроком.', 1),
(944, 1, 13, 'EXPEDITION_XSKIRMISH', 'Во время экспедиции Ваши корабли наткнулись на инопланетный флот, появившийся из ниоткуда. Неизвестная цивилизация оказалась враждебна, завязалась битва. Смотрите отчет о сражении в разделе ''Боевые отчёты''.', 1),
(945, 1, 13, 'EXPEDITION_RESOURCE_DISCOVERY_1', 'Ваши исследователи обнаружили старые и не рабочие корабли, дрейфующие в космосе. Командование распорядилось забрать имеющиеся в трюмах ресурсы: {@metal} металла, {@silicon} кремния и {@hydrogen} водорода.', 1),
(946, 1, 13, 'EXPEDITION_SHIPS_DISCOVERY', 'Ваши исследователи обнаружили дрейфующий в открытом космосе флот, который оказался в состоянии консервации. Командование распорядилось привести найденные корабли на базу: {@new_ships}', 1),
(947, 1, 13, 'EXPEDITION_NOTHING_1', 'Ваш флот долго бороздил просторы вселенной, однако сенсоры учённых так и не смогли зафиксировать ничего интересного.', 1),
(948, 1, 4, 'UNIT_A_CORVETTE', 'Корвет инопланетян', 1),
(949, 1, 4, 'UNIT_A_SCREEN', 'Щитовой корабль инопланетян', 1),
(950, 1, 13, 'EXPEDITION_BATTLEFIELD_DISCOVERY', 'Ваши исследователи обнаружили следы давно отгремевшей битвы. Среди тонн покореженного металла удалось найти корабли, пригодные для дальнейшего использования: {@new_ships}', 1),
(951, 1, 13, 'EXPEDITION_NOTHING_2', 'Ваши исследователи прошли мимо Сверхновой звезды и сделали великолепные фотографии. Больше ничего интересного в выбранном секторе они не нашли.', 1),
(952, 1, 13, 'EXPEDITION_LOST_1', 'К сожалению связь с экспедицией была утеряна.', 1),
(953, 1, 4, 'UNIT_A_PALADIN', 'Паладин инопланетян', 1),
(954, 1, 4, 'UNIT_A_FRIGATE', 'Фрегат инопланетян', 1),
(955, 1, 4, 'UNIT_A_TORPEDOCARIER', 'Торпедоносец инопланетян', 1),
(956, 1, 13, 'EXPEDITION_DELAY_RETURN', 'Ваши исследователи ничего не нашли, к тому же они заблудились. На поиск пути домой понадобиться на {@percent}% больше времени.', 1),
(957, 1, 13, 'EXPEDITION_FAST_RETURN_1', 'Ваши исследователи ничего не нашли. К счастью, они обнаружили по пути стабильную черную дыру, проход через которую позволит им сократить обратный путь на {@percent}%', 1),
(958, 1, 13, 'EXPEDITION_SENSOR_REPORT', 'Шпионские зонды просканировали шлейф эха темной материи и обнаружили следы {@visits} экспедиций в секторе {@exp_sector}. Поисковая мощность экспедиции составила {@exp_power}. Исследователи изучали выбранный сектор {@exp_hours} часов. Текущий результат экспедиции произошел с вероятностью {@exp_percent}%', 1),
(959, 1, 1, 'RESEARCH_EXPO_TECH', 'Необходимо исследовать экспедиционную технологию', 1),
(960, 1, 1, 'TOO_MANY_EXPOS', 'Уровень экспедиционной технологии не позволяет отправлять такое количество экспедиций.', 1),
(961, 1, 13, 'EXPEDITION_SENSOR_CLEAR_REPORT', 'Шпионские зонды просканировали шлейф эха темной материи и обнаружили, что сектор {@exp_sector} никто не посещал в ближайшие дни - это очень хорошо! Исследователи советуют Вам слетать в этот сектор еще несколько раз для более тщательного его изучения. Поисковая мощность экспедиции составила {@exp_power}. Исследователи изучали выбранный сектор {@exp_hours} часов. Текущий результат экспедиции произошел с вероятностью {@exp_percent}%', 1),
(962, 1, 10, 'EXPEDITION_TIME', 'Время на исследования в экспедиции', 1),
(963, 1, 1, 'EXPEDITION', 'Экспедиция', 1),
(964, 1, 13, 'EXPEDITION_SUBJECT', 'Отчёт экспедиции', 1),
(965, 1, 13, 'EXPEDITION_SENSOR_SUBJECT', 'Данные с разведзонда', 1),
(966, 1, 1, 'SENDER', 'Отправитель', 1),
(967, 1, 1, 'RECIEVER', 'Получатель', 1),
(968, 1, 1, 'MENU_RESTRANSFERS', 'Переданные ресурсы', 1),
(969, 1, 12, 'TRANSFERS_COUNT', 'Количество разгрузок', 1),
(970, 1, 12, 'TOTAL_RES_TRANSFER', 'Сумма ресурсов', 1),
(971, 1, 12, 'RT_GROUP_RECIEVER', 'Группировать по получателю', 1),
(972, 1, 12, 'RT_GROUP_SENDER', 'Группировать по отправителю', 1),
(973, 1, 12, 'RT_SEARCH_USER', 'Поиск по имени', 1),
(974, 1, 13, 'EXPEDITION_FAST_RETURN_2', 'Ваши исследователи ничего не нашли. К счастью, из короны ближайшей звезды исходит поток солнечного ветра, который позволит им сократить время обратного пути на {@percent}%', 1),
(975, 1, 13, 'EXPEDITION_ASTEROID_DISCOVERY_NO_CARGO', 'Ваши исследователи нашли астероидное поле обломков: {@debrismetal} металла и {@debrissilicon} кремния. К сожалению в экспедиции не было переработчиков, чтобы собрать ресурсы из открытого космоса.', 1),
(976, 1, 13, 'EXPEDITION_ASTEROID_DISCOVERY_1', 'Ваши исследователи нашли астероидное поле обломков: {@debrismetal} металла и {@debrissilicon} кремния. Переработчики добыли: {@metal} металла и {@silicon} кремния.', 1),
(977, 1, 13, 'EXPEDITION_RESOURCE_DISCOVERY_2', 'Отличная новость: Ваши исследователи обнаружили необитаемую планету с ресурсами: {@debrismetal} металла, {@debrissilicon} кремния и {@debrishydrogen} водорода. Флот забрал: {@metal} металла, {@silicon} кремния и {@hydrogen} водорода.', 1),
(978, 1, 13, 'EXPEDITION_NOTHING_3', 'Ваши исследователи провели все время, предоставленное на изучение выбранного сектора. Но они не нашли ничего интересного.', 1),
(979, 1, 13, 'EXPEDITION_NOTHING_4', 'Ваш флот обнаружил одну планету, привлекшую внимание! Исследователи нашли на ней забавных маленьких зверьков. Больше ничего обнаружено не было.', 1),
(980, 1, 13, 'EXPEDITION_NOTHING_5', 'Ваши исследователи запеленговали на пути следования флот огромных размеров инопланетного происхождения. Командование приняло решение не рисковать и вернуться на базу.', 1),
(981, 1, 13, 'EXPEDITION_LOST_2', 'Связь с Вашими исследователями потеряна. Скорее всего, они больше не вернутся...', 1),
(982, 1, 13, 'EXPEDITION_NOTHING_7', 'Ваши исследователи прошли мимо огромной туманности антиматерии. Больше ничего обнаружено не было.', 1),
(983, 1, 13, 'EXPEDITION_NOTHING_6', 'Ваши исследователи обнаружили на пути следования нестабильную черную дыру. Командование приняло решение не рисковать и вернуться на базу.', 1),
(984, 1, 13, 'EXPEDITION_ASTEROID_DISCOVERY_2', 'Ваши исследователи нашли давно отгремевшее поле битвы. От разрушенных кораблей остались обломки, которые можно собрать: {@debrismetal} металла и {@debrissilicon} кремния. Переработчики добыли: {@metal} металла и {@silicon} кремния.', 1),
(985, 1, 13, 'EXPEDITION_FAST_RETURN_3', 'Флот Вашей экспедиции попал в поле действия огромного магнитного поля неизвестного происхождения. К счастью, это позволит им сократить время обратного пути на {@percent}%', 1),
(986, 1, 13, 'RETREAT_OTHER', '{@username} отменил Удержание на {@planet_from} {@coords_from}. Ваш флот ({@fleet}) возвращается на {@planet} {@coords}.', 1),
(987, 1, 13, 'RETREAT_OTHER_SUBJECT', 'Отмена удержания', 1),
(988, 1, 6, 'HOURLY_PRODUCTION', 'За час', 1),
(989, 1, 4, 'BALLISTICS_TECH', 'Баллистическая технология', 1),
(990, 1, 4, 'BALLISTICS_TECH_DESC', 'Баллистический анализатор управляет высокоточным наведением оружия, увеличивая точность прямых попаданий в юниты противника.', 1),
(991, 1, 4, 'BALLISTICS_TECH_FULL_DESC', 'Технология баллистического анализа позволяет компьютерным системам просчитывать бой до его начала на основе пространственного расположения, технических характеристик юнитов и траекторий огневых путей и излучений. Это делает возможным вести прицельный и высокоточный огонь на всем протяжении боя. Технология уменьшает промахи и попадания в уже уничтоженные юниты.', 1),
(992, 1, 4, 'MASKING_TECH', 'Маскировочная технология', 1),
(993, 1, 4, 'MASKING_TECH_DESC', 'Технология радио-локационной маскировки создает помехи в работе баллистического анализатора и систем наведения огня противника.', 1),
(994, 1, 4, 'MASKING_TECH_FULL_DESC', 'Технология радио-локационной маскировки создает помехи в работе баллистического анализатора и систем наведения огня противника. Эта технология увеличивает живучесть своих юнитов за счет уменьшения точности стрельбы огневых орудий противника.', 1),
(995, 1, 17, 'COST', 'Стоимость', 1),
(996, 1, 17, 'BALLISTICS_POWER', 'Баллистика', 1),
(997, 1, 4, 'SIM_TECH_LIST', 'Технологии', 1),
(998, 1, 18, 'BALLISTICS_POWER', 'Баллистика', 1),
(999, 1, 18, 'MASKING_POWER', 'Маскировка', 1),
(1000, 1, 17, 'MASKING_POWER', 'Маскировка', 1),
(1001, 1, 4, 'REQUIRE_TIME_EXT', 'Время строительства', 1),
(1002, 1, 13, 'EXPEDITION_CREDITS_DISCOVERY_1', 'Ваши исследователи обнаружили поле сражения. К сожалению все корабли не исправны и без ресурсов, но в одном из уцелевших сейфов исследователи нашли {@credits} кредитов. Поздравляем, кредиты уже переведены на Ваш счет. Флот возвращается на базу.', 1),
(1003, 1, 13, 'EXPEDITION_CREDITS_DISCOVERY_2', 'Экспедиционное оборудование запеленговало странный объект. Это оказалась капитанская рубка неизвестного корабля с работающим позывным устройством. Рубка оказалась отрезанной от основного корабля супер оружием, исследователи поражены, ничего подобного они не видели. В абсолютно целом сейфе исследователи нашли {@credits} кредитов. Поздравляем, кредиты уже переведены на Ваш счет. Флот возвращается на базу.', 1);
INSERT INTO `na_phrases` (`phraseid`, `languageid`, `phrasegroupid`, `title`, `content`, `translated`) VALUES
(1004, 1, 13, 'EXPEDITION_CREDITS_DISCOVERY_3', 'Экспедиционное оборудование запеленговало странный объект. Это оказался одноместный поврежденный космический корабль с мертвым существом неизвестной расы. Под сиденьем инопланетянина исследователи нашли {@credits} кредитов. Поздравляем, кредиты уже переведены на Ваш счет. Флот возвращается на базу.', 1),
(1005, 1, 13, 'EXPEDITION_CREDITS_DISCOVERY_4', 'Экспедиционное оборудование запеленговало странный объект. Это оказался мертвый инопланетянин-пилот, о чем свидетельствует его экипировка. Исследование показало, что инопланетянин умер, находясь в открытом космосе в состоянии анабиоза {@anabios_years} лет, когда системы поддержания жизнеобеспечения израсходовали свои ресурсы (видимо его выкинуло в открытый космос в каком-то сражении). В одежде пилота обнаружен позывной маячок и {@credits} кредитов. Кредиты уже переведены на Ваш счет. Флот возвращается на базу.', 1),
(1006, 1, 13, 'EXPEDITION_CREDITS_DISCOVERY_5', 'Экспедиционное оборудование запеленговало странный объект. Это оказался небольшой поврежденный корабль инопланетян. Исследователи внимательно осмотрели его и кое что нашли: хитрые инопланетяне спрятали в тайнике {@credits} кредитов. Поздравляем, кредиты уже переведены на Ваш счет. Флот возвращается на базу.', 1),
(1007, 1, 13, 'EXPEDITION_CREDITS_DISCOVERY_6', 'Ваши исследователи обнаружили поле сражения. К сожалению все корабли не исправны и без ресурсов, но в тайнике одного из кораблей внимательные исследователи нашли {@credits} кредитов. Поздравляем, кредиты уже переведены на Ваш счет. Флот возвращается на базу.', 1),
(1008, 1, 4, 'ALIEN_TECH', 'Инопланетная технология', 1),
(1009, 1, 4, 'ALIEN_TECH_DESC', 'Эта технология позволяет ремонтировать инопланетные корабли.', 1),
(1010, 1, 4, 'ALIEN_TECH_FULL_DESC', 'Эта технология позволяет ремонтировать инопланетные корабли.', 1),
(1011, 1, 4, 'UNIT_A_CORVETTE_DESC', 'Очень быстрый и экономичный боевой корабль с хорошим вооружением.', 1),
(1012, 1, 4, 'UNIT_A_SCREEN_DESC', 'Уникальный щитовой корабль. Непревзойденная защищенность позволяет принимать на себе основной удар противника.', 1),
(1013, 1, 4, 'UNIT_A_PALADIN_DESC', 'Небольшой корабль огневой поддержки. Оснащен высокоточным оружием и системой маскировки.', 1),
(1014, 1, 4, 'UNIT_A_FRIGATE_DESC', 'Огромная огневая мощь и большая вместимость. Способен наносить разрушающие удары противнику.', 1),
(1015, 1, 4, 'UNIT_A_TORPEDOCARIER_DESC', 'Быстрый корабль для нанесения внезапного удара. Оснащен мощным оружием с системой автоматического наведения.', 1),
(1016, 1, 4, 'UNIT_A_CORVETTE_FULL_DESC', 'Очень быстрый и экономичный боевой корабль с хорошим вооружением.', 1),
(1017, 1, 4, 'UNIT_A_SCREEN_FULL_DESC', 'Уникальный щитовой корабль. Непревзойденная защищенность позволяет принимать на себе основной удар противника.', 1),
(1018, 1, 4, 'UNIT_A_PALADIN_FULL_DESC', 'Небольшой корабль огневой поддержки. Оснащен высокоточным оружием и системой маскировки.', 1),
