(1095, 1, 1, 'CANT_RECALL_YET', 'Нельзя отозвать лот так рано.', 1),
(1096, 1, 1, 'EXCH_CANNT_RETREAT_TRANSPORT', 'Вы не можете расторгнуть договор купли-продажи и отозвать транспорт.', 1),
(1097, 1, 1, 'BUY_SUCCEED', 'Покупка совершена.', 1),
(1098, 1, 1, 'BUY_FAILED', 'Невозможно совершить покупку.', 1),
(1099, 1, 1, 'EXCH_LOT_DETAILS', 'Лот', 1),
(1100, 1, 4, 'UNIT_EXCH_SUPPORT_RANGE_DESC', 'Межгалактический спутник увеличивает радиус действия биржи. Продавцы могут добавлять лоты на продажу только в случае нахождения в радиусе действия.', 1),
(1101, 1, 4, 'UNIT_EXCH_SUPPORT_RANGE_FULL_DESC', 'Межгалактический спутник - это огромный объект, вращающийся на орбите планеты. Он практически полностью состоит из высокотехнологичной аппаратуры для поддержания стабильной и бесперебойной связи с самыми далекими звездными системами во вселенной. При объединении таких спутников в группы, они способны улучшать качество связи многократно. Межгалактический спутник необходим для работы биржи. Каждый такой спутник увеличивает радиус действия межгалактической биржи на количество уровней компьютерной технологии. Радиус действия измеряется в звездных системах. Каждые 300 систем увеличивают радиус действия на 1 галактику. Продавцы могут добавлять лоты на продажу только в случае нахождения в радиусе действия биржи.', 1),
(1102, 1, 4, 'EXCHANGE_DESC', 'На межгалактической бирже игроки подают заявки на продажу товаров.', 1),
(1103, 1, 4, 'EXCHANGE_FULL_DESC', 'Межгалактическая биржа необходима для осуществления торговых сделок в галактиках. Для нормального ее функционирования, необходимо создать и поддерживать в рабочем состоянии инфраструктуру из Межгалактических спутников и Биржевых подстанций.', 1),
(1104, 1, 1, 'EXCH_DISTANCE', 'Радиус действия биржи (зв. систем)', 1),
(1105, 1, 1, 'EXCH_LOTS', 'Лотов на бирже (занято/макс.)', 1),
(1106, 1, 1, 'EXCH_PURCHASE', 'Покупка лота', 1),
(1107, 1, 1, 'BUY_SECCEED', 'Спасибо за покупку на Межгалактической бирже!', 1),
(1108, 1, 1, 'DELIVERY_UNITS', 'Доставка купленного флота', 1),
(1109, 1, 13, 'DELIVERY_UNITS_REPORT', 'Купленный флот (%s) достиг планеты %s %s. <br /> Флот оставил груз: %s металла, %s кремния и %s водорода.', 1),
(1110, 1, 13, 'DELIVERY_UNITS_REPORT_SUBJECT', 'Доставлен купленный флот', 1),
(1111, 1, 1, 'DELIVERY_RESOURSES', 'Доставка купленных ресурсов', 1),
(1112, 1, 3, 'FLEET_MESSAGE_DELIVERY_UNITS', 'Флот ({@fleet}) с {@planet} {@coords} достигает координат {@target} {@targetcoords}. Задание: {@mission}. <br />Груз: {@metal} металла, {@silicon} кремния и {@hydrogen} водорода.', 1),
(1113, 1, 3, 'FLEET_MESSAGE_OTHER_RES', 'Чужой флот ({@fleet}) {@username} {@message} с {@planet} {@coords} достигает Ваших координат {@target} {@targetcoords}. Задание: {@mission}.<br />Груз: {@metal} металла, {@silicon} кремния и {@hydrogen} водорода.', 1),
(1114, 1, 4, 'EXCH_OFFICE_DESC', 'Торговое представительство необходимо для возможности продавать на Межгалактической бирже.', 1),
(1115, 1, 4, 'EXCH_OFFICE_FULL_DESC', 'Торговое представительство необходимо для возможности продавать на Межгалактической бирже. Каждый уровень представительства увеличивает максимальное количество Ваших лотов на 2.', 1),
(1116, 1, 4, 'UNIT_EXCH_SUPPORT_SLOT_DESC', 'Биржевая подстанция увеличивает максимальное количество лотов, обслуживаемое биржей.', 1),
(1117, 1, 4, 'UNIT_EXCH_SUPPORT_SLOT_FULL_DESC', 'Биржевая подстанция увеличивает максимальное количество лотов, обслуживаемое биржей.', 1),
(1118, 1, 3, 'FLEET_MESSAGE_DELIVERY_UNITS_SELLER', 'Флот ({@fleet}) с {@planet} {@coords} достигает координат {@target} {@targetcoords}. Задание: {@mission}. <br />Груз: {@metal} металла, {@silicon} кремния и {@hydrogen} водорода.', 1),
(1119, 1, 1, 'DELIVERY_UNITS_SELLER', 'Доставка проданного флота', 1),
