(1158, 1, 20, 'FLAG_MOVABLE', 'Перевозимый', 1),
(1159, 1, 4, 'ARTEFACTS_TECH', 'Изучение артефактов', 1),
(1160, 1, 4, 'ARTEFACTS_TECH_DESC', 'Технология позволяет активировать артефакты. Количество одновременно работающих артефактов на всех планетах увеличивается с каждым уровнем на 1.', 1),
(1161, 1, 4, 'ARTEFACTS_TECH_FULL_DESC', 'В исследовании инопланетных артефактов работают самые лучшие научные подразделения Вашей империи. Для изучения неизвестных технологий и механизмов работы артефактов используются лучшие эвристические методы анализа и супер компьютерные технологии. Данная технология позволяет использовать артефакты и поддерживать некоторые из них в рабочем состоянии некоторое время. Максимальное количество активированных артефактов на всех планетах ограничено уровнем этой технологии.', 1),
(1162, 1, 4, 'MERCHANTS_MARK', 'Знак торговца', 1),
(1163, 1, 4, 'MERCHANTS_MARK_DESC', 'Уменьшает комиссию на бирже и в обменнике', 1),
(1164, 1, 4, 'MERCHANTS_MARK_FULL_DESC', 'Дает возможность совершать покупки на бирже и производить обмен ресурсов со сниженной комиссией', 1),
(1165, 1, 4, 'CATALYST', 'Катализатор', 1),
(1166, 1, 4, 'CATALYST_DESC', 'Увеличивает выработку ресурсов на 10%.', 1),
(1167, 1, 4, 'CATALYST_FULL_DESC', 'Универсальный катализатор ускоряет ход химических процессов при синтезе металла, кремния и водорода. В течение недели выработка ресурсов на всех планетах увеличивается на 10%.', 1),
(1168, 1, 4, 'POWER_GENERATOR', 'Энерготранс', 1),
(1169, 1, 4, 'POWER_GENERATOR_DESC', 'Увеличивает выработку энергии на 15%, а щитовую технологию - на 1 уровень.', 1),
(1170, 1, 4, 'POWER_GENERATOR_FULL_DESC', 'Дает прирост производительности всех электростанций и спутников на 15%. Увеличивает щитовую технологию на 1 уровень.', 1),
(1171, 1, 4, 'ATOMIC_DENSIFIER', 'Атомный уплотнитель', 1),
(1172, 1, 4, 'ATOMIC_DENSIFIER_DESC', 'Увеличивает емкость хранилищ на 15%, а броневую технологию - на 1 уровень.', 1),
(1173, 1, 4, 'ATOMIC_DENSIFIER_FULL_DESC', 'Генерирует силовое поле, сжимающее вещество, что позволяет хранилищам вмещать больше ресурсов. В течение недели емкость хранилищ ресурсов на всех планетах увеличивается на 15%. Увеличивает броневую технологию на 1 уровень.', 1),
(1174, 1, 20, 'BUY_FOR_RESOURCES', 'Купить за ресурсы', 1),
(1175, 1, 20, 'BUY_FOR_CREDITS', 'Купить за кредиты', 1),
(1176, 1, 20, 'ARTEFACT_MARKET', 'Магазин артефактов', 1),
(1177, 1, 1, 'OR', 'или', 1),
(1178, 1, 4, 'ANNIHILATION_ENGINE', 'Аннигиляционный модуль', 1),
(1179, 1, 4, 'ANNIHILATION_ENGINE_DESC', 'При подключении к любому типу двигателей увеличивает скорость флота в полете на 10%.', 1),
(1180, 1, 4, 'ANNIHILATION_ENGINE_FULL_DESC', 'Аннигиляция - взаимоуничтожение частицы и античастицы при их столкновении с высвобождением огромного количества энергии. Антиматерию крайне сложно синтезировать и хранить, поэтому создание эффективного двигателя, основанного на принципе аннигиляции, пока невозможно. Однако среди обломков крупных инопланетных кораблей были найдены модули двигателей, работающих именно по такому принципу. Некоторые из них находятся в рабочем состоянии и могут быть совмещены с известными типами двигателей, давая им прирост производительности в 10%.', 1),
(1181, 1, 4, 'SUPERCOMPUTER', 'Суперкомпьютер', 1),
(1182, 1, 4, 'SUPERCOMPUTER_DESC', 'Повышает уровень компьютерной технологии на 1 и увеличивает скорость исследований в два раза. Срабатывает для исследований запущенных после активации Суперкомпьютера. После деактивации, ускоренные исследования не замедляются!', 1),
(1183, 1, 4, 'SUPERCOMPUTER_FULL_DESC', 'В одной из экспедиций удалось захватить уникальное инопланетное устройство, которое при подробном изучении оказалось суперкомпьютером инопланетян. Суперкомпьютер удалось привести в действие и включить в исследовательскую сеть. Он обладает огромной вычислительной мощностью и способен контролировать действия дополнительного флота. Одновременно с этим Суперкомпьютер занимается решением наиболее сложных исследовательских задач, уменьшая время исследований в 2 раза. Срабатывает для исследований запущенных после активации Суперкомпьютера. После деактивации, ускоренные исследования не замедляются! Два Суперкомпьютера увеличат скорость исследований в 4-е раза!', 1),
(1184, 1, 4, 'MEMORY_MODULE__15_15', 'Модуль памяти', 1),
(1185, 1, 4, 'MEMORY_MODULE__15_15_DESC', 'Повышает уровень оружейной технологии до 15.<br /><i>Требования: Оружейная технология (Уровень 14)</i>', 1),
(1186, 1, 4, 'MEMORY_MODULE__15_15_FULL_DESC', 'Иногда в экспедициях удается найти инопланетные модули памяти и расшифровать хранящиеся в них данные. Этот модуль содержит информацию об оружейной технологии 15 уровня.', 1),
(1187, 1, 4, 'MEMORY_MODULE__23_12', 'Модуль памяти', 1),
(1188, 1, 4, 'MEMORY_MODULE__23_12_DESC', 'Повышает уровень лазерной технологии до 12.<br /><i>Требования: Лазерная технология (Уровень 11)</i>', 1),
(1189, 1, 4, 'MEMORY_MODULE__23_12_FULL_DESC', 'Иногда в экспедициях удается найти инопланетные модули памяти и расшифровать хранящиеся в них данные. Этот модуль содержит информацию о лазерной технологии 12 уровня.', 1),
(1190, 1, 4, 'MEMORY_MODULE__28_1', 'Модуль памяти', 1),
(1191, 1, 4, 'MEMORY_MODULE__28_1_DESC', 'Дает возможность изучить гравитационную технологию.', 1),
(1192, 1, 4, 'MEMORY_MODULE__28_1_FULL_DESC', 'Иногда в экспедициях удается найти инопланетные модули памяти и расшифровать хранящиеся в них данные. Этот модуль содержит информацию о гравитационной технологии 1 уровня.', 1),
(1193, 1, 4, 'MEMORY_MODULE__16_15', 'Модуль памяти', 1),
(1194, 1, 4, 'MEMORY_MODULE__16_15_DESC', 'Повышает уровень щитовой технологии до 15.<br /><i>Требования: Щитовая технология (Уровень 14)</i>', 1),
(1195, 1, 4, 'MEMORY_MODULE__16_15_FULL_DESC', 'Иногда в экспедициях удается найти инопланетные модули памяти и расшифровать хранящиеся в них данные. Этот модуль содержит информацию о щитовой технологии 15 уровня.', 1),
(1196, 1, 4, 'MEMORY_MODULE__17_15', 'Модуль памяти', 1),
(1197, 1, 4, 'MEMORY_MODULE__17_15_DESC', 'Повышает уровень броневой технологии до 15.<br /><i>Требования: Броневая технология (Уровень 14)</i>', 1),
(1198, 1, 4, 'MEMORY_MODULE__17_15_FULL_DESC', 'Иногда в экспедициях удается найти инопланетные модули памяти и расшифровать хранящиеся в них данные. Этот модуль содержит информацию о броневой технологии 15 уровня.', 1),
(1199, 1, 4, 'MEMORY_MODULE__110_1', 'Модуль памяти', 1),
(1200, 1, 4, 'MEMORY_MODULE__110_1_DESC', 'Дает возможность изучить инопланетную технологию.', 1),
(1201, 1, 4, 'MEMORY_MODULE__110_1_FULL_DESC', 'Иногда в экспедициях удается найти инопланетные модули памяти и расшифровать хранящиеся в них данные. Этот модуль содержит информацию об инопланетной технологии 1 уровня.', 1),
(1202, 1, 4, 'ASSEMBLY_MODULE__31_10', 'Модуль сборки', 1),
(1203, 1, 4, 'ASSEMBLY_MODULE__31_10_DESC', 'Добавляет к флоту 10 легких истребителей.', 1),
(1204, 1, 4, 'ASSEMBLY_MODULE__31_10_FULL_DESC', 'Развитие инопланетной техники позволяет создавать роботов, подобных известным в галактике нанитам. Однако вместо нанитов общего назначения инопланетяне предпочитают использовать специализированных нанитов, оптимизированных для выполнения единственной задачи. Модуль сборки состоит из микрокомпьютера, управляющего процессом сборки, и множества нанитов, предназначенных для создания кораблей конкретного типа. Этот модуль предназначен для сборки 10 легких истребителей.', 1),
(1205, 1, 4, 'ASSEMBLY_MODULE__42_1', 'Модуль сборки', 1),
(1206, 1, 4, 'ASSEMBLY_MODULE__42_1_DESC', 'Добавляет к флоту 1 Звезду смерти.', 1),
(1207, 1, 4, 'ASSEMBLY_MODULE__42_1_FULL_DESC', 'Развитие инопланетной техники позволяет создавать роботов, подобных известным в галактике нанитам. Однако вместо нанитов общего назначения инопланетяне предпочитают использовать специализированных нанитов, оптимизированных для выполнения единственной задачи. Модуль сборки состоит из микрокомпьютера, управляющего процессом сборки, и множества нанитов, предназначенных для создания кораблей конкретного типа. Этот модуль предназначен для сборки 1 Звезды смерти.', 1),
(1208, 1, 4, 'REPAIR_BOT', 'Ремонтный робот', 1),
(1209, 1, 4, 'REPAIR_BOT_DESC', 'Ремонтирует все корабли на планете.', 1),
(1210, 1, 4, 'REPAIR_BOT_FULL_DESC', 'Ремонтный робот способен анализировать структуру любых кораблей и восстанавливать их броню. За один запуск он способен отремонтировать весь флот на планете. Однако робот имеет ограниченный запас энергии, поэтому после трех запусков он становится бесполезным.', 1),
(1211, 1, 4, 'ROBOT_CONTROL_SYSTEM', 'Система управления роботами', 1),
(1212, 1, 4, 'ROBOT_CONTROL_SYSTEM_DESC', 'Система управления роботами (СУР) повышает в 2 раза скорость строительства зданий, флота и обороны. Срабатывает для заданий запущенных после активации СУР. После деактивации, ускоренные задания не замедляются! ', 1),
(1213, 1, 4, 'ROBOT_CONTROL_SYSTEM_FULL_DESC', 'Система управления роботами (СУР) позволяет эффективнее распределять задачи для роботов при строительстве на планете зданий, флота и обороны. Скорость строительства увеличивается в 2 раза. Срабатывает для заданий запущенных после активации СУР. После деактивации, ускоренные задания не замедляются! Два СУР увеличат скорость строительства в 4-е раза!', 1),
(1214, 1, 12, 'STAT_POINTS', 'Всего очков', 1),
(1215, 1, 12, 'STAT_UNIT_POINTS', 'Юниты (очков)', 1),
