(1234, 1, 4, 'BATTLE_SHELL_POWER_FULL_DESC', 'Увеличивает во время сражения силу брони на 10% для всех юнитов всех игроков своей стороны.', 1),
(1235, 1, 4, 'BATTLE_SHELL_POWER_DESC', 'Увеличивает во время сражения силу брони на 10% для всех юнитов всех игроков своей стороны.', 1),
(1236, 1, 4, 'BATTLE_SHELL_POWER', 'Единство брони', 1),
(1237, 1, 4, 'BATTLE_SHIELD_POWER', 'Единство щитов', 1),
(1238, 1, 4, 'BATTLE_SHIELD_POWER_DESC', 'Увеличивает во время сражения силу щитов на 10% для всех юнитов всех игроков своей стороны.', 1),
(1239, 1, 4, 'BATTLE_SHIELD_POWER_FULL_DESC', 'Увеличивает во время сражения силу щитов на 10% для всех юнитов всех игроков своей стороны.', 1),
(1240, 1, 4, 'BATTLE_ATTACK_POWER_FULL_DESC', 'Увеличивает во время сражения силу атаки на 10% для всех юнитов всех игроков своей стороны.', 1),
(1241, 1, 4, 'BATTLE_ATTACK_POWER_DESC', 'Увеличивает во время сражения силу атаки на 10% для всех юнитов всех игроков своей стороны.', 1),
(1242, 1, 4, 'BATTLE_ATTACK_POWER', 'Единство атаки', 1),
(1243, 1, 4, 'MOON_CREATOR', 'Лунный творец', 1),
(1244, 1, 4, 'MOON_CREATOR_DESC', 'Позволяет создать луну на орбите планеты.', 1),
(1245, 1, 4, 'MOON_CREATOR_FULL_DESC', 'Позволяет создать луну на орбите планеты.', 1),
(1246, 1, 4, 'PLANET_CREATOR_FULL_DESC', 'Позволяет создать дополнительную планету. Необходимо отправить в составе флота с колонизатором на свободные координаты.', 1),
(1247, 1, 4, 'PLANET_CREATOR_DESC', 'Позволяет создать дополнительную планету. Необходимо отправить в составе флота с колонизатором на свободные координаты.', 1),
(1248, 1, 4, 'PLANET_CREATOR', 'Планетарный творец', 1),
(1249, 1, 1, 'DESTROY_ATTACK', 'Разрушить постройку', 1),
(1250, 1, 18, 'DEBRIS_METAL_AND_SILICON', 'На орбите находится: %s металла и %s кремния.', 1),
(1251, 1, 18, 'MOON_ARTEFACT_APPEARED', 'Появился лунный артефакт!', 1),
(1252, 1, 18, 'MOON_ARTEFACT_CHANCE', 'В результате сражения напряженность пространственно временного поля составила %s%%. Возможно появление артефакта из параллельного мира.', 1),
(1253, 1, 18, 'MOON_ARTEFACT_NOT_APPEARED', 'В этот раз артефакт не появился.', 1),
(1254, 1, 18, 'START_REPORT_TARGET_BUILDING', 'Атакующий собирается разрушить:', 1),
(1255, 1, 18, 'DESTROY_MISSION_DEATH_STAR_DESTROYED', 'Генераторы Звезды Сметри не выдержали, она взорвалась.', 1),
(1256, 1, 18, 'TARGET_BUILDING_NOT_DESTROYED', 'Не удалось разрушить:', 1),
(1257, 1, 18, 'DESTROYED_BUILDING_PLANET_METAL_AND_SILICON', 'Высвобождено ресурсов на планете: %s металла и %s кремния.', 1),
(1258, 1, 18, 'TARGET_BUILDING_DESTROYED', 'Атакующий разрушил:', 1),
(1259, 1, 13, 'BUILDING_DESTROYED_MSG', 'В сражении на планете {@coords_planet} была разрушена Ваша постройка {@building_name}.', 1),
(1260, 1, 13, 'BUILDING_DESTROYED_SUBJECT', 'Ваша постройка была разрушена', 1),
(1261, 1, 13, 'LOST_ARTEFACTS_SUBJECT', 'Потеря артефактов', 1),
(1262, 1, 13, 'LOST_ARTEFACTS_MSG', 'В сражении на планете {@coords_planet} атакующий захватил Ваши артефакты: {@artefacts}.', 1),
(1263, 1, 13, 'ARTEFACTS_GRASPED_MSG', 'В сражении на планете {@coords_from} были захвачены артефакты: {@artefacts}. Ваш флот вместе с артефактами прибудет на планету {@planet} {@coords}.', 1),
(1264, 1, 13, 'ARTEFACTS_GRASPED_SUBJECT', 'Захват артефактов противника', 1),
(1265, 1, 3, 'BATTLE_ACTIVE_EXPERIENCE', 'Накопленный опыт', 1),
(1266, 1, 18, 'FRIEND_LINK', 'Покажи это сражение друзьям', 1),
(1267, 1, 18, 'REPORT_SEND_TO_FRIEND', 'Отправить отчёт другу', 1),
