(1269, 1, 18, 'BATTLE_REPORT_TEXT', 'Командование флота получило сообщение от игрока {@username}, он прислал ссылку на <a href=''{@friendlink}'' target=''_blank''>боевой отчет</a>.', 1),
(1270, 1, 18, 'REPORT_TEXT_QUOTE', '<br/><br/>Сообщение от {@username}: <blockquote>{@text}</blockquote>', 1),
(1271, 1, 18, 'REPORT_EMAIL', 'E-mail получателя или ник игрока. Несколько получателей можно перечислять через запятые.', 1),
(1272, 1, 18, 'FRIEND_LINK', 'Покажи это сражение друзьям', 1),
(1273, 1, 1, 'MUST_LOGIN', 'Необходима авторизация', 1),
(1274, 1, 18, 'MAX_MAILS_EXCEED', 'Вы не можете отправлять более {@maxmails} писем в день.', 1),
(1275, 1, 18, 'INVALID_MAIL', 'Неверный e-mail', 1),
(1276, 1, 18, 'DELIVERY_ACCEPTED', 'Письмо принято к отправке', 1),
(1277, 1, 1, 'FAILURE', 'Ошибка!', 1),
(1278, 1, 5, 'BUILDING_MAX_LEVEL_REACHED', 'Достигнут максимальный уровень для постройки', 1),
(1279, 1, 3, 'SET_NEW_HOME_PLANET', 'Установить главную планету', 1),
(1280, 1, 3, 'CUR_HOME_PLANET', 'Главная планета', 1),
(1281, 1, 18, 'START_REPORT_TARGET_MOON', 'Атакующий собирается уничтожить Луну.', 1),
(1282, 1, 18, 'TARGET_MOON_DESTROYED', 'Генераторы Звезд Смерти атакующего накапливают энергию для гравитационной атаки и делают выстрел по Луне. Всё более усиливающиеся толчки сотрясают спутник. Луна начинает деформироваться, по ее экватору несколько раз проходят гравитационные волны, затем взрыв ослепляет приборы атакующего. Мгновенье и приборы фиксируют пустоту, Луна уничтожена, ее больше нет.', 1),
(1283, 1, 18, 'ATTACKER_FLLETS_EXPLODE', 'Генераторы Звезд Смерти атакующего накапливают энергию для гравитационной атаки и делают выстрел по Луне. Усиливающиеся толчки сотрясают спутник, но не могут разорвать его. Гравитация Луны выбрасывает лишнюю энергию. Мощнейшая энергетическая волна направляется к флоту атакующего, затем хлопок. Флот атакующего распадается на субматерию и исчезает во мраке вселенной.', 1),
(1284, 1, 18, 'TARGET_MOON_NOT_DESTROYED', 'Генераторы Звезд Смерти атакующего накапливают энергию для гравитационной атаки и делают выстрел по Луне. Толчки, один за одним, сотрясают спутник, но Луна остается на месте. Спутник стабилизируется высвобождая лишнюю энергию гравитационными импульсами. Мощности генераторов Звезд Смерти не хватило, чтобы уничтожить Луну.', 1),
(1285, 1, 18, 'DESTROY_MISSION_TITLE', 'Специальное задание', 1),
(1287, 1, 13, 'MOON_DESTROYED_MSG', 'Ваша Луна по координатам {@coords_planet} была уничтожена.', 1),
