INSERT INTO `na_phrases` (`phraseid`, `languageid`, `phrasegroupid`, `title`, `content`, `translated`) VALUES
(1340, 1, 13, 'MSG_CREDIT_EXCHANGE_BUY', 'Вы купили лот на бирже за {@credits} кредитов.', 1),
(1341, 1, 13, 'MSG_CREDIT_EXCHANGE_SELL', 'У Вас купили лот на бирже за {@credits} кредитов.', 1),
(1342, 1, 13, 'MSG_CREDIT_EXCHANGE_PROFIT', 'На Вашей бирже произошла покупка, заработанная комиссия составила {@credits} кредитов.', 1),
(1343, 1, 13, 'MSG_CREDIT_EXCHANGE_DEFFEND', 'За защиту биржи Вам была начислена комиссия {@credits} кредитов.', 1),
(1344, 1, 13, 'MSG_CREDIT_EXCHANGE_BUY_LOT', 'Вы купили лот ({@lot}) за {@credits} кредитов.', 1),
(1345, 1, 13, 'MSG_CREDIT_EXCHANGE_SELL_LOT', 'У Вас купили лот ({@lot}) за {@credits} кредитов.', 1),
(1346, 1, 13, 'MSG_CREDIT_ARTEFACT_BUY_LOT', 'Вы купили артефакт ({@lot}) за {@credits} кредитов.', 1),
(1347, 1, 13, 'MSG_CREDIT_MARKET', 'Вы купили на рынке ресурсы за {@credits} кредитов.', 1),
(1348, 1, 4, 'SHADOW_SHIP', 'Тень', 1),
(1349, 1, 4, 'SHADOW_SHIP_DESC', 'Быстрый корабль для эффективного обстрела противника с большого расстояния. Слаб в обороне.', 1),
(1350, 1, 4, 'SHADOW_SHIP_FULL_DESC', 'Быстрый и неуловимый корабль для эффективного обстрела противника в атаке. Корабль Тень - это секретная военная разработка лучших ученых империи. Он появился при переработке и модернизации Легкого истребителя. Специально разработанное для Тени многозарядное орудие идеально приспособлено для стрельбы по большим кораблям противника. Тень обладает совершено новой системой вооружения, способной вести прицельный огонь с огромных расстояний, новым генератором щитового поля, высокой маневренностью и генератором помех для улучшения маскировки. Но Тень слаба в обороне, т.к. находясь на орбите планеты не может занять огневые позиции на достаточном удалении от противника.', 1),
(1351, 1, 13, 'MSG_CREDIT_FOR_VIP', 'Вы запустили задание вне очереди за {@credits} кредитов.', 1),
(1352, 1, 18, 'DESTROY_MISSION_DEATH_STARS_DESTROYED', 'Генераторы Звезды Сметри не выдержали перегрузок, взорвалось ЗС: %d', 1),
(1353, 1, 13, 'MSG_CREDIT_BUY', 'Вы приобрели {@credits} кредитов.', 1),
(1354, 1, 10, 'NO_FREE_EXPO_SLOTS', 'Нет свободных экспедиционных слотов', 1),
(1355, 1, 4, 'MOON_ROBOTIC_FACTORY', 'Лунная фабрика роботов', 1),
(1356, 1, 4, 'MOON_ROBOTIC_FACTORY_FULL_DESC', 'Предоставляет простую рабочую силу, которую можно применять при строительстве планетарной инфраструктуры. Каждый уровень развития фабрики повышает скорость строительства зданий.', 1),
(1357, 1, 5, 'MOON_ROBOTIC_FACTORY_DESC', 'Предоставляет простую рабочую силу, которую можно применять при строительстве планетарной инфраструктуры. Каждый уровень развития фабрики повышает скорость строительства зданий.', 1),
(1358, 1, 7, 'SPACE_EVENTS_LIST', 'Текущие задания во вселенной', 1),
(1359, 1, 3, 'PLANET_ANIGILATION', 'Планета {@planet} самоуничтожится гравитационной аномалией.', 1),
(1360, 1, 13, 'NEUTRAL_PLANET_FOUND', 'После длительных блужданий по просторам вселенной, сенсоры экспедиции засекли странную активность в районе {@planet}.<br/>Подлетев поближе, ученые обнаружили, что это неизвестная ранее планета инопланетян с обломками от сражения. Видимо кто-то недавно разбил тут большой флот. На орбите планеты обнаружены обломки: {@metal} металла и {@silicon} кремния. Поспешите, чтобы забрать их, т.к. планета не стабильна и скоро разрушится, кроме этого о планете известно кому-то еще!', 1),
(1361, 1, 13, 'NEUTRAL_PLANET_DIE', 'Оказывается не зря инопланетный флот так бился за эту планету. В её коре стали проявляться невиданные по силе гравитационные аномалии и, прежде чем ученые успели исследовать их, планета {@planet} развалилась на субматерию.', 1),
(1362, 1, 13, 'EXPEDITION_NEUTRAL_PLANET', 'Исследователям удалось установить координаты планеты, на которой произошел бой: {@planet}.<br/>Обломки, оставшиеся после битвы, находятся на её орбите: {@m_scraps} металла и {@s_scraps} кремния. Поспешите, чтобы забрать их, т.к. планета не стабильна и скоро разрушится, кроме этого о планете может узнать кто-то еще!', 1),
(1363, 1, 13, 'EXPEDITION_NEUTRAL_PLANET_SUBJ', 'Открытие неизвестной планеты', 1),
(1364, 1, 1, 'NEUTRAL_PLANET_NAME', 'UFO-251', 1),
(1365, 1, 3, 'ANIGILATION_TIMER', 'Планета {@target_mission} самоуничтожится гравитационной аномалией.', 1),
(1366, 1, 20, 'WRONG_ARTEFACT_PLANET', 'Расположен на другой планете', 1),
(1367, 1, 4, 'PACK_BUILDING_NOW', 'Запаковать текущий уровень в артефакт', 1),
(1368, 1, 20, 'OUTSTANDING_ARTEFACT_REQUIREMENTS', '', 1),
(1369, 1, 13, 'EXPEDITION_SENSOR_POOR_REPORT', 'Шпионские зонды просканировали шлейф эха темной материи и обнаружили следы {@visits} экспедиций в секторе {@exp_sector}. Исследователи, посовещавшись, решили предложить Вам не летать в этот сектор несколько дней. Попробуйте найти менее посещенные экспедициями сектора. Поисковая мощность составила {@exp_power}. Исследователи изучали выбранный сектор {@exp_hours} часов. Текущий результат экспедиции произошел с вероятностью {@exp_percent}%', 1),
(1370, 1, 12, 'BS_SHOW_NO_DESTROYED', 'показывать бои без потерь (грабежи ресурсов)', 1),
(1371, 1, 12, 'EXCH_LOT_MIN_PRICE', 'За партию', 1),
(1372, 1, 1, 'MENU_REFERAL', 'Рефералы', 1),
(1373, 1, 12, 'BS_ALLIANCE_FILTER', 'Альянс', 1),
(1374, 1, 12, 'BS_ALLIANCE_FILTER_INFO', '', 1),
(1375, 1, 6, 'FLEET_CONSUMPTION', 'Флот', 1),
(1377, 1, 4, 'MOON_HYDROGEN_LAB', 'Лунный синтезатор водорода', 1),
(1378, 1, 4, 'MOON_HYDROGEN_LAB_FULL_DESC', 'Лунный синтезатор добывает водород изо льда с кратеров, расположенных на полюсах луны. Это самые темные и неизведанные места на луне, туда никогда не попадает свет со звезды. Ученные активно работают над изучением скрытых возможностей по добыче водорода на луне. Энергию для синтезатора могут дать захваченные в бою солнечные спутники.', 1),
(1379, 1, 5, 'MOON_HYDROGEN_LAB_DESC', 'Лунный синтезатор добывает водород изо льда с кратеров, расположенных на полюсах луны. Это самые темные и неизведанные места. Энергию для синтезатора могут дать захваченные в бою солнечные спутники.', 1),
(1380, 1, 6, 'HALTING_CONSUMPTION', 'Удержание {@fleet} с {@planet}', 1),
