(1382, 1, 6, 'ONE_UNIT_CONSUMPTION', 'Один юнит потребляет: {@basicHydrogenCons} водорода.', 1),
(1383, 1, 6, 'ONE_UNIT_CONSUMPTION_EXT', 'Один юнит потребляет: {@basicHydrogenCons} водорода <br />(что составляет: {@metalCons} металла, {@siliconCons} кремния и {@hydrogenCons} водорода)', 1),
