(1401, 1, 1, 'AGREE', 'Согласиться', 1),
(1403, 1, 8, 'SKIN_TYPE_MOBI', 'Мобильный', 1),
(1404, 1, 1, 'MENU_PLANET_OPTIONS', 'Планета', 1),
(1405, 1, 1, 'MENU_USER_AGREEMENT', 'Соглашение', 1),
(1406, 1, 24, 'USER_AGREEMENT_NEW_PRE_TEXT', '<span class=''true''>Чтобы продолжить игру, подтвердите Соглашение (кнопочка в конце этой страницы).</span>', 1),
(1407, 1, 1, 'TW_UPCOMING_BLOCK', 'Скоро начнутся технические работы (ТР). Во время работ Вы не сможете войти в игру. ТР завершатся в {@tw_end_time} (время московское).', 1),
(1408, 1, 1, 'TW_UPCOMING', 'Скоро начнутся технические работы (ТР). Любые завершающиеся во время ТР задания будут приостановлены. Порядок возобновления заданий сохранится. ТР завершатся в {@tw_end_time} (время московское).', 1),
(1409, 1, 1, 'TW_IN_PROGRESS', 'В данный момент идут технические работы (ТР).', 1),
