(2281, 2, 7, 'PW_LOST_EMAIL_SUCCESS', 'You will receive further instructions via email.', 0),
(2282, 2, 7, 'REGISTRATION', 'Registration', 0),
(2283, 2, 7, 'REGISTRATION_BANNED_FOR_IP', 'You just registered. {@minutes} Wait a minute and try again.', 0),
(2284, 2, 7, 'REGISTRATION_MAIL', 'Thanks {@regUsername} for registration in the {config}pagetitle{/config}! <br /> <br /> Your password is: {@regPassword} <br /> <br /> You need to activate your account. Click on the link below to confirm or copy it into the address bar of your browser: <br /> <br /> {@activationLink} <br /> <br /> Sincerely, <br /> {config}pagetitle{/config} command', 0),
(2285, 2, 7, 'REQUEST_DATA', 'Send', 0),
(2286, 2, 7, 'REQUEST_PASSWORD', 'Hello, {@req_username}! <br /> <br /> Somebody, maybe you, the site asked for the {config}pagetitle{/config} a forgotten password. If you do forget your password, to get a new click on the link below: <br /> <br /> {@new_pw_url} <br /> <br /> If you did not ask for a password, ignore this message. <br /> <br /> The request has been sent to the IP-address {@req_ipaddress}. <br /> <br /> To activate your account without having to change your password, click on the link below: <br /> <br /> {@reactivate_url} <br /> <br /> Sincerely, <br /> Your command {config}pagetitle{/config}', 0),
(2287, 2, 7, 'REQUEST_USERNAME', 'Hello, {@req_username}! Someone, probably you, the site asked for the {config}pagetitle{/config} forgot login. Your username: {@req_username} If you have not forgotten your login, we advise you to change settings in your email. The request has been sent to the IP-address {@req_ipaddress}. Sincerely, Your Team {config}pagetitle{/config}', 0),
(2288, 2, 7, 'RULES', 'Regulations', 0),
(2289, 2, 7, 'SCREENSHOTS', 'Screenshots', 0),
(2290, 2, 7, 'SCREENSHOT_GALAXY_BROWSER', 'Presentation of the Galaxy', 0),
