(2866, 2, 13, 'EXPEDITION_RESOURCE_DISCOVERY_1', 'Researchers have found your old and not working ships, drifting in space. Command ordered to take the available resources in the holds of {@metal} metal {@silicon} Si and {@hydrogen} hydrogen.', 0),
(2867, 2, 13, 'EXPEDITION_SHIPS_DISCOVERY', 'Your researchers found drifting in space fleet, which has been able to preservation. Command ordered to bring the ships to the base found: {@new_ships}', 0),
(2868, 2, 13, 'EXPEDITION_NOTHING_1', 'Your fleet for a long time to surf the universe, but scientists sensors have not been able to record anything of interest.', 0),
