(2871, 2, 13, 'EXPEDITION_BATTLEFIELD_DISCOVERY', 'Your investigators found traces of long otgremevshey battle. Among the tons of crumpled metal vessels found suitable for further use: {@new_ships}', 0),
(2872, 2, 13, 'EXPEDITION_NOTHING_2', 'Your explorers passed by the Supernova and made great photos. Nothing more interesting in the chosen sector, they have found.', 0),
