(2877, 2, 13, 'EXPEDITION_DELAY_RETURN', 'Your researchers did not find anything, besides they are lost. Search on the way home needed to {@percent}% more time.', 0),
(2878, 2, 13, 'EXPEDITION_FAST_RETURN_1', 'Your researchers have found nothing. Fortunately, they found the path of a stable black hole, a passage through which will allow them to cut way back on the {@percent}%', 0),
(2879, 2, 13, 'EXPEDITION_SENSOR_REPORT', 'Spy probe scanned the trail echoes of dark matter and found traces of {@visits} expeditions in the sector {@exp_sector}. Search power of the expedition was {@exp_power}. The researchers studied a selected sector {@exp_hours} hours. The current result of the expedition took place with the probability of {@exp_percent}%', 0),
(2880, 2, 1, 'RESEARCH_EXPO_TECH', 'Necessary to investigate the forwarding technology', 0),
(2881, 2, 1, 'TOO_MANY_EXPOS', 'The level of technology does not allow forwarding to send a number of expeditions.', 0),
(2882, 2, 13, 'EXPEDITION_SENSOR_CLEAR_REPORT', 'Spy probe scanned the trail echoes of dark matter and found that the sector {@exp_sector} No one attended in the next few days - it&#39;s very good! Researchers advise you to fly in this sector a few more times for a more detailed study it. Search power of the expedition was {@exp_power}. The researchers studied a selected sector {@exp_hours} hours. The current result of the expedition took place with the probability of {@exp_percent}%', 0),
