(2895, 2, 13, 'EXPEDITION_FAST_RETURN_2', 'Your researchers have found nothing. Fortunately, the crown of the nearest star is based on the flow of the solar wind, which will allow them to reduce the time return to the {@percent}%', 0),
(2896, 2, 13, 'EXPEDITION_ASTEROID_DISCOVERY_NO_CARGO', 'Your researchers found fragments of asteroid field: {@debrismetal} metal {@debrissilicon} silicon. Unfortunately the expedition was not refiners to raise resources from outer space.', 0),
(2897, 2, 13, 'EXPEDITION_ASTEROID_DISCOVERY_1', 'Your researchers found fragments of asteroid field: {@debrismetal} metal {@debrissilicon} silicon. Processors extracted: {@metal} metal {@silicon} silicon.', 0),
(2898, 2, 13, 'EXPEDITION_RESOURCE_DISCOVERY_2', 'Good news: Your researchers found an uninhabited planet with resources: {@debrismetal} metal {@debrissilicon} Si and {@debrishydrogen} hydrogen. The fleet took: {@metal} metal {@silicon} Si and {@hydrogen} hydrogen.', 0),
(2899, 2, 13, 'EXPEDITION_NOTHING_3', 'Your researchers conducted all the time granted for the study of the selected sectors. But they did not find anything interesting.', 0),
(2900, 2, 13, 'EXPEDITION_NOTHING_4', 'Your fleet has found a planet that drew your attention! Researchers have found her funny little animals. Nothing else was found.', 0),
(2901, 2, 13, 'EXPEDITION_NOTHING_5', 'Your zapelengovali researchers in the path of an enormous size fleet of alien origin. Command decided not to risk and return to base.', 0),
(2902, 2, 13, 'EXPEDITION_LOST_2', 'Relationship with your lost explorers. Most likely, they will not come back ...', 0),
(2903, 2, 13, 'EXPEDITION_NOTHING_7', 'Your explorers passed by a huge nebula of antimatter. Nothing else was found.', 0),
(2904, 2, 13, 'EXPEDITION_NOTHING_6', 'Your researchers found in the path of an unstable black hole. Command decided not to risk and return to base.', 0),
(2905, 2, 13, 'EXPEDITION_ASTEROID_DISCOVERY_2', 'Researchers have found your long otgremevshee battlefield. Ships were destroyed by debris, which can be collected: {@debrismetal} metal {@debrissilicon} silicon. Processors extracted: {@metal} metal {@silicon} silicon.', 0),
(2906, 2, 13, 'EXPEDITION_FAST_RETURN_3', 'Fleet of your expedition came to the attention of a huge magnetic field of unknown origin. Fortunately, this will allow them to reduce time return to the {@percent}%', 0),
(2907, 2, 13, 'RETREAT_OTHER', '{@username} Hold on canceled {@planet_from} {@coords_from}. Your fleet ({@fleet}) returns to the {@planet} {@coords}.', 0),
