(3096, 2, 1, 'OR', 'or', 0),
(3097, 2, 4, 'ANNIHILATION_ENGINE', 'Annihilation module', 0),
(3098, 2, 4, 'ANNIHILATION_ENGINE_DESC', 'When you connect to any type of engine speeds up fleet in flight at 10%.', 0),
(3099, 2, 4, 'ANNIHILATION_ENGINE_FULL_DESC', 'Annihilation - mutual destruction of particles and antiparticles when they collide with the release of huge amounts of energy. Antimatter is very difficult to synthesize and store, so an effective engine, based on the principle of annihilation, it is impossible. But among the fragments of large alien ships have been found-ins engines is on this principle. Some of them are in working condition and can be combined with certain types of engines, giving them a performance boost of 10%.', 0),
(3100, 2, 4, 'SUPERCOMPUTER', 'Supercomputer', 0),
(3101, 2, 4, 'SUPERCOMPUTER_DESC', 'Increases the level of computer technology in a research and increases the speed in half. Works for studies launched after the activation of a supercomputer. After deactivation, the accelerated research has not slowed down!', 0),
(3102, 2, 4, 'SUPERCOMPUTER_FULL_DESC', 'In one of the expeditions was to capture the unique alien device that, when detailed study was a supercomputer aliens. Supercomputer able to put into effect and included in the research network. He has a tremendous processing power and is able to control the actions of the additional fleet. Simultaneously, the supercomputer is addressing the most complex research problems, reducing time studies in 2 times. Works for studies launched after the activation of a supercomputer. After deactivation, the accelerated research has not slowed down! Two supercomputer will increase the speed of research into the 4th time!', 0),
(3103, 2, 4, 'MEMORY_MODULE__15_15', 'Memory module', 0),
(3104, 2, 4, 'MEMORY_MODULE__15_15_DESC', 'Increases the level of weapons technology to 15. <br /> <i> Requirements: Weapons Technology (level 14) </i>', 0),
(3105, 2, 4, 'MEMORY_MODULE__15_15_FULL_DESC', 'Sometimes the expeditions can be found alien memory and decrypt their data. This module contains information on weapons technology level 15.', 0),
(3106, 2, 4, 'MEMORY_MODULE__23_12', 'Memory module', 0),
(3107, 2, 4, 'MEMORY_MODULE__23_12_DESC', 'Increases the level of laser technology to 12. <br /> <i> Requires: Laser Technology (level 11) </i>', 0),
(3108, 2, 4, 'MEMORY_MODULE__23_12_FULL_DESC', 'Sometimes the expeditions can be found alien memory and decrypt their data. This module contains information on laser technology at level 12.', 0),
(3109, 2, 4, 'MEMORY_MODULE__28_1', 'Memory module', 0),
(3110, 2, 4, 'MEMORY_MODULE__28_1_DESC', 'Makes it possible to study the gravitational technique.', 0),
(3111, 2, 4, 'MEMORY_MODULE__28_1_FULL_DESC', 'Sometimes the expeditions can be found alien memory and decrypt their data. This module contains information about the gravitational Technology Level 1.', 0),
(3112, 2, 4, 'MEMORY_MODULE__16_15', 'Memory module', 0),
(3113, 2, 4, 'MEMORY_MODULE__16_15_DESC', 'Increases shield technology to 15. <br /> <i> Requirements: Shielding Technology (level 14) </i>', 0),
(3114, 2, 4, 'MEMORY_MODULE__16_15_FULL_DESC', 'Sometimes the expeditions can be found alien memory and decrypt their data. This module contains information on the billboard technology level 15.', 0),
(3115, 2, 4, 'MEMORY_MODULE__17_15', 'Memory module', 0),
(3116, 2, 4, 'MEMORY_MODULE__17_15_DESC', 'Increases armor technology to 15. <br /> <i> Requires: Armor Technology (Level 14) </i>', 0),
(3117, 2, 4, 'MEMORY_MODULE__17_15_FULL_DESC', 'Sometimes the expeditions can be found alien memory and decrypt their data. This module contains information on the technology level 15 armor.', 0),
(3118, 2, 4, 'MEMORY_MODULE__110_1', 'Memory module', 0),
(3119, 2, 4, 'MEMORY_MODULE__110_1_DESC', 'Makes it possible to study the alien technology.', 0),
(3120, 2, 4, 'MEMORY_MODULE__110_1_FULL_DESC', 'Sometimes the expeditions can be found alien memory and decrypt their data. This module contains information about the alien technology level 1.', 0),
(3121, 2, 4, 'ASSEMBLY_MODULE__31_10', 'Module assembly', 0),
(3122, 2, 4, 'ASSEMBLY_MODULE__31_10_DESC', 'Adds to the fleet 10 light fighters.', 0),
(3123, 2, 4, 'ASSEMBLY_MODULE__31_10_FULL_DESC', 'The development of alien technology allows you to create robots, like the well-known in the galaxy of nanites. However, instead of general-purpose nanites aliens prefer to use specialized nanites, which are optimized to perform a single task. The module assembly consists of a microcomputer that controls the build process, and many nanites designed to create a specific type of ship. This module is intended to build 10 lightweight fighters.', 0),
(3124, 2, 4, 'ASSEMBLY_MODULE__42_1', 'Module assembly', 0),
(3125, 2, 4, 'ASSEMBLY_MODULE__42_1_DESC', 'Adds to the fleet a Death Star.', 0),
(3126, 2, 4, 'ASSEMBLY_MODULE__42_1_FULL_DESC', 'The development of alien technology allows you to create robots, like the well-known in the galaxy of nanites. However, instead of general-purpose nanites aliens prefer to use specialized nanites, which are optimized to perform a single task. The module assembly consists of a microcomputer that controls the build process, and many nanites designed to create a specific type of ship. This module is designed to build a Death Star.', 0),
(3127, 2, 4, 'REPAIR_BOT', 'Repair Bot', 0),
(3128, 2, 4, 'REPAIR_BOT_DESC', 'Repairs all vehicles on the planet.', 0),
(3129, 2, 4, 'REPAIR_BOT_FULL_DESC', 'Repair Bot is able to analyze the structure of all the ships and repair their armor. For a start it is able to repair the entire fleet on the planet. However, the robot has a limited supply of energy, so after three starts, it becomes useless.', 0),
(3130, 2, 4, 'ROBOT_CONTROL_SYSTEM', 'The system of control robots', 0),
(3131, 2, 4, 'ROBOT_CONTROL_SYSTEM_DESC', 'The system of robot control (RMS) increased by 2 times the speed of construction of buildings, fleet and defense. Triggered for jobs running after activation of the URA. After deactivation, the accelerated job does not slow down!', 0),
(3132, 2, 4, 'ROBOT_CONTROL_SYSTEM_FULL_DESC', 'The system of robot control (RMS) allows you to better allocate tasks to robots in the construction of buildings on the planet, and fleet defense. The rate of construction increased by 2 times. Triggered for jobs running after activation of the URA. After deactivation, the accelerated job does not slow down! Two RMS will increase the speed of construction in the 4th time!', 0),
