(3599, 3, 3, 'FLEET_MESSAGE_OWN', 'Ihre Flotte ({@fleet}) mit {@planet} {@coords} gesendet am {@target} {@targetcoords}. Assignment:. {@mission} <br /> Cargo: {@metal} Metall {@silicon} Si und {@hydrogen} Wasserstoff.', 0),
(3600, 3, 3, 'FLEET_MESSAGE_RETURN', 'Ihre Flotte ({@fleet}) mit {@planet} {@coords} nach {@target} {@targetcoords}. Assignment: {@mission}. <br /> Cargo: {@metal} Metall {@silicon} Si und {@hydrogen} Wasserstoff.', 0),
(3601, 3, 3, 'FLEET_MESSAGE_ROCKET_ATTACK', 'Ihre Raketen ({@rockets}) mit {@planet} {@coords} {@target} erreichen {@targetcoords}.', 0),
(3602, 3, 3, 'FLEET_MESSAGE_ROCKET_ATTACK_FOREIGN', 'Feindliche Raketen ({@rockets}) {@username} {@message} auf {@planet} {@coords} {@target} erreichen {@targetcoords}.', 0),
(3603, 3, 3, 'INVALID_PLANET_NAME', 'Der Name des Planeten enthalt ungultige Zeichen.', 0),
(3604, 3, 3, 'NEW_PLANET_NAME', 'Der neue Name des Planeten', 0),
(3605, 3, 3, 'PLANETDIAMETER', 'Durchmesser', 0),
(3606, 3, 3, 'PLANET_OPTIONS', 'Optionen Planeten', 0),
(3607, 3, 1, 'POINTS', 'Brille', 0),
(3608, 3, 3, 'POSITION', 'Koordinaten', 0),
(3609, 3, 3, 'RANK_OF_USERS', '{@rank} aus {@totalUsers}', 0),
(3610, 3, 3, 'RELEASE', 'Freisetzung', 0),
(3611, 3, 3, 'SERVER_TIME', 'Server Zeit', 0),
(3612, 3, 3, 'STAR_SUR_MSG', 'Alien Fleet ({@fleet}), der Spieler mit der {@username} {@planet} {@coords} Bewegung auf {@target} {@targetcoords}. Assignment: {@mission}', 0),
(3613, 3, 3, 'STAR_SUR_MSG_RETURN', 'Alien Fleet ({@fleet}) kehrt mit einer {@planet} {@coords} auf {@target} {@targetcoords}. Assignment: {@mission}', 0),
(3614, 3, 3, 'TEMPERATURE', 'Temperatur', 0),
(3615, 3, 4, 'ABORT', 'Stornieren', 0),
(3616, 3, 4, 'BATTLE_SHIP', 'Schlachtschiff', 0),
(3617, 3, 4, 'BATTLE_SHIP_DESC', 'Schlachtschiffe der Regel bilden die Grundlage fur die Flotte. Ihre schweren Geschutze, hohe Geschwindigkeit und gro?e Tonnage machen ernsthaften Rivalen.', 0),
(3618, 3, 4, 'BATTLE_SHIP_FULL_DESC', 'Schlachtschiffe der Regel bilden die Grundlage fur die Flotte. Ihre schweren Geschutze, hohe Geschwindigkeit und gro?e Tonnage machen ernsthaften Rivalen.', 0),
(3619, 3, 4, 'BOMBER', 'Bomber', 0),
(3620, 3, 4, 'BOMBER_DESC', 'Bomber wurde entwickelt, um die Planeten-Schutz zu zerstoren.', 0),
(3621, 3, 4, 'BOMBER_FULL_DESC', 'Bomber wurde entwickelt, um die Planeten-Schutz zu zerstoren. Mit dem Laser-Augen, er hat nur eine Bombe auf dem Plasma-Oberflache des Planeten und damit verursachen gro?e Schaden an der defensiven Strukturen. Nachteile: relativ langsamen Schiff.', 0),
(3622, 3, 4, 'COLONY_SHIP', 'Colonizer', 0),
(3623, 3, 4, 'COLONY_SHIP_DESC', 'Mit diesem Schiff erkunden Sie unbewohnten Planeten.', 0),
(3624, 3, 4, 'COLONY_SHIP_FULL_DESC', 'Colonizer ist fur die Entwicklung von bisher unbesetzten Planeten bestimmt. Es ist in der neuen Kolonie als Lieferant von Rohstoffen verwendet werden - es zerlegt und alle nutzliches Material fur die Entwicklung von einem neuen Licht.', 0),
(3625, 3, 4, 'COMBUSTION_ENGINE', 'Dusentriebwerk', 0),
(3626, 3, 4, 'COMBUSTION_ENGINE_DESC', 'Technologie fur die Entwicklung von kleinen Motoren komsicheskih Schiffe, die mit einem kleinen Verbrauch von Kraftstoff uber weite Strecken fliegen konnen.', 0),
(3627, 3, 4, 'COMBUSTION_ENGINE_FULL_DESC', 'Der Motor basiert auf dem Prinzip der Ruckkehr basiert. Matter auf hohe Temperaturen aufgeheizt, wird in die entgegengesetzte Richtung geworfen und Beschleunigung verleiht dem Schiff. Der Wirkungsgrad dieser Motoren ist recht klein, aber sie sind sehr zuverlassig, billig zu produzieren und zu pflegen. Daruber hinaus nehmen sie weniger Platz an Bord im Vergleich zu anderen Motoren, so sind sie immer noch ziemlich oft auf kleinen Schiffen gefunden. Da Triebwerke die Grundlage fur jede Weltraummission sind, sollten sie so fruh wie moglich zu prufen. Die weitere Entwicklung dieser Motoren macht die folgenden Fahrzeuge auf jeder Ebene ist 10% schneller: <br /> <br /> kleinen Frachter (bis kein untersucht kick Motor Stufe 5), gro?e Transporte, Licht-Kampfer und Spion-Sonden.', 0),
(3628, 3, 4, 'COMPUTER_TECH', 'Computer Technology', 0),
(3629, 3, 4, 'COMPUTER_TECH_DESC', 'Mit zunehmender Leistung der Computer befehlen kann mehr und mehr Flotten. Jede Ebene der Computer-Technologie steigert die maximale Anzahl der Flotten zu eins.', 0),
(3630, 3, 4, 'COMPUTER_TECH_FULL_DESC', 'Computer-Technologie wurde entwickelt, um die verfugbare Rechenleistung zu erhohen. Als Folge entwickeln sich die Welt noch produktiver und effizienter EDV-Systeme, Rechenleistung erhoht und die Rate, mit der Rechenprozesse. Mit zunehmender Leistungsfahigkeit von Computern gleichzeitig Befehl eine wachsende Zahl von Flotten. Jede Stufe der Entwicklung der Computertechnologie macht es moglich, eine Flotte Befehl. Je mehr verteilt Flotte, desto mehr konnen Sie Angriffe und damit einzufangen mehr Material. Naturlich ist diese Technik sinnvoll und Handler, da es ihnen gleichzeitig zu senden mehr Handelsflotten ermoglicht. Aus diesem Grund sollten Sie immer die Entwicklung der Computertechnologie im gesamten Spiel.', 0),
(3631, 3, 4, 'CONTINUE', 'Vorgehen', 0),
(3632, 3, 4, 'CRUISER', 'Kreuzer', 0),
(3633, 3, 4, 'CRUISER_DESC', 'Cruisers fast dreimal starker als der schwere Kampfer geschutzt, und die Feuerkraft uberlegen sind schwere Kampfer fast zwei-fach. Daruber hinaus sind sie sehr schnell.', 0),
(3634, 3, 4, 'CRUISER_FULL_DESC', 'Mit der Entwicklung von Lasern und schwere Ionen Kanone schweren Kampfer sind zunehmend gezwungen. Trotz zahlreicher Verbesserungen in Feuerkraft und nicht Vorbehalte konnten so verandert werden, um wirksam zu begegnen diese defensive Werkzeuge. Es wurde daher beschlossen, eine neue Klasse von Schiffen, die ein Hotel und mehr Feuerkraft kombinieren bauen wurde. So gab es einen Kreuzer. Cruisers fast dreimal starker als der schwere Kampfer geschutzt und haben mehr als doppelt so Feuerkraft. Daruber hinaus sind sie sehr schnell. Es gibt keine bessere Waffe gegen durchschnittlich Verteidigung. Fast ein Jahrhundert Kreuzer unbegrenzte Herrschaft im Universum. Mit dem Aufkommen von Kanonen und Plasmakanonen Gauss ihre Herrschaft beendet. Doch heute sind sie bereit, gegen Gruppen von Kampfern zu verwenden.', 0),
(3635, 3, 4, 'DEATH_STAR', 'Death Star', 0),
(3636, 3, 4, 'DEATH_STAR_DESC', 'Death Star ist mit einem riesigen Graviton Kanone, Schiffen und sogar den Mond zu zerstoren kann, ausgestattet.', 0),
(3637, 3, 4, 'DEATH_STAR_FULL_DESC', 'Der Todesstern ist mit einer Graviton Waffe, die alle Arten von Schiffen zerstoren konnen und sogar den Mond ausgestattet. Zur Herstellung von ausreichend Energie, ist der Star der Tod fast ausschlie?lich aus den Generatoren zusammen. Nur ein gro?er Star des Reiches uber genugend Ressourcen und Personal fur den Bau des riesigen Schiffes.', 0),
(3638, 3, 4, 'DEMOLISH', 'Zerstorung:', 0),
(3639, 3, 4, 'DEMOLISH_NOW', '&quot;Zerstort&quot;', 0),
(3640, 3, 4, 'ENERGY_TECH', 'Energy Technology', 0),
(3641, 3, 4, 'ENERGY_TECH_DESC', 'Der Besitz von verschiedenen Arten von Energie ist fur viele neue Technologien benotigt werden.', 0),
(3642, 3, 4, 'ENERGY_TECH_FULL_DESC', 'Der Besitz von verschiedenen Arten von Energie ist fur viele neue Technologien benotigt werden.', 0),
(3643, 3, 4, 'ESPIONAGE_SENSOR', 'Spy Probe', 0),
(3644, 3, 4, 'ESPIONAGE_SENSOR_DESC', 'Spy-Sonden - das sind kleine wendige Schiffe, die Daten liefern aus einer Entfernung von Flotten und Planeten.', 0),
(3645, 3, 4, 'ESPIONAGE_SENSOR_FULL_DESC', 'Spy-Sonden - das sind kleine wendige Schiffe, die Daten liefern aus einer Entfernung von Flotten und Planeten. Ihr High-Power-Motor ermoglicht es ihnen, lange Strecken ein paar Sekunden lang zu reisen. Einmal in der Umlaufbahn eines Planeten eingefuhrt, bleiben sie dort fur einige Zeit, um die Montage der Daten. Zu diesem Zeitpunkt kann der Feind sie mit relativer Leichtigkeit und Angriff zu erkennen. Um Platz zu sparen wurde nicht gefunden keine Rustung oder Schilde, oder Waffen, die die Sonden bei leichten Zielen macht.', 0),
(3646, 3, 4, 'EXPO_TECH', 'Expedition Technologie', 0),
(3647, 3, 4, 'EXPO_TECH_DESC', 'Jetzt die Schiffe konnen mit dem Forschungs-Einheit, die die Verarbeitung von Daten in langen Flugen gesammelt ausgestattet sein.', 0),
(3648, 3, 4, 'EXPO_TECH_FULL_DESC', 'Forwarding-Technologie umfasst eine Vielzahl von Scan-Technologien und ermoglicht es Ihnen, die Schiffe der verschiedenen Klassen der Forschungs-Modul auszustatten. Es enthalt eine Datenbank, ein kleines mobiles Labor und verschiedene biokletki und Behalter fur die Proben. Fur die Sicherheit des Schiffes bei der Untersuchung von gefahrlichen Anlagen Forschungs-Modul ist mit einer autarken Stromversorgung und Generator von Energie-Feld, das in extremen Situationen Surround Research Module machtige Energie-Feld kann ausgestattet.', 0),
(3649, 3, 4, 'FRIGATE', 'Schlachtkreuzer', 0),
(3650, 3, 4, 'FRIGATE_DESC', 'Schlachtkreuzer ist spezialisiert auf das Abfangen feindliche Flotten.', 0),
(3651, 3, 4, 'FRIGATE_FULL_DESC', 'Diese High-Tech-Schiff bringt Tod angreifende Flotte. Seine fortschrittliche Laserkanonen halten schwere feindliche Schiffe auf Distanz und kann ein paar Einheiten durch eine Salve zu eliminieren. Aufgrund seiner geringen Gro?e und unglaublich machtige Waffen, Schlachtkreuzer Tragfahigkeit sehr klein, aber auf Kosten einer Hyperraum-Motor und wenig Verbrauch.', 0),
(3652, 3, 4, 'GAUSS_GUN', 'Gau?kanone', 0),
(3653, 3, 4, 'GAUSS_GUN_DESC', 'Gauss Kanone beschleunigt Multi-Tonnen-Ladungen mit der gewaltigen Kosten von Energie.', 0),
(3654, 3, 4, 'GAUSS_GUN_FULL_DESC', 'Fur eine lange Zeit als obsolet Artillerie gegen die Entwicklung der modernen Laser-und Ionen-Technologie und werden standig verbessert Sicherheit, wahrend neue Forschung uber Energietechnologien sind nicht erlaubt zu holen Gewehre, eine neue Ebene. In der Regel haben die Prinzipien der elektromagnetischen Masse Beschleunigern auf der Erde seit dem 20. Jahrhundert bekannt. Einer von ihnen - Gauss Kanone. Mit der Entscheidung der technischen Schwierigkeiten bei der Verwendung als Waffe ist Wirklichkeit geworden. Multi-Tonnen-Geschosse sind durch das Magnetfeld mit einem enormen Aufwand an Energie beschleunigt und die Drehzahl, dass Staub in die Luft um das Geschoss verbrannt werden, und die Schallwelle schuttelt die Erde. Selbst die modernen Rustungen und Schilde kann kaum widerstehen disruptive Kraft des Gauss Kanone, und oft passiert ist, dass das Ziel einfach durch zu fegen. Defenses selbst deaktiviert, sobald sie schwer verletzt sind.', 0),
(3655, 3, 4, 'GRAVI', 'Gravitationsphysik Technologie', 0),
(3656, 3, 4, 'GRAVI_DESC', 'Graviton - ein Teilchen, das weder Masse noch Ladung hat und bestimmt die Schwerkraft. Durch den Betrieb einer geballten Ladung von Gravitonen Wissenschaftlern gelungen, ein kunstliches Gravitationsfeld, das in der Lage, Schiffe und sogar den Mond zu zerstoren, ist zu schaffen. Da die Hohe dieser Technologie kann den Kraftstoffverbrauch reduzieren.', 0),
(3657, 3, 4, 'GRAVI_FULL_DESC', 'Graviton - ein Teilchen, das weder Masse noch Ladung hat und bestimmt die Schwerkraft. Durch den Betrieb einer geballten Ladung von Gravitonen Wissenschaftlern gelungen, ein kunstliches Gravitationsfeld, das wie ein schwarzes Loch, zieht in eine Menge zu schaffen, so konnen Sie zerstore Schiffe und sogar der Mond. Da das Niveau dieser Technologie lasst sich der Kraftstoffverbrauch wahrend des Fluges zu verringern ganzen Schiff. Um zu erfahren, eine neue Stufe der Technologie eine enorme Menge an Energie. Spalte zeigt den Anteil der Produktion von Kraftstoff aus dem Grundwert fur einen bestimmten Stand der Technik.', 0),
(3658, 3, 4, 'GUN_TECH', 'Waffentechnik', 0),
(3659, 3, 4, 'GUN_TECH_DESC', 'Waffen-Technologie macht effizienter Waffensysteme. Jede Stufe vergro?ert die Macht der Waffen von militarischen Einheiten von 10% der Primarenergie.', 0),
(3660, 3, 4, 'GUN_TECH_FULL_DESC', 'Waffentechnik ist in erster Linie die weitere Entwicklung der verfugbaren Waffensystemen beschaftigt. In diesem Fall unterstreicht die Tatsache, dass die verfugbaren Energieversorgung mehr und mehr genau diese Energie. Da dieses Waffensystems wird effizienter, sondern eine Waffe mehr Schaden anrichtet. Jede Stufe der Waffentechnik erhoht die Macht der Waffen von militarischen Einheiten um 10%. Weapons Technology ist fur die Wettbewerbsfahigkeit von Teilen des Inhalts wichtig. Daher sollte es immer im Laufe des Spiels entwickeln.', 0),
(3661, 3, 4, 'HYDROGEN_LAB', 'Synthesizer Wasserstoff', 0),
(3662, 3, 4, 'HYDROGEN_LAB_FULL_DESC', 'Die Verbesserung der Synthesizer erhoht die Effizienz in den Ozean des Planeten und folglich gro?ere Produktion von Wasserstoff-Prozess. Wasserstoff benotigt wird als Treibstoff fur Schiffe, die fast alle Studien zeigen die Galaxien, sowie fur die sensorische Phalanx.', 0),
(3663, 3, 4, 'HYDROGEN_PLANT', 'Thermonuclear Kraftwerk', 0),
(3664, 3, 4, 'HYDROGEN_PLANT_FULL_DESC', 'Auf Fusionskraftwerke durch Kernfusion unter enormem Druck und hoher Temperatur aus 2 Atomen des schweren Wasserstoffs werden in ein Heliumatom kombiniert. In diesem Fall wird die Bildung von Helium-Kernen, durch die Energie in 41,32 x 10 -13 J in Form von Strahlung (also die Verbrennung von Wasserstoff entsteht 1 g von 172 MWh Energie) produziert. Je mehr ein Fusionsreaktor, desto schwieriger Prozesse der Synthese produziert der Reaktor mehr Energie. Extraktion von Energie kann auch durch die Entwicklung von Energietechnologien gefordert werden.', 0),
(3665, 3, 4, 'HYDROGEN_STORAGE', 'Kapazitat fur Wasserstoff', 0),
(3666, 3, 4, 'HYDROGEN_STORAGE_FULL_DESC', 'Gro?e Speicherkapazitat fur die Speicherung von erzeugtem Wasserstoff. Sie sind meist in der Nahe des Platz-Port gefunden. Als sie sind, desto mehr Wasserstoff in ihnen gespeichert werden. Wenn sie gefullt sind, stoppt die Produktion von Wasserstoff.', 0),
(3667, 3, 4, 'HYPERSPACE_ENGINE', 'Hyperraumantrieb', 0),
(3668, 3, 4, 'HYPERSPACE_ENGINE_DESC', 'Arches Raum um das Schiff. Die weitere Entwicklung dieser Motoren macht einige Schiffe schneller.', 0),
(3669, 3, 4, 'HYPERSPACE_ENGINE_FULL_DESC', 'Aufgrund der Raum-Zeit-Krummung in unmittelbarer Nahe des Schiffes Raum schrumpft schneller als Uberwindung der Distanzen. Je hoher entwickelt Hyperraum-Laufwerk, je hoher die Kompression Raum, so dass mit jeder Stufe der Geschwindigkeit der Schiffe um 30% erhoht.', 0),
(3670, 3, 4, 'HYPERSPACE_TECH', 'Hyperraumtechnik', 0),
(3671, 3, 4, 'HYPERSPACE_TECH_DESC', 'Durch Verflechtung der 4. und 5. Dimension wurde es moglich, neue, sparsamere und effizientere Motoren zu erkunden. Daruber hinaus entdeckten Wissenschaftler, dass ein gekrummter Raum im Bereich des Sensors Phalanx erhoht.', 0),
(3672, 3, 4, 'HYPERSPACE_TECH_FULL_DESC', 'Durch Verflechtung der 4. und 5. Dimension wurde es moglich, neue, sparsamere und effizientere Motoren zu erkunden. Daruber hinaus entdeckten Wissenschaftler, dass ein gekrummter Raum im Bereich des Sensors Phalanx von 10% fur jede Ebene der Technologie erhoht.', 0),
(3673, 3, 4, 'IGN', 'Intergalactic Research Network', 0),
(3674, 3, 4, 'IGN_DESC', 'Dieses Netzwerk ermoglicht die Kommunikation von Wissenschaftlern in den Forschungslaboren in verschiedenen Planeten. Jede neue Ebene konnen Sie mit einem Netzwerk von weiteren Labors herstellen.', 0),
(3675, 3, 4, 'IGN_FULL_DESC', 'Dieses Netzwerk ermoglicht die Kommunikation von Wissenschaftlern in den Forschungslaboren in verschiedenen Planeten. Jede neue Ebene konnen Sie mit dem Netzwerk fur mehr Labor herstellen (erste trat im Labor von hoheren Ebenen). Von allen vereint in einem Netzwerk von Laboratorien in jeder Studie beteiligten nur diejenigen, die ausreichend fur die Durchfuhrung dieser Forschung Ebene. Die Rate-Studie ist die Summe der Werte der beteiligten Laboratorien.', 0),
(3676, 3, 4, 'IMPULSE_ENGINE', 'Kick-Motor', 0),
(3677, 3, 4, 'IMPULSE_ENGINE_DESC', 'Pulse-Motor auf dem Prinzip der Ruckkehr basiert. Die weitere Entwicklung dieser Motoren macht einige Schiffe schneller,', 0),
(3678, 3, 4, 'IMPULSE_ENGINE_FULL_DESC', 'Pulse-Motor auf dem Prinzip der Ruckkehr basiert, und die Erwarmung der Materie in einer Kernreaktion durchgefuhrt. Es ist auch moglich, eine zusatzliche Masse zu injizieren. Die weitere Entwicklung dieser Motoren macht die folgenden Fahrzeuge auf allen Ebenen zu 20% schneller: Bomber, Kreuzer, Zerstorer und schwere Kolonisatoren. Jede Stufe der Entwicklung erhoht sich die Reichweite des interplanetaren Raketen.', 0),
(3679, 3, 4, 'INTERCEPTOR_ROCKET', 'Abfangraketen', 0),
(3680, 3, 4, 'INTERCEPTOR_ROCKET_DESC', 'Interceptors zerstoren angreifenden Raketen interplanetaren.', 0),
(3681, 3, 4, 'INTERCEPTOR_ROCKET_FULL_DESC', 'Interceptors zerstoren angreifenden Raketen interplanetaren. Eine Abfangrakete zerstorte eine einzige interplanetaren Rakete.', 0),
(3682, 3, 4, 'INTERPLANETARY_ROCKET', 'Interplanetary Rakete', 0),
(3683, 3, 4, 'INTERPLANETARY_ROCKET_DESC', 'Interplanetary Raketen auf feindliche Verteidigung zu zerstoren.', 0),
(3684, 3, 4, 'INTERPLANETARY_ROCKET_FULL_DESC', 'Interplanetary Raketenabwehr den Feind zu vernichten. Zerstorte interplanetaren Raketenabwehr wird nicht wiederhergestellt werden.', 0),
(3685, 3, 4, 'ION_GUN', 'Ion Cannon', 0),
(3686, 3, 4, 'ION_GUN_DESC', 'Ion Cannon sendet eine Welle auf das Ziel-Ionen, die die Schilde destabilisiert und beschadigte die Elektronik.', 0),
(3687, 3, 4, 'ION_GUN_FULL_DESC', 'Im 21. Jahrhundert auf der Erde bestand bereits, dass in der Regel als EMI bekannt ist. EMI zeigt elektromagnetischen Impuls, der die Fahigkeit zu zusatzlichen Spannungen in der Schaltung zu induzieren und somit zu massiven Storungen, die alle sensiblen Instrumente zerstoren kann hat. Dann EMP Waffen waren in erster Linie auf Raketen und Bomben auf, und in Kombination mit nuklearen Waffen. Inzwischen haben EMP-Waffen entwickelt, da sie ein gro?es Potenzial nicht zerstoren Ziele, und sie nicht in der Lage zu kampfen und zu manovrieren und damit zu erleichtern ihrer Gefangennahme sah. Bisher ist die hochste Form der EMP-Waffen durch eine Ionenkanone vertreten. Er sendet eine Welle auf das Ziel-Ionen (elektrisch geladene Teilchen), welche die Schilde destabilisiert und beschadigte die Elektronik nur, wenn es nicht sehr gut geschutzt, manchmal nur totale Zerstorung. Kinetic punch Kraft vernachlassigt werden kann. Ionic-Technologie wird nur auf Kreuzern sowie Energie-Ionen-Kanonen eingesetzt ist riesig, und im Kampf oft zu zerstoren, nicht um das Ziel zu lahmen. Defenses selbst deaktiviert, sobald sie schwer verletzt sind.', 0),
(3688, 3, 4, 'ION_TECH', 'Ionen-Technologie', 0),
(3689, 3, 4, 'ION_TECH_DESC', 'Wahrlich eine todliche Strahl induzierten beschleunigten Ionen. Nach Kontakt mit einem Gegenstand, die sie verursachen enorme Schaden.', 0),
(3690, 3, 4, 'ION_TECH_FULL_DESC', 'Wahrlich eine todliche Strahl induzierten beschleunigten Ionen. Nach Kontakt mit einem Gegenstand, die sie verursachen enorme Schaden.', 0),
(3691, 3, 4, 'LARGE_SHIELD', 'Gro?e Schildkuppel', 0),
(3694, 3, 4, 'LARGE_TRANSPORTER', 'Gro?e Transport', 0),
(3695, 3, 4, 'LARGE_TRANSPORTER_DESC', 'Die weitere Entwicklung von kleinen transportiert es moglich, Schiffe mit mehr Kapazitat und dank fortgeschrittener Motor, der Lage, sich schneller als kleine Fahrzeuge zu schaffen.', 0),
(3696, 3, 4, 'LARGE_TRANSPORTER_FULL_DESC', 'An Bord dieses Schiffes hat nur eine schwache Bewaffnung und keine gro?eren Technologie ... Aus diesem Grund sollten sie nie ohne Begleitung gefahren werden. Aufgrund seiner hoch entwickelten transportieren gro?e Triebwerk dient als schnelle interplanetare Zusteller von Ressourcen, sie begleitet auch die Flotten in den Angriffen auf die feindlichen Planeten, so viel wie moglich Ressourcen zu erfassen.', 0),
(3697, 3, 4, 'LASER_TECH', 'Lasertechnik', 0),
(3698, 3, 4, 'LASER_TECH_DESC', 'Aufgrund der Lichtstrahl tritt, die in Kontakt mit dem Objekt, das ihm Verletzungen konzentrieren.', 0),
(3699, 3, 4, 'LASER_TECH_FULL_DESC', 'Lasers (Lichtverstarkung durch stimulierte Emission von Strahlung) erzeugen intensive Energie Strahl von koharentem Licht. Diese Gerate finden Anwendung in verschiedensten Bereichen, vom Computer bis zum schweren optischen Laser, die frei Rustung Raumsonde geschnitten werden. Laser-Technologie ist ein wichtiger Baustein fur die weitere Untersuchung der Waffentechnologie.', 0),
(3700, 3, 4, 'LIGHT_FIGHTER', 'Leichter Jager', 0),
(3701, 3, 4, 'LIGHT_FIGHTER_DESC', 'Leichter Jager - ein Manover, das Schiff, das auf fast jedem Planeten gefunden werden konnen. Die Kosten sind nicht besonders gro?, der Hauptzweck - die Schlacht fur gro?e Schiffe zu unterstutzen.', 0),
(3702, 3, 4, 'LIGHT_FIGHTER_FULL_DESC', 'Leichter Jager - ein Manover, das Schiff, das auf fast jedem Planeten gefunden werden konnen. Er hat eine schwache Verteidigung und Waffen-Systeme sind einfach und dient als die angreifenden Schiffes zu unterstutzen. Seine Geschwindigkeit, mit der eine gro?e Zahl kombiniert, kann eine hervorragende Pufferzone und Schutz fur gro?ere Schiffe bieten.', 0),
(3703, 3, 4, 'LIGHT_LASER', 'Lichtlaser', 0),
(3704, 3, 4, 'LIGHT_LASER_DESC', 'Mit einem konzentrierten Angriff Ziel Photonen konnen viel bolshih Schaden als mit konventionellen ballistischen Waffen erreicht werden.', 0),
(3705, 3, 4, 'LIGHT_LASER_FULL_DESC', 'Zum Ausgleich fur die uberlange Fortschritte in der Technologie und Raumfahrzeuge, hatten Wissenschaftler eine Festung zu schaffen, mit den gro?eren und besser bewaffnet Flotten umzugehen. Dies hat zu einer leichten Laser gefuhrt. Mit einem konzentrierten Angriff Ziel Photonen konnen viel mehr Schaden anrichten als mit konventionellen ballistischen Waffen erreicht werden. Um gegen die starkere Feuerkraft neue Arten von Schiffen ist es auch mit fortgeschrittenen Schilden ausgerustet. Um jedoch die Produktionskosten niedrig blieben, ist die Struktur nicht weiter ausgebaut werden. Licht-Laser hat den besten Preis und Qualitat, so ist es auch interessant fur fortgeschrittene Zivilisationen. Defenses selbst deaktiviert, sobald sie schwer verletzt sind.', 0),
(3706, 3, 4, 'METALMINE', 'Mine fur die Extraktion von Metall', 0),
(3707, 3, 4, 'METALMINE_FULL_DESC', 'Die wichtigsten Anbieter von Rohstoffen fur den Bau von tragenden Strukturen von Gebauden und Schiffen. Metal - das billigste Rohstoffe, aber es braucht mehr als alles andere. Fur Metall Produktion erfordert weniger Energie. Mehr als Minen, so sind sie tiefer. Auf den meisten Planeten, wird das Metall in gro?eren Tiefen, mit Hilfe dieser tieferen Minen konnen mehr Metall Produktionssteigerungen zu produzieren. Zur gleichen Zeit den gro?eren Minen mehr Energie benotigen.', 0),
(3708, 3, 4, 'METAL_STORAGE', 'Metall-Lagerung', 0),
(3709, 3, 4, 'METAL_STORAGE_FULL_DESC', 'Gro?e Speicherkapazitat fur die extrahierten ore. Was es ist, desto mehr Metall kann man es behalten. Wenn es voll ist, hort der Erzbergbau.', 0),
(3710, 3, 4, 'MOON_BASE', 'Mondbasis', 0),
(3711, 3, 4, 'MOON_BASE_DESC', 'Der Mond hat keine Atmosphare, so, bevor er mochte eine Mondbasis zu errichten.', 0),
(3712, 3, 4, 'MOON_BASE_FULL_DESC', 'Der Mond hat keine Atmosphare, so, bevor er mochte eine Mondbasis zu errichten. Es sorgt fur die notige Luft, die Schwerkraft und Warme. Je hoher das Niveau der Entwicklung einer Mondbasis, desto gro?er die gesicherten Bereich der Biosphare. Jede Ebene aufbauen konnen eine Mondbasis 3 des Feldes, bis zu einer maximalen Flache von der gesamten dem Mond. Sie ist 2 (Durchmesser luny/1000) ^ 2, wobei jede Stufe der Mondbasis selbst belegt einen Platz.', 0),
(3713, 3, 4, 'NANO_FACTORY', 'Fabrik Naniten', 0),
(3714, 3, 4, 'NANO_FACTORY_FULL_DESC', 'Fabrik Naniten sind eine Krone der Robotik. Nanites - ein Roboter von der Gro?e eines Nanometer, die durch die Kombination von einem Netzwerk in der Lage, au?ergewohnliche Aufgaben. Unmittelbar nach der Studie, erhohen sie die Produktivitat in fast allen Bereichen. Mit jedem Level reduziert die Naniten Fabrikhallen, Schiffe und Verteidigungsanlagen in die Halfte.', 0),
(3715, 3, 4, 'PLASMA_GUN', 'Plasma Pistole', 0),
(3716, 3, 4, 'PLASMA_GUN_DESC', 'Laser Technologie perfektioniert wurde, hat Ionen-Technologie die letzte Stufe erreicht.', 0),
(3717, 3, 4, 'PLASMA_GUN_FULL_DESC', 'Laser Technologie perfektioniert wurde, hat Ionen-Technologie die letzte Stufe erreicht, und es wurde angenommen, dass so gut wie unmoglich, auch aus qualitativer Sicht der Artillerie-Systeme, um noch gro?ere Effizienz zu erreichen. Aber alles hatte sich verandert, wenn die Idee, beide Systeme zu kombinieren. Mit Fusion-Technologie, Laser-erhitztem Material (meist Wasserstoff) auf extrem hohe Temperaturen und erreicht Millionen von Grad. Ion-Technologie bietet die Anreicherung des Plasmas elektrische Ladung, deren Stabilisierung und Beschleunigung. Sobald die Ladung ausreichend erwarmt, ionisiert und unter Druck steht, dann loslassen, mit Hilfe von Beschleunigern in Richtung des Ziels. Luminous blaue Farbe des Plasma-Ball ist beeindruckend, fragen Sie einfach, wie lange sie die Besatzung des Ziels zu genie?en, wenn nach ein paar Sekunden Rustung in Stucke brach, und der Elektronik wird brennen ... Plasma Pistole ist in der Regel die schrecklichsten Waffen, und diese Technik hat ihren Preis. Defenses selbst deaktiviert, sobald sie schwer verletzt sind.', 0),
(3718, 3, 4, 'PLASMA_TECH', 'Plasma-Technologie', 0),
(3719, 3, 4, 'PLASMA_TECH_DESC', 'Weiterentwicklung des Ionen-Technologie, die die Ionen beschleunigt werden nicht, und die Hochenergie-Plasma. Es hat eine verheerende Wirkung in Kontakt mit einem Objekt.', 0),
(3720, 3, 4, 'PLASMA_TECH_FULL_DESC', 'Weiterentwicklung des Ionen-Technologie, die die Ionen beschleunigt werden nicht, und die Hochenergie-Plasma. Es hat eine verheerende Wirkung in Kontakt mit einem Objekt.', 0),
(3721, 3, 4, 'PRODUCTION_TIME', 'Benotigte Zeit:', 0),
(3722, 3, 4, 'RECYCLER', 'Recycler', 0),
(3723, 3, 4, 'RECYCLER_DESC', 'Mit dem Prozessor von Rohstoffen aus den Trummern extrahiert.', 0),
(3724, 3, 4, 'RECYCLER_FULL_DESC', 'Weltraumschlachten nehmen mehr Dimensionen. Zerstorte Tausende von Schiffen und die daraus resultierenden Ablagerungen, die fur immer verloren zu sein schien. Normale Transporte nicht schlie?en konnte, um sie sein, ohne dass ernsthaft kleine Fragmente beschadigt Ansatz. Mit der Neueroffnung in Schutzschild-Technologie moglich geworden, effektiv zu beseitigen dieses Problem, eine neue Klasse von Schiffen, wie ein gro?es Fahrzeug - Prozessor. Mit ihm konnen Sie Wiederverwendung verloren schien Ressourcen. Aufgrund der neuen Boards sind kleine Stucke nicht mehr eine Gefahr. Leider erfordern diese Gerate Platz, so dass ihr Cargo-Tonnage auf 20 000 begrenzt.', 0),
(3725, 3, 4, 'REQUIRES', 'Erforderlich', 0),
(3726, 3, 4, 'RESEARCH_LAB', 'Forschungslabor', 0),
(3727, 3, 4, 'RESEARCH_LAB_FULL_DESC', 'Um zu untersuchen, neue Technologien mussen die Forschungsstation arbeiten. Die Hohe der Forschungs-Station ist ein entscheidender Faktor dafur, wie schnell konnen neue Technologien gemeistert werden. Je hoher das Niveau der Entwicklung der Forschung im Labor, desto mehr kann durch neue Technologien untersucht werden. Um so schnell wie moglich zur Forschung auf einem Planeten komplett, schickte er alle zur Verfugung stehenden Wissenschaftler und verlassen somit ihre Planeten. Wenn die Technologie untersucht wurde, kehrten die Wissenschaftler in ihrem Heimatplaneten, und fuhren mit ihnen Wissen uber sie. Da neue Technologien konnen auf andere Planeten angewendet werden.', 0),
(3728, 3, 4, 'RESEARCH_LAB_REQUIRED', 'Notwendig, um ein Forschungslabor zu errichten.', 0),
(3729, 3, 4, 'ROBOTIC_FACTORY', 'Factory-Robot', 0),
(3730, 3, 4, 'ROBOTIC_FACTORY_FULL_DESC', 'Bietet eine einfache Arbeit, die in den Bau eines planetaren Infrastruktur eingesetzt werden konnen. Jede Stufe erhoht die Geschwindigkeit der Fabrikhallen.', 0),
(3731, 3, 4, 'ROCKET_LAUNCHER', 'Raketenwerfer', 0),
(3732, 3, 4, 'ROCKET_LAUNCHER_DESC', 'Rocket Launcher - einfach und billig Mittel der Verteidigung.', 0),
(3733, 3, 4, 'ROCKET_LAUNCHER_FULL_DESC', 'Rocket Launcher - einfach und billig Mittel der Verteidigung. Da es sich um eine Weiterentwicklung des herkommlichen ballistischen Waffen, dann ist es nicht mehr notig Upgrade. Kleine Produktionskosten, deren Nutzung gegen kleinere Flotten zu rechtfertigen, aber mit der Zeit an Wert verliert. Spater wird es nur, um den Feind abzulenken Aufnahmen verwendet. Defenses selbst deaktiviert, sobald sie schwer verletzt sind.', 0),
(3734, 3, 4, 'ROCKET_STATION', 'Raketensilos', 0),
(3735, 3, 4, 'ROCKET_STATION_DESC', 'Verwendet werden, um die Raketen zu speichern.', 0),
(3736, 3, 4, 'ROCKET_STATION_FULL_DESC', 'Raketensilos verwendet werden, um Raketen zu speichern. Jede Ebene kann fur funf Minuten vor zehn interplanetaren Abfangjager mehr gespeichert werden. Ein interplanetaren Raum zu starten erfordert zwei Mal mehr als die Abfangraketen. Vielleicht eine Kombination von verschiedenen Arten von Raketen.', 0),
(3737, 3, 4, 'SHELL_TECH', 'Rustung Technologie', 0),
(3738, 3, 4, 'SHELL_TECH_DESC', 'Spezielle Legierungen verbessern die Rustung des Raumschiffs. So kann die Stabilitat der Rustung mit jedem Level von 10% zu erhohen.', 0),
(3739, 3, 4, 'SHELL_TECH_FULL_DESC', 'Spezielle Legierungen verbessern die Rustung des Raumschiffs. Einmal fand sehr Legierung, verandern besonderen Strahlen die molekulare Struktur des Raumschiffes, und bringt es auf den Zustand der untersuchten Legierung. So kann die Stabilitat der Rustung mit jedem Level von 10% zu erhohen.', 0),
(3740, 3, 4, 'SHIELD_TECH', 'Abschirmtechnik', 0),
(3741, 3, 4, 'SHIELD_TECH_DESC', 'Diese Technologie macht die Schilde der Schiffe und Verteidigungsanlagen effizienter. Jede Stufe erhoht die Effizienz der Schilde fur 10% der Hauptkraft. Mit jedem Level konnen Sie bauen eine schutzende Kuppel.', 0),
(3742, 3, 4, 'SHIELD_TECH_FULL_DESC', 'Die Entwicklung dieser Technologie erlaubt es, die Versorgung mit Energie Schilde und Schutzschirme, die wiederum erhoht ihre Stabilitat und die Fahigkeit zu absorbieren oder reflektieren Energie Angriffe zu erhohen. Dank jeder Ebene untersucht die Wirksamkeit des Schiffes Panels und stationaren Generatoren, Energiefelder um 10% der Nennkapazitat erhoht. Daruber hinaus kann jede Stufe in der Verteidigung mehr schutzenden Kuppeln gebaut werden. Jede Ebene ermoglicht es Ihnen, einen gro?en Schild Kuppel oder zwei kleine zu bauen. Vielleicht mit einer Kombination der Schild Kuppeln.', 0),
(3743, 3, 4, 'SHIPYARD', 'Werft', 0),
(3744, 3, 4, 'SHIPYARD_FULL_DESC', 'In der Werft produziert alle Arten von Schiffen. Was es ist, desto schneller konnen Sie bauen immer komplexer und gro?ere Schiffe. Daruber hinaus erhoht sich mit jedem Level den Werften bei 1% Angriffskraft und eine 0,1-Ebene der Ballistik Schiffe geschickt, um den Planeten angreifen.', 0),
(3745, 3, 4, 'SHIPYARD_REQUIRED', 'Notwendig, eine Werft zu bauen.', 0),
(3746, 3, 4, 'SILICON_LAB', 'Mine fur die Extraktion von Kieselsaure', 0);
INSERT INTO `na_phrases` (`phraseid`, `languageid`, `phrasegroupid`, `title`, `content`, `translated`) VALUES
(3747, 3, 4, 'SILICON_LAB_FULL_DESC', 'Die wichtigsten Anbieter von Rohstoffen fur elektronische Bauelemente und Legierungen. Fur die Herstellung von Silizium dauert etwa doppelt so viel Energie als der Bergbau das Metall, so ist es daher wertvoller. Silizium ist fur alle Fahrzeuge und Gebaude erforderlich. Leider, wie notwendig fur den Bau und Forschung, wird das Feld von Silizium in der Regel sehr selten und, wie die meisten Metalle, in gro?eren Tiefen vorkommen. Daher ist fur die Verbesserung der Mine und erhoht die Produktion, als gro?ere und reinem Silizium Einlagen entwickelt.', 0),
(3748, 3, 4, 'SILICON_STORAGE', 'Silicon Storage', 0),
(3749, 3, 4, 'SILICON_STORAGE_FULL_DESC', 'In diesem riesigen Sammlung von gespeicherten noch nicht verarbeitet Silizium. Je gro?er der Speicher, desto mehr Silizium dort platziert haben. Wenn es leer ist, ist die Gewinnung der Ressource beendet.', 0),
(3750, 3, 4, 'SMALL_SHIELD', 'Kleine Schildkuppel', 0),
(3753, 3, 4, 'SMALL_TRANSPORTER', 'Kleiner Transporter', 0),
(3754, 3, 4, 'SMALL_TRANSPORTER_DESC', 'Kleine Cargo - ein Manover, das Schiff, das schnell transportieren konnen die Rohstoffe zu anderen Planeten.', 0),
(3755, 3, 4, 'SMALL_TRANSPORTER_FULL_DESC', 'Pickups sind etwa die gleiche Gro?e wie die Kampfer, aber sie haben keine leistungsstarken Motoren und luftgestutzten Waffen aus Grunden der Platzersparnis. Kleine Ladevolumen 5000 Einheiten des Rohstoffs. Aufgrund der geringen Feuerkraft kleine Transporte oft von anderen korablyami.Kogda kick Motor begleitet werden, bevor die 5. Etappe wurde untersucht, erhoht ein kleines Transportunternehmen dem Basiszinssatz, und es ist mit dieser Art von Motor.', 0),
(3756, 3, 4, 'SOLAR_PLANT', 'Solar Power', 0),
(3757, 3, 4, 'SOLAR_PLANT_FULL_DESC', 'Um Energie fur die Minen und Synthesizer benotigen riesige Solarkraftwerke. Die gro?eren Stationen sind gebaut worden, um so mehr die Oberflache mit Quarzplatten abgedeckt ist, dass Verfahren Lichtenergie in Strom um. Solarkraftwerke sind die Grundlage der Energieversorgung des Planeten.', 0),
(3758, 3, 4, 'SOLAR_SATELLITE', 'Solar-Satelliten', 0),
(3759, 3, 4, 'SOLAR_SATELLITE_DESC', 'Solar-Satelliten - eine einfache Plattform von Photovoltaik-Arrays, die in einer hohen Umlaufbahn befinden. Sie sammeln Sonnenlicht und ubertragen Sie es mit einem Laser an eine Bodenstation.', 0),
(3760, 3, 4, 'SOLAR_SATELLITE_FULL_DESC', 'Solar-Satelliten in den Orbit gestartet Planeten. Sie sammeln Sonnenenergie und ubertragen sie an die Bodenstation. Die Effizienz der Solarenergie-Satelliten abhangig von der Sonneneinstrahlung. Im Prinzip ist die Erzeugung von Energie in der Umlaufbahn, mehr nah an die Sonne hoher als die auf Planeten weit von der Sonne. Wegen seiner Preis-Leistungs-Solar-Satelliten losen die Energieprobleme vieler Welten. Aber beachten Sie: Solar-Satelliten konnen im Kampf zerstort werden.', 0),
(3761, 3, 4, 'SPYWARE', 'Spionage', 0),
(3762, 3, 4, 'SPYWARE_DESC', 'Mit dieser Technologie extrahiert die Daten auf anderen Planeten.', 0),
(3763, 3, 4, 'SPYWARE_FULL_DESC', 'Spionage ist so konzipiert, neue und effizientere Sensoren zu studieren. Je hoher die Technologie entwickelt wird, desto mehr Informationen ein Spieler uber die Ereignisse in ihrer Umgebung. Der Unterschied in der Hohe der Spionage gegen den Feind entscheidend ist - je mehr seine eigenen Spion Technologie, desto mehr Informationen in die Intelligenz und desto geringer die Chance, entdeckt zu enthalten untersucht. Je mehr Sonden geschickt ist, desto mehr Details uber den Feind los, aber es erhoht das Risiko, entdeckt zu werden. Verbessert auch die Spionage Ansiedlung auslandischer Marinen. Es war auch wichtig Niveau der Entwicklung der eigenen Spionage. Ab der zweiten Ebene der Entwicklung bei einem Angriff auf Sie, sondern Berichte uber den Angriff wird auch angezeigt, und die Gesamtzahl der angreifenden Schiffe. Auf der vierten Ebene der anerkannten Arten der Schiffe angreift, sowie deren Gesamtzahl, wahrend das achte - die genaue Zahl der einzelnen Arten von Schiffen. Fur die Raiders ist diese Technologie sehr wichtig, weil sie Informationen daruber, ob das Opfer Flotte und / oder zum Schutz ausgesetzt sind oder nicht, so sollten Sie es so bald wie moglich zu untersuchen bietet. Best of all - unmittelbar nach dem Studium der kleine Transporte.', 0),
(3764, 3, 4, 'STAR_DESTROYER', 'Kammerjager', 0),
(3765, 3, 4, 'STAR_DESTROYER_DESC', 'Shredder - King von Kriegsschiffen.', 0),
(3766, 3, 4, 'STAR_DESTROYER_FULL_DESC', 'Shredder - King von Kriegsschiffen. Seine multiflangovye Ionen-, Plasma-und Gau?-Geschutzturme kann aufgrund seiner fortschrittlichen Peil-Sensoren sind bis zu 99% sogar High-Speed-wendig Kampfer. Da Schredder sehr gro? sind, ist ihre Mobilitat sehr eingeschrankt, und wie sie zu der Schlacht Station statt einer Bekampfung Schiff kampfen. Der Verbrauch von Wasserstoff in ihnen so hoch wie ihre Kampfkraft.', 0),
(3767, 3, 4, 'STAR_GATE', 'Intergalactic Gateway', 0),
(3768, 3, 4, 'STAR_GATE_DESC', 'Gates - das ist eine riesige Teleporter, die jeweils andere Flotten jeder Gro?e ohne aufwandige senden konnen.', 0),
(3769, 3, 4, 'STAR_GATE_FULL_DESC', 'Gates - das ist eine riesige Teleporter, die jeweils andere Flotten jeder Gro?e ohne aufwandige senden konnen. Diese Teleporter benotigen keinen Wasserstoff, sondern zwischen den beiden Sprungen sollte eine Stunde dauern, sonst das Tor peregreyutsya. Kann nicht auch Transfer-Ressourcen. Der gesamte Prozess erfordert eine sehr hoch entwickelte Technologie. Die Produktion zeigt die Anzahl der Sekunden es dauert, bis das Tor wieder aufzuladen.', 0),
(3770, 3, 4, 'STAR_SURVEILLANCE', 'Sensor Phalanx', 0),
(3771, 3, 4, 'STAR_SURVEILLANCE_DESC', 'Hochfrequenz-Sensoren sind voll scan das Frequenzspektrum der Strahlung auf die Phalanx.', 0),
(3772, 3, 4, 'STAR_SURVEILLANCE_FULL_DESC', 'Hochfrequenz-Sensoren sind voll scan das Frequenzspektrum der Strahlung auf die Phalanx. Leistungsstarke Computer verbinden die kleinsten Schwankungen der Energiepreise und damit Informationen uber die Bewegungen von Schiffen auf fernen Planeten. Um den Mond muss Energie in Form von Wasserstoff (5000-per-view) angegeben werden. Zeige den Ubergang von der Mond in den Galaxy-Menu und klicken auf das entsprechende Symbol in der Menu Aktion des Planeten, die im Bereich der Sensoren ist.', 0),
(3773, 3, 4, 'STORAGE_CAPICITY', 'Kapazitat', 0),
(3774, 3, 4, 'STRONG_FIGHTER', 'Schwerer Jager', 0),
(3775, 3, 4, 'STRONG_FIGHTER_DESC', 'Die weitere Entwicklung eines leichten Kampfer, ist es besser geschutzt und hat der Angriffskraft.', 0),
(3776, 3, 4, 'STRONG_FIGHTER_FULL_DESC', 'Mit der Weiterentwicklung eines leichten Kampfer, haben Wissenschaftler auf den Punkt, wo es war klar, dass ein gewohnlicher Motor nicht uber die notwendigen Macht zu kommen. Um optimal mit dem Schiff, wurde zuerst von den Schrittmotor verwendet. Obwohl er erhohte den Preis, aber es eroffneten sich auch neue Chancen. Durch den Einsatz des Motors blieb mehr Energie, um Waffen und Schilde, aber auch fur diese Art von Kampfern wurden auch wertvolle Materialien verwendet. Dies hat zu einer verbesserten strukturellen Integritat und eine starke Feuerkraft gefuhrt, so dass in der Schlacht er eine gro?ere Bedrohung als sein Vorganger. Nach diesen Anderungen ist schwerer Jager eine neue Ara der Technologie-, Schiffbau-, Technologie-kreyserostroeniya Basis.', 0),
(3777, 3, 4, 'STRONG_LASER', 'Schwerer Laser', 0),
(3778, 3, 4, 'STRONG_LASER_DESC', 'Schwerer Laser stellt eine Weiterentwicklung des Laserlichts.', 0),
(3779, 3, 4, 'STRONG_LASER_FULL_DESC', 'Schwerer Laser stellt eine Weiterentwicklung des Laserlichts. Die Struktur wurde gestarkt und verbessert mit neuen Materialien. Shell tun konnte sehr viel resistenter. Zur gleichen Zeit wurde verbessert und die Energie-System und dem Zielcomputer, so dass der Laser kann hart sein, viel mehr Energie auf Kurs zu konzentrieren. Defenses selbst deaktiviert, sobald sie schwer verletzt sind.', 0),
(3780, 3, 4, 'TERRA_FORMER', 'Terraformer', 0),
(3781, 3, 4, 'TERRA_FORMER_DESC', 'Terraformer umwandeln kann gro?e Flachen eignen sie sich fur den Bau.', 0),
(3782, 3, 4, 'TERRA_FORMER_FULL_DESC', 'Da die Entwicklung der Planeten wird zunehmend wichtige Frage der Grenzen der Nutzflache. Solche traditionellen Methoden, wie Gebaude Hohen und Tiefen, waren unzureichend. Eine kleine Gruppe von Physikern und nanotehnikov eine Losung gefunden - Terraformer. Die Ausgaben riesige Mengen an Energie verwandeln kann Terraformer weite Gebiete und sogar ganze Kontinente, so dass sie fur Gebaude. Diese Struktur kontinuierlich spezifische Naniten, die fur die gleichbleibende Qualitat des Bodens erzeugt werden.', 0),
(3783, 3, 5, 'ALREADY_BUILDED', 'Bereits gebaut', 0),
(3784, 3, 5, 'BUILD', 'Konstruieren', 0),
(3785, 3, 5, 'BUILDING_AT_WORK', 'Beschaftigt', 0),
(3786, 3, 5, 'CONSTRUCTION', 'Gebaude', 0),
(3787, 3, 5, 'CONSTRUCTIONS', 'Gebaude', 0),
(3788, 3, 5, 'CURRENTLY_IN_WORK', 'Aktueller Job:', 0),
(3789, 3, 5, 'DEFENSE', 'Verteidigung', 0),
(3790, 3, 5, 'HYDROGEN_LAB_DESC', 'Auszuge aus dem Wasser auf dem Planeten ein kleiner Teil des Wasserstoffs.', 0),
(3791, 3, 5, 'HYDROGEN_PLANT_DESC', 'Auszuge Energie aus dem Prozess der Bildung eines Helium-Atoms mit zwei Atomen des schweren Wasserstoffs.', 0),
(3792, 3, 5, 'HYDROGEN_STORAGE_DESC', 'Gro?e Speicherkapazitat fur sbereganiya erzeugtem Wasserstoff.', 0),
(3793, 3, 5, 'METALMINE_DESC', 'Die wichtigsten Anbieter von Rohstoffen fur den Bau von tragenden Strukturen von Gebauden und Schiffen.', 0),
(3794, 3, 5, 'METAL_STORAGE_DESC', 'Speicher fur die rohen Erze vor der weiteren Verarbeitung.', 0),
(3795, 3, 5, 'MOON_BUILDING', 'Spezielle Konstruktion', 0),
(3796, 3, 5, 'NANO_FACTORY_DESC', 'Die Fabrik produziert spezielle Naniten entwickelt Roboter - Naniten. Nanites - es ist Roboter, die durch die Kombination in der Lage, au?ergewohnliche Aufgaben.', 0),
(3797, 3, 5, 'OUTSTANDING_MISSIONS', 'Queue aufbauen', 0),
(3798, 3, 5, 'QUANTITY', 'Anzahl', 0),
(3799, 3, 5, 'REQUIREMENTS', 'Bedarf', 0),
(3800, 3, 5, 'RESEARCH', 'Studie', 0),
(3801, 3, 5, 'RESEARCH_LAB_DESC', 'Brauchen Sie fur die Erforschung neuer Technologien.', 0),
(3802, 3, 5, 'RESEARCH_OF_LEVEL', 'Untersuchen Sie das Niveau der', 0),
(3803, 3, 5, 'ROBOTIC_FACTORY_DESC', 'Bietet eine einfache Arbeit, die in den Bau eines planetaren Infrastruktur eingesetzt werden konnen. Jede Stufe erhoht die Geschwindigkeit der Fabrikhallen.', 0),
(3804, 3, 5, 'ROCKET_STATION_FULL', 'Meiner ist gefullt mit', 0),
(3805, 3, 5, 'SHIPS_EXIST', 'in Gegenwart von %s', 0),
(3806, 3, 5, 'SHIPYARD_DESC', 'In der Werft produziert alle Arten von Schiffen. Daruber hinaus erhoht Werft Angriffskraft und Ballistik Angriff Schiffe.', 0),
(3807, 3, 5, 'SHIP_CONSTRUCTION', 'Werft', 0),
(3808, 3, 5, 'SILICON_LAB_DESC', 'Die wichtigsten Anbieter von Rohstoffen fur elektronische Bauelemente und Legierungen.', 0),
(3809, 3, 5, 'SILICON_STORAGE_DESC', 'Speicher fur die Verarbeitung Silizium.', 0),
(3810, 3, 5, 'SOLAR_PLANT_DESC', 'Erzeugt Energie aus Sonnenlicht. Die Energie fur die meisten Gebaude erforderlich.', 0),
(3811, 3, 5, 'UPGRADE_TO_LEVEL', 'Construct Ebene', 0),
(3812, 3, 6, 'CAPACITY', 'Kapazitat', 0),
(3813, 3, 6, 'CONSUME', 'Verbraucht', 0),
(3814, 3, 6, 'DAILY_PRDOUCTION', 'Pro Tag', 0),
(3815, 3, 6, 'DIFFERENCE', 'Unterschied', 0),
(3816, 3, 6, 'MONTHLY_PRDOUCTION', 'Pro Monat', 0),
(3817, 3, 6, 'PRODUCTION', 'Produktion', 0),
(3818, 3, 6, 'PROD_ONE_SOLAR_SATELLITE', 'Ein Satellit stellt {@prodPerSat} Energie', 0),
(3819, 3, 6, 'RESOURCE_PRODUCTION_FOR_PLANET', 'Produktion Ressourcen auf dem Planeten:', 0),
(3820, 3, 6, 'SHUT_DOWN', 'Ausschalten', 0),
(3821, 3, 6, 'START_UP', 'Umfassen', 0),
(3822, 3, 6, 'SUM', 'Nur', 0),
(3823, 3, 6, 'WEEKLY_PRDOUCTION', 'Pro Woche', 0),
(3824, 3, 7, 'ACCEPT_AGB', 'Durch die Teilnahme erklaren Sie sich mit den Regeln.', 0),
(3825, 3, 7, 'AGB', 'Policies / Richtlinien', 0),
(3826, 3, 7, 'BOARD', 'Forum', 0),
(3827, 3, 7, 'BOARD_DESC', 'Hier finden Sie Antworten auf alle Ihre Fragen.', 0),
