(4349, 3, 4, 'REPAIR_FACTORY_DESC', 'Repair Hangar ist fur die Reparatur von beschadigten und Entsorgung von unnotigen Einheiten erforderlich.', 0),
(4350, 3, 4, 'REPAIR_FACTORY_FULL_DESC', 'Repair Hangar erforderlich ist, um zwei Vorgange: 1 - Reparatur beschadigter Schiffe und Festungen, 2 - Recycling unerwunschte Fahrzeuge und Verteidigung, um die Ressourcen zu bekommen.', 0),
(4351, 3, 4, 'REPAIR_REQUIRED', 'Notwendig, um einen Hangar zu bauen.', 0),
