INSERT INTO `na_phrases` (`phraseid`, `languageid`, `phrasegroupid`, `title`, `content`, `translated`) VALUES
(4389, 3, 18, 'UNIT_SUMMARY', 'Nur', 0),
(4390, 3, 18, 'SHOW_BATTLE_MATRIX', 'Lassen Sie sich die Matrix zu kampfen.', 0),
(4391, 3, 18, 'HIDE_BATTLE_MATRIX', 'Blenden Sie die Matrix zu kampfen.', 0),
(4392, 3, 18, 'BMAT_ATTER_HIT', 'Hit der angreifenden Einheit (%s) auf Einheit des Verteidigers (%s)', 0),
(4393, 3, 18, 'BMAT_DEFENDER_HIT', 'Hit der Defensive (%s) auf Einheit des Angreifers (%s)', 0),
(4394, 3, 18, 'BMAT_ATTER_PERCENT', 'Prozentsatz der Treffer fur eine Einheit angreift (%s) auf Einheit der Verteidigung (%s)', 0),
(4395, 3, 18, 'BMAT_ATTER_DAMAGE', 'Einheit Angreifer (%s) verursacht Schaden an der Verteidigung der Einheit der (%s)', 0),
(4396, 3, 18, 'BMAT_DEFENDER_PERCENT', 'Prozentsatz der Treffer fur die verteidigende Einheit (%s) auf Einheit des Angreifers (%s)', 0),
(4397, 3, 18, 'BMAT_DEFENDER_DAMAGE', 'Die verteidigende Einheit (%s) verursacht Schaden an Einheit des Angreifers (%s)', 0),
(4398, 3, 18, 'UNIT_NOTHING', 'Schutt', 0),
(4399, 3, 18, 'BMAT_ATTER_ALL_SHOTS', 'Die Anzahl der Schusse Angreifer', 0),
(4400, 3, 18, 'BMAT_DEFENDER_ALL_SHOTS', 'Die Anzahl der Schusse Verteidiger', 0),
(4401, 3, 18, 'BMAT_ATTER_UNIT_DAMAGE', 'Einheit Angreifer verursacht Schaden an den Verteidiger', 0),
(4402, 3, 18, 'BMAT_DEFENDER_UNIT_DAMAGE', 'Die verteidigende Einheit verursacht Schaden an den Angreifer', 0),
(4403, 3, 18, 'BMAT_ATTER_UNIT_DAMAGE_PERCENT', 'Der Beitrag der Schaden fur die verteidigende Einheit', 0),
(4404, 3, 18, 'BMAT_DEFENDER_UNIT_DAMAGE_PERCENT', 'Der Beitrag der Schaden fur die angreifende Einheit in', 0),
(4405, 3, 18, 'BMAT_DEFENDER_ALL_DAMAGE', 'Insgesamt (Schadigung Schilde und Rustungen), kann ein Angreifer', 0),
(4406, 3, 18, 'BMAT_ATTER_ALL_DAMAGE', 'Insgesamt (Schadigung Schilde und Rustungen), der Verteidigung', 0),
(4407, 3, 18, 'BMAT_DEFENDER_UNIT_SHOTS', 'Die Anzahl der Schusse auf die Angreifer Einheit', 0),
(4408, 3, 18, 'BMAT_ATTER_UNIT_SHOTS', 'Die Anzahl der Aufnahmen auf den Verteidiger Einheit', 0),
(4409, 3, 18, 'UNIT_NOTHING_INFO', 'Falling into der zerstorten Einheiten, Storungen, etc.', 0),
(4410, 3, 1, 'MENU_DISASSEMBLE', 'Erholung', 0),
(4411, 3, 4, 'QUEUE_REPAIR_PREFIX', 'Reparatur', 0),
(4412, 3, 4, 'QUEUE_DISASSEMBLE_PREFIX', 'Erholung', 0),
(4413, 3, 5, 'DISASSEMBLE', 'Nutzen', 0),
(4414, 3, 4, 'LANCER_SHIP', 'Ulan', 0),
(4415, 3, 4, 'LANCER_SHIP_DESC', 'Schnelle und effektive Kriegsschiff, auf dem modernsten Technologien gebaut. Ausgestattet mit einer machtigen Waffe zu katastrophalen Schaden an den Feind zu verursachen.', 0),
(4416, 3, 4, 'LANCER_SHIP_FULL_DESC', 'Schnelle und effektive Kriegsschiff, auf dem modernsten Technologien gebaut. Ausgestattet mit leistungsstarken Waffen, die katastrophalen Schaden an den Feind fuhren kann. Zum Aufladen Energie Kanonen-Schiff braucht Zeit, so das Schiff hat eine schlechte Feuerrate. Das Schiff wurde von den Wissenschaftlern als Hilfs-Waffe fur zuzufugen massiven Schlag gegen den Feind, und daher am effektivsten, wenn mit dem Rest der Flotte zusammen entwickelt.', 0),
(4417, 3, 17, 'FRONT', 'Front', 0),
(4418, 3, 18, 'FRONT', 'Front', 0),
(4419, 3, 18, 'ATTACKER_LOST_RES', 'Verluste Angreifer: %s (%s %s Metall Silizium).', 0),
(4420, 3, 18, 'DEFENDER_LOST_RES', 'Der Verlust der Verteidiger: %s (%s %s Metall Silizium).', 0),
(4421, 3, 18, 'ATTACKER_LOST_RES_4', 'Verluste Angreifer: %s (%s Metall %s Si, %s Wasserstoff).', 0),
(4422, 3, 18, 'DEFENDER_LOST_RES_4', 'Der Verlust der Verteidiger: %s (%s Metall %s Si, %s Wasserstoff).', 0),
(4423, 3, 18, 'HIDE_BATTLE_TEXT', 'Die Information ist nicht verfugbar fur die Anzeige.', 0),
(4424, 3, 18, 'ROCKET_ATTACK_TIME', 'Raketenangriff in der %s Stunden:', 0),
(4425, 3, 11, 'ROCKET_ATTACK_REPORT', 'Bericht Raketenangriff', 0),
(4426, 3, 11, 'ASSAULT_REPORT_TURNS', 'Runde', 0),
(4427, 3, 12, 'BS_USER_FILTER', 'Spielername', 0),
(4428, 3, 12, 'BS_USER_FILTER_INFO', '', 0),
(4429, 3, 6, 'DAILY_PRODUCTION', 'Pro Tag', 0),
(4430, 3, 6, 'MONTHLY_PRODUCTION', 'Pro Monat', 0),
(4431, 3, 6, 'WEEKLY_PRODUCTION', 'Pro Woche', 0),
(4432, 3, 1, 'PREV', 'Prev.', 0),
(4433, 3, 1, 'NEXT', 'Seq.', 0),
(4434, 3, 1, 'RELATED_MSG', 'Nachrichten mit dem Spieler verbunden.', 0),
(4435, 3, 13, 'EXPEDITION_XSKIRMISH', 'Wahrend der Expedition, lief das Schiff in eine fremde Flotte erschien aus dem Nichts. Unbekannte Zivilisation feindlich Schlacht. Siehe den Bericht von der Schlacht im &quot;Krieg berichtet.&quot;', 0),
(4436, 3, 13, 'EXPEDITION_RESOURCE_DISCOVERY_1', 'Forscher haben die alte und nicht arbeiten Schiffe gefunden, treiben im Raum. Befehl angewiesen, die verfugbaren Ressourcen in den Laderaumen der {@metal} Metall {@silicon} Si und {@hydrogen} Wasserstoff zu nehmen.', 0),
(4437, 3, 13, 'EXPEDITION_SHIPS_DISCOVERY', 'Ihre Forscher fanden heraus, treiben im Raum Flotte, die in der Lage, die Erhaltung hat. Befehl Befehl, die Schiffe an der Basis gefunden zu bringen: {@new_ships}', 0),
(4438, 3, 13, 'EXPEDITION_NOTHING_1', 'Ihre Flotte fur eine lange Zeit, um das Universum surfen, aber die Wissenschaftler Sensoren nicht in der Lage, etwas von Interesse aufnehmen.', 0),
(4439, 3, 4, 'UNIT_A_CORVETTE', 'Corvette ET', 0),
(4440, 3, 4, 'UNIT_A_SCREEN', 'Schild fremde Fahrzeug', 0),
(4441, 3, 13, 'EXPEDITION_BATTLEFIELD_DISCOVERY', 'Ihr Ermittler fanden Spuren von langen otgremevshey Schlacht. Unter den Tonnen zerknitterten metallischen Behaltern geeignet erwiesen fur die weitere Verwendung: {@new_ships}', 0),
(4442, 3, 13, 'EXPEDITION_NOTHING_2', 'Ihr Entdecker weitergegeben durch die Supernova und machte tolle Fotos. Nichts mehr interessant in dem gewahlten Sektor haben sie gefunden.', 0),
(4443, 3, 13, 'EXPEDITION_LOST_1', 'Leider war die Kommunikation mit der Expedition verloren.', 0),
(4444, 3, 4, 'UNIT_A_PALADIN', 'Paladin ET', 0),
(4445, 3, 4, 'UNIT_A_FRIGATE', 'Fregatte ET', 0),
(4446, 3, 4, 'UNIT_A_TORPEDOCARIER', 'Torpedo ET', 0),
(4447, 3, 13, 'EXPEDITION_DELAY_RETURN', 'Ihre Forscher fanden nichts, au?er sie verloren sind. Suchen Sie auf dem Weg nach Hause musste {@percent}% mehr Zeit.', 0),
(4448, 3, 13, 'EXPEDITION_FAST_RETURN_1', 'Ihre Forscher haben nichts gefunden. Glucklicherweise sie den Weg einer stabilen schwarzen Loch gefunden, wird eine Passage durch die es ihnen ermoglichen Weg zuruck geschnitten auf der {@percent}%', 0),
(4449, 3, 13, 'EXPEDITION_SENSOR_REPORT', 'Spy-Sonde abgetastet den Spuren Echos der Dunklen Materie und fanden Spuren von {@visits} Expeditionen in diesem Sektor {@exp_sector}. Search Leistung der Expedition war {@exp_power}. Die Forscher untersuchten eine ausgewahlte Branche {@exp_hours} Stunden. Das aktuelle Ergebnis der Expedition fand mit der Wahrscheinlichkeit von {@exp_percent}%', 0),
(4450, 3, 1, 'RESEARCH_EXPO_TECH', 'Notwendig, um die Weiterleitung Technologie untersuchen', 0),
(4451, 3, 1, 'TOO_MANY_EXPOS', 'Das Niveau der Technik nicht moglich Weiterleitung an eine Reihe von Expeditionen zu senden.', 0),
(4452, 3, 13, 'EXPEDITION_SENSOR_CLEAR_REPORT', 'Spy-Sonde abgetastet den Spuren Echos der dunklen Materie und fand, dass der Sektor {@exp_sector} Niemand in den nachsten Tagen besucht - es ist sehr gut! Die Forscher raten Ihnen, in diesem Sektor zu fliegen ein paar Mal fur eine detailliertere Studie. Search Leistung der Expedition war {@exp_power}. Die Forscher untersuchten eine ausgewahlte Branche {@exp_hours} Stunden. Das aktuelle Ergebnis der Expedition fand mit der Wahrscheinlichkeit von {@exp_percent}%', 0),
(4453, 3, 10, 'EXPEDITION_TIME', 'Time to Forschungsexpedition', 0),
(4454, 3, 1, 'EXPEDITION', 'Expedition', 0),
(4455, 3, 13, 'EXPEDITION_SUBJECT', 'Der Bericht der Expedition', 0),
(4456, 3, 13, 'EXPEDITION_SENSOR_SUBJECT', 'Daten aus razvedzonda', 0),
(4457, 3, 1, 'SENDER', 'Absender', 0),
(4458, 3, 1, 'RECIEVER', 'Empfanger', 0),
(4459, 3, 1, 'MENU_RESTRANSFERS', 'Sent Ressourcen', 0),
(4460, 3, 12, 'TRANSFERS_COUNT', 'Anzahl der Entladung', 0),
(4461, 3, 12, 'TOTAL_RES_TRANSFER', 'Die Menge an Ressourcen', 0),
(4462, 3, 12, 'RT_GROUP_RECIEVER', 'Gruppe durch den Empfanger', 0),
(4463, 3, 12, 'RT_GROUP_SENDER', 'Gruppe von Absender', 0),
(4464, 3, 12, 'RT_SEARCH_USER', 'Suche nach Name', 0),
(4465, 3, 13, 'EXPEDITION_FAST_RETURN_2', 'Ihre Forscher haben nichts gefunden. Glucklicherweise ist die Krone der nachste Stern auf dem Fluss des Sonnenwindes basiert, die es ihnen ermoglichen, die Zeit zuruck, um die {@percent}% reduzieren', 0),
(4466, 3, 13, 'EXPEDITION_ASTEROID_DISCOVERY_NO_CARGO', 'Ihre Forscher fanden heraus, Bruchstucke von Asteroiden-Feld: {@debrismetal} {@debrissilicon} Metall Silizium. Leider wurde die Expedition nicht Raffinerien, um Ressourcen aus dem Weltraum zu erhohen.', 0),
(4467, 3, 13, 'EXPEDITION_ASTEROID_DISCOVERY_1', 'Ihre Forscher fanden heraus, Bruchstucke von Asteroiden-Feld: {@debrismetal} {@debrissilicon} Metall Silizium. Prozessoren extrahiert: {@metal} {@silicon} Metall Silizium.', 0),
(4468, 3, 13, 'EXPEDITION_RESOURCE_DISCOVERY_2', 'Gute Nachrichten: Ihre Forscher fanden heraus, einem unbewohnten Planeten mit Ressourcen: {@debrismetal} Metall {@debrissilicon} Si und {@debrishydrogen} Wasserstoff. Die Flotte nahm: {@metal} Metall {@silicon} Si und {@hydrogen} Wasserstoff.', 0),
(4469, 3, 13, 'EXPEDITION_NOTHING_3', 'Ihre Forscher fuhrten die ganze Zeit fur das Studium der ausgewahlten Sektoren gewahrt. Aber sie fand nichts Interessantes.', 0),
(4470, 3, 13, 'EXPEDITION_NOTHING_4', 'Ihre Flotte ist ein Planet, der Ihre Aufmerksamkeit zog gefunden! Die Forscher haben ihre lustigen Tierchen gefunden. Nichts anderes gefunden wurde.', 0),
(4471, 3, 13, 'EXPEDITION_NOTHING_5', 'Ihre zapelengovali Forscher in den Pfad einer enormen Gro?e Flotte au?erirdischer Herkunft. Kommando beschlossen, Risiko und Rendite zu Boden.', 0),
(4472, 3, 13, 'EXPEDITION_LOST_2', 'Beziehung zu Ihrer verlorenen Entdecker. Hochstwahrscheinlich werden sie nicht wiederkommen ...', 0),
(4473, 3, 13, 'EXPEDITION_NOTHING_7', 'Ihr Entdecker weitergegeben von einer riesigen Nebel von Antimaterie. Nichts anderes gefunden wurde.', 0),
(4474, 3, 13, 'EXPEDITION_NOTHING_6', 'Ihre Forscher in den Weg eines instabilen Schwarzes Loch gefunden. Kommando beschlossen, Risiko und Rendite zu Boden.', 0),
(4475, 3, 13, 'EXPEDITION_ASTEROID_DISCOVERY_2', 'Forscher haben Ihre langen otgremevshee Schlachtfeld gefunden. {@debrismetal} {@debrissilicon} Metall Silizium: Schiffe wurden von Trummern, die gesammelt werden konnen zerstort werden. Prozessoren extrahiert: {@metal} {@silicon} Metall Silizium.', 0),
(4476, 3, 13, 'EXPEDITION_FAST_RETURN_3', 'Flotte Ihrer Expedition kam, um die Aufmerksamkeit eines gro?en Magnetfeldes von unbekannter Herkunft. Glucklicherweise wird diese ermoglichen ihnen damit Zeit zuruck, um die {@percent}% reduzieren', 0),
(4477, 3, 13, 'RETREAT_OTHER', '{@username} Halten auf abgesagt {@planet_from} {@coords_from}. Ihre Flotte ({@fleet}) kehrt in den {@planet} {@coords}.', 0),
(4478, 3, 13, 'RETREAT_OTHER_SUBJECT', 'Abbrechen Halten', 0),
(4479, 3, 6, 'HOURLY_PRODUCTION', 'Pro Stunde', 0),
(4480, 3, 4, 'BALLISTICS_TECH', 'Ballistic Technologie', 0),
(4481, 3, 4, 'BALLISTICS_TECH_DESC', 'Ballistic Analyzer arbeitet mit prazise gefuhrten Waffen, die Erhohung der Genauigkeit der direkten Zugriffe auf die feindlichen Einheiten.', 0),
(4482, 3, 4, 'BALLISTICS_TECH_FULL_DESC', 'Technologie fur ballistische Analyse ermoglicht Computer-Systeme, um den Kampf zu berechnen, bevor es auf der Grundlage der raumlichen Lage, Performance-Einheiten und Feuer Wege und Bahnen der Strahlung beginnt. Dies macht es moglich, sollen Feuer und Prazision uber den Kampf zu fuhren. Die Technologie reduziert Fehler und Fallen in die bereits zerstorten Einheiten.', 0),
(4483, 3, 4, 'MASKING_TECH', 'Masking-Technologie', 0),
(4484, 3, 4, 'MASKING_TECH_DESC', 'Technologie-Radio-Standort schafft eine Maskierung Larm in den Analysator und ballistische Leitsysteme von feindlichem Feuer.', 0),
(4485, 3, 4, 'MASKING_TECH_FULL_DESC', 'Technologie-Radio-Standort schafft eine Maskierung Larm in den Analysator und ballistische Leitsysteme von feindlichem Feuer. Diese Technologie erhoht die Uberlebensfahigkeit ihrer Einheiten durch die Reduzierung der Brand Genauigkeit schie?en Kanonen des Feindes.', 0),
(4486, 3, 17, 'COST', 'Wert', 0),
(4487, 3, 17, 'BALLISTICS_POWER', 'Ballistik', 0),
(4488, 3, 4, 'SIM_TECH_LIST', 'Technologie', 0),
(4489, 3, 18, 'BALLISTICS_POWER', 'Ballistik', 0),
(4490, 3, 18, 'MASKING_POWER', 'Verkleidung', 0),
(4491, 3, 17, 'MASKING_POWER', 'Verkleidung', 0),
(4492, 3, 4, 'REQUIRE_TIME_EXT', 'Bauzeit', 0),
(4493, 3, 13, 'EXPEDITION_CREDITS_DISCOVERY_1', 'Ihre Forscher fanden heraus, das Schlachtfeld. Leider sind nicht alle Schiffe unversehrt und ohne Mittel, aber in einer der Uberlebenden, fanden die Forscher sicher {@credits} Darlehen. Herzlichen Gluckwunsch, Gutschriften auf Ihr Konto uberwiesen. Die Flotte kehrte zur Basis.', 0),
(4494, 3, 13, 'EXPEDITION_CREDITS_DISCOVERY_2', 'Expedition Equipment zapelengovalo seltsames Objekt. Es war die Kabine des Kapitans mit einem unbekannten Schiff Rufzeichen Arbeitsgerat. Felling von der Haupt-Schiff Superwaffe geschnitten, uberraschte die Forscher, nichts wie haben sie nicht gesehen. In der Regel absolut sicher, fanden die Forscher die {@credits} Darlehen. Herzlichen Gluckwunsch, Gutschriften auf Ihr Konto uberwiesen. Die Flotte kehrte zur Basis.', 0),
(4495, 3, 13, 'EXPEDITION_CREDITS_DISCOVERY_3', 'Expedition Equipment zapelengovalo seltsames Objekt. Dies war doppelt so beschadigt Raumschiff mit einem toten Tier unbekannten Rasse. Unter dem Sitz, fanden die Forscher eine fremde {@credits} Darlehen. Herzlichen Gluckwunsch, Gutschriften auf Ihr Konto uberwiesen. Die Flotte kehrte zur Basis.', 0),
(4496, 3, 13, 'EXPEDITION_CREDITS_DISCOVERY_4', 'Expedition Equipment zapelengovalo seltsames Objekt. Es war ein toter Alien Pilot, wie sein Outfit zeigt. Die Forschung hat gezeigt, dass der Auslander gestorben, wahrend in den offenen Raum in einem Zustand der verschobenen Animation {@anabios_years} Jahren, wenn die lebenserhaltenden Systeme haben ihre Ressourcen aufgewendet (scheinbar im freien Raum in einigen Schlacht geworfen.) Die Kleidung fanden die Piloten Leuchtfeuer und rufen {@credits} Darlehen. Credits sind auf Ihr Konto uberwiesen. Die Flotte kehrte zur Basis.', 0),
(4497, 3, 13, 'EXPEDITION_CREDITS_DISCOVERY_5', 'Expedition Equipment zapelengovalo seltsames Objekt. Es war ein wenig beschadigt fremdes Raumschiff. Die Forscher sorgfaltig gepruft und fand etwas: hinterhaltigen Aliens in einem geheimen {@credits} Darlehen versteckt. Herzlichen Gluckwunsch, Gutschriften auf Ihr Konto uberwiesen. Die Flotte kehrte zur Basis.', 0),
(4498, 3, 13, 'EXPEDITION_CREDITS_DISCOVERY_6', 'Ihre Forscher fanden heraus, das Schlachtfeld. Leider sind nicht alle Schiffe unversehrt und ohne Mittel, aber in einem Geheimfach eines der Schiffe sorgfaltiger Forscher haben die {@credits} Darlehen gefunden. Herzlichen Gluckwunsch, Gutschriften auf Ihr Konto uberwiesen. Die Flotte kehrte zur Basis.', 0),
(4499, 3, 4, 'ALIEN_TECH', 'Alien Technology', 0),
(4500, 3, 4, 'ALIEN_TECH_DESC', 'Diese Technologie ermoglicht es Ihnen, die fremden Schiffe zu reparieren.', 0),
(4501, 3, 4, 'ALIEN_TECH_FULL_DESC', 'Diese Technologie ermoglicht es Ihnen, die fremden Schiffe zu reparieren.', 0),
(4502, 3, 4, 'UNIT_A_CORVETTE_DESC', 'Sehr schnelle und effiziente Bekampfung Schiff mit guten Waffen.', 0),
(4503, 3, 4, 'UNIT_A_SCREEN_DESC', 'Die einzigartige Hohlkorper. Beispiellose Sicherheit la?t sich die Hauptlast der Feind.', 0),
(4504, 3, 4, 'UNIT_A_PALADIN_DESC', 'Kleine Feuer-Unterstutzung ausgeliefert. Ausgestattet mit Prazisionswaffen und Camouflage-System.', 0),
(4505, 3, 4, 'UNIT_A_FRIGATE_DESC', 'Ein riesiges Feuer Macht und gro?er Kapazitat. Ist in der Lage, schadliche Schlage, um den Feind zu verursachen.', 0),
(4506, 3, 4, 'UNIT_A_TORPEDOCARIER_DESC', 'Schnell Schiff fur Uberraschungsangriff. Ausgestattet mit einer machtigen Waffe mit automatischer Ziel.', 0),
(4507, 3, 4, 'UNIT_A_CORVETTE_FULL_DESC', 'Sehr schnelle und effiziente Bekampfung Schiff mit guten Waffen.', 0),
(4508, 3, 4, 'UNIT_A_SCREEN_FULL_DESC', 'Die einzigartige Hohlkorper. Beispiellose Sicherheit la?t sich die Hauptlast der Feind.', 0),
(4509, 3, 4, 'UNIT_A_PALADIN_FULL_DESC', 'Kleine Feuer-Unterstutzung ausgeliefert. Ausgestattet mit Prazisionswaffen und Camouflage-System.', 0),
(4510, 3, 4, 'UNIT_A_FRIGATE_FULL_DESC', 'Ein riesiges Feuer Macht und gro?er Kapazitat. Ist in der Lage, schadliche Schlage, um den Feind zu verursachen.', 0),
