(4599, 3, 1, 'DELIVERY_UNITS', 'Lieferung der gekauften Flotte', 0),
(4600, 3, 13, 'DELIVERY_UNITS_REPORT', 'Gekauft Fleet (%s) erreicht den Planeten %s %s. <br /> Die Flotte verlie? den Laden: %s Metall %s Si und %s Wasserstoff.', 0),
