(4647, 3, 20, 'FLAG_MOVABLE', 'Transportabel', 0),
(4648, 3, 4, 'ARTEFACTS_TECH', 'Die Studie von Artefakten', 0),
(4649, 3, 4, 'ARTEFACTS_TECH_DESC', 'Die Technologie ermoglicht es Ihnen, Artefakte zu aktivieren. Die Anzahl der gleichzeitigen Artefakte auf allen Planeten steigt mit jedem Level um 1 erhoht.', 0),
(4650, 3, 4, 'ARTEFACTS_TECH_FULL_DESC', 'In der Studie von au?erirdischen Artefakten mieten die besten wissenschaftlichen Abteilungen des Imperiums. Dem unbekannten Technologien und Mechanismen der Artefakte mit den besten Heuristiken und Super-Computer-Technologie zu studieren. Diese Technologie erlaubt den Einsatz von Artefakten und halten einige von ihnen im Betrieb fur einige Zeit. Maximale Anzahl der aktivierten Artefakten auf allen Planeten wird auf das Niveau der Technologie beschrankt.', 0),
(4651, 3, 4, 'MERCHANTS_MARK', 'Registrieren Kaufmann', 0),
(4652, 3, 4, 'MERCHANTS_MARK_DESC', 'Reduzieren Sie Provision fur den Austausch und die gemeinsame Nutzung von Ressourcen mit 20% bis 3%', 0),
(4653, 3, 4, 'MERCHANTS_MARK_FULL_DESC', 'Ermoglicht Ihnen, Einkaufe auf den Austausch und die gemeinsame Nutzung von Ressourcen mit dem reduzierten Provision machen 3% statt 20%', 0),
(4654, 3, 4, 'CATALYST', 'Katalysator', 0),
(4655, 3, 4, 'CATALYST_DESC', 'Erhoht die Produktion von Ressourcen um 10%.', 0),
(4656, 3, 4, 'CATALYST_FULL_DESC', 'Universal-Katalysator beschleunigt chemische Reaktionen in der Synthese von Metall, Silizium und Wasserstoff. Wahrend der Woche der Produktion auf alle Ressourcen des Planeten um 10% erhoht.', 0),
(4657, 3, 4, 'POWER_GENERATOR', 'Energotrans', 0),
(4658, 3, 4, 'POWER_GENERATOR_DESC', 'Erhoht die Energie um 15% und Abschirmtechnik - 1 Ebene.', 0),
(4659, 3, 4, 'POWER_GENERATOR_FULL_DESC', 'Gibt die Leistung der Strom-und Satelliten auf 15%. Erhoht Schutzschild-Technologie auf einer Ebene.', 0),
(4660, 3, 4, 'ATOMIC_DENSIFIER', 'Atomic Dichtung', 0),
(4661, 3, 4, 'ATOMIC_DENSIFIER_DESC', 'Erhoht die Speicherkapazitat um 15% und Rustung Technologie - auf einer Ebene.', 0),
(4662, 3, 4, 'ATOMIC_DENSIFIER_FULL_DESC', 'Erzeugt ein Kraftfeld, Komprimieren einer Substanz, die mehr Speicher-Ressourcen aufnehmen kann. In der Woche vom Speicherkapazitat auf alle Ressourcen des Planeten um 15% erhoht. Erhoht die Rustung Technologie, um Tier-1.', 0),
(4663, 3, 20, 'BUY_FOR_RESOURCES', 'Kaufen Sie jetzt fur Ressourcen', 0),
(4664, 3, 20, 'BUY_FOR_CREDITS', 'Credits kaufen', 0),
(4665, 3, 20, 'ARTEFACT_MARKET', 'Shop-Artefakte', 0),
(4666, 3, 1, 'OR', 'oder', 0),
(4667, 3, 4, 'ANNIHILATION_ENGINE', 'Annihilation-Modul', 0),
(4668, 3, 4, 'ANNIHILATION_ENGINE_DESC', 'Wenn Sie auf jede Art von Drehzahlen Anschluss von bis Flotte im Flug bei 10%.', 0),
(4669, 3, 4, 'ANNIHILATION_ENGINE_FULL_DESC', 'Annihilation - gegenseitige Vernichtung von Teilchen und Antiteilchen, wenn sie mit der Veroffentlichung von riesigen Mengen an Energie kollidieren. Antimaterie ist sehr schwierig zu synthetisieren und zu speichern, damit eine effektive Maschine, auf dem Prinzip der Vernichtung basiert, ist es unmoglich. Aber unter den Fragmenten der gro?en fremden Schiffe gefunden haben-ins-Motoren basiert auf diesem Prinzip. Einige von ihnen sind in einwandfreiem Zustand und kann mit bestimmten Arten von Motoren kombiniert werden, indem sie ihnen eine Leistungssteigerung von 10%.', 0),
(4670, 3, 4, 'SUPERCOMPUTER', 'Supercomputer', 0),
(4671, 3, 4, 'SUPERCOMPUTER_DESC', 'Erhoht das Niveau der Computer-Technologie in ein Forschungs-und erhoht die Geschwindigkeit um die Halfte. Works fur Studien nach der Aktivierung eines Supercomputers gestartet. Nach der Deaktivierung ist die beschleunigte Forschung nicht gebremst!', 0),
(4672, 3, 4, 'SUPERCOMPUTER_FULL_DESC', 'In einer der Expeditionen war es, die einzigartige au?erirdische Gerat erfassen, dass, wenn detaillierte Studie eines Supercomputers Auslander war. Supercomputer in der Lage, in die Tat umzusetzen und in die Forschung Netzwerk. Er hat eine enorme Rechenleistung und ist in der Lage, die Aktionen der Flotte mehr Kontrolle. Gleichzeitig wird der Supercomputer Bewaltigung der komplexen Probleme der Forschung, Verkurzung der Studien in 2 mal. Works fur Studien nach der Aktivierung eines Supercomputers gestartet. Nach der Deaktivierung ist die beschleunigte Forschung nicht gebremst! Zwei Supercomputer wird die Geschwindigkeit der Forschung in die 4. Mal zu steigern!', 0),
(4673, 3, 4, 'MEMORY_MODULE__15_15', 'Speichermodul', 0),
(4674, 3, 4, 'MEMORY_MODULE__15_15_DESC', 'Erhoht das Niveau der Waffentechnologie zu 15 <br /> <i>. Voraussetzungen: Waffentechnik (Stufe 14) </i>', 0),
(4675, 3, 4, 'MEMORY_MODULE__15_15_FULL_DESC', 'Manchmal sind die Expeditionen konnen fremde Gedachtnis-und Entschlusselung ihrer Daten zu finden. Dieses Modul enthalt Informationen uber die Waffen-Technologie Level 15.', 0),
(4676, 3, 4, 'MEMORY_MODULE__23_12', 'Speichermodul', 0),
(4677, 3, 4, 'MEMORY_MODULE__23_12_DESC', '. Erhoht das Niveau der Laser-Technologie bis 12 <br /> <i> Benotigt: Lasertechnik (Stufe 11) </i>', 0),
(4678, 3, 4, 'MEMORY_MODULE__23_12_FULL_DESC', 'Manchmal sind die Expeditionen konnen fremde Gedachtnis-und Entschlusselung ihrer Daten zu finden. Dieses Modul enthalt Informationen uber Lasertechnik auf Level 12.', 0),
(4679, 3, 4, 'MEMORY_MODULE__28_1', 'Speichermodul', 0),
(4680, 3, 4, 'MEMORY_MODULE__28_1_DESC', 'Macht es moglich, die Schwerkraft-Technik zu studieren.', 0),
(4681, 3, 4, 'MEMORY_MODULE__28_1_FULL_DESC', 'Manchmal sind die Expeditionen konnen fremde Gedachtnis-und Entschlusselung ihrer Daten zu finden. Dieses Modul enthalt Informationen uber die Schwerkraft Technologie Level 1.', 0),
(4682, 3, 4, 'MEMORY_MODULE__16_15', 'Speichermodul', 0),
(4683, 3, 4, 'MEMORY_MODULE__16_15_DESC', 'Erhoht Schutzschild-Technologie bis 15 <br /> <i>. Voraussetzungen: Shielding Technology (Ebene 14) </i>', 0),
(4684, 3, 4, 'MEMORY_MODULE__16_15_FULL_DESC', 'Manchmal sind die Expeditionen konnen fremde Gedachtnis-und Entschlusselung ihrer Daten zu finden. Dieses Modul enthalt Informationen uber die Billboard-Technologie Level 15.', 0),
(4685, 3, 4, 'MEMORY_MODULE__17_15', 'Speichermodul', 0),
(4686, 3, 4, 'MEMORY_MODULE__17_15_DESC', '. Erhoht die Rustung Technologie bis 15 <br /> <i> Benotigt: Armor Technology (Level 14) </i>', 0),
(4687, 3, 4, 'MEMORY_MODULE__17_15_FULL_DESC', 'Manchmal sind die Expeditionen konnen fremde Gedachtnis-und Entschlusselung ihrer Daten zu finden. Dieses Modul enthalt Informationen uber die Technologie der Stufe 15 Rustung.', 0),
(4688, 3, 4, 'MEMORY_MODULE__110_1', 'Speichermodul', 0),
(4689, 3, 4, 'MEMORY_MODULE__110_1_DESC', 'Macht es moglich, die au?erirdische Technologie untersuchen.', 0),
(4690, 3, 4, 'MEMORY_MODULE__110_1_FULL_DESC', 'Manchmal sind die Expeditionen konnen fremde Gedachtnis-und Entschlusselung ihrer Daten zu finden. Dieses Modul enthalt Informationen uber die au?erirdische Technologie Ebene 1.', 0),
(4691, 3, 4, 'ASSEMBLY_MODULE__31_10', 'Baugruppenmontage', 0),
(4692, 3, 4, 'ASSEMBLY_MODULE__31_10_DESC', 'Fugt die Flotte 10 leichte Kampfer.', 0),
(4693, 3, 4, 'ASSEMBLY_MODULE__31_10_FULL_DESC', 'Die Entwicklung von Alien-Technologie ermoglicht es Ihnen, Roboter zu schaffen, wie das in der Galaxie der Naniten bekannt. Doch statt des Mehrzweck-Naniten Aliens lieber spezialisierte Naniten, die optimiert werden, um eine bestimmte Aufgabe ausfuhren verwenden. Das Modul besteht aus einem Mikrocomputer, dass der Build-Prozess steuert, und viele Naniten entworfen, um eine bestimmte Art von Schiff zu schaffen. Dieses Modul soll zu 10 leichte Jager zu bauen.', 0),
(4694, 3, 4, 'ASSEMBLY_MODULE__42_1', 'Baugruppenmontage', 0),
(4695, 3, 4, 'ASSEMBLY_MODULE__42_1_DESC', 'Fugt der Flotte einen Todesstern.', 0),
(4696, 3, 4, 'ASSEMBLY_MODULE__42_1_FULL_DESC', 'Die Entwicklung von Alien-Technologie ermoglicht es Ihnen, Roboter zu schaffen, wie das in der Galaxie der Naniten bekannt. Doch statt des Mehrzweck-Naniten Aliens lieber spezialisierte Naniten, die optimiert werden, um eine bestimmte Aufgabe ausfuhren verwenden. Das Modul besteht aus einem Mikrocomputer, dass der Build-Prozess steuert, und viele Naniten entworfen, um eine bestimmte Art von Schiff zu schaffen. Dieses Modul ist entworfen, um eine Todesstern zu bauen.', 0),
(4697, 3, 4, 'REPAIR_BOT', 'Repair Bot', 0),
(4698, 3, 4, 'REPAIR_BOT_DESC', 'Reparaturen aller Fahrzeuge auf dem Planeten.', 0),
(4699, 3, 4, 'REPAIR_BOT_FULL_DESC', 'Repair Bot in der Lage ist, die Struktur aller Schiffe zu analysieren und reparieren ihre Rustung. Fur den Anfang ist es in der Lage, die gesamte Flotte auf dem Planeten zu reparieren. Allerdings hat der Roboter einen begrenzten Vorrat an Energie, so dass nach drei Starts, wird es unbrauchbar.', 0),
(4700, 3, 4, 'ROBOT_CONTROL_SYSTEM', 'Das System der Kontrolle Roboter', 0),
(4701, 3, 4, 'ROBOT_CONTROL_SYSTEM_DESC', 'Das System der Robotersteuerung (RMS) erhohte sich um 2-mal die Geschwindigkeit der Errichtung von Gebauden, Flotte und Verteidigung. Ausgelost fur Auftrage ausgefuhrt nach der Aktivierung des URA. Nach der Deaktivierung wird die beschleunigte Job nicht bremsen!', 0),
(4702, 3, 4, 'ROBOT_CONTROL_SYSTEM_FULL_DESC', 'Das System der Robotersteuerung (RMS) ermoglicht es Ihnen, besser zuordnen Aufgaben Roboter in den Bau von Gebauden auf dem Planeten, und Flotte Verteidigung. Die Rate der Bau erhohte sich um 2-mal. Ausgelost fur Auftrage ausgefuhrt nach der Aktivierung des URA. Nach der Deaktivierung wird die beschleunigte Job nicht bremsen! Zwei RMS wird die Geschwindigkeit der Konstruktion in das 4. Mal zu steigern!', 0),
