(4751, 3, 13, 'LOST_ARTEFACTS_MSG', 'In der Schlacht auf dem Planeten {@coords_planet} Angreifer packte Ihre Artefakte: {@artefacts}.', 0),
(4752, 3, 13, 'ARTEFACTS_GRASPED_MSG', 'In der Schlacht auf dem Planeten {@coords_from} wurden gefangen Artefakte: {@artefacts}. Ihre Flotte zusammen mit den Artefakten wird zu einem Planeten {@planet} {@coords} kommen.', 0),
