(4758, 3, 18, 'BATTLE_REPORT_TEXT', 'Die Marine erhielt eine Nachricht von Spieler {@username}, schickte er einen Link zu den <a href=''{@friendlink}'' target=''_blank''> </a> Kampfbericht.', 0),
(4759, 3, 18, 'REPORT_TEXT_QUOTE', '<br/> <br/> durch {@username} Posted <blockquote> {@text} </blockquote>', 0),
(4760, 3, 18, 'REPORT_EMAIL', 'E-mail Empfanger oder die Spitznamen der Spieler. Mehrere Empfanger werden durch Komma getrennt werden.', 0),
