(4762, 3, 18, 'MAX_MAILS_EXCEED', 'Sie konnen nicht senden mehr als {@maxmails} Briefe am Tag.', 0),
(4763, 3, 18, 'INVALID_MAIL', 'Ungultige e-mail', 0),
(4764, 3, 18, 'DELIVERY_ACCEPTED', 'Brief fur den Versand akzeptiert', 0),
