(4766, 3, 5, 'BUILDING_MAX_LEVEL_REACHED', 'Erreichte einen Hochstwert fur den Bau von', 0),
(4767, 3, 3, 'SET_NEW_HOME_PLANET', 'Set Heimatplaneten', 0),
(4768, 3, 3, 'CUR_HOME_PLANET', 'Home Planet', 0),
(4769, 3, 18, 'START_REPORT_TARGET_MOON', 'Der Angreifer wird zum Mond zu zerstoren.', 0),
(4770, 3, 18, 'TARGET_MOON_DESTROYED', 'Generatoren Tod Sterne Angreifer speichern Energie fur die Schwere des Angriffs und machen den Schuss auf den Mond. Bei immer mehr Beben erschuttern den Satelliten. Der Mond beginnt, an seinem Aquator verformen mehrfach Gravitationswellen, dann eine Explosion von blendenden Gerate Angreifer. Sofortige und Instrumente aufnehmen void moon zerstort wird, es existiert nicht mehr.', 0),
(4771, 3, 18, 'ATTACKER_FLLETS_EXPLODE', 'Generatoren Tod Sterne Angreifer speichern Energie fur die Schwere des Angriffs und machen den Schuss auf den Mond. Wachsende Zittern schuttelt den Satelliten, aber kann ihn nicht brechen. Schwerkraft des Mondes gibt uberschussige Energie. Eine machtige Welle von Energie an die Flotte angreifen, dann Baumwolle. Die Flotte ist in submateriyu Angreifer aufgeteilt, und verschwindet in der Dunkelheit des Alls.', 0),
(4772, 3, 18, 'TARGET_MOON_NOT_DESTROYED', 'Generatoren Tod Sterne Angreifer speichern Energie fur die Schwere des Angriffs und machen den Schuss auf den Mond. Schocks, einer nach dem anderen und schuttelte den Satelliten, aber der Mond bleibt bestehen. Der Satellit ist durch die Freigabe der uberschussigen Energie durch die Schwerkraft Impulse stabilisiert. Stromerzeuger, sind Tod Sterne nicht genug, um den Mond zu zerstoren.', 0),
(4773, 3, 18, 'DESTROY_MISSION_TITLE', 'Spezielle Zuordnung', 0),
(4774, 3, 13, 'MOON_DESTROYED_MSG', 'Ihr Mond ist in den Koordinaten {@coords_planet} zerstort wurde.', 0),
