(4812, 3, 3, 'FLEET_MESSAGE_DELIVERY_ARTEFACTS', 'Ihre Flotte ({@fleet}) mit {@planet} {@coords} gesendet am {@target} {@targetcoords}. Assignment: {@mission} <br /> Cargo:. {@artefact}', 0),
(4813, 3, 3, 'FLEET_MESSAGE_DELIVERY_ARTEFACTS_SELLER', 'Alien Fleet ({@fleet}) {@username} {@message} auf {@planet} {@coords} erreicht Ihre Koordinaten {@target} {@targetcoords}. Assignment: {@mission} <br /> Cargo:. {@artefact}', 0),
(4814, 3, 2, 'ACCOUNT_ACTIVATION', 'Konto ist immer noch im aktiven.', 0),
(4815, 3, 2, 'ACCOUNT_ACTIVATION_MAIL', 'Konto noch nicht aktiviert. Wir schicken Ihnen eine Email mit einem Link zur Aktivierung.', 0),
(4816, 3, 7, 'REGISTRATION_MAIL_AGAIN', 'Dank {@regUsername} fur die Eintragung in die {config}pagetitle{/config}! <br /> <br /> Sie mussen Ihr Konto zu aktivieren. Klicken Sie auf den untenstehenden Link, um zu bestatigen oder kopieren Sie sie in die Adresszeile Ihres Browsers ein: <br /> <br /> {@activationLink} <br /> <br /> Mit freundlichen Gru?en, <br /> {config}pagetitle{/config}-Befehl', 0),
(4817, 3, 13, 'MSG_DISAPEAR_ARTEFACT_USED', 'Vollig erschopft Artefakt {@name} auf {@coords}', 0),
(4818, 3, 13, 'MSG_CREDIT', 'Nachricht aus dem Kredit-System', 0),
(4819, 3, 13, 'MSG_CREDIT_FOR_MINER', 'Fur hohere Bergbau Niveau Ihnen Bonus-Credits {@credits} angefallen sind.', 0),
(4820, 3, 13, 'MSG_CREDIT_EXCHANGE_BUY', 'Sie kauften eine Menge im Austausch fur die {@credits} Darlehen.', 0),
(4821, 3, 13, 'MSG_CREDIT_EXCHANGE_SELL', 'Sie haben sich eine Menge uber die Borse fur die {@credits} Darlehen.', 0),
(4822, 3, 13, 'MSG_CREDIT_EXCHANGE_PROFIT', 'Auf dem Austausch fand einen Kauf, war die Kommission von der {@credits} Darlehen verdient.', 0),
(4823, 3, 13, 'MSG_CREDIT_EXCHANGE_DEFFEND', 'Fur den Schutz Ihrer Exchange Commission hat am {@credits} Darlehen gepruft.', 0),
(4824, 3, 13, 'MSG_CREDIT_EXCHANGE_BUY_LOT', 'Sie kauften eine Menge ({@lot}) fur {@credits} Darlehen.', 0),
(4825, 3, 13, 'MSG_CREDIT_EXCHANGE_SELL_LOT', 'Sie haben sich eine Menge ({@lot}) fur {@credits} Darlehen.', 0),
(4826, 3, 13, 'MSG_CREDIT_ARTEFACT_BUY_LOT', 'Sie kaufte das Artefakt ({@lot}) fur {@credits} Darlehen.', 0),
(4827, 3, 13, 'MSG_CREDIT_MARKET', 'Sie kaufte auf dem Markt Ressourcen fur die {@credits} Darlehen.', 0),
(4828, 3, 4, 'SHADOW_SHIP', 'Schatten', 0),
(4829, 3, 4, 'SHADOW_SHIP_DESC', 'Schnelle Schiffe effektiv Angriff des Feindes aus der Ferne. Schwache Verteidigung.', 0),
(4830, 3, 4, 'SHADOW_SHIP_FULL_DESC', 'Schnelle und schwer Schiff effektiv greifen die Gegner im Angriff. Schatten Schiff - ist eine geheime militarische Entwicklung der besten Gelehrten des Reiches. Er erschien in der Verarbeitung und Modernisierung eines leichten Kampfer. Speziell fur die Wiederholung der Schatten-Werkzeug ideal fur Aufnahmen gro?e Schiffe geeignet ausgelegt. Shadow hat ein neues Waffensystem in der Lage fuhren sollen Feuer aus gro?en Entfernungen, die neue Schild-Generator Feld, hohe Wendigkeit und Noise-Generator zur Tarnung zu verbessern verpflichtet. Aber der Schatten ist schwach in der Verteidigung, da auf diesem Planeten die Umlaufbahn nicht nehmen Feuerstellungen in einem ausreichenden Abstand vom Feind.', 0),
(4831, 3, 13, 'MSG_CREDIT_FOR_VIP', 'Sie fuhren aus der Warteschlange fur die {@credits} Darlehen.', 0);
INSERT INTO `na_phrases` (`phraseid`, `languageid`, `phrasegroupid`, `title`, `content`, `translated`) VALUES
(4832, 3, 18, 'DESTROY_MISSION_DEATH_STARS_DESTROYED', 'Generatoren Stern Smetri nicht ertragen Staus, explodierte AP: %d', 0),
(4833, 3, 13, 'MSG_CREDIT_BUY', 'Sie haben die {@credits} Darlehen erworben.', 0),
(4834, 3, 10, 'NO_FREE_EXPO_SLOTS', 'Es sind keine freien Slots Expedition', 0),
(4835, 3, 4, 'MOON_ROBOTIC_FACTORY', 'Lunar Robot Factory', 0),
(4836, 3, 4, 'MOON_ROBOTIC_FACTORY_FULL_DESC', 'Bietet eine einfache Arbeit, die in den Bau eines planetaren Infrastruktur eingesetzt werden konnen. Jede Stufe erhoht die Geschwindigkeit der Fabrikhallen.', 0),
(4837, 3, 5, 'MOON_ROBOTIC_FACTORY_DESC', 'Bietet eine einfache Arbeit, die in den Bau eines planetaren Infrastruktur eingesetzt werden konnen. Jede Stufe erhoht die Geschwindigkeit der Fabrikhallen.', 0),
(4838, 3, 7, 'SPACE_EVENTS_LIST', 'Aktueller Job im Universum', 0),
(4839, 3, 3, 'PLANET_ANIGILATION', 'Planet {@planet} Selbstzerstorung Schwerkraft-Anomalie.', 0),
(4840, 3, 13, 'NEUTRAL_PLANET_FOUND', 'Nach langen Spaziergangen auf den Weiten des Universums, entdeckt die Sensoren eine seltsame Mission Tatigkeit im Bereich der {@planet}. <br/> Naherkommen fanden sie, dass diese bisher unbekannte Planeten von Auslandern aus den Trummern der Schlacht. Offensichtlich jemand vor kurzem brach eine gro?e Flotte hier. Auf der Umlaufbahn des Planeten entdeckt das Wrack: {@metal} {@silicon} Metall Silizium. Hurry, um sie abzuholen, weil Planeten ist nicht stabil und wird bald zerstort werden, au?er dass die Planeten um jemand anderes bekannt ist!', 0),
(4841, 3, 13, 'NEUTRAL_PLANET_DIE', 'Es stellt sich heraus das fremde Flotte ist nicht umsonst als Kampf um den Planeten. In seiner Kruste begann eine beispiellose Starke der Gravitations-Anomalien zeigen und vor Wissenschaftlern hatte, um sie zu untersuchen, brach ein Planet {@planet} auf submateriyu.', 0),
(4843, 3, 13, 'EXPEDITION_NEUTRAL_PLANET_SUBJ', 'Die Eroffnung eines unbekannten Planeten', 0),
(4844, 3, 1, 'NEUTRAL_PLANET_NAME', 'UFO-251', 0),
(4845, 3, 3, 'ANIGILATION_TIMER', 'Planet {@target_mission} Selbstzerstorung Schwerkraft-Anomalie.', 0),
(4846, 3, 20, 'WRONG_ARTEFACT_PLANET', 'Es ist auf einem anderen Planeten befinden', 0),
(4847, 3, 4, 'PACK_BUILDING_NOW', 'Um das derzeitige Niveau der Artefakt-Pack', 0),
(4848, 3, 20, 'OUTSTANDING_ARTEFACT_REQUIREMENTS', '', 0),
(4849, 3, 13, 'EXPEDITION_SENSOR_POOR_REPORT', 'Spy-Sonde abgetastet den Spuren Echos der Dunklen Materie und fanden Spuren von {@visits} Expeditionen in diesem Sektor {@exp_sector}. Forscher, Beratung, beschlossen, Ihnen nicht fliegen in diesem Bereich fur mehrere Tage. Versuchen Sie, ein weniger von Expeditionen des Sektors besucht. Search Macht war {@exp_power}. Die Forscher untersuchten eine ausgewahlte Branche {@exp_hours} Stunden. Das aktuelle Ergebnis der Expedition fand mit der Wahrscheinlichkeit von {@exp_percent}%', 0),
(4850, 3, 12, 'BS_SHOW_NO_DESTROYED', 'Schaukampfe ohne Verlust (Diebstahl von Ressourcen)', 0),
(4851, 3, 12, 'EXCH_LOT_MIN_PRICE', 'Fur die Partei', 0),
(4852, 3, 1, 'MENU_REFERAL', 'Verweise', 0),
(4853, 3, 12, 'BS_ALLIANCE_FILTER', 'Allianz', 0),
(4854, 3, 12, 'BS_ALLIANCE_FILTER_INFO', '', 0),
(4855, 3, 6, 'FLEET_CONSUMPTION', 'Flotte', 0),
(4856, 3, 4, 'MOON_HYDROGEN_LAB', 'Lunar Wasserstoff-Synthesizer', 0),
(4857, 3, 4, 'MOON_HYDROGEN_LAB_FULL_DESC', 'Lunar-Synthesizer erzeugt Wasserstoff aus dem Eis mit Kratern an den Polen des Mondes befindet. Dies ist die dunkle und unerforschten Orten auf dem Mond gibt es nie Licht des Sterns. Wissenschaftler arbeiten aktiv an der Studie der versteckten Features fur die Gewinnung von Wasserstoff auf dem Mond. Power fur den Synthesizer kann in der Schlacht Solar-Satelliten eingefangen zu geben.', 0),
(4858, 3, 5, 'MOON_HYDROGEN_LAB_DESC', 'Lunar-Synthesizer erzeugt Wasserstoff aus dem Eis mit Kratern an den Polen des Mondes befindet. Dies ist die dunkle und unerforschten Orten. Power fur den Synthesizer kann in der Schlacht Solar-Satelliten eingefangen zu geben.', 0),
(4859, 3, 6, 'HALTING_CONSUMPTION', 'Retention {@fleet} auf {@planet}', 0),
(4860, 3, 6, 'DEFENSE_CONSUMPTION', 'Verteidigung', 0),
(4861, 3, 6, 'ONE_UNIT_CONSUMPTION', 'Verbraucht eine Einheit: {@basicHydrogenCons} Wasserstoff.', 0),
(4862, 3, 6, 'ONE_UNIT_CONSUMPTION_EXT', 'Verbraucht eine Einheit: {@basicHydrogenCons} <br /> Wasserstoff (das hei?t: {@metalCons} Metall {@siliconCons} Si und {@hydrogenCons} Wasserstoff)', 0),
(4863, 3, 1, 'RESET_BUTTON', 'Anderungen verwerfen', 0),
(4864, 3, 1, 'BS_IN_SPACE', 'Irgendwo im Raum', 0),
(4865, 3, 1, 'ACHIEVEMENT', 'Leistung', 0),
