(4869, 3, 22, 'ACHIEVEMENT_BONUS', 'Auszeichnung', 0),
(4870, 3, 22, 'RECALC_ACHIEVEMENTS', 'Berechnen', 0),
(4871, 3, 23, 'SN_OK_TITLE', 'Die Entgegennahme von Leistungen Klassenkameraden', 0),
(4872, 3, 23, 'SN_OK_DESC', 'Beschreibung der Zahlung Klassenkameraden', 0),
(4873, 3, 23, 'SN_OK_CREDITS', '{@credit} Credits', 0),
(4874, 3, 1, 'USER_AGREEMENT', 'Nutzungsvereinbarung', 0),
(4875, 3, 24, 'USER_AGREEMENT_PRE_TEXT', '', 0),
(4876, 3, 24, 'USER_AGREEMENT_POST_TEXT', '', 0),
(4877, 3, 1, 'TOP_MENU', 'Menu', 0),
(4878, 3, 1, 'TOP_MENU_PLANETS', 'Planet', 0),
(4879, 3, 1, 'TOP_MENU_BUY_CREDIT', 'Top-up-Darlehen', 0),
(4880, 3, 1, 'AGREE', 'Zustimmen', 0),
(4881, 3, 8, 'SKIN_TYPE_MOBI', 'Mobile', 0),
(4882, 3, 1, 'MENU_PLANET_OPTIONS', 'Planet', 0),
(4883, 3, 1, 'MENU_USER_AGREEMENT', 'Vereinbarung', 0),
(4884, 3, 24, 'USER_AGREEMENT_NEW_PRE_TEXT', '<span class=''true''> Um das Spiel fortzusetzen, bestatigen Sie die Vereinbarung (Buttons am Ende dieser Seite.) </span>', 0),
(4885, 3, 1, 'TW_UPCOMING_BLOCK', 'Wird in Kurze beginnen die technischen Arbeiten (TP). Wahrend der Arbeit kann man nicht ins Spiel kommen. TP wird in {@tw_end_time} end (Moskauer Zeit).', 0),
(4886, 3, 1, 'TW_UPCOMING', 'Wird in Kurze beginnen die technischen Arbeiten (TP). Jede wahrend des TP Aufgabe beendet wird ausgesetzt. Die Wiederaufnahme der Arbeitsplatze bleiben erhalten. TP wird in {@tw_end_time} end (Moskauer Zeit).', 0),
(4887, 3, 1, 'TW_IN_PROGRESS', 'Nun zu den technischen Arbeiten (TP) zu gehen.', 0),
(4888, 3, 1, 'COUNTDOWN_TW', 'TR', 0),
(4889, 3, 1, 'COUNTDOWN_WAIT', 'Laufen', 0),
(4890, 3, 1, 'MENU_NOTEPAD', 'Notizbuch', 0),
(4891, 3, 1, 'NOTEPAD', 'Notizbuch', 0),
(4892, 3, 4, 'REG_NO_AGREEMENT', 'Sie mussen nicht mit der EULA zustimmen.', 0),
(4893, 3, 4, 'REG_AGREE', 'Ich habe gelesen und stimme zu.', 0),
(4894, 3, 4, 'REG_AGREEMENT', 'Lesen Sie den Nutzungsvertrag.', 0),
(4895, 3, 4, 'TW_SIMULATOR', 'Sind technische Arbeiten ist Gefechtsfeldsimulation nicht verfugbar.', 0),
(4896, 3, 22, 'LOGIN', 'Willkommen.', 0),
(4897, 3, 22, 'LOGIN_DESC', 'Um Ihren ersten Bonus Ressourcen, klicken Sie auf einen Bonus. Das Achievement-System wird Ihnen helfen, pass den Verlauf der jungen Kampfer zu einem Gewitter Welt OXSAR geworden. Zur Durchfuhrung der Leistungen, ist es notwendig, alle Anforderungen zu erfullen. Erfolge, die Sie ausgeblendet haben, konnen Sie immer uber den Menupunkt Erfolge.', 0),
(4898, 3, 22, 'FIRST_METAL', 'Metal - die Grundlage von allem.', 0),
(4899, 3, 22, 'FIRST_METAL_DESC', 'Fur den Bau von Gebauden, Schiffen und Verteidigung, sowie zu studieren einige der Technologien, die benotigt Metall. Es ist an der Mine produziert. Erstellen Sie Ihre erste Mine zur Gewinnung von Metall.', 0),
(4900, 3, 22, 'FIRST_SILICON', 'Silicon Materials.', 0),
(4901, 3, 22, 'FIRST_SILICON_DESC', 'Silicon wird verwendet, um Chips, die notwendig sind fur die Forscher sind, zu arbeiten und sind in fast jedem Gerat und Struktur verwendet produzieren. Erstellen Sie Ihre erste Mine in Produktion Silizium und starten Sie Ihren Weg an die Entwicklung von Hochtechnologie.', 0),
(4902, 3, 22, 'FIRST_HYDROGEN', 'Blaues Blut.', 0),
(4903, 3, 22, 'FIRST_HYDROGEN_DESC', 'In der fernen Zukunft der Zivilisation aufgegeben Ol als Hauptenergiequelle, Wasserstoff ist nun universell einsetzbar. Er fliegt die Schiffe und nutzt wissenschaftliche Gerate. Erstellen Sie Ihre erste Synthesizer, und stellen die Wasserstoff als Kraftstoff unseres Planeten.', 0),
(4904, 3, 22, 'FIRST_SOLAR', 'Schutzen Sie die Umwelt.', 0),
(4905, 3, 22, 'FIRST_SOLAR_DESC', 'Sun - ein riesiges Kraftwerk, die Sie gerade lernen, sich aus seiner Macht. Erstellen Sie eine Solarstromanlage und sorgen fur Warme und Energie unseres Planeten.', 0),
(4906, 3, 22, 'FIRST_ROBOT', 'Roboter bei der Arbeit!', 0),
(4907, 3, 22, 'FIRST_ROBOT_DESC', 'Wissenschaftler haben herausgefunden, dass der Einsatz von Robotern stroitelsvo Gebauden und Schiffen Geschwindigkeiten. Erstellen Sie eine Fabriksroboter um herauszufinden, ob dies ist.', 0),
(4908, 3, 22, 'STARTER', 'Stabiles Fundament', 0),
(4909, 3, 22, 'STARTER_DESC', 'Bevor Sie in den Raum gehen, Organisieren Sie Ihre Planeten.', 0),
(4910, 3, 22, 'FIVE_ATTACKER', 'Eisen Muskeln.', 0),
(4911, 3, 22, 'FIVE_ATTACKER_DESC', 'Nicht alle der Welt werden Sie als ihren Herrscher anerkennen. Baue einige Schiffe anzugreifen der Plan fur den Start Ihrer Siegeszug quer durch die Galaxie.', 0),
(4912, 3, 22, 'FIRST_ENERGY', 'Sun - unser Freund.', 0),
(4913, 3, 22, 'FIRST_ENERGY_DESC', 'Exploring die Sonnenstrahlung kann versuchen, sie aus der Energie. Sich Energie-Technologie zur Erzeugung von Strom zu erhohen.', 0),
(4914, 3, 22, 'TEN_TRANSPORT', 'Space Truckers.', 0),
(4915, 3, 22, 'TEN_TRANSPORT_DESC', 'Fur den Transport von Waren zwischen den Planeten, als auch Ressourcen von anderen Planeten sammeln sich am besten transportiert. Weitere Transporte tragen konnen zusatzliche Lieferungen von Treibstoff, wodurch die Reichweite der Flotte.', 0),
(4916, 3, 22, 'FIRST_DEFFENCE', 'Befestigen Sie die Wand.', 0),
(4917, 3, 22, 'FIRST_DEFFENCE_DESC', 'Galaxy - eine gefahrliche und harte Stelle. Wahrend Sie die Flotte von Raum surfen, konnen auf eurem Planeten anderen Spieler angreifen. Machen Sie sie zur Selbstgefalligkeit zu zahlen - beginnen Abwehrkrafte aufbauen.', 0),
(4918, 3, 22, 'FIRST_ENGINE', 'Pre-Training.', 0),
(4919, 3, 22, 'FIRST_ENGINE_DESC', 'Um Ihr Schiff im Raum bewegen und brauchen verlassliche moschnye Motoren. Untersuchen seinen ersten Motor werden Sie einen Schritt naher an der Eroberung des Weltraums.', 0),
(4920, 3, 22, 'FIVE_ROCKET', 'Wir sind nicht allein, aber wir sind geschutzt.', 0),
(4921, 3, 22, 'FIVE_ROCKET_DESC', 'Zuverlassig schutzen hinten - Aufbau einer Raketenabwehr!', 0),
(4922, 3, 22, 'SIMULATE_BATTLE', 'Taktische Genies.', 0),
(4923, 3, 22, 'STATE_ASSAULT_SIMULATION', 'Fuhren Sie eine Simulation der Schlacht.', 0),
(4924, 3, 22, 'SIMULATE_BATTLE_DESC', 'Der Sieg in einer Schlacht fur 80 Prozent besteht aus kompetenten Planung. Ihre Wissenschaftler werden Ihnen dabei helfen, entwickelten sie ein System, um vorherzusagen, welche alle Ihre taktischen Schema zu uberprufen. Suchen Sie es in die Schlacht Simulator und versuchen, einen weiteren Kampf im Labor zu verbringen.', 0),
(4925, 3, 22, 'FIRST_RESS_EXCHANGE', 'Marktwirtschaft.', 0),
(4926, 3, 22, 'STATE_RES_UPDATE_EXCHANGE', 'Exchange-Ressourcen in den Warmetauscher', 0),
(4927, 3, 22, 'FIRST_RESS_EXCHANGE_DESC', 'Fur gro?e Dinge haben nicht immer genugend Ressourcen. Wie schon, dass in dein Reich Borse eroffnet. Suchen Sie es in das Menu. Losen Sie eine Reihe von Ressourcen auf den anderen und auch weiterhin seinen Aufstieg zur Weltherrschaft.', 0),
(4928, 3, 22, 'FIRST_COMPUTER_TECH', 'Offnen Sie eine zweite Front.', 0),
(4929, 3, 22, 'FIRST_COMPUTER_TECH_DESC', 'Oft muss fur seinen Sieg uber den Feind an mehreren Stellen auf einmal anzugreifen. Zur Koordination der angreifenden Flotten benotigen enorme Rechenleistung. Untersuchen Sie Computer-Technologie, um eine gro?e Anzahl von Flotten verwalten.', 0),
(4930, 3, 22, 'TUTORIAL_END', 'Das Ende des Kurses werden die jungen Kampfer.', 0),
(4931, 3, 22, 'TUTORIAL_END_DESC', 'Bevor Sie den Kurs zu absolvieren die jungen Kampfer, komplette Ausstattung seines Imperiums.', 0),
(4932, 3, 13, 'MSG_CREDIT_EXCHANGE_RESERVE', 'Sie hat eine Menge, um den Austausch fur die {@credits} Darlehen.', 0),
(4933, 3, 13, 'MSG_CREDIT_EXCHANGE_FROM_RESERVE', 'Auf dem Exchange wurde eine Menge gesagt, belief sich Provisionen zu {@credits} Darlehen.', 0),
(4934, 3, 2, 'BIG_LOT_FLEET', 'Sie sind nicht Schiffe.', 0),
(4935, 3, 2, 'BIG_LOT_COMISSION', 'Sie haben nicht genugend Credits um auf dem Los Borse platziert werden.', 0),
(4936, 3, 2, 'BIG_LOT_CANT_RESERV', 'Sie haben nicht die Ressourcen, um auf dem Los Borse platziert werden. Versuchen Sie, die Artikel neu einstellen.', 0),
(4937, 3, 1, 'MENU_SUPPORT', 'Verordnung der Unterstutzung', 0),
(4938, 3, 2, 'BIG_LOT_ARTEFACT', 'Das Artefakt ist im Flug oder an der Borse.', 0),
(4939, 3, 1, 'MENU_ACHIEVEMENTS', 'Erfolge', 0),
(4940, 3, 18, 'BATTLE_REPORT_SUBJECT', 'Die Marine war ein Hinweis auf die militarische Bericht uber die Spieler {@username}', 0),
(4941, 3, 4, 'ASSAULT_REPORT_TITLE', 'Der Bericht der Schlacht', 0),
(4942, 3, 1, 'EXCH_MAX_PRICE_ERR', 'Preis der Partie sind vielleicht nicht so hoch.', 0),
(4943, 3, 18, 'MOON_ARTEFACT_CHANCE_LOW', 'Das Potenzial der Raum-Zeit-Feld ist teilweise erschopft, als Ergebnis der Schlacht war er %s%%. Es kann ein Artefakt aus einer parallelen Welt zu sein.', 0),
(4944, 3, 18, 'MOON_ARTEFACT_CHANCE_NONE', 'Das Potenzial der Raum-Zeit-Bereich erschopft, wird der Ladevorgang. Das Aussehen des Artefakts ist derzeit nicht moglich.', 0),
(4945, 3, 22, 'MOON_BONUS_ONLY', 'Der Preis fur diese Leistung kann nur auf dem Mond gewonnen werden.', 0),
(4946, 3, 22, 'PLANET_BONUS_ONLY', 'Der Preis fur diese Leistung kann nicht auf den Mond zu bekommen.', 0),
(4947, 3, 11, 'ARTEFACT_MESSAGES', 'System Artefakte', 0),
(4948, 3, 11, 'CREDIT_MESSAGES', 'Darlehen', 0),
(4949, 3, 4, 'WRONG_LEAVE_PHRASE', 'Sie geben den falschen Begriff. Phrase Gro?-und Kleinschreibung.', 0),
(4950, 3, 4, 'LEAVE', 'VERLASSEN', 0),
(4951, 3, 2, 'CANNOT_DELETE_HOME_PLANET', 'Sie konnen nicht aus dem Heimatplaneten.', 0),
(4952, 3, 3, 'PLANET_IS_NOT_FORMED_YET', 'Planet erst noch gebildet werden', 0),
(4953, 3, 1, 'UNFORMED_PLANET_NAME', 'Nebel', 0),
(4954, 3, 4, 'HOME_PLANET_REQUIRED', 'Ihre Kolonisten sind bereits auf der Suche nach einem geeigneten Planeten im Universum fur die Besiedlung. Sie konnen immer noch umschauen, sehen Sie sich den Chat ein, der Aktienmarkt, sehen Sie sich das Spiel-Menu (es ist auf der linken Seite). Wenn Sie mochten, konnen Sie das Spiel in den Einstellungen offline (am unteren Rand des Spiel-Menu).', 0),
(4955, 3, 1, 'COLONIZE_RANDOM_PLANET', 'Besiedeln gegeben uncharted', 0),
(4956, 3, 3, 'FLEET_MESSAGE_COLONIZE_NEW_USER_PLANET', 'Ihre Flotte ({@fleet}) auf eine Mission geschickt: {@mission} <br /> Cargo:. {@metal} Metall {@silicon} Si und {@hydrogen} Wasserstoff.', 0),
(4957, 3, 14, 'ALLIANCE_FOUND_BLOCKED_BY_USER_POINTS', 'Du kannst jetzt nicht eine Allianz, weil Sie haben zu wenig Punkte. Sie mussen ein Minimum von {@min_points} Punkte haben, konnen Sie {@user_points} Punkte.', 0),
(4958, 3, 7, 'EMAIL_DOMAIN_FAILED', 'Auf {@email_domain_failed} Domain E-Mails nicht zu erreichen. Bitte verwenden Sie ein anderes Postfach fur die Registrierung, zum Beispiel @ ya.ru, @ mail.ru, @ gmail.com, etc.', 0),
(4959, 3, 23, 'SN_OK_CREDITS_STRING', '<span class=''confederation''> {@total} </span> <br/> Credits ({@raw} <span class=''true''> + {@bonus} als Geschenk an </span>)', 0),
(4960, 3, 25, 'CHANGE_NAME_TITLE', 'Willkommen', 0),
(4961, 3, 25, 'ACHIV_BONUS_TITLE', 'Das Achievement-System', 0),
(4962, 3, 25, 'ACHIV_BONUS_DESC', '<p /> Um das Spiel schneller zu meistern, folgen Sie den Anweisungen der Leistung - die jungen Kampfer naturlich. Einfach fuhrt die vorgeschlagenen Anforderungen und erhalten eine Belohnung. <p /> Klicken Sie nun Taste <b> Holen Sie sich Ihre Pramie und verstecken </b> (der Pfeil auf ihn), um Ihre erste Bonus Spiel zu bekommen.', 0),
(4963, 3, 25, 'MENU_ACHIEVEMENTS_TITLE', 'Erfolge', 0),
(4964, 3, 25, 'MENU_ACHIEVEMENTS_DESC', 'Wenn Sie auf die Erreichung der <b> </b> ausblenden oder <b> Holen Sie sich Ihre Pramie und verstecken </b>, wird die Leistung nicht auf allen Seiten angezeigt werden. Um zu sehen, die versteckten (zusammengeklappt) Leistung auf die Seite Achievements (angedeutet durch den Pfeil darauf) zu gehen.', 0),
(4965, 3, 25, 'MENU_ACHIEVEMENTS_PAGE_TITLE', 'Mehr Informationen uber die Leistungen der', 0),
(4966, 3, 25, 'MENU_ACHIEVEMENTS_PAGE_DESC', 'Um die Leistungen mussen bestimmte Anforderungen erfullen. Sie sofort, nachdem Sie uvidesh Liste der Auszeichnungen in der Beschreibung der Leistungen. Grune bemerkt Anforderungen erfullt, rot - offen.', 0),
(4967, 3, 25, 'MENU_BUILD_TITLE', 'Bildung und Wohnungsbau', 0),
(4968, 3, 25, 'MENU_BUILD_DESC', 'Zur Erfullung der Leistung des &quot;Schutzen Sie die Umwelt&quot;, ist es notwendig, ein Solarkraftwerk (dieser Struktur, das Spiel auch als ein Gebaude oder eine Konstruktion genannt) zu bauen. Zum Aufbau eines Solarkraftwerks, um die Gebaude zu gehen.', 0),
(4969, 3, 25, 'BUILD_SOLAR_TITLE', 'Bau', 0),
(4970, 3, 25, 'BUILD_SOLAR_DESC', '<p /> Um ein Gebaude zu errichten, mussen alle Anforderungen fur den Bau und die notwendige Menge an Ressourcen. <p /> Solarstrom wird direkt nach dem Synthesizer Wasserstoff angezeigt. Klicken Sie auf die Build-Solar-Kraftwerk vor der Beschreibung. Blattern Sie nach unten ein wenig, wenn eine Schaltflache nicht sichtbar ist Build.', 0),
(4971, 3, 25, 'SHOW_ME_TUTORIAL_TITLE', 'Tips', 0),
(4972, 3, 25, 'SHOW_ME_TUTORIAL_DESC ', '<p /> Tipps konnen Sie durch Drucken der Taste in das Eingabefeld <b> </b> ausblenden gedreht werden. Um zu zeigen, die Spitzen wieder auf eine Frage klicken fur die <b> </b> (es ist jetzt durch den Pfeil gekennzeichnet). Klicken Sie auf <p /> <b> auf </b> Weiter, um fortzufahren Erkundung des Spiels.', 0),
(4973, 3, 25, 'MENU_GALAXY_TITLE', 'Einfuhrung in die Galaxie', 0),
(4974, 3, 25, 'MENU_GALAXY_DESC', '<p /> Wahrend das Solarkraftwerk gebaut wird, schauen wir uns ein Star-System suchen, wo Ihre Planeten. Ich frage mich, wenn Sie Nachbarn haben. Go to the Galaxy.', 0),
(4975, 3, 25, 'MENU_GALAXY_DESC_TITLE', 'Sehen Sie sich die Galaxy', 0),
(4976, 3, 25, 'MENU_GALAXY_DESC_DESC', '<p /> Das Universum besteht aus Galaxien OXSAR, die von Sternsystemen bestehen. Jedes System kann bis zu 30 Planeten befinden. <p /> Wenn Sie die Galaxie verbraucht hierbei 10 Wasserstoff!', 0),
(4977, 3, 25, 'MENU_CHAT_TITLE', 'Introduction to chat', 0),
(4978, 3, 25, 'MENU_CHAT_DESC', '<p /> Fur die Kommunikation zwischen Spielern und Neulingen helfen, um das Spiel zu plaudern. Mal sehen, was jetzt passiert. <p /> Zum Chat.', 0),
(4979, 3, 25, 'MENU_CHAT_DESC_TITLE', 'Plaudern', 0),
(4980, 3, 25, 'MENU_CHAT_DESC_DESC', '<p /> Es gibt zwei Arten von Chat - General Chat und der Allianz. In den allgemeinen Chat kann mit allen Spielern zu kommunizieren. In einem Chat-Allianz - nur die Spieler ein konkretes Bundnis. Sie konnen an einer bestehenden Allianz zur Entwicklung und gemeinsam kampfen.', 0),
(4981, 3, 25, 'SOLARPLANT_BONUS_TITLE', 'Durchgefuhrt, um zu erreichen', 0),
(4982, 3, 25, 'SOLARPLANT_BONUS_DESC', '<p /> Nach Abschluss der Bau von Solarkraftwerken Sie erfullt alle Anforderungen zu erreichen, &quot;Schutzen Sie die Umwelt.&quot; Belohnung: eine zweite Ebene der Solarenergie und 2 Solar-Satelliten. Dies wird Energie auf eurem Planeten in Kurze. Es ist Zeit, die Belohnung zu erhalten.', 0),
(4983, 3, 25, 'MENU_FLEET_TITLE', 'Die Vertrautheit mit Navy', 0),
(4984, 3, 25, 'MENU_FLEET_DESC', 'Anzeigen und senden ihre Schiffe im Flug von einer Seite der Flotte sein. <br /> Gehen Sie zuruck.', 0),
(4985, 3, 25, 'MENU_FLEET_DESC_TITLE', 'Flotte Ubersicht', 0),
(4986, 3, 25, 'MENU_FLEET_DESC_DESC', 'Auf der Seite der Flotte konnen Sie alle ihre Schiffe auf diesem Planeten zu sehen und damit das Senden sie zum Angriff, oder eine Expedition zum Management und den Transport zu anderen Planeten zu laden, oder einfach, um zwischen Ihren Planeten bewegen.', 0),
(4987, 3, 25, 'MENU_SIMULATOR_TITLE', 'Schlacht-Simulator', 0),
(4988, 3, 25, 'MENU_SIMULATOR_DESC', '<p /> Bald werden Sie in der Lage, in den Raum zu gehen und andere Spieler angreifen. Eine wichtige Komponente der den Feind zu besiegen - proschityvanie Chancen fur eine erfolgreiche Ausgang der Schlacht. Dazu mussen Sie Simulator zu bekampfen.', 0),
(4989, 3, 25, 'MENU_SIMULATOR_DESC_TITLE', 'Simulierte Schlacht', 0),
(4990, 3, 25, 'MENU_SIMULATOR_DESC_DESC', 'Um die Durchfuhrung der einfachste Simulation der Schlacht - und fuhren die Flotte angreifen Verteidiger, und klicken Sie dann auf Simulieren <b> </b> am unteren Rand der Seite. Wissen, wie man den Kampf simulieren Sie im Vorbeigehen den Kurs der jungen Kampfer zu helfen.', 0),
(4991, 3, 25, 'CONTINUE_ACHIV_TITLE', 'Kurs des jungen Soldaten', 0),
(4992, 3, 25, 'CONTINUE_ACHIV_DESC', '<p /> Nun wissen Sie viel uber das Spiel. Fortsetzung zu seinem Reich nach den Anweisungen eines jungen Soldaten Course (um nur die notwendigen Voraussetzungen fur die Leistungen fuhren) zu entwickeln, und sehr bald werden Sie in den Raum gehen, mit Kriegsschiffen und in der Lage, militarische Operationen durchfuhren. <p /> Genie?en Sie das Spiel.', 0),
(4993, 3, 25, 'PLANET_CREATION_WAIT_TITLE', 'Warten auf einen Planeten', 0),
(4994, 3, 25, 'PLANET_CREATION_WAIT_DESC', 'Euer Planet erstellt wird, noch ein bisschen warten und aktualisieren Sie die Seite.', 0),
(4995, 3, 25, 'SOLARPLANT_CONSTRUCTED_TITLE', 'Abschluss der Bauarbeiten', 0),
(4996, 3, 25, 'SOLARPLANT_CONSTRUCTED_DESC', '<p /> Solarstrom, den Sie vor einiger Zeit zu bauen, wahrscheinlich bereits gebaut gestartet. Lassen Sie es sehen. Gehen Sie auf die Gebaude.', 0),
(4997, 3, 25, 'MENU_GALAXY_COORD_DESC', '<p /> Um die verschiedenen Galaxien und Systeme zu sehen, konnen Sie die gewunschte kordinaty in das Eingabefeld ein. Die Koordinaten des Planeten erscheinen [X: Y: Z], wobei X - Anzahl der Galaxie, Y - Anzahl der Sternsysteme, Z - Zahl der Planeten. <p /> Die geringere Zahl der Planeten ist die Erde naher an die Sterne, je hoher die Temperatur sein kann. Die Temperatur beeinflusst die Produktion von Wasserstoff, als es ist, desto weniger Wasserstoff erzeugt. Aber mehr Energie wird durch Solarzellen-Satelliten erzeugt.', 0),
(4998, 3, 25, 'MENU_GALAXY_COORD_TITLE', 'Die Koordinaten des Planeten', 0),
(4999, 3, 8, 'RESEND_ACTIVATION_LABEL', 'Eine neue Nachricht uber aktiviert auf e-mail', 0),
(5000, 3, 8, 'RESEND_ACTIVATION', 'Senden', 0),
(5001, 3, 1, 'PLEASE_ACTIVATE_ACCOUNT', 'Die Aktivierung des e-mail noch nicht implementiert. Uberprufen Sie bitte meine E-Mails, schickte sie einen Brief uber die Aktivierung. Dies muss geschehen, um nicht zu verlieren den Zugriff auf das Spiel und in der Lage sein, ein vergessenes Passwort wiederherzustellen oder Andern der aktuellen, falls erforderlich. Wenn Sie noch keine haben einen Brief uber die Aktivierung in der e-mail, fragen Sie ihn zanogo auf der Seite Einstellungen. Wenn der Brief nicht nach mehreren Versuchen kommen, die E-Mail auf der anderen Seite auch auf der Seite Einstellungen.', 0),
(5002, 3, 25, 'SOLAR_PLANT_WAIT_TITLE', 'Notwendig, um die SES-Konstrukt', 0),
(5003, 3, 25, 'SOLAR_PLANT_WAIT_DESC', '<p /> Der nachste Schritt besteht darin, ein Solarkraftwerk zu bauen. Wenn Sie bereits begonnen haben, Gebaude, denn die Fertigstellung warten und klicken Sie auf <b> </b> Weiter. Ansonsten Baubeginn jetzt.', 0),
(5004, 3, 18, 'SHIPYARD_POWER', 'Werft', 0),
(5005, 3, 18, 'DEFENSE_FACTORY_POWER', 'Equi. Anlage', 0),
(5006, 3, 12, 'EXCH_TITLE_EXISTS', 'Der Austausch mit dem Namen {@exch_title} existiert bereits!', 0),
(5007, 3, 4, 'PLANET_TEMP_CREATOR_FULL_DESC', 'Hiermit konnen Sie planetarischen Leuchtturm zu schaffen - eine temporare Zwergplanet auf den Mond fur den Einsatz von Schiffen. Die Gebaude sind auf dem Mond gebaut ist viel schneller als herkommliche Monde, aber es kann durch den Todesstern in jeder Galaxie zerstort werden. Nach der Zerstorung des Mondes am Leuchtturm, kann die neue nicht gebaut werden. Lighthouse vollig zerstort sich selbst, der Schwerkraft-Anomalie in 3 Wochen (mit allen Gebauden auf sie, wenn vorhanden), sollte die Flotte auch vor der Zerstorung geerntet werden. Lighthouse - ein Planetensatz, der Mond oder ein Planet kann ein Leuchtfeuer, jederzeit bei Bedarf zu verlassen. So erstellen Sie einen Leuchtturm, mussen Sie ein Artefakt in der Navy aus dem Kolonisator schicken, um die freie Position.', 0),
(5008, 3, 4, 'PLANET_TEMP_CREATOR_DESC', 'Hier konnen Sie eine temporare Zwergplanet mit einem Mond fur einen Punkt Dislokation fur 3 Wochen zu schaffen. Auf dem Mond den Leuchtturm kann viel schneller als herkommliche Monden gebaut werden, aber es zerstort werden kann. So erstellen Sie einen Leuchtturm, mussen Sie ein Artefakt in der Navy aus dem Kolonisator schicken, um die freie Position.', 0),
(5009, 3, 4, 'PLANET_TEMP_CREATOR', 'Planetary Leuchtturm', 0),
(5010, 3, 4, 'TRANSMITTER', 'Sender', 0),
(5011, 3, 4, 'TRANSMITTER_DESC', 'Die schweren Transportschiff mit einer riesigen Kapazitat und eine skalierbare Fortbewegungsmittel.', 0),
(5012, 3, 4, 'TRANSMITTER_FULL_DESC', 'Die schweren Transportschiff ist auf neue Entwicklungen in der heutigen Motoren und Rumpf Schutz errichtet. Diese Technologien haben eine vernunftige Uberlebensrate der Transportschiff mit einer riesigen Kapazitat und skalierbare High-Speed-Eigenschaften erlaubt. Einzigartige Motor Line-Up konnen Sie mehrere Motoren zu aktualisieren, zu erreichen mit beispielloser Geschwindigkeit fur andere Transporte in das Reich.', 0),
(5013, 3, 1, 'ARTEFACT_NOT_BUYABLE', 'Kann man nicht kaufen', 0),
(5014, 3, 13, 'TEMP_PLANET_DIE', '{@planet} Leuchtturm durch die Schwerkraft-Anomalie zerstort.', 0),
(5015, 3, 13, 'TEMP_PLANET_DIE_SUBJ', 'Lighthouse zerstort', 0),
(5016, 3, 10, 'JUMP_SUCCESSFUL_HITCHED', 'Eine Uberlastung des Systems mit Teleportation, ist etwas schief gelaufen, aber es scheint alles in Ordnung ist.', 0),
(5017, 3, 13, 'RETREAT_TRANSPORT', '{@username} Fahrzeuge umgesturzt auf {@planet_from} {@coords_from}. Ihre Flotte ({@fleet}) kehrt in den {@planet} {@coords}.', 0),
(5018, 3, 13, 'RETREAT_TRANSPORT_SUBJECT', 'Abbrechen Transport', 0),
(5019, 3, 10, 'CONTROL_EVENT', 'Verwalten', 0),
(5020, 3, 10, 'FLEET_MESSAGE_HOLDING_FUEL', 'Navy ({@fleet}), die zur {@username} {@message} auf {@planet} {@coords} ist die Bahn {@target} {@targetcoords} {@target_username} {@target_message}. <br /> Cargo: {@metal} Metall {@silicon} Si und {@hydrogen} Wasserstoff. Kraftstoff: {@fuel_hydrogen} Wasserstoff.', 0),
(5021, 3, 10, 'UNLOAD_RESOURCES', 'Entladen', 0),
(5022, 3, 10, 'LOAD_RESOURCES', 'Herunterladen', 0),
(5023, 3, 10, 'FLEET_MESSAGE_HOLDING', 'Navy ({@fleet}), die zur {@username} {@message} auf {@planet} {@coords} ist die Bahn {@target} {@targetcoords} {@target_username} {@target_message}. <br /> Cargo: {@metal} Metall {@silicon} Si und {@hydrogen} Wasserstoff.', 0),
(5024, 3, 1, 'STARGATE_JUMP', 'Teleportation', 0),
(5025, 3, 13, 'STARGATE_JUMP_REPORT', 'Ihre Flotte (%s) haben erfolgreich an den %s %s teleportiert.', 0),
(5026, 3, 13, 'STARGATE_JUMP_REPORT_SUBJECT', 'Teleportation erfolgreich', 0),
(5027, 3, 4, 'IGLA_MORI', 'Needle Mori Coleys', 0),
(5028, 3, 4, 'IGLA_MORI_DESC', 'Hier konnen Sie die Space Hopper zu aktivieren, um die Flotte (einschlie?lich Ladung) durch das intergalaktische Gateway-Modus giperpoleta bewegen. Zur gleichen Zeit jede Stunde Flug verwandelt sich in den ublichen 10 Sekunden wird der Kraftstoffverbrauch in 1000 reduziert. So aktivieren Sie die hyper Flug, sollten Sie Nadel in die Navy add wahrend der Umschichtung zwischen den Monden des Tores.', 0),
(5029, 3, 4, 'IGLA_MORI_FULL_DESC', 'Needle Mori Coleys durchdringt Raum und schafft ein Krater mit Funktionen, die Sie bewegen die Flotte (einschlie?lich Ladung) durch das intergalaktische Gateway-Modus giperpoleta lassen. In diesem Modus wird die Flotte eine Entfernung entspricht reist zu den ublichen 1-stundigen Flug 10 Sekunden lang wird der Kraftstoffverbrauch in 1000 reduziert. Fur eine lange Zeit, hat die Arbeit dieses Artefakt blieb, bis eine Gruppe von Wissenschaftlern unbekannt nicht entziffern konnte die Korrespondenz von Auslandern in den Computer beschlagnahmt Schiff Alien-Rasse. Name des Artefakts ist die Namen von Wissenschaftlern, ihr Prinzip zu entwirren gegeben. Interstellar Tore sind nach Gebrauch verschlossen, wie in Teleportation. So aktivieren Sie die hyper Flug, sollten Sie Nadel in die Navy add wahrend der Umschichtung zwischen den Monden des Tores.', 0),
(5030, 3, 13, 'SURVEILLANCE_DETECTED', 'Die Marine hat Aktivitaten in der Frequenz des Sensors Phalanx um den {@coords_planet}, der Planet war jemand gescannt gefunden.', 0),
(5031, 3, 13, 'SURVEILLANCE_DETECTED_SUBJ', 'Planet gescannt Fremden beruhren Phalanx', 0),
(5032, 3, 13, 'ALIEN_HALTING_MSG', 'Die Marine eine Nachricht von einer au?erirdischen Rasse: Zdravastvuyte, kommen wir zu den Welten! Alien-Flotte Positionen auf der Umlaufbahn {@coords_planet} genommen.', 0),
(5033, 3, 13, 'ALIEN_HALTING_SUBJ', 'Kontakt mit einer au?erirdischen Zivilisation', 0),
(5034, 3, 3, 'FLEET_MESSAGE_ALIEN_HOLDING', 'Alien-Flotte ({@fleet}) ist im Orbit {@target} {@targetcoords}.', 0),
(5035, 3, 3, 'FLEET_MESSAGE_ALIEN', 'Alien-Flotte ({@fleet}) erreicht Ihre Koordinaten {@target} {@targetcoords}. Assignment:. {@mission} <br /> Cargo: {@metal} Metall {@silicon} Si und {@hydrogen} Wasserstoff.', 0),
(5036, 3, 3, 'FLEET_MESSAGE_ALIEN_OTHER', 'Alien-Flotte ({@fleet}) flog, um die Koordinaten {@target} {@targetcoords}. Assignment:. {@mission} <br /> Cargo: {@metal} Metall {@silicon} Si und {@hydrogen} Wasserstoff.', 0),
(5037, 3, 3, 'FLEET_MESSAGE_ALIEN_OTHER_2', 'Alien-Flotte ({@fleet}) bewegt sich die Koordinaten {@target} {@targetcoords}. Assignment:. {@mission} <br /> Cargo: {@metal} Metall {@silicon} Si und {@hydrogen} Wasserstoff.', 0),
(5038, 3, 13, 'MSG_CREDIT_BUILDING_UNIT', 'Sie haben mit dem Bau (die {@name}) fur {@credits} Darlehen.', 0),
(5039, 3, 13, 'MSG_CREDIT_RESEARCHING', 'Sie studierte ({@name}) fur {@credits} Darlehen.', 0),
(5040, 3, 13, 'MSG_CREDIT_ALIEN_GRAB', 'Die Marine gefunden brechen Lagerung Darlehen, die Au?erirdischen entfuhrt {@credits} Darlehen.', 0),
(5041, 3, 13, 'MSG_CREDIT_ALIEN_GIFT', 'Die Marine eine Nachricht von ET: Vielen Dank fur gostipriemstistvo, um das Geschenk imyani blagodarnast {@credits} Kredite zu akzeptieren.', 0),
(5042, 3, 1, 'CONFIRM_BUILDING_USE_CREDIT', 'Fur den Bau ({@name}) {@credit} Kredite benotigen.', 0),
(5043, 3, 1, 'CONFIRM_OK', 'OK', 0),
(5044, 3, 1, 'CONFIRM_CANCEL', 'Stornieren', 0),
(5045, 3, 1, 'CONFIRM_TITLE_WARNING', 'Achtung', 0),
(5046, 3, 1, 'EXCH_NEWLOT_FEATURED', 'Ausgewahlten Exchange', 0),
(5047, 3, 1, 'EXCH_LOTS_FEATURED', 'Premium bietet', 0),
(5048, 3, 1, 'PREMIUM', 'Pramie', 0),
(5049, 3, 1, 'CONFIRM_PREMIUN_LOT_USE_CREDIT', 'Erhohen Sie die Menge ({@name}) in die Liste fur Premium Credits {@credit}?', 0),
(5050, 3, 13, 'MSG_CREDIT_EXCHANGE_PREMIUM_LOT', 'Sie hob eine Menge ({@name}), um die Liste der Pramie fur die {@credits} Darlehen.', 0),
(5051, 3, 1, 'PREMIUN_LIST_MAX_SIZE', 'Premium bietet fur den Konsumenten billiger und profitabler fur Verkaufer. Schnelligkeit der Zustellung ist doppelt so schnell, doppelt so Kraftstoff billiger ist. Qualitat des Produktes getestet intergalaktischen Vereinigung durch das Fehlen von Kratzern und Beschadigungen garantiert! Maximum zeigt, {@count} Lose. Nach der Veroffentlichung der Liste Element bleibt in den Status eines Premium und kann auf der Liste wieder hinzugefugt werden.', 0),
(5052, 3, 1, 'CONFIRM_LOT_RECALL', 'Sind Sie sicher, dass Sie die Menge ({@name}) entfernen?', 0),
(5053, 3, 1, 'EXCH_RECALL_AND_BAN', 'Verbot', 0),
(5054, 3, 1, 'CONFIRM_EXCH_RECALL_AND_BAN', 'Sind Sie sicher, dass Sie an den Verkaufer zu verbieten und nehmen Sie es vom lot ({@name})?', 0),
(5055, 3, 1, 'PREMIUN_LOT_SLOGAN', 'Preis abzuglich Versand schneller.', 0),
(5056, 3, 1, 'PREMIUN_SELLER_INFO', 'Verkaufer eine Pramie. Bietet eine schnelle und kostengunstige Lieferung von Waren.', 0),
(5057, 3, 1, 'MSG_EXCH_LOT_BACK_RESOURSES', 'Am Ende der Partie ({@lot}) blieb in Anspruch genommenen Mittel wurden sie zuruck zu den {@planet} zuruckgegeben. <br /> Cargo: {@metal} Metall {@silicon} Si und {@hydrogen} Wasserstoff.', 0),
(5058, 3, 1, 'MSG_EXCH_LOT_BACK_RESOURSES_SUBJ', 'Return of unverbrauchten Ressourcen', 0),
(5059, 3, 4, 'MOON_LAB', 'Lunar Lab', 0),
(5060, 3, 4, 'MOON_LAB_FULL_DESC', 'Lunar Lab (LL) - ist die perfekte Struktur auf dem Mond und vielleicht sogar im ganzen Reich, die Frucht der Top-Wissenschaftler Arbeit ist. Jede Ebene der M 10-fache erhoht der planetarischen Forschungslabor in der IIA beteiligt. Dies gibt die Moglichkeit, die zeitaufwandige und nicht erreichbar, ohne den LL-Technologie Forschung. Daruber hinaus ermoglicht jedem Level zu AA auf dem Mond nutzen 10% der Leistung der Planetenmuhle Naniten, dass Sie mehr und mehr grandiose Gebaude erstellen konnen. Aber das ist nicht alles, haben Wissenschaftler einen Weg durch M verfugbaren Felder auf dem Mond fur alle seine starkere Entwicklung zu erweitern gefunden.', 0),
(5061, 3, 5, 'MOON_LAB_DESC', 'Mond wieder beschleunigt Laborforschung zur Verfugung stellen den Mond, Planeten-Muhle Naniten, fugt freie Felder auf dem Mond.', 0),
(5062, 3, 4, 'MOON_REPAIR_FACTORY_DESC', 'Lunar Wartungshalle fur die Reparatur von beschadigten und Entsorgung von unerwunschten Einheiten erforderlich.', 0),
(5063, 3, 4, 'MOON_REPAIR_FACTORY_FULL_DESC', 'Lunar-Wartungshalle wird benotigt, um zwei Vorgange: 1 - Reparatur von beschadigten Schiffe und Festungen, 2 - Recycling unerwunschte Fahrzeuge und Verteidigung, um die Ressourcen zu bekommen.', 0),
(5064, 3, 4, 'MOON_REPAIR_FACTORY', 'Lunar Werfthalle', 0),
(5065, 3, 1, 'PLANET_UNDER_ATTACK', 'Es ist unmoglich, den Job jetzt zu tun. Auf dem Planeten kampfen. Versuchen Sie es in einer Sekunde.', 0),
(5066, 3, 10, 'EXPEDITION_WARNING', 'Die Expedition finden Sie Ressourcen, Flottenmanagement, treffen Auslander und vieles mehr. mehr. Aber vergessen Sie nicht, dass die Expedition immer behaftet ist, ist es moglich, die Flotte zu verlieren. Beginnen Sie nicht mit auf eine Expedition Flotte, ware der Verlust, die sinnvoll fur Sie!', 0),
