(5165, 4, 3, 'FLEET_MESSAGE_FORMATION', '<p> Спільно з %s з %s %s: %s </p>', 0),
(5166, 4, 3, 'FLEET_MESSAGE_HOLDING_1', 'Ваш флот ({@fleet}) з {@planet} {@coords} знаходиться на орбіті {@target} {@targetcoords}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.', 0),
(5167, 4, 3, 'FLEET_MESSAGE_HOLDING_2', 'Чужий флот ({@fleet}) {@username} {@message} з {@planet} {@coords} знаходиться на орбіті {@target} {@targetcoords}.', 0),
(5168, 4, 3, 'FLEET_MESSAGE_OTHER', 'Чужий флот ({@fleet}) {@username} {@message} з {@planet} {@coords} досягає Ваших координат {@target} {@targetcoords}. Завдання: {@mission}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.', 0),
(5169, 4, 3, 'FLEET_MESSAGE_OWN', 'Ваш флот ({@fleet}) з {@planet} {@coords} відправлений на {@target} {@targetcoords}. Завдання: {@mission}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.', 0),
(5170, 4, 3, 'FLEET_MESSAGE_RETURN', 'Ваш флот ({@fleet}) з {@planet} {@coords} повертається на {@target} {@targetcoords}. Завдання: {@mission}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.', 0),
(5171, 4, 3, 'FLEET_MESSAGE_ROCKET_ATTACK', 'Ваші ракети ({@rockets}) з {@planet} {@coords} {досягають 103} {@targetcoords}.', 0),
(5172, 4, 3, 'FLEET_MESSAGE_ROCKET_ATTACK_FOREIGN', 'Ворожі ракети ({@rockets}) {@username} {@message} з {@planet} {@coords} {досягають 105} {@targetcoords}.', 0),
(5173, 4, 3, 'INVALID_PLANET_NAME', 'Назва планети містить неприпустимі символи.', 0),
