(5181, 4, 3, 'SERVER_TIME', 'Серверне час', 0),
(5182, 4, 3, 'STAR_SUR_MSG', 'Чужий флот ({@fleet}) гравця {@username} з {@planet} {@coords} рухається на {@target} {@targetcoords}. Завдання: {@mission}', 0),
(5183, 4, 3, 'STAR_SUR_MSG_RETURN', 'Чужий флот ({@fleet}) повертається з {@planet} {@coords} на {@target} {@targetcoords}. Завдання: {@mission}', 0),
(5184, 4, 3, 'TEMPERATURE', 'Температура', 0),
(5185, 4, 4, 'ABORT', 'Скасування', 0),
(5186, 4, 4, 'BATTLE_SHIP', 'Лінкор', 0),
(5187, 4, 4, 'BATTLE_SHIP_DESC', 'Лінкори як правило складають основу флоту. Їх важкі гармати, висока швидкість і великий вантажний тоннаж роблять їх серйозними противниками.', 0),
(5188, 4, 4, 'BATTLE_SHIP_FULL_DESC', 'Лінкори як правило складають основу флоту. Їх важкі гармати, висока швидкість і великий вантажний тоннаж роблять їх серйозними противниками.', 0),
(5189, 4, 4, 'BOMBER', 'Бомбер', 0),
(5190, 4, 4, 'BOMBER_DESC', 'Бомбер був розроблений спеціально для того, щоб знищувати планетарну захист.', 0),
(5191, 4, 4, 'BOMBER_FULL_DESC', 'Бомбер був розроблений спеціально для того, щоб знищувати планетарну захист. За допомогою лазерного прицілу він точно скидає плазмові бомби на поверхню планети і таким чином наносить величезні пошкодження оборонним спорудам. Недоліки: досить повільний корабель.', 0),
(5192, 4, 4, 'COLONY_SHIP', 'Колонізатор', 0),
(5193, 4, 4, 'COLONY_SHIP_DESC', 'За допомогою цього корабля можна освоювати незаселені планети.', 0),
(5194, 4, 4, 'COLONY_SHIP_FULL_DESC', 'Колонізатор призначений для освоєння раніше не зайнятих планет. Він використовується в новій колонії у якості постачальника сировини - його розбирають і використовують весь корисний матеріал для освоєння нового світла.', 0),
(5195, 4, 4, 'COMBUSTION_ENGINE', 'Реактивний двигун', 0),
(5196, 4, 4, 'COMBUSTION_ENGINE_DESC', 'Технологія для розвитку двигунів невеликих комсіческіх кораблів, що дозволяє літати з невеликим споживанням палива на великі відстані.', 0),
(5197, 4, 4, 'COMBUSTION_ENGINE_FULL_DESC', 'Реактивний двигун грунтується на принципі віддачі. Матерія, розігріта до високих температур, викидається в напрямку, протилежному руху і дає прискорення корабля. Ефективність цих двигунів досить мала, але вони досить надійні, дешеві у виробництві та обслуговуванні. Крім того вони займають набагато менше місця на кораблі в порівнянні з іншими двигунами, тому їх усе ще досить часто можна зустріти на маленьких кораблях. Так як реактивні двигуни є основою будь-якого польоту в космос, слід досліджувати їх якомога раніше. Подальший розвиток цих двигунів робить такі кораблі з кожним рівнем на 10% швидше: <br /> <br /> малі транспорти (до тих пір поки не буде досліджено імпульсний двигун 5-го рівня), великі транспорти, легкі винищувачі і шпигунські зонди.', 0),
(5198, 4, 4, 'COMPUTER_TECH', 'Комп&#39;ютерна технологія', 0),
(5199, 4, 4, 'COMPUTER_TECH_DESC', 'Зі збільшенням потужності комп&#39;ютерів можна командувати все більшою кількістю флотів. Кожен рівень комп&#39;ютерної технології збільшує максимальну кількість флотів на один.', 0),
(5200, 4, 4, 'COMPUTER_TECH_FULL_DESC', 'Комп&#39;ютерна технологія призначена для розширення наявних комп&#39;ютерних потужностей. В результаті на планеті розвиваються більш продуктивні та ефективні комп&#39;ютерні системи, зростає обчислювальна потужність і швидкість протікання обчислювальних процесів. З підвищенням потужності комп&#39;ютерів можна одночасно командувати все більшою кількістю флотів. Кожен рівень розвитку комп&#39;ютерної технології дає можливість командувати +1 флотом. Чим більше розсилається флотів, тим більше можна здійснювати нальотів і тим самим захоплювати більше сировини. Природно, що ця технологія корисна і торговцям, так як вона дозволяє їм одночасно розсилати більше торговельних флотів. З цієї причини слід постійно розвивати комп&#39;ютерну технологію протягом всієї гри.', 0),
(5201, 4, 4, 'CONTINUE', 'Продовжити', 0),
(5202, 4, 4, 'CRUISER', 'Крейсер', 0),
(5203, 4, 4, 'CRUISER_DESC', 'Крейсери майже втричі сильніше застережені, ніж важкі винищувачі, а з вогневої потужності вони перевершують важкі винищувачі майже в два рази. До того ж вони дуже швидкі.', 0);
INSERT INTO `na_phrases` (`phraseid`, `languageid`, `phrasegroupid`, `title`, `content`, `translated`) VALUES
(5204, 4, 4, 'CRUISER_FULL_DESC', 'З розвитком важких лазерів і іонних гармат важкі винищувачі все більше витіснялися. Незважаючи на численні вдосконалення вогнева міць і бронювання не могли бути настільки змінені, щоб дієво протистояти цим оборонним знаряддям. Тому було вирішено побудувати новий клас кораблів, який об&#39;єднував би в собі більше бронювання та вогневої мощі. Так з&#39;явився крейсер. Крейсери майже втричі сильніше застережені, ніж важкі винищувачі і мають більш ніж подвоєною вогневої міццю. До того ж вони дуже швидкі. Немає кращого зброї проти середньої захисту. Майже століття крейсери необмежено панували у всесвіті. З появою знарядь Гаусса і плазмових знарядь їх панування закінчилося. Проте і сьогодні їх охоче застосовують проти груп винищувачів.', 0),
(5205, 4, 4, 'DEATH_STAR', 'Зірка смерті', 0),
(5206, 4, 4, 'DEATH_STAR_DESC', 'Зірка смерті оснащена гігантської гравітонів гарматою, яка може знищувати кораблі і навіть місяця.', 0),
(5207, 4, 4, 'DEATH_STAR_FULL_DESC', 'Зірка Смерті оснащена гравітонів гарматою, яка може знищувати всі типи кораблів і навіть місяця. Для виробництва достатньої кількості енергії, зірка смерті практично повністю складається з генераторів. Тільки величезні зоряні імперії мають достатньо ресурсів і працівників для будівництва цього величезного корабля.', 0),
(5208, 4, 4, 'DEMOLISH', 'Знищення:', 0),
(5209, 4, 4, 'DEMOLISH_NOW', '&laquo; Знести &laquo;', 0),
(5210, 4, 4, 'ENERGY_TECH', 'Енергетична технологія', 0),
(5211, 4, 4, 'ENERGY_TECH_DESC', 'Володіння різними видами енергії необхідно для багатьох нових технологій.', 0),
(5212, 4, 4, 'ENERGY_TECH_FULL_DESC', 'Володіння різними видами енергії необхідно для багатьох нових технологій.', 0),
(5213, 4, 4, 'ESPIONAGE_SENSOR', 'Шпигунський зонд', 0),
(5214, 4, 4, 'ESPIONAGE_SENSOR_DESC', 'Шпигунські зонди - це маленькі маневрені кораблі, які доставляють з великих відстаней дані про флотах і планетах.', 0),
(5215, 4, 4, 'ESPIONAGE_SENSOR_FULL_DESC', 'Шпигунські зонди - це маленькі маневрені кораблі, які доставляють з великих відстаней дані про флотах і планетах. Їх високопотужний двигун дозволяє їм долати великі відстані за кілька секунд. Одного разу потрапивши на орбіту якої-небудь планети, вони перебувають там деякий час для складання даних. У цей час ворог може їх відносно легко виявити і атакувати. Для економії місця не було виявлено ні броні, ні щитів, ні знарядь, що робить зонди у разі виявлення легкими цілями.', 0),
(5216, 4, 4, 'EXPO_TECH', 'Експедиційна технологія', 0),
(5217, 4, 4, 'EXPO_TECH_DESC', 'Тепер кораблі можна оснащувати дослідницьким модулем, що забезпечує обробку зібраних даних в умовах тривалих польотів.', 0),
(5218, 4, 4, 'EXPO_TECH_FULL_DESC', 'Експедиційна технологія охоплює різні технології сканування і дає можливість оснащувати кораблі різних класів дослідницьким модулем. Він містить базу даних, маленьку пересувну лабораторію, а також різні біоклеткі і судини для проб. Для безпеки корабля при дослідженні небезпечних об&#39;єктів дослідницький модуль оснащений автономним енергозабезпеченням та генератором енергетичного поля, який в екстремальних ситуаціях може оточувати дослідницький модуль потужним енергетичним полем.', 0),
(5219, 4, 4, 'FRIGATE', 'Лінійний крейсер', 0),
(5220, 4, 4, 'FRIGATE_DESC', 'Лінійний крейсер спеціалізується на перехопленні ворожих флотів.', 0),
(5221, 4, 4, 'FRIGATE_FULL_DESC', 'Цей високотехнологічний корабель несе смерть атакуючим флотам. Його вдосконалені лазерні гармати утримують важкі кораблі противника на відстані і можуть знищувати кілька одиниць одним залпом. За рахунок його малих розмірів і неймовірно потужного озброєння, вантажопідйомність лінійного крейсера дуже мала, але за рахунок Гіперпросторовий двигуна також мало споживання палива.', 0),
(5222, 4, 4, 'GAUSS_GUN', 'Гармата Гаусса', 0),
(5223, 4, 4, 'GAUSS_GUN_DESC', 'Гармата Гаусса прискорює багатотонні заряди з гігантськими затратами енергії.', 0),
(5224, 4, 4, 'GAUSS_GUN_FULL_DESC', 'Довгий час артилерійські знаряддя вважалися застарілими на тлі розвитку сучасної лазерної та іонної техніки і постійно поліпшується захисту, поки нові дослідження в галузі енергетичної технології не дозволили підняти артилерію на якісно новий рівень. Взагалі-то принципи електромагнітних прискорювачів мас були відомі на Землі вже з 20-го сторіччя. Один з них - гармата Гаусса. З вирішенням технічних труднощів використання її в якості зброї стало реальністю. Багатотонні снаряди прискорюються магнітним полем при величезних витратах енергії і мають таку вихідну швидкість, що частинки пилу в повітрі навколо снаряда згоряють, а звукова хвиля стрясає землю. Навіть сучасна броня і щити насилу можуть протистояти пробивний силі гармати Гаусса, і нерідко трапляється так, що мета просто прострілюється наскрізь. Оборонні споруди деактивуються самі по собі, як тільки вони сильно пошкоджуються.', 0),
(5225, 4, 4, 'GRAVI', 'Гравітаційна технологія', 0),
(5226, 4, 4, 'GRAVI_DESC', 'Гравітон - це частка, яка не володіє ні масою ні зарядом і визначає силу тяжіння. Шляхом запуску концентрованого заряду гравітонів ученим вдалося створити штучне гравітаційне поле, яке здатне знищувати кораблі і навіть місяця. З підвищенням рівня цієї технології вдається скоротити витрату палива.', 0),
(5227, 4, 4, 'GRAVI_FULL_DESC', 'Гравітон - це частка, яка не володіє ні масою ні зарядом і визначає силу тяжіння. Шляхом запуску концентрованого заряду гравітонів ученим вдалося створити штучне гравітаційне поле, яке, подібно чорної діри, втягує в себе масу, завдяки чому можна знищувати кораблі і навіть місяця. З підвищенням рівня цієї технології вдається скоротити витрату палива в польоті всіма кораблями. Щоб вивчити новий рівень технології потрібна величезна кількість енергії. Колонка Виробництво показує відсоток споживання палива від базового значення при даному рівні технології.', 0),
(5228, 4, 4, 'GUN_TECH', 'Збройна технологія', 0),
(5229, 4, 4, 'GUN_TECH_DESC', 'Збройна технологія робить системи озброєння ефективніше. Кожен рівень збільшує потужність озброєння військових частин на 10% від основної потужності.', 0),
(5230, 4, 4, 'GUN_TECH_FULL_DESC', 'Збройна технологія займається насамперед подальшим розвитком наявних систем озброєння. При цьому особливе значення надається тому, щоб постачати наявні системи більшою енергією і більш точно цю енергію спрямовувати. Завдяки цьому системи озброєння стають ефективніше, а зброя викликає більше руйнувань. Кожен рівень збройової технології збільшує потужність озброєння військових частин на 10%. Збройна технологія важлива для конкурентоспроможного змісту частин. Тому варто було б її постійно розвивати протягом всієї гри.', 0),
(5231, 4, 4, 'HYDROGEN_LAB', 'Синтезатор водню', 0),
(5232, 4, 4, 'HYDROGEN_LAB_FULL_DESC', 'Удосконалення синтезатора сприяє збільшенню його ефективності по обробці води океану планети і, як наслідок, більшою виробленні водню. Водень необхідний як паливо для кораблів, майже для всіх досліджень, перегляду галактик, а також для використання сенсорної фаланги.', 0),
(5233, 4, 4, 'HYDROGEN_PLANT', 'Термоядерна електростанція', 0),
(5234, 4, 4, 'HYDROGEN_PLANT_FULL_DESC', 'На термоядерні електростанції за допомогою термоядерного синтезу під величезним тиском і при високій температурі 2 атома важкого водню об&#39;єднуються в один атом гелію. При цьому, при утворенні ядра гелію, виробляється енергія в 41,32 * 10 ^ -13 Дж у вигляді випромінювання (т.ч. при згоранні 1 г водню виробляється 172 МВт * год енергії). Чим більше термоядерний реактор, тим складніше процеси синтезування, реактор виробляє більше енергії. Видобуток енергії також може бути підвищена за рахунок розвитку енергетичної технології.', 0),
(5235, 4, 4, 'HYDROGEN_STORAGE', 'Ємність для водню', 0),
(5236, 4, 4, 'HYDROGEN_STORAGE_FULL_DESC', 'Величезні ємності для зберігання видобутого водню. Вони зазвичай знаходяться у районі космічних портів. Чим вони більші, тим більше водню в них може зберігатися. Якщо вони заповнені, то добування водню припиняється.', 0),
(5237, 4, 4, 'HYPERSPACE_ENGINE', 'Гіперпросторовий двигун', 0),
(5238, 4, 4, 'HYPERSPACE_ENGINE_DESC', 'Вигинає простір навколо корабля. Подальший розвиток цих двигунів робить деякі кораблі швидше.', 0),
(5239, 4, 4, 'HYPERSPACE_ENGINE_FULL_DESC', 'Завдяки просторово-часовому вигину в безпосередньому оточенні корабля простір стискається, чим швидше долаються далекі відстані. Чим вище розвинений Гіперпросторовий привід, тим вище стиснення простору, завдяки чому з кожним рівнем швидкість кораблів підвищується на 30%.', 0),
(5240, 4, 4, 'HYPERSPACE_TECH', 'Гіперпросторова технологія', 0),
(5241, 4, 4, 'HYPERSPACE_TECH_DESC', 'Шляхом сплетення 4-го та 5-го вимірювання стало можливим досліджувати новий більш економний і ефективний двигун. Крім цього вчені виявили, що викривлений простір збільшує радіус дії сенсорної фаланги.', 0),
(5242, 4, 4, 'HYPERSPACE_TECH_FULL_DESC', 'Шляхом сплетення 4-го та 5-го вимірювання стало можливим досліджувати новий більш економний і ефективний двигун. Крім цього вчені виявили, що викривлений простір збільшує радіус дії сенсорної фаланги на 10% за кожен рівень технології.', 0),
(5243, 4, 4, 'IGN', 'Міжгалактична дослідницька мережа', 0),
(5244, 4, 4, 'IGN_DESC', 'Ця мережа робить можливим спілкування вчених, що працюють в дослідницьких лабораторіях різних планет. Кожен новий рівень дозволяє приєднати до мережі додаткову лабораторію.', 0),
(5245, 4, 4, 'IGN_FULL_DESC', 'Ця мережа робить можливим спілкування вчених, що працюють в дослідницьких лабораторіях різних планет. Кожен новий рівень дозволяє приєднати до мережі додаткову лабораторію (в першу чергу приєднуються лабораторії старших рівнів). З усіх об&#39;єднаних у мережу лабораторій, в кожному дослідженні беруть участь тільки ті, які мають достатній для проведення даного дослідження рівень. Швидкість дослідження відповідає сумі рівнів беруть участь у ньому лабораторій.', 0),
(5246, 4, 4, 'IMPULSE_ENGINE', 'Імпульсний двигун', 0),
(5247, 4, 4, 'IMPULSE_ENGINE_DESC', 'Імпульсний двигун грунтується на принципі віддачі. Подальший розвиток цих двигунів робить деякі кораблі швидше,', 0),
(5248, 4, 4, 'IMPULSE_ENGINE_FULL_DESC', 'Імпульсний двигун грунтується на принципі віддачі, причому розігрів матерії здійснюється в ході ядерної реакції. Також можна впорснути додаткову масу. Подальший розвиток цих двигунів робить такі кораблі з кожним рівнем на 20% швидше: бомбери, крейсери, важкі винищувачі і колонізатори. Кожен рівень розвитку збільшує радіус дії міжпланетних ракет.', 0),
(5249, 4, 4, 'INTERCEPTOR_ROCKET', 'Ракета-перехоплювач', 0),
(5250, 4, 4, 'INTERCEPTOR_ROCKET_DESC', 'Ракети-перехоплювачі знищують атакуючі міжпланетні ракети.', 0),
(5251, 4, 4, 'INTERCEPTOR_ROCKET_FULL_DESC', 'Ракети-перехоплювачі знищують атакуючі міжпланетні ракети. Одна ракета-перехоплювач знищує одну міжпланетну ракету.', 0),
(5252, 4, 4, 'INTERPLANETARY_ROCKET', 'Міжпланетна ракета', 0),
(5253, 4, 4, 'INTERPLANETARY_ROCKET_DESC', 'Міжпланетні ракети знищують ворожу оборону.', 0),
(5254, 4, 4, 'INTERPLANETARY_ROCKET_FULL_DESC', 'Міжпланетні ракети знищують захист супротивника. Знищені міжпланетними ракетами оборонні споруди більше не відновлюються.', 0),
(5255, 4, 4, 'ION_GUN', 'Іонне знаряддя', 0),
(5256, 4, 4, 'ION_GUN_DESC', 'Іонне знаряддя направляє на ціль хвилю іонів, яка дестабілізує щити і ушкоджує електроніку.', 0),
(5257, 4, 4, 'ION_GUN_FULL_DESC', 'У 21-му столітті на Землі вже існувало те, що загальновідомо як ЕМІ. ЕМІ означає електромагнітний імпульс, який має здатність індукувати додаткові напруги в схеми і тим самим завдавати масові перешкоди, які можуть знищити всі чутливі прилади. Тоді ЕМІ-знаряддя були в основному на базі ракет і бомб, також у комбінації з ядерними знаряддями. Між тим ЕМІ-знаряддя постійно розвивалися, так як в них бачили великий потенціал не знищувати цілі, а робити їх нездатними до бою і маневреності і, тим самим, спрощувати їх захоплення. Поки що найвища форма ЕМІ-знарядь представлена ??іонним знаряддям. Воно направляє на ціль хвилю іонів (електрично заряджених частинок), яка дестабілізує щити і ушкоджує електроніку, тільки якщо вона не дуже добре захищена, що іноді подібно повного знищення. Кінетичної пробивний силою можна знехтувати. Іонна техніка використовується тільки на крейсерах, так як споживання енергії іонними знаряддями величезна, і в бою часто доводиться знищувати, а не паралізувати мету. Оборонні споруди деактивуються самі по собі, як тільки вони сильно пошкоджуються.', 0),
(5258, 4, 4, 'ION_TECH', 'Іонні акумулятори', 0),
(5259, 4, 4, 'ION_TECH_DESC', 'Воістину смертоносний наводяться промінь з прискорених іонів. При попаданні на який-небудь об&#39;єкт вони завдають величезної шкоди.', 0),
(5260, 4, 4, 'ION_TECH_FULL_DESC', 'Воістину смертоносний наводяться промінь з прискорених іонів. При попаданні на який-небудь об&#39;єкт вони завдають величезної шкоди.', 0),
(5261, 4, 4, 'LARGE_SHIELD', 'Великий щитової купол', 0),
(5264, 4, 4, 'LARGE_TRANSPORTER', 'Великий транспорт', 0),
(5265, 4, 4, 'LARGE_TRANSPORTER_DESC', 'Подальший розвиток малих транспортів дозволило створити кораблі, що володіють більшою місткістю і, завдяки більш розвиненому двигуну, здатними пересуватися швидше, ніж малий транспорт.', 0),
(5266, 4, 4, 'LARGE_TRANSPORTER_FULL_DESC', 'На борту цього корабля є лише слабке озброєння і немає серйозних технологій ... З цієї причини їх ніколи не слід запускати без супроводу. Завдяки своєму високорозвиненому реактивному двигуну великий транспорт служить в якості швидкого міжпланетного постачальник ресурсів, також він супроводжує флоти при нападах на ворожі планети, щоб захопити якомога більше ресурсів.', 0),
(5267, 4, 4, 'LASER_TECH', 'Лазерна технологія', 0),
(5268, 4, 4, 'LASER_TECH_DESC', 'Завдяки фокусуванню світла виникає промінь, який при потраплянні на об&#39;єкт завдає йому ушкодження.', 0),
(5269, 4, 4, 'LASER_TECH_FULL_DESC', 'Лазери (посилення світла за допомогою індукованого випромінювання викиду) виробляють насичений енергетичний промінь когерентного світла. Ці прилади знаходять застосування у всіляких областях, від оптичних комп&#39;ютерів до важких лазерів, які вільно ріжуть броню космічних кораблів. Лазерна технологія є важливим елементом для дослідження подальших збройових технологій.', 0),
(5270, 4, 4, 'LIGHT_FIGHTER', 'Легкий винищувач', 0),
(5271, 4, 4, 'LIGHT_FIGHTER_DESC', 'Легкий винищувач - це маневрений корабель, який можна знайти майже на кожній планеті. Витрати на нього не особливо великі, головне призначення - підтримка в битві для великих кораблів.', 0),
(5272, 4, 4, 'LIGHT_FIGHTER_FULL_DESC', 'Легкий винищувач - це маневрений корабель, який можна знайти майже на кожній планеті. Він має слабкий захист і прості системи озброєння і служить як атакуючого корабля підтримки. Його швидкість в поєднанні з великою кількістю, можуть забезпечити чудову буферну зону і захист для більш великих кораблів.', 0),
(5273, 4, 4, 'LIGHT_LASER', 'Легкий лазер', 0),
(5274, 4, 4, 'LIGHT_LASER_DESC', 'За допомогою концентрованого обстрілу мети фотонами можна досягти значно більших руйнувань, ніж при застосуванні звичайного балістичного озброєння.', 0),
(5275, 4, 4, 'LIGHT_LASER_FULL_DESC', 'Для компенсації надмірних успіхів у галузі технології космічних кораблів, вчені повинні були створити оборонну споруду, справляється з більшими і краще озброєними флотами. Це призвело до появи легкого лазера. За допомогою концентрованого обстрілу мети фотонами можна досягти значно більших руйнувань, ніж при застосуванні звичайного балістичного озброєння. Для протистояння сильнішою вогневої потужності нових типів кораблів він також оснащений вдосконаленими щитами. Однак, щоб вартість виробництва залишалася низькою, структура далі не посилювалася. Легкий лазер володіє найкращим співвідношенням ціни і якості, тому він також цікавий і для більш розвинених цивілізацій. Оборонні споруди деактивуються самі по собі, як тільки вони сильно пошкоджуються.', 0),
(5276, 4, 4, 'METALMINE', 'Рудник з видобутку металу', 0),
(5277, 4, 4, 'METALMINE_FULL_DESC', 'Основний постачальник сировини для будівництва несучих структур будівель і кораблів. Метал - найдешевша сировина, але зате його потрібно більше, ніж усього іншого. Для виробництва металу потрібно найменше енергії. Чим рудники більше, тим вони глибше. На більшості планет метал знаходиться на великих глибинах, за допомогою цих більш глибоких рудників можна видобувати більше металів, виробництво зростає. У той же час більш великі рудники вимагають більше енергії.', 0),
(5278, 4, 4, 'METAL_STORAGE', 'Сховище металу', 0),
(5279, 4, 4, 'METAL_STORAGE_FULL_DESC', 'Величезне сховище для видобутих руд. Чим воно більше, тим більше металу можна в ньому зберігати. Якщо воно заповнене, то видобуток металу припиняється.', 0),
(5280, 4, 4, 'MOON_BASE', 'Місячна база', 0),
(5281, 4, 4, 'MOON_BASE_DESC', 'Місяць не має атмосферою, тому перед заселенням потрібно спорудити місячну базу.', 0),
(5282, 4, 4, 'MOON_BASE_FULL_DESC', 'Місяць не має атмосферою, тому перед заселенням потрібно спорудити місячну базу. Вона забезпечує необхідні повітря, гравітацію і тепло. Чим вище рівень розвитку місячної бази, тим більше забезпечена біосферою площу. Кожен рівень місячної бази може забудувати 3 поля, максимум до площі всієї місяця. Вона становить 2 (діаметр луни/1000) ^ 2, причому кожний рівень місячної бази сам займає одне поле.', 0),
(5283, 4, 4, 'NANO_FACTORY', 'Фабрика нанітов', 0),
(5284, 4, 4, 'NANO_FACTORY_FULL_DESC', 'Фабрика нанітов являє собою вінець робототехніки. Наніти - це роботи розміром в нанометр, які шляхом об&#39;єднання в мережу в змозі виконувати екстраординарні завдання. Відразу ж після дослідження вони збільшують продуктивність майже у всіх областях. З кожним рівнем фабрика нанітов скорочує час будівництва будівель, кораблів і оборонних споруд вдвічі.', 0),
(5285, 4, 4, 'PLASMA_GUN', 'Плазмове знаряддя', 0),
(5286, 4, 4, 'PLASMA_GUN_DESC', 'Лазерна технологія була доведена до досконалості, іонна техніка досягла кінцевої стадії.', 0),
(5287, 4, 4, 'PLASMA_GUN_FULL_DESC', 'Лазерна технологія була доведена до досконалості, іонна техніка досягла кінцевої стадії і вважалося, що практично неможливо, навіть з якісної точки зору гарматної системи, досягти ще більшої ефективності. Але все повинно було змінитися, коли з&#39;явилася ідея об&#39;єднати обидві системи. Використовуючи технології термоядерного синтезу, лазерами нагрівають речовина (зазвичай водень) до надвисоких температур, що досягають мільйонів градусів. Іонна техніка забезпечує збагачення плазми електричним зарядом, її стабілізацію і прискорення. Як тільки заряд досить нагрітий, іонізоване і знаходиться під тиском, то його випускають за допомогою прискорювачів в напрямку мети. Світловий голубуватим кольором плазмовий куля виглядає переконливо, тільки питається, чи довго їм буде насолоджуватися команда корабля-мети, якщо через кілька секунд броня розірветься на шматки, а електроніка згорить ... Плазмове знаряддя вважається взагалі найстрашнішою зброєю, і в цієї техніки є своя ціна. Оборонні споруди деактивуються самі по собі, як тільки вони сильно пошкоджуються.', 0),
(5288, 4, 4, 'PLASMA_TECH', 'Плазмова технологія', 0),
(5289, 4, 4, 'PLASMA_TECH_DESC', 'Подальший розвиток іонної технології, яка прискорює не іони, а високоенергетичну плазму. Вона надає спустошливе дію при попаданні на який-небудь об&#39;єкт.', 0),
(5290, 4, 4, 'PLASMA_TECH_FULL_DESC', 'Подальший розвиток іонної технології, яка прискорює не іони, а високоенергетичну плазму. Вона надає спустошливе дію при попаданні на який-небудь об&#39;єкт.', 0),
(5291, 4, 4, 'PRODUCTION_TIME', 'Потрібно часу:', 0),
(5292, 4, 4, 'RECYCLER', 'Переробник', 0),
(5293, 4, 4, 'RECYCLER_DESC', 'За допомогою переробника видобувається сировина з уламків.', 0),
(5294, 4, 4, 'RECYCLER_FULL_DESC', 'Космічні бої брали все більших масштабів. Знищувалися тисячі кораблів і виникали при цьому уламки здавалися назавжди втраченими. Нормальні транспорти не могли близько до них наблизитися, не будучи сильно пошкодженими маленькими уламками. З новим відкриттям в області щитової технології стало можливо ефективно усувати цю проблему, виник новий клас корабля, подібний великим транспорту - переробник. З його допомогою можна було заново використовувати здавалися втраченими ресурси. Через нові щитів маленькі уламки більше не являли собою небезпеки. На жаль, ці пристрої вимагають простору, тому його вантажного тоннаж обмежений до 20 000.', 0),
(5295, 4, 4, 'REQUIRES', 'Потрібен', 0),
(5296, 4, 4, 'RESEARCH_LAB', 'Дослідницька лабораторія', 0),
(5297, 4, 4, 'RESEARCH_LAB_FULL_DESC', 'Для дослідження нових технологій необхідна робота дослідницької станції. Рівень розвитку дослідницької станції є вирішальним фактором того, як швидко можуть бути освоєні нові технології. Чим вище рівень розвитку дослідницької лабораторії, тим більше може бути досліджено нових технологій. Для того, щоб якомога швидше завершити дослідницькі роботи на одній планеті, на неї посилаються всі наявні вчені і, таким чином, покидають свої планети. Як тільки технологія досліджена, вчені повертаються на свої рідні планети і переносять з собою знання про неї. Так нові технології можна застосовувати і на інших планетах.', 0),
(5298, 4, 4, 'RESEARCH_LAB_REQUIRED', 'Необхідно побудувати дослідну лабораторію.', 0),
(5299, 4, 4, 'ROBOTIC_FACTORY', 'Фабрика роботів', 0),
(5300, 4, 4, 'ROBOTIC_FACTORY_FULL_DESC', 'Надає просту робочу силу, яку можна застосовувати при будівництві планетарної інфраструктури. Кожен рівень розвитку фабрики підвищує швидкість будівництва будівель.', 0),
(5301, 4, 4, 'ROCKET_LAUNCHER', 'Ракетна установка', 0),
(5302, 4, 4, 'ROCKET_LAUNCHER_DESC', 'Ракетна установка - просте і дешевий засіб оборони.', 0),
(5303, 4, 4, 'ROCKET_LAUNCHER_FULL_DESC', 'Ракетна установка - просте і дешевий засіб оборони. Так як це розвиток звичайних балістичних знарядь, то йому не потрібно подальшої модернізації. Малі витрати на його виробництво виправдовують його застосування проти більш маленьких флотів, але з часом він втрачає значення. Пізніше його використовують лише для відводу ворожих пострілів. Оборонні споруди деактивуються самі по собі, як тільки вони сильно пошкоджуються.', 0),
(5304, 4, 4, 'ROCKET_STATION', 'Ракетна шахта', 0),
(5305, 4, 4, 'ROCKET_STATION_DESC', 'Служить для зберігання ракет.', 0),
(5306, 4, 4, 'ROCKET_STATION_FULL_DESC', 'Ракетні шахти служать для зберігання ракет. З кожним рівнем можна зберігати на п&#39;ять міжпланетних або десять ракет-перехоплювачів більше. Одна міжпланетна ракета вимагає місця в два рази більше, ніж ракета-перехоплювач. Можливо будь комбінування різних типів ракет.', 0),
(5307, 4, 4, 'SHELL_TECH', 'Броньова технологія', 0),
(5308, 4, 4, 'SHELL_TECH_DESC', 'Спеціальні сплави покращують броню космічних кораблів. Так, стійкість броні може збільшуватися з кожним рівнем на 10%.', 0),
(5309, 4, 4, 'SHELL_TECH_FULL_DESC', 'Спеціальні сплави покращують броню космічних кораблів. Як тільки знайдений дуже стійкий сплав, спеціальні промені змінюють молекулярну структуру космічного корабля, і доводить її до стану вивченого сплаву. Так, стійкість броні може збільшуватися з кожним рівнем на 10%.', 0),
(5310, 4, 4, 'SHIELD_TECH', 'Щитова технологія', 0),
(5311, 4, 4, 'SHIELD_TECH_DESC', 'Ця технологія робить щити кораблів і оборонних споруд ефективніше. Кожен рівень підвищує ефективність щитів на 10% від основної потужності. З кожним рівнем можна будувати більше захисних куполів.', 0),
(5312, 4, 4, 'SHIELD_TECH_FULL_DESC', 'Розвиток цієї технології дозволяє збільшувати постачання енергією щитів і захисних екранів, що в свою чергу підвищує їх стійкість і здатність поглинати або відображати енергію атак противника. Завдяки цьому з кожним вивченим рівнем ефективність корабельних щитів і стаціонарних генераторів енергополе підвищується на 10% від номінальної потужності. Крім цього, з кожним рівнем можна будувати в обороні більше захисних куполів. Кожен рівень дозволяє побудувати один великий щитової купол або два малих. Можливо будь комбінування щитових куполів.', 0),
(5313, 4, 4, 'SHIPYARD', 'Верф', 0),
(5314, 4, 4, 'SHIPYARD_FULL_DESC', 'У будівельній верфі виробляються всі види кораблів. Чим вона більша, тим швидше можна будувати більш складні і більш великі кораблі. Крім цього кожен рівень Верфі збільшує на 1% силу атаки і на 0,1 рівня балістику кораблів, відправлених в атаку з даної планети.', 0),
(5315, 4, 4, 'SHIPYARD_REQUIRED', 'Необхідно побудувати верф.', 0),
(5316, 4, 4, 'SILICON_LAB', 'Рудник з видобутку кремнію', 0),
(5317, 4, 4, 'SILICON_LAB_FULL_DESC', 'Основний постачальник сировини для електронних будівельних елементів і сплавів. Для видобутку кремнію потрібно приблизно вдвічі більше енергії, ніж для видобутку металу, тому він, відповідно, цінується більше. Кремній потрібно для всіх кораблів і будівель. На жаль, такі необхідні для будівництва та досліджень, родовища кремнію зазвичай дуже рідкісні і, як і більшість металів, залягають на великих глибинах. Тому при удосконаленні рудника також підвищується виробництво, так як освоюються більші і чисті поклади кремнію.', 0),
(5318, 4, 4, 'SILICON_STORAGE', 'Сховище кремнію', 0),
(5319, 4, 4, 'SILICON_STORAGE_FULL_DESC', 'У цьому величезному сховищі складується ще не оброблений кремній. Чим більше сховище, тим більше кремнію туди поміщається. Якщо воно заповнене, то видобуток даного ресурсу припиняється.', 0),
(5320, 4, 4, 'SMALL_SHIELD', 'Малий щитової купол', 0),
(5323, 4, 4, 'SMALL_TRANSPORTER', 'Малий транспорт', 0),
(5324, 4, 4, 'SMALL_TRANSPORTER_DESC', 'Малий транспорт - це маневрений корабель, який може швидко транспортувати сировину на інші планети.', 0),
(5325, 4, 4, 'SMALL_TRANSPORTER_FULL_DESC', 'Перевезення мають приблизно такий же розмір, що і винищувачі, але вони не мають потужними двигунами та бортовим озброєнням заради економії місця. Малий транспорт вміщує 5000 одиниць сировини. Унаслідок малої вогневої мощі малі транспорти часто супроводжуються іншими кораблямі.Когда імпульсний двигун досліджений до 5-го ступеня, у малого транспорту підвищується базова швидкість і він оснащується цим типом двигуна.', 0),
(5326, 4, 4, 'SOLAR_PLANT', 'Сонячна електростанція', 0),
(5327, 4, 4, 'SOLAR_PLANT_FULL_DESC', 'Для забезпечення енергією рудників і синтезаторів необхідні величезні сонячні електростанції. Чим більше побудовано станцій, тим більше поверхні покрито кварцовими пластинами, які переробляють світлову енергію в електроенергію. Сонячні електростанції являють собою основу енергозабезпечення планети.', 0),
(5328, 4, 4, 'SOLAR_SATELLITE', 'Сонячний супутник', 0),
(5329, 4, 4, 'SOLAR_SATELLITE_DESC', 'Сонячні супутники - це прості платформи з сонячних батарей, які знаходяться на високій орбіті. Вони збирають сонячне світло і передають його за допомогою лазера на наземну станцію.', 0),
(5330, 4, 4, 'SOLAR_SATELLITE_FULL_DESC', 'Сонячні супутники запускаються на орбіту планети. Вони збирають сонячну енергію і передають її на наземну станцію. Ефективність сонячних супутників залежить від потужності сонячного випромінювання. В принципі, видобуток енергії на орбітах, більш наближених до сонця, вище, ніж на планетах, віддалених від сонця. Через свій співвідношення ціни і якості сонячні супутники вирішують енергетичні проблеми багатьох світів. Але увага: сонячні супутники можуть бути знищені в бою.', 0),
(5331, 4, 4, 'SPYWARE', 'Шпигунство', 0),
(5332, 4, 4, 'SPYWARE_DESC', 'За допомогою цієї технології видобуваються дані про інші планети.', 0),
(5333, 4, 4, 'SPYWARE_FULL_DESC', 'Шпигунство призначений для дослідження нових і більш ефективних сенсорів. Чим вище розвинута ця технологія, тим більше інформації має гравець про події в своєму оточенні. Різниця в рівнях шпигунства з противником грає вирішальну роль - чим більше досліджена власна шпигунська технологія, тим більше інформації міститься в розвідданих і тим менше шанс бути виявленим. Чим більше послано зондів, тим більше збирається подробиць про супротивника, але при цьому зростає небезпека бути виявленим. Також шпигунство вдосконалює визначення місцезнаходження чужих флотів. При цьому також важливий рівень розвитку власного шпигунства. Починаючи з другого рівня його розвитку при атаці на Вас крім повідомлення про напад показується також і загальна чисельність нападаючих кораблів. З четвертого рівня розпізнається вид нападників кораблів, так само як і їх загальна чисельність, а з восьмого - точна чисельність кожного типу кораблів. Для нальотчиків ця технологія дуже важлива, оскільки вона надає інформацію про те, виставила чи жертва флот і / або захист чи ні, тому слід дослідити її якомога раніше. Найкраще - відразу ж після дослідження малих транспортів.', 0),
(5334, 4, 4, 'STAR_DESTROYER', 'Знищувач', 0),
(5335, 4, 4, 'STAR_DESTROYER_DESC', 'Знищувач - король серед військових кораблів.', 0),
(5336, 4, 4, 'STAR_DESTROYER_FULL_DESC', 'Знищувач - король серед військових кораблів. Його мультіфланговие іонні, плазмові й гауссових гарматні башти можуть завдяки своїм вдосконаленим пеленгаційної сенсорам вражати з точністю до 99% навіть швидкісні маневрені винищувачі. Так як знищувачі дуже великі, їх маневреність дуже обмежена, і в бою вони подібні швидше бойової станції, ніж бойовому кораблю. Споживання водню у них так само високо, як і їх бойова міць.', 0),
(5337, 4, 4, 'STAR_GATE', 'Міжгалактичні врата', 0),
(5338, 4, 4, 'STAR_GATE_DESC', 'Ворота - це величезні телепортери, які можуть пересилати між собою флоти будь-яких розмірів без тимчасових витрат.', 0);
INSERT INTO `na_phrases` (`phraseid`, `languageid`, `phrasegroupid`, `title`, `content`, `translated`) VALUES
(5339, 4, 4, 'STAR_GATE_FULL_DESC', 'Ворота - це величезні телепортери, які можуть пересилати між собою флоти будь-яких розмірів без тимчасових витрат. Ці телепортери не вимагають водню, проте між двома стрибками повинен пройти одну годину, інакше ворота перегріються. Неможлива також пересилання ресурсів. Весь процес вимагає вкрай високо розвиненою технології. Виробництво показує кількість секунд, потрібних для перезарядки врат.', 0),
(5340, 4, 4, 'STAR_SURVEILLANCE', 'Сенсорна фаланга', 0),
(5341, 4, 4, 'STAR_SURVEILLANCE_DESC', 'Високочастотні сенсори повністю переглядають спектр частот всіх потрапляють на фалангу випромінювань.', 0),
(5342, 4, 4, 'STAR_SURVEILLANCE_FULL_DESC', 'Високочастотні сенсори повністю переглядають спектр частот всіх потрапляють на фалангу випромінювань. Потужні комп&#39;ютери комбінують найдрібніші коливання енергії і таким чином отримують інформацію про пересування кораблів на віддалених планетах. Для перегляду на місяці повинна бути надана енергія у формі водню (5 000 за перегляд). Перегляд здійснюється переходом з місяця в меню Галактика і натисканням на відповідну іконку в меню Дія планети, що знаходиться в радіусі дії сенсорів.', 0),
(5343, 4, 4, 'STORAGE_CAPICITY', 'Місткість', 0),
(5344, 4, 4, 'STRONG_FIGHTER', 'Важкий винищувач', 0),
(5345, 4, 4, 'STRONG_FIGHTER_DESC', 'Подальший розвиток легкого винищувача, він краще захищений і має більшу силу атаки.', 0),
(5346, 4, 4, 'STRONG_FIGHTER_FULL_DESC', 'При подальшому розвитку легкого винищувача вчені дійшли до моменту, коли стало ясно, що звичайний двигун не володіє необхідною потужністю. Для того, щоб оптимально пересувати корабель, був вперше використаний імпульсний двигун. Хоч він і підвищив вартість, проте він також відкрив нові можливості. Завдяки застосуванню цього двигуна залишилося більше енергії для озброєння і щитів, крім того, для цього виду винищувачів також використовувалися цінні матеріали. Це призвело до поліпшеної структурної цілісності і сильнішою вогневої потужності, завдяки чому в бою він представляє більшу загрозу, ніж його попередник. Після цих змін важкий винищувач являє собою нову еру технології кораблебудування, основу технології крейсеростроенія.', 0),
(5347, 4, 4, 'STRONG_LASER', 'Важкий лазер', 0),
(5348, 4, 4, 'STRONG_LASER_DESC', 'Важкий лазер є подальшим розвитком легкого лазера.', 0),
(5349, 4, 4, 'STRONG_LASER_FULL_DESC', 'Важкий лазер являє собою подальший розвиток легкого лазера. Структура була посилена і вдосконалена новими матеріалами. Оболонку змогли зробити значно більш стійкою. Одночасно була поліпшена і енергетична система і цільовий комп&#39;ютер, так що важкий лазер може концентрувати значно більше енергії на цілі. Оборонні споруди деактивуються самі по собі, як тільки вони сильно пошкоджуються.', 0),
(5350, 4, 4, 'TERRA_FORMER', 'Терраформер', 0),
(5351, 4, 4, 'TERRA_FORMER_DESC', 'Терраформер може перетворювати величезні території роблячи їх придатними для забудови.', 0),
(5352, 4, 4, 'TERRA_FORMER_FULL_DESC', 'У міру забудови планет все більш важливим ставав питання про обмеженість придатних для використання площ. Такі традиційні методи, як будівництво увись і углиб, виявилися недостатніми. Маленька група фізиків і нанотехніки знайшла рішення - Терраформер. Витрачаючи величезна кількість енергії Терраформер може перетворювати величезні території і навіть цілі континенти, роблячи їх придатними для забудови. У цій будівлі безперервно проводяться спеціальні наніти, що відповідають за постійну якість грунту.', 0),
(5353, 4, 5, 'ALREADY_BUILDED', 'Вже побудовано', 0),
(5354, 4, 5, 'BUILD', 'Побудувати', 0),
(5355, 4, 5, 'BUILDING_AT_WORK', 'Зайнято', 0),
(5356, 4, 5, 'CONSTRUCTION', 'Будівлі', 0),
(5357, 4, 5, 'CONSTRUCTIONS', 'Будинки', 0),
(5358, 4, 5, 'CURRENTLY_IN_WORK', 'Поточне завдання:', 0),
(5359, 4, 5, 'DEFENSE', 'Оборона', 0),
(5360, 4, 5, 'HYDROGEN_LAB_DESC', 'Витягує з води на планеті незначну частку водню.', 0),
(5361, 4, 5, 'HYDROGEN_PLANT_DESC', 'Видобуває енергію з процесу утворення атома гелію двома атомами важкого водню.', 0),
(5362, 4, 5, 'HYDROGEN_STORAGE_DESC', 'Величезні ємності для сбереганія видобутого водню.', 0),
(5363, 4, 5, 'METALMINE_DESC', 'Основний постачальник сировини для будівництва несучих структур будівель і кораблів.', 0),
(5364, 4, 5, 'METAL_STORAGE_DESC', 'Сховище для необроблених руд металів до їх подальшої переробки.', 0),
(5365, 4, 5, 'MOON_BUILDING', 'Особливі споруди', 0),
(5366, 4, 5, 'NANO_FACTORY_DESC', 'Фабрика нанітов виробляє спеціальних еволюціонували роботів - нанітов. Наніти - це роботи, які шляхом об&#39;єднання в змозі виконувати екстраординарні завдання.', 0),
(5367, 4, 5, 'OUTSTANDING_MISSIONS', 'Черга споруди', 0),
(5368, 4, 5, 'QUANTITY', 'Число', 0),
(5369, 4, 5, 'REQUIREMENTS', 'Вимоги', 0),
(5370, 4, 5, 'RESEARCH', 'Дослідження', 0),
(5371, 4, 5, 'RESEARCH_LAB_DESC', 'Необхідна для дослідження нових технологій.', 0),
(5372, 4, 5, 'RESEARCH_OF_LEVEL', 'Дослідити рівень', 0),
(5373, 4, 5, 'ROBOTIC_FACTORY_DESC', 'Надає просту робочу силу, яку можна застосовувати при будівництві планетарної інфраструктури. Кожен рівень розвитку фабрики підвищує швидкість будівництва будівель.', 0),
(5374, 4, 5, 'ROCKET_STATION_FULL', 'Шахта заповнена', 0),
(5375, 4, 5, 'SHIPS_EXIST', 'в наявності %s', 0),
(5376, 4, 5, 'SHIPYARD_DESC', 'У будівельній верфі виробляються всі види кораблів. Крім цього Верф збільшує силу атаки і балістику атакуючих кораблів.', 0),
(5377, 4, 5, 'SHIP_CONSTRUCTION', 'Верф', 0),
(5378, 4, 5, 'SILICON_LAB_DESC', 'Основний постачальник сировини для електронних будівельних елементів і сплавів.', 0),
(5379, 4, 5, 'SILICON_STORAGE_DESC', 'Сховище для обробленого кремнію.', 0),
(5380, 4, 5, 'SOLAR_PLANT_DESC', 'Виробляє енергію з сонячних променів. Енергія потрібна для роботи більшості будівель.', 0),
(5381, 4, 5, 'UPGRADE_TO_LEVEL', 'Побудувати рівень', 0),
(5382, 4, 6, 'CAPACITY', 'Місткість', 0),
(5383, 4, 6, 'CONSUME', 'Споживає', 0),
(5384, 4, 6, 'DAILY_PRDOUCTION', 'За день', 0),
(5385, 4, 6, 'DIFFERENCE', 'Різниця', 0),
(5386, 4, 6, 'MONTHLY_PRDOUCTION', 'За місяць', 0),
(5387, 4, 6, 'PRODUCTION', 'Виробництво', 0),
(5388, 4, 6, 'PROD_ONE_SOLAR_SATELLITE', 'Один супутник видобуває: {@prodPerSat} енергії', 0),
(5389, 4, 6, 'RESOURCE_PRODUCTION_FOR_PLANET', 'Виробництво ресурсів на планеті:', 0),
(5390, 4, 6, 'SHUT_DOWN', 'Вимкнути', 0),
(5391, 4, 6, 'START_UP', 'Включити', 0),
(5392, 4, 6, 'SUM', 'Усього', 0),
(5393, 4, 6, 'WEEKLY_PRDOUCTION', 'За тиждень', 0),
(5394, 4, 7, 'ACCEPT_AGB', 'Входячи, Ви автоматично погоджуєтесь з правилами.', 0),
(5395, 4, 7, 'AGB', 'Політика / Правила', 0),
(5396, 4, 7, 'BOARD', 'Форум', 0),
(5397, 4, 7, 'BOARD_DESC', 'Тут можна отримати відповіді на всі виниклі питання.', 0),
(5398, 4, 7, 'CHANGE_PASSWORD', 'Змінити пароль', 0),
(5399, 4, 7, 'DISCLAIMER', 'Вихідні', 0),
(5400, 4, 7, 'EMAIL_CHECK', 'Будь ласка, введіть адресу електронної пошти.', 0),
(5401, 4, 7, 'EMAIL_EXISTS', 'Такий E-Mail вже зареєстрований.', 0),
(5402, 4, 7, 'EMAIL_INVALID', 'Адреса електронної пошти є недійсним.', 0),
(5403, 4, 7, 'EMAIL_NOT_FOUND', 'Введений e-mail не існує.', 0),
(5404, 4, 7, 'ERROR_PASSWORD_CHANGED', 'Введено неправильні дані. Пароль не може бути змінений.', 0),
(5405, 4, 7, 'FORGOTTEN', 'забули?', 0),
(5407, 4, 7, 'INFOS_HELP', 'Допомога', 0),
(5408, 4, 7, 'LOGIN', 'Увійти', 0),
(5409, 4, 7, 'LOST_PW_HINT_1', 'Вказівки', 0),
(5410, 4, 7, 'LOST_PW_HINT_2', 'Якщо Ви забули ім&#39;я користувача, введіть E-Mail. Якщо забули пароль, необхідно ввести ім&#39;я користувача і E-Mail.', 0),
(5411, 4, 7, 'LOST_PW_SUBJECT_1', '{config}pagetitle{/config}: Відновлення логіна.', 0),
(5412, 4, 7, 'LOST_PW_SUBJECT_2', '{config}pagetitle{/config}: Відновлення пароля.', 0),
(5413, 4, 7, 'MAXIMUM_LOGIN_ATTEMPTS_REACHED', 'Досягнуто максимальну кількість спроб входу.', 0),
(5414, 4, 7, 'NO_ACCESS', 'Неправильна сесія.', 0),
(5415, 4, 7, 'NO_ACTIVATION', 'Зазначений користувач ще не активовано.', 0),
(5416, 4, 7, 'OPEN_SOURCE', 'Open Source', 0),
(5417, 4, 7, 'PASSWORD_CHANGED', 'Пароль був успішно змінений', 0),
(5418, 4, 7, 'PASSWORD_CHECK', 'Пароль має бути від %d до %d символів.', 0),
(5419, 4, 7, 'PASSWORD_FORGOTTEN', 'Нагадати пароль', 0),
(5420, 4, 7, 'PASSWORD_INVALID', 'Невірний пароль.', 0),
(5421, 4, 7, 'PW_LOST_EMAIL_SUCCESS', 'Подальші інструкції Ви отримаєте електронною поштою.', 0),
(5422, 4, 7, 'REGISTRATION', 'Реєстрація', 0),
(5423, 4, 7, 'REGISTRATION_BANNED_FOR_IP', 'Ви тільки що зареєструвалися. Зачекайте {@minutes} хвилин і спробуйте знову.', 0),
(5424, 4, 7, 'REGISTRATION_MAIL', 'Дякуємо {@regUsername} за реєстрацію в {config}pagetitle{/config}! <br /> <br /> Ваш пароль: {@regPassword} <br /> <br /> Вам потрібно активувати обліковий запис. Перейдіть по посиланню нижче для підтвердження або скопіюйте її в адресну рядок Вашого браузера: <br /> <br /> {@activationLink} <br /> <br /> З повагою, <br /> команда {config}pagetitle{/config}', 0),
(5425, 4, 7, 'REQUEST_DATA', 'Надіслати', 0),
(5426, 4, 7, 'REQUEST_PASSWORD', 'Доброго дня, {@req_username}! <br /> <br /> Хтось, можливо Ви, на сайті {config}pagetitle{/config} запросив забутий пароль. Якщо Ви справді забули пароль, то для отримання нового натисніть на посилання нижче: <br /> <br /> {@new_pw_url} <br /> <br /> Якщо Ви не запитували пароля, ігноруйте цей лист. <br /> <br /> Запит був відправлений з IP-адреси {@req_ipaddress}. <br /> <br /> Щоб активувати обліковий запис без зміни пароля, натисніть на посилання нижче: <br /> <br /> {@reactivate_url} <br /> <br /> З повагою, <br /> Ваша команда {config}pagetitle{/config}', 0),
(5427, 4, 7, 'REQUEST_USERNAME', 'Доброго дня, {@req_username}! Хтось, можливо Ви, на сайті {config}pagetitle{/config} запросили забутий логін. Ваш Логін: {@req_username} Якщо Ви не забували свій логін, радимо Вам в налаштуваннях змінити адресу електронної пошти. Запит був відправлений з IP-адреси {@req_ipaddress}. З повагою, Ваша команда {config}pagetitle{/config}', 0),
(5428, 4, 7, 'RULES', 'Правила', 0),
(5429, 4, 7, 'SCREENSHOTS', 'Скріншоти', 0),
(5430, 4, 7, 'SCREENSHOT_GALAXY_BROWSER', 'Подання Галактики', 0),
(5431, 4, 7, 'SCREENSHOT_MAIN_PAGE', 'Домашнаяя сторінка', 0),
(5432, 4, 7, 'SIGN_IN', 'Увійти', 0),
(5433, 4, 7, 'SIGN_UP', 'Реєструватися', 0),
(5434, 4, 7, 'START_UP_MESSAGE', 'Ласкаво просимо в {config}pagetitle{/config}! {config}pagetitle{/config} - це багатокористувацька космічна онлайн гра. Всі гравці розвиваються в единной всесвіту. Тут можна запрошувати друзів і об&#39;єднувати свої зусилля в нападі на ворогів і оборони, використовувати унікальну систему бою і власний симулятор битв. Біржа дозволить вести торгівлю ресурсами, кораблями і артефактами з іншими гравцями, наукові дослідження відкриють нові технології і більш досконалі системи озброєння. Використовуючи безліч стратегій і тактик розвитку, ти зможеш розширювати свою імперію і посилювати вплив на інші галактики в ім&#39;я головної мети - стати господарем {config}pagetitle{/config}. Щоб розвиток імперії йшло повним ходом, лад шахти з видобутку ресурсів. Коли закінчується будівництво або накопичується потрібну кількість ресурсів, дію нові будівлі в меню <i> Будівлі </i>. Проте, не забувай про Енергію. Без Енергії жодна шахта не зможе видобувати ресурси. Система Досягнень допоможе тобі стати грозою {config}pagetitle{/config}. Йди її підказок і твоє розвиток піде по оптимальному шляху. Будь-які питання по грі можна обговорити на <i> Чаті </i>, не соромся, запитуй, там завжди готові прийти на допомогу. З повагою, твоя команда {config}pagetitle{/config}', 0),
(5435, 4, 7, 'START_UP_MESSAGE_SUBJECT', 'Ласкаво просимо, {@regUsername}!', 0),
(5436, 4, 7, 'SUCCESS_REGISTRATION', 'Ви успішно зареєструвалися у Всесвіті. Для того щоб почати грати, зайдіть в свою поштову скриньку, дочекайтеся отримання листа та дотримуйтесь інструкцій. Всесвіт чекає на тебе, поквапся!', 0),
