(5653, 4, 13, 'FLEET_RETURNED', 'Ваш флот (%s) повернувся з %s на %s %s. <br /> Флот привіз вантаж: %s металу, %s кремнію і %s водню.', 0),
(5654, 4, 13, 'FLEET_RETURNED_SUBJECT', 'Повернення флоту', 0),
(5655, 4, 13, 'MEMBER_RECEIPTED', 'Ваша заявка розглянута і прийнята. Ласкаво просимо до альянсу %s', 0),
(5656, 4, 13, 'MEMBER_REFUSED', 'На жаль, Ваша заявка на участь в альянсі [%s] відхилена. Ви можете пробувати знову або грати на самоті.', 0),
(5657, 4, 13, 'PLANET_COLONIZED', 'Колоністи виявили планету на координатах %s з умовами, придатними для життя і починають освоювати колонію.', 0),
(5658, 4, 13, 'PLANET_OCCUPIED', 'Ваш флот досяг координат %s, але ця планета вже зайнята. Колоністи повертаються на базу.', 0),
(5659, 4, 13, 'POSITION_REPORT', 'Ваш флот (%s) досяг планети %s %s. <br /> Флот залишив вантаж: %s металу, %s кремнію і %s водню.', 0),
(5660, 4, 13, 'POSITION_REPORT_SUBJECT', 'Швидке розміщення', 0),
(5661, 4, 13, 'RECYLCING_REPORT', 'Ваші %s переробників видобули %s ресурсів. На координатах було %s металу і %s кремнію. Ви здобули %s металу і %s кремнію.', 0),
(5662, 4, 13, 'RECYLCING_REPORT_SUBJECT', 'Поле уламків: %s', 0),
(5663, 4, 13, 'ROCKET_ATTACK_MSG_ATTACKER', 'Ракетна атака на планету {@planet} {@coords} завершилося успішно. Гравець {@defender} {позбувся 103} очок після атаки {@rockets} межпланетимі ракетами.', 0),
(5664, 4, 13, 'ROCKET_ATTACK_MSG_DEFENDER', 'Ваша планета {@planet} {@coords} була схильна ракетної атаки. Гравець {@attacker} атакував {@rockets} ракетами. Втрати складають {@lostunits} очок.', 0),
(5665, 4, 13, 'ROCKET_ATTACK_REPORT_HEADLINE', 'Ракетна атака на {@planet} {@coords}', 0),
(5666, 4, 13, 'ROCKET_ATTACK_SUBJECT', 'Ракетна атака', 0),
(5667, 4, 13, 'TOO_MANY_PLANETS', 'Ваш флот досяг координат %s, але при спробі колонізувати планету в сусідніх імперіях виникли невдоволення з приводу кількості Ваших колоній. Флот повертається назад.', 0),
