(5669, 4, 13, 'TRANSPORT_ACCOMPLISHED', 'Ваш флот досяг %s %s. <br /> Флот доставив вантаж: %s металу, %s кремнію і %s водню.', 0),
(5670, 4, 13, 'TRANSPORT_ACCOMPLISHED_OTHER', 'Чужий флот з %s %s від %s {досяг 103} %s. <br /> Флот доставив вантаж: %s металу, %s кремнію і %s водню.', 0),
