(7506, 4, 4, 'DEFENSE_FACTORY', 'Оборонний завод', 0),
(7507, 4, 4, 'DEFENSE_FACTORY_FULL_DESC', 'В оборонному заводі виробляються всі види оборонних споруд. Чим він більший, тим швидше можна будувати більш складні і більш великі оборонні споруди. Крім цього кожен рівень заводу збільшує на 1% силу щитів і на 0,1 рівні маскування юнітів, що виконують обороняли роль в битві.', 0),
(7508, 4, 4, 'DEFENSE_FACTORY_REQUIRED', 'Необхідно побудувати оборонний завод.', 0),
(7509, 4, 5, 'DEFENSE_FACTORY_DESC', 'В оборонному заводі виробляються всі види оборонних споруд. Крім цього оборонний завод збільшує силу щитів і маскування юнітів, що виконують обороняли роль в битві.', 0),
(7510, 4, 5, 'REPAIR_NOT_AVAILABLE', 'Технологія ремонту не відома', 0),
