(7549, 4, 18, 'UNIT_NOTHING_INFO', 'Потрапляння в знищені юніти, промахи і т.п.', 0),
(7550, 4, 1, 'MENU_DISASSEMBLE', 'Утилізація', 0),
(7551, 4, 4, 'QUEUE_REPAIR_PREFIX', 'Ремонт', 0),
(7552, 4, 4, 'QUEUE_DISASSEMBLE_PREFIX', 'Утилізація', 0),
(7553, 4, 5, 'DISASSEMBLE', 'Утилізувати', 0),
(7554, 4, 4, 'LANCER_SHIP', 'Лансер', 0),
(7555, 4, 4, 'LANCER_SHIP_DESC', 'Швидкий і ефективний військовий корабель, побудований на найсучасніших технологіях. Оснащений наймогутнішим озброєнням для нанесення катастрофічних руйнувань противнику.', 0),
(7556, 4, 4, 'LANCER_SHIP_FULL_DESC', 'Швидкий і ефективний військовий корабель, побудований на найсучасніших технологіях. Оснащений наймогутнішим озброєнням, яке здатне завдавати катастрофічні руйнування противнику. Для перезарядки енергетичної гармати корабля потрібен якийсь час, тому корабель має погану скорострільністю. Корабель спроектований вченими, як допоміжний зброю при нанесенні масштабного удару ворогу, тому найбільш ефективний у поєднанні з рештою флотом.', 0),
(7557, 4, 17, 'FRONT', 'Фронт', 0),
(7558, 4, 18, 'FRONT', 'Фронт', 0),
(7559, 4, 18, 'ATTACKER_LOST_RES', 'Втрати атакуючого: %s (%s металу, %s кремнію).', 0),
(7560, 4, 18, 'DEFENDER_LOST_RES', 'Втрати обороняється: %s (%s металу, %s кремнію).', 0),
(7561, 4, 18, 'ATTACKER_LOST_RES_4', 'Втрати атакуючого: %s (%s металу, %s кремнію, %s водню).', 0),
(7562, 4, 18, 'DEFENDER_LOST_RES_4', 'Втрати обороняється: %s (%s металу, %s кремнію, %s водню).', 0),
(7563, 4, 18, 'HIDE_BATTLE_TEXT', 'Інформація не доступна для перегляду.', 0),
(7564, 4, 18, 'ROCKET_ATTACK_TIME', 'Ракетна атака в %s годин:', 0),
(7565, 4, 11, 'ROCKET_ATTACK_REPORT', 'Звіт про ракетну атаку', 0),
(7566, 4, 11, 'ASSAULT_REPORT_TURNS', 'Раундів', 0),
(7567, 4, 12, 'BS_USER_FILTER', 'Ім&#39;я гравця', 0),
(7568, 4, 12, 'BS_USER_FILTER_INFO', '', 0),
(7569, 4, 6, 'DAILY_PRODUCTION', 'За день', 0),
(7570, 4, 6, 'MONTHLY_PRODUCTION', 'За місяць', 0),
(7571, 4, 6, 'WEEKLY_PRODUCTION', 'За тиждень', 0),
(7572, 4, 1, 'PREV', 'Перед.', 0),
(7573, 4, 1, 'NEXT', 'Наст.', 0),
(7574, 4, 1, 'RELATED_MSG', 'Повідомлення, пов&#39;язані з цим гравцем.', 0),
(7575, 4, 13, 'EXPEDITION_XSKIRMISH', 'Під час експедиції Ваші кораблі наткнулися на інопланетний флот, що з&#39;явився з нізвідки. Невідома цивілізація виявилася ворожа, зав&#39;язалася битва. Дивіться звіт про битву в розділі &#39;Бойові звіти&#39;.', 0),
(7576, 4, 13, 'EXPEDITION_RESOURCE_DISCOVERY_1', 'Ваші дослідники виявили старі і не робочі кораблі, що дрейфують у космосі. Командування розпорядилося забрати наявні в трюмах ресурси: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.', 0),
(7577, 4, 13, 'EXPEDITION_SHIPS_DISCOVERY', 'Ваші дослідники виявили дрейфує у відкритому космосі флот, який опинився в стані консервації. Командування розпорядилося привести знайдені кораблі на базу: {@new_ships}', 0),
(7578, 4, 13, 'EXPEDITION_NOTHING_1', 'Ваш флот довго борознив простори всесвіту, проте сенсори вчених так і не змогли зафіксувати нічого цікавого.', 0),
(7579, 4, 4, 'UNIT_A_CORVETTE', 'Корвет інопланетян', 0),
(7580, 4, 4, 'UNIT_A_SCREEN', 'Щитовий корабель інопланетян', 0),
(7581, 4, 13, 'EXPEDITION_BATTLEFIELD_DISCOVERY', 'Ваші дослідники виявили сліди давно відгриміла битви. Серед тонн понівеченого металу вдалося знайти кораблі, придатні для подальшого використання: {@new_ships}', 0),
(7582, 4, 13, 'EXPEDITION_NOTHING_2', 'Ваші дослідники пройшли повз Наднової зірки і зробили чудові фотографії. Більше нічого цікавого в обраному секторі вони не знайшли.', 0),
(7583, 4, 13, 'EXPEDITION_LOST_1', 'На жаль зв&#39;язок з експедицією була загублена.', 0),
(7584, 4, 4, 'UNIT_A_PALADIN', 'Паладин інопланетян', 0),
(7585, 4, 4, 'UNIT_A_FRIGATE', 'Фрегат інопланетян', 0),
(7586, 4, 4, 'UNIT_A_TORPEDOCARIER', 'Торпедоносець інопланетян', 0),
(7587, 4, 13, 'EXPEDITION_DELAY_RETURN', 'Ваші дослідники нічого не знайшли, до того ж вони заблукали. На пошук шляху додому знадобитися на {@percent}% більше часу.', 0),
(7588, 4, 13, 'EXPEDITION_FAST_RETURN_1', 'Ваші дослідники нічого не знайшли. На щастя, вони виявили по шляху стабільну чорну діру, прохід через яку дозволить їм скоротити зворотній шлях на {@percent}%', 0),
(7589, 4, 13, 'EXPEDITION_SENSOR_REPORT', 'Шпигунські зонди просканували шлейф луни темної матерії і виявили сліди {@visits} експедицій в секторі {@exp_sector}. Пошукова потужність експедиції склала {@exp_power}. Дослідники вивчали обраний сектор {@exp_hours} годин. Поточний результат експедиції стався з імовірністю {@exp_percent}%', 0),
(7590, 4, 1, 'RESEARCH_EXPO_TECH', 'Необхідно дослідити експедиційну технологію', 0),
(7591, 4, 1, 'TOO_MANY_EXPOS', 'Рівень експедиційної технології не дозволяє відправляти таку кількість експедицій.', 0),
(7592, 4, 13, 'EXPEDITION_SENSOR_CLEAR_REPORT', 'Шпигунські зонди просканували шлейф луни темної матерії і виявили, що сектор {@exp_sector} ніхто не відвідував в найближчі дні - це дуже добре! Дослідники радять Вам злітати в цей сектор ще кілька разів для більш ретельного його вивчення. Пошукова потужність експедиції склала {@exp_power}. Дослідники вивчали обраний сектор {@exp_hours} годин. Поточний результат експедиції стався з імовірністю {@exp_percent}%', 0),
(7593, 4, 10, 'EXPEDITION_TIME', 'Час на дослідження в експедиції', 0),
(7594, 4, 1, 'EXPEDITION', 'Експедиція', 0),
(7595, 4, 13, 'EXPEDITION_SUBJECT', 'Звіт експедиції', 0),
(7596, 4, 13, 'EXPEDITION_SENSOR_SUBJECT', 'Дані з разведзонда', 0),
(7597, 4, 1, 'SENDER', 'Відправник', 0),
(7598, 4, 1, 'RECIEVER', 'Одержувач', 0),
(7599, 4, 1, 'MENU_RESTRANSFERS', 'Надіслані ресурси', 0),
(7600, 4, 12, 'TRANSFERS_COUNT', 'Кількість розвантажень', 0),
(7601, 4, 12, 'TOTAL_RES_TRANSFER', 'Сума ресурсів', 0),
(7602, 4, 12, 'RT_GROUP_RECIEVER', 'Групувати по одержувачу', 0),
(7603, 4, 12, 'RT_GROUP_SENDER', 'Групувати по відправникові', 0),
(7604, 4, 12, 'RT_SEARCH_USER', 'Пошук по імені', 0),
(7605, 4, 13, 'EXPEDITION_FAST_RETURN_2', 'Ваші дослідники нічого не знайшли. На щастя, з корони найближчої зірки виходить потік сонячного вітру, який дозволить їм скоротити час зворотного шляху на {@percent}%', 0),
(7606, 4, 13, 'EXPEDITION_ASTEROID_DISCOVERY_NO_CARGO', 'Ваші дослідники знайшли астероїдне поле уламків: {@debrismetal} металу і {@debrissilicon} кремнію. На жаль в експедиції не було переробників, щоб зібрати ресурси з відкритого космосу.', 0),
(7607, 4, 13, 'EXPEDITION_ASTEROID_DISCOVERY_1', 'Ваші дослідники знайшли астероїдне поле уламків: {@debrismetal} металу і {@debrissilicon} кремнію. Переробники добули: {@metal} металу і {@silicon} кремнію.', 0),
(7608, 4, 13, 'EXPEDITION_RESOURCE_DISCOVERY_2', 'Відмінна новина: Ваші дослідники виявили нежилу планету з ресурсами: {@debrismetal} металу, {@debrissilicon} кремнію і {@debrishydrogen} водню. Флот забрав: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.', 0),
(7609, 4, 13, 'EXPEDITION_NOTHING_3', 'Ваші дослідники провели весь час, наданий на вивчення обраного сектора. Але вони не знайшли нічого цікавого.', 0),
(7610, 4, 13, 'EXPEDITION_NOTHING_4', 'Ваш флот виявив одну планету, привернула увагу! Дослідники знайшли на ній кумедних маленьких тваринок. Більше нічого виявлено не було.', 0),
(7611, 4, 13, 'EXPEDITION_NOTHING_5', 'Ваші дослідники запеленгували на шляху прямування флот величезних розмірів інопланетного походження. Командування прийняло рішення не ризикувати і повернутися на базу.', 0),
(7612, 4, 13, 'EXPEDITION_LOST_2', 'Зв&#39;язок з Вашими дослідниками втрачена. Швидше за все, вони більше не повернуться ...', 0),
(7613, 4, 13, 'EXPEDITION_NOTHING_7', 'Ваші дослідники пройшли мимо величезної туманності антиматерії. Більше нічого виявлено не було.', 0),
(7614, 4, 13, 'EXPEDITION_NOTHING_6', 'Ваші дослідники виявили на шляху прямування нестабільну чорну діру. Командування прийняло рішення не ризикувати і повернутися на базу.', 0),
(7615, 4, 13, 'EXPEDITION_ASTEROID_DISCOVERY_2', 'Ваші дослідники знайшли давно відгриміла поле битви. Від зруйнованих кораблів залишилися уламки, які можна зібрати: {@debrismetal} металу і {@debrissilicon} кремнію. Переробники добули: {@metal} металу і {@silicon} кремнію.', 0),
(7616, 4, 13, 'EXPEDITION_FAST_RETURN_3', 'Флот Вашої експедиції потрапив у поле дії величезного магнітного поля невідомого походження. На щастя, це дозволить їм скоротити час зворотного шляху на {@percent}%', 0),
(7617, 4, 13, 'RETREAT_OTHER', '{@username} скасував Утримання на {@planet_from} {@coords_from}. Ваш флот ({@fleet}) повертається на {@planet} {@coords}.', 0),
(7618, 4, 13, 'RETREAT_OTHER_SUBJECT', 'Скасування утримання', 0),
(7619, 4, 6, 'HOURLY_PRODUCTION', 'За годину', 0),
(7620, 4, 4, 'BALLISTICS_TECH', 'Балістична технологія', 0),
(7621, 4, 4, 'BALLISTICS_TECH_DESC', 'Балістичний аналізатор управляє високоточним наведенням зброї, збільшуючи точність прямих влучень у юніти супротивника.', 0),
(7622, 4, 4, 'BALLISTICS_TECH_FULL_DESC', 'Технологія балістичного аналізу дозволяє комп&#39;ютерним системам прораховувати бій до його початку на основі просторового розташування, технічних характеристик юнітов і траєкторій вогневих шляхів і випромінювань. Це робить можливим вести прицільний і високоточний вогонь на всьому протязі бою. Технологія зменшує промахи і попадання в уже знищені юніти.', 0),
(7623, 4, 4, 'MASKING_TECH', 'Маскувальна технологія', 0),
(7624, 4, 4, 'MASKING_TECH_DESC', 'Технологія радіо локаційної маскування створює перешкоди в роботі балістичного аналізатора і систем наведення вогню противника.', 0),
(7625, 4, 4, 'MASKING_TECH_FULL_DESC', 'Технологія радіо локаційної маскування створює перешкоди в роботі балістичного аналізатора і систем наведення вогню противника. Ця технологія збільшує живучість своїх юнітів за рахунок зменшення точності стрільби вогневих гармат противника.', 0),
(7626, 4, 17, 'COST', 'Вартість', 0),
(7627, 4, 17, 'BALLISTICS_POWER', 'Балістика', 0),
(7628, 4, 4, 'SIM_TECH_LIST', 'Технології', 0),
(7629, 4, 18, 'BALLISTICS_POWER', 'Балістика', 0),
(7630, 4, 18, 'MASKING_POWER', 'Маскування', 0),
(7631, 4, 17, 'MASKING_POWER', 'Маскування', 0),
(7632, 4, 4, 'REQUIRE_TIME_EXT', 'Час будівництва', 0),
(7633, 4, 13, 'EXPEDITION_CREDITS_DISCOVERY_1', 'Ваші дослідники виявили поле бою. На жаль всі кораблі не справні і без ресурсів, але в одному з уцілілих сейфів дослідники знайшли {@credits} кредитів. Вітаємо, кредити вже переведені на Ваш рахунок. Флот повертається на базу.', 0),
(7634, 4, 13, 'EXPEDITION_CREDITS_DISCOVERY_2', 'Експедиційне обладнання запеленгували дивний об&#39;єкт. Це виявилася капітанська рубка невідомого корабля з працюючим позивним пристроєм. Рубка виявилася відрізаною від основного корабля супер зброєю, дослідники вражені, нічого подібного вони не бачили. В абсолютно цілому сейфі дослідники знайшли {@credits} кредитів. Вітаємо, кредити вже переведені на Ваш рахунок. Флот повертається на базу.', 0),
(7635, 4, 13, 'EXPEDITION_CREDITS_DISCOVERY_3', 'Експедиційне обладнання запеленгували дивний об&#39;єкт. Це виявився одномісний пошкоджений космічний корабель з мертвим істотою невідомої раси. Під сидінням інопланетянина дослідники знайшли {@credits} кредитів. Вітаємо, кредити вже переведені на Ваш рахунок. Флот повертається на базу.', 0),
(7636, 4, 13, 'EXPEDITION_CREDITS_DISCOVERY_4', 'Експедиційне обладнання запеленгували дивний об&#39;єкт. Це виявився мертвий інопланетянин-пілот, про що свідчить його екіпіровка. Дослідження показало, що інопланетянин помер, перебуваючи у відкритому космосі в стані анабіозу {@anabios_years} років, коли системи підтримки життєзабезпечення витратили свої ресурси (мабуть його викинуло у відкритий космос в якомусь битві). В одязі пілота виявлений позивний маячок і {@credits} кредитів. Кредити вже переведені на Ваш рахунок. Флот повертається на базу.', 0),
(7637, 4, 13, 'EXPEDITION_CREDITS_DISCOVERY_5', 'Експедиційне обладнання запеленгували дивний об&#39;єкт. Це виявився невеликий пошкоджений корабель інопланетян. Дослідники уважно оглянули його і дещо знайшли: хитрі інопланетяни сховали в схованці {@credits} кредитів. Вітаємо, кредити вже переведені на Ваш рахунок. Флот повертається на базу.', 0),
(7638, 4, 13, 'EXPEDITION_CREDITS_DISCOVERY_6', 'Ваші дослідники виявили поле бою. На жаль всі кораблі не справні і без ресурсів, але в тайнику одного з кораблів уважні дослідники знайшли {@credits} кредитів. Вітаємо, кредити вже переведені на Ваш рахунок. Флот повертається на базу.', 0),
(7639, 4, 4, 'ALIEN_TECH', 'Інопланетна технологія', 0),
(7640, 4, 4, 'ALIEN_TECH_DESC', 'Ця технологія дозволяє ремонтувати інопланетні кораблі.', 0),
(7641, 4, 4, 'ALIEN_TECH_FULL_DESC', 'Ця технологія дозволяє ремонтувати інопланетні кораблі.', 0),
(7642, 4, 4, 'UNIT_A_CORVETTE_DESC', 'Дуже швидкий і економічний бойовий корабель з гарним озброєнням.', 0),
(7643, 4, 4, 'UNIT_A_SCREEN_DESC', 'Унікальний щитової корабель. Неперевершена захищеність дозволяє приймати на себе основний удар супротивника.', 0),
(7644, 4, 4, 'UNIT_A_PALADIN_DESC', 'Невеликий корабель вогневої підтримки. Оснащений високоточною зброєю і системою маскування.', 0),
(7645, 4, 4, 'UNIT_A_FRIGATE_DESC', 'Величезна вогнева міць і велика місткість. Здатний завдавати руйнують удари супротивника.', 0),
(7646, 4, 4, 'UNIT_A_TORPEDOCARIER_DESC', 'Швидкий корабель для нанесення раптового удару. Оснащений потужною зброєю з системою автоматичного наведення.', 0),
