(7730, 4, 1, 'EXCH_LOT_DETAILS', 'Лот', 0),
(7731, 4, 4, 'UNIT_EXCH_SUPPORT_RANGE_DESC', 'Міжгалактичний супутник збільшує радіус дії біржі. Продавці можуть додавати лоти на продаж тільки у випадку знаходження в радіусі дії.', 0),
(7732, 4, 4, 'UNIT_EXCH_SUPPORT_RANGE_FULL_DESC', 'Міжгалактичний супутник - це величезний об&#39;єкт, що обертається на орбіті планети. Він практично повністю складається з високотехнологічної апаратури для підтримки стабільної та безперебійної зв&#39;язку з самими далекими зоряними системами у всесвіті. При об&#39;єднанні таких супутників в групи, вони здатні покращувати якість зв&#39;язку багаторазово. Міжгалактичний супутник необхідний для роботи біржі. Кожен такий супутник збільшує радіус дії міжгалактичної біржі на подвійне кількість рівнів комп&#39;ютерної технології. Радіус дії вимірюється в зоряних системах. Кожні 300 систем збільшують радіус дії на 1 галактику. Продавці можуть додавати лоти на продаж тільки у випадку знаходження в радіусі дії біржі.', 0),
(7733, 4, 4, 'EXCHANGE_DESC', 'На міжгалактичної біржі гравці подають заявки на продаж товарів.', 0),
(7734, 4, 4, 'EXCHANGE_FULL_DESC', 'Міжгалактична біржа необхідна для здійснення торгових операцій в галактиках. Для нормального її функціонування, необхідно створити та підтримувати в робочому стані інфраструктуру з міжгалактичного супутників і Біржових підстанцій.', 0),
(7735, 4, 1, 'EXCH_DISTANCE', 'Радіус дії біржі (зв. систем)', 0),
(7736, 4, 1, 'EXCH_LOTS', 'Лотів на біржі (зайнято / макс.)', 0),
(7737, 4, 1, 'EXCH_PURCHASE', 'Покупка лота', 0),
(7738, 4, 1, 'BUY_SECCEED', 'Дякуємо за покупку на міжгалактичний біржі!', 0),
(7739, 4, 1, 'DELIVERY_UNITS', 'Доставка купленого флоту', 0),
(7740, 4, 13, 'DELIVERY_UNITS_REPORT', 'Куплений флот (%s) досяг планети %s %s. <br /> Флот залишив вантаж: %s металу, %s кремнію і %s водню.', 0),
(7741, 4, 13, 'DELIVERY_UNITS_REPORT_SUBJECT', 'Доставлений куплений флот', 0),
(7742, 4, 1, 'DELIVERY_RESOURSES', 'Доставка куплених ресурсів', 0),
(7743, 4, 3, 'FLEET_MESSAGE_DELIVERY_UNITS', 'Флот ({@fleet}) з {@planet} {@coords} досягає координат {@target} {@targetcoords}. Завдання: {@mission}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.', 0),
(7744, 4, 3, 'FLEET_MESSAGE_OTHER_RES', 'Чужий флот ({@fleet}) {@username} {@message} з {@planet} {@coords} досягає Ваших координат {@target} {@targetcoords}. Завдання: {@mission}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.', 0),
(7745, 4, 4, 'EXCH_OFFICE_DESC', 'Торгове представництво необхідно для можливості продавати на міжгалактичний біржі.', 0),
(7746, 4, 4, 'EXCH_OFFICE_FULL_DESC', 'Торгове представництво необхідно для можливості продавати на міжгалактичний біржі. Кожен рівень представництва збільшує максимальну кількість Ваших лотів на 2.', 0),
(7747, 4, 4, 'UNIT_EXCH_SUPPORT_SLOT_DESC', 'Біржова підстанція збільшує максимальну кількість лотів, що обслуговується біржею.', 0),
(7748, 4, 4, 'UNIT_EXCH_SUPPORT_SLOT_FULL_DESC', 'Біржова підстанція збільшує максимальну кількість лотів, що обслуговується біржею.', 0),
(7749, 4, 3, 'FLEET_MESSAGE_DELIVERY_UNITS_SELLER', 'Флот ({@fleet}) з {@planet} {@coords} досягає координат {@target} {@targetcoords}. Завдання: {@mission}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.', 0),
