(7783, 4, 20, 'DEACTIVATE_ALL', 'Деактивувати всі', 0),
(7784, 4, 20, 'FLAG_UNIQUE', 'Унікальний', 0),
(7785, 4, 20, 'FLAG_USABLE', 'Використовуваний', 0),
(7786, 4, 20, 'FLAG_STATIC', 'Неперевозімий', 0),
(7787, 4, 20, 'FLAG_MOVABLE', 'Перевозиться', 0),
(7788, 4, 4, 'ARTEFACTS_TECH', 'Вивчення артефактів', 0),
(7789, 4, 4, 'ARTEFACTS_TECH_DESC', 'Технологія дозволяє активувати артефакти. Кількість одночасно працюючих артефактів на всіх планетах збільшується з кожним рівнем на 1.', 0),
(7790, 4, 4, 'ARTEFACTS_TECH_FULL_DESC', 'У дослідженні інопланетних артефактів працюють найкращі наукові підрозділи Вашої імперії. Для вивчення невідомих технологій та механізмів роботи артефактів використовуються кращі евристичні методи аналізу та супер комп&#39;ютерні технології. Дана технологія дозволяє використовувати артефакти і підтримувати деякі з них в робочому стані деякий час. Максимальна кількість активованих артефактів на всіх планетах обмежена рівнем цієї технології.', 0),
(7791, 4, 4, 'MERCHANTS_MARK', 'Знак торговця', 0),
(7792, 4, 4, 'MERCHANTS_MARK_DESC', 'Зменшує комісію на біржі і при обміні ресурсів з 20% до 3%', 0),
(7793, 4, 4, 'MERCHANTS_MARK_FULL_DESC', 'Дає можливість здійснювати покупки на біржі і обмін ресурсів зі зниженою комісією 3% замість 20%', 0),
(7794, 4, 4, 'CATALYST', 'Каталізатор', 0),
(7795, 4, 4, 'CATALYST_DESC', 'Збільшує вироблення ресурсів на 10%.', 0),
(7796, 4, 4, 'CATALYST_FULL_DESC', 'Універсальний каталізатор прискорює хід хімічних процесів при синтезі металу, кремнію та водню. Протягом тижня вироблення ресурсів на всіх планетах збільшується на 10%.', 0),
(7797, 4, 4, 'POWER_GENERATOR', 'Енерготранс', 0),
(7798, 4, 4, 'POWER_GENERATOR_DESC', 'Збільшує вироблення енергії на 15%, а щитову технологію - на 1 рівень.', 0),
(7799, 4, 4, 'POWER_GENERATOR_FULL_DESC', 'Дає приріст продуктивності всіх електростанцій і супутників на 15%. Збільшує щитову технологію на 1 рівень.', 0),
(7800, 4, 4, 'ATOMIC_DENSIFIER', 'Атомний ущільнювач', 0),
(7801, 4, 4, 'ATOMIC_DENSIFIER_DESC', 'Збільшує ємність сховищ на 15%, а броньовий технологію - на 1 рівень.', 0),
(7802, 4, 4, 'ATOMIC_DENSIFIER_FULL_DESC', 'Генерує силове поле, стискає речовину, що дозволяє сховищ вміщати більше ресурсів. Протягом тижня ємність сховищ ресурсів на всіх планетах збільшується на 15%. Збільшує броньовий технологію на 1 рівень.', 0),
(7803, 4, 20, 'BUY_FOR_RESOURCES', 'Купити за ресурси', 0),
(7804, 4, 20, 'BUY_FOR_CREDITS', 'Купити за кредити', 0),
(7805, 4, 20, 'ARTEFACT_MARKET', 'Магазин артефактів', 0),
(7806, 4, 1, 'OR', 'або', 0),
(7807, 4, 4, 'ANNIHILATION_ENGINE', 'Анігіляційний модуль', 0),
(7808, 4, 4, 'ANNIHILATION_ENGINE_DESC', 'При підключенні до будь-якого типу двигунів збільшує швидкість флоту в польоті на 10%.', 0),
(7809, 4, 4, 'ANNIHILATION_ENGINE_FULL_DESC', 'Анігіляція - взаємознищення частинки і античастинки при їх зіткненні з вивільненням величезної кількості енергії. Антиматерію вкрай складно синтезувати і зберігати, тому створення ефективного двигуна, заснованого на принципі анігіляції, поки неможливо. Однак серед уламків великих інопланетних кораблів були знайдені модулі двигунів, що працюють саме за таким принципом. Деякі з них знаходяться в робочому стані і можуть бути суміщені з відомими типами двигунів, даючи їм приріст продуктивності в 10%.', 0),
(7810, 4, 4, 'SUPERCOMPUTER', 'Суперкомп&#39;ютер', 0),
(7811, 4, 4, 'SUPERCOMPUTER_DESC', 'Підвищує рівень комп&#39;ютерної технології на 1 і збільшує швидкість досліджень в два рази. Спрацьовує для досліджень запущених після активації суперкомп&#39;ютера. Після деактивації, прискорені дослідження не сповільнюються!', 0),
(7812, 4, 4, 'SUPERCOMPUTER_FULL_DESC', 'В одній з експедицій вдалося захопити унікальне інопланетне пристрій, який при детальному вивченні виявилося суперкомп&#39;ютером інопланетян. Суперкомп&#39;ютер вдалося привести в дію і включити в дослідницьку мережу. Він володіє величезною обчислювальною потужністю і здатний контролювати дії додаткового флоту. Одночасно з цим Суперкомп&#39;ютер займається вирішенням найбільш складних дослідницьких завдань, зменшуючи час досліджень в 2 рази. Спрацьовує для досліджень запущених після активації суперкомп&#39;ютера. Після деактивації, прискорені дослідження не сповільнюються! Два суперкомп&#39;ютера збільшать швидкість досліджень в 4-е рази!', 0),
(7813, 4, 4, 'MEMORY_MODULE__15_15', 'Модуль пам&#39;яті', 0),
(7814, 4, 4, 'MEMORY_MODULE__15_15_DESC', 'Підвищує рівень збройової технології до 15. <br /> <i> Вимоги: Збройова технологія (Рівень 14) </i>', 0),
(7815, 4, 4, 'MEMORY_MODULE__15_15_FULL_DESC', 'Іноді в експедиціях вдається знайти інопланетні модулі пам&#39;яті і розшифрувати зберігаються в них дані. Цей модуль містить інформацію про збройової технології 15 рівня.', 0),
(7816, 4, 4, 'MEMORY_MODULE__23_12', 'Модуль пам&#39;яті', 0),
(7817, 4, 4, 'MEMORY_MODULE__23_12_DESC', 'Підвищує рівень лазерної технології до 12. <br /> <i> Вимоги: Лазерна технологія (Рівень 11) </i>', 0),
(7818, 4, 4, 'MEMORY_MODULE__23_12_FULL_DESC', 'Іноді в експедиціях вдається знайти інопланетні модулі пам&#39;яті і розшифрувати зберігаються в них дані. Цей модуль містить інформацію про лазерної технології 12 рівня.', 0),
(7819, 4, 4, 'MEMORY_MODULE__28_1', 'Модуль пам&#39;яті', 0),
(7820, 4, 4, 'MEMORY_MODULE__28_1_DESC', 'Дає можливість вивчити гравітаційну технологію.', 0),
(7821, 4, 4, 'MEMORY_MODULE__28_1_FULL_DESC', 'Іноді в експедиціях вдається знайти інопланетні модулі пам&#39;яті і розшифрувати зберігаються в них дані. Цей модуль містить інформацію про гравітаційної технології 1 рівня.', 0),
(7822, 4, 4, 'MEMORY_MODULE__16_15', 'Модуль пам&#39;яті', 0),
(7823, 4, 4, 'MEMORY_MODULE__16_15_DESC', 'Підвищує рівень щитової технології до 15. <br /> <i> Вимоги: Щитова технологія (Рівень 14) </i>', 0),
(7824, 4, 4, 'MEMORY_MODULE__16_15_FULL_DESC', 'Іноді в експедиціях вдається знайти інопланетні модулі пам&#39;яті і розшифрувати зберігаються в них дані. Цей модуль містить інформацію про щитової технології 15 рівня.', 0),
(7825, 4, 4, 'MEMORY_MODULE__17_15', 'Модуль пам&#39;яті', 0),
(7826, 4, 4, 'MEMORY_MODULE__17_15_DESC', 'Підвищує рівень броньовий технології до 15. <br /> <i> Вимоги: Броньова технологія (Рівень 14) </i>', 0),
(7827, 4, 4, 'MEMORY_MODULE__17_15_FULL_DESC', 'Іноді в експедиціях вдається знайти інопланетні модулі пам&#39;яті і розшифрувати зберігаються в них дані. Цей модуль містить інформацію про броньовий технології 15 рівня.', 0),
(7828, 4, 4, 'MEMORY_MODULE__110_1', 'Модуль пам&#39;яті', 0);
INSERT INTO `na_phrases` (`phraseid`, `languageid`, `phrasegroupid`, `title`, `content`, `translated`) VALUES
(7829, 4, 4, 'MEMORY_MODULE__110_1_DESC', 'Дає можливість вивчити інопланетну технологію.', 0),
(7830, 4, 4, 'MEMORY_MODULE__110_1_FULL_DESC', 'Іноді в експедиціях вдається знайти інопланетні модулі пам&#39;яті і розшифрувати зберігаються в них дані. Цей модуль містить інформацію про інопланетної технології 1 рівня.', 0),
(7831, 4, 4, 'ASSEMBLY_MODULE__31_10', 'Модуль збірки', 0),
(7832, 4, 4, 'ASSEMBLY_MODULE__31_10_DESC', 'Додає до флоту 10 легких винищувачів.', 0),
(7833, 4, 4, 'ASSEMBLY_MODULE__31_10_FULL_DESC', 'Розвиток інопланетної техніки дозволяє створювати роботів, подібних відомим в галактиці нанітам. Однак замість нанітов загального призначення інопланетяни воліють використовувати спеціалізованих нанітов, оптимізованих для виконання єдиного завдання. Модуль збірки складається з мікрокомп&#39;ютера, керуючого процесом складання, і безлічі нанітов, призначених для створення кораблів конкретного типу. Цей модуль призначений для складання 10 легких винищувачів.', 0),
(7834, 4, 4, 'ASSEMBLY_MODULE__42_1', 'Модуль збірки', 0),
(7835, 4, 4, 'ASSEMBLY_MODULE__42_1_DESC', 'Додає до флоту 1 зірку смерті.', 0),
(7836, 4, 4, 'ASSEMBLY_MODULE__42_1_FULL_DESC', 'Розвиток інопланетної техніки дозволяє створювати роботів, подібних відомим в галактиці нанітам. Однак замість нанітов загального призначення інопланетяни воліють використовувати спеціалізованих нанітов, оптимізованих для виконання єдиного завдання. Модуль збірки складається з мікрокомп&#39;ютера, керуючого процесом складання, і безлічі нанітов, призначених для створення кораблів конкретного типу. Цей модуль призначений для збирання 1 Зорі смерті.', 0),
(7837, 4, 4, 'REPAIR_BOT', 'Ремонтний робот', 0),
(7838, 4, 4, 'REPAIR_BOT_DESC', 'Ремонтує всі кораблі на планеті.', 0),
(7839, 4, 4, 'REPAIR_BOT_FULL_DESC', 'Ремонтний робот здатний аналізувати структуру будь-яких кораблів і відновлювати їх броню. За один запуск він здатний відремонтувати весь флот на планеті. Однак робот має обмежений запас енергії, тому після трьох запусків він стає марним.', 0),
(7840, 4, 4, 'ROBOT_CONTROL_SYSTEM', 'Система керування роботами', 0),
(7841, 4, 4, 'ROBOT_CONTROL_SYSTEM_DESC', 'Система керування роботами (СУР) підвищує в 2 рази швидкість будівництва будівель, флоту і оборони. Спрацьовує для завдань запущених після активації СУР. Після деактивації, прискорені завдання не сповільнюються!', 0),
(7842, 4, 4, 'ROBOT_CONTROL_SYSTEM_FULL_DESC', 'Система керування роботами (СУР) дозволяє ефективніше розподіляти завдання для роботів при будівництві на планеті будівель, флоту і оборони. Швидкість будівництва збільшується в 2 рази. Спрацьовує для завдань запущених після активації СУР. Після деактивації, прискорені завдання не сповільнюються! Два СУР збільшать швидкість будівництва в 4-е рази!', 0),
(7843, 4, 12, 'STAT_POINTS', 'Усього очок', 0),
(7844, 4, 12, 'STAT_UNIT_POINTS', 'Юніти (очок)', 0),
