(7863, 4, 4, 'BATTLE_SHELL_POWER_FULL_DESC', 'Збільшує під час битви силу броні на 10% для всіх юнітів всіх гравців своєї сторони.', 0),
(7864, 4, 4, 'BATTLE_SHELL_POWER_DESC', 'Збільшує під час битви силу броні на 10% для всіх юнітів всіх гравців своєї сторони.', 0),
(7865, 4, 4, 'BATTLE_SHELL_POWER', 'Єдність броні', 0),
(7866, 4, 4, 'BATTLE_SHIELD_POWER', 'Єдність щитів', 0),
(7867, 4, 4, 'BATTLE_SHIELD_POWER_DESC', 'Збільшує під час битви силу щитів на 10% для всіх юнітів всіх гравців своєї сторони.', 0),
(7868, 4, 4, 'BATTLE_SHIELD_POWER_FULL_DESC', 'Збільшує під час битви силу щитів на 10% для всіх юнітів всіх гравців своєї сторони.', 0),
(7869, 4, 4, 'BATTLE_ATTACK_POWER_FULL_DESC', 'Збільшує під час битви силу атаки на 10% для всіх юнітів всіх гравців своєї сторони.', 0),
(7870, 4, 4, 'BATTLE_ATTACK_POWER_DESC', 'Збільшує під час битви силу атаки на 10% для всіх юнітів всіх гравців своєї сторони.', 0),
(7871, 4, 4, 'BATTLE_ATTACK_POWER', 'Єдність атаки', 0),
(7872, 4, 4, 'MOON_CREATOR', 'Місячний творець', 0),
(7873, 4, 4, 'MOON_CREATOR_DESC', 'Дозволяє створити місяць на орбіті планети.', 0),
(7874, 4, 4, 'MOON_CREATOR_FULL_DESC', 'Дозволяє створити місяць на орбіті планети.', 0),
(7875, 4, 4, 'PLANET_CREATOR_FULL_DESC', 'Дозволяє створити додаткову планету. Необхідно відправити у складі флоту з колонізатором на вільні координати.', 0),
(7876, 4, 4, 'PLANET_CREATOR_DESC', 'Дозволяє створити додаткову планету. Необхідно відправити у складі флоту з колонізатором на вільні координати.', 0),
(7877, 4, 4, 'PLANET_CREATOR', 'Планетарний творець', 0),
(7878, 4, 1, 'DESTROY_ATTACK', 'Зруйнувати споруду', 0),
