(7953, 4, 3, 'FLEET_MESSAGE_DELIVERY_ARTEFACTS_SELLER', 'Чужий флот ({@fleet}) {@username} {@message} з {@planet} {@coords} досягає Ваших координат {@target} {@targetcoords}. Завдання: {@mission}. <br /> Вантаж: {@artefact}', 0),
(7954, 4, 2, 'ACCOUNT_ACTIVATION', 'Аккаунт ще на активовано.', 0),
