(7965, 4, 13, 'MSG_CREDIT_EXCHANGE_SELL_LOT', 'У Вас купили лот ({@lot}) за {@credits} кредитів.', 0),
(7966, 4, 13, 'MSG_CREDIT_ARTEFACT_BUY_LOT', 'Ви купили артефакт ({@lot}) за {@credits} кредитів.', 0),
(7967, 4, 13, 'MSG_CREDIT_MARKET', 'Ви купили на ринку ресурси за {@credits} кредитів.', 0),
(7968, 4, 4, 'SHADOW_SHIP', 'Тінь', 0),
(7969, 4, 4, 'SHADOW_SHIP_DESC', 'Швидкий корабель для ефективного обстрілу противника з великої відстані. Слабкий в обороні.', 0),
(7970, 4, 4, 'SHADOW_SHIP_FULL_DESC', 'Швидкий і невловимий корабель для ефективного обстрілу противника в атаці. Корабель Тінь - це секретна військова розробка кращих вчених імперії. Він з&#39;явився при переробці та модернізації Легкого винищувача. Спеціально розроблене для Тіні багатозарядна знаряддя ідеально пристосоване для стрільби по великих кораблях противника. Тінь має скоєно новою системою озброєння, здатної вести прицільний вогонь з величезних відстаней, новим генератором щитового поля, високою маневреністю і генератором перешкод для поліпшення маскування. Але Тінь слабка в обороні, тому що перебуваючи на орбіті планети не може зайняти вогневі позиції на достатньому видаленні від противника.', 0),
(7971, 4, 13, 'MSG_CREDIT_FOR_VIP', 'Ви запустили завдання позачергово за {@credits} кредитів.', 0),
(7972, 4, 18, 'DESTROY_MISSION_DEATH_STARS_DESTROYED', 'Генератори Зірки сметрі не витримали перевантажень, вибухнуло ЗС: %d', 0),
(7973, 4, 13, 'MSG_CREDIT_BUY', 'Ви придбали {@credits} кредитів.', 0),
(7974, 4, 10, 'NO_FREE_EXPO_SLOTS', 'Немає вільних експедиційних слотів', 0),
(7975, 4, 4, 'MOON_ROBOTIC_FACTORY', 'Місячна фабрика роботів', 0),
(7976, 4, 4, 'MOON_ROBOTIC_FACTORY_FULL_DESC', 'Надає просту робочу силу, яку можна застосовувати при будівництві планетарної інфраструктури. Кожен рівень розвитку фабрики підвищує швидкість будівництва будівель.', 0),
(7977, 4, 5, 'MOON_ROBOTIC_FACTORY_DESC', 'Надає просту робочу силу, яку можна застосовувати при будівництві планетарної інфраструктури. Кожен рівень розвитку фабрики підвищує швидкість будівництва будівель.', 0),
(7978, 4, 7, 'SPACE_EVENTS_LIST', 'Поточні завдання у всесвіті', 0),
(7979, 4, 3, 'PLANET_ANIGILATION', 'Планета {@planet} самознищиться гравітаційної аномалією.', 0),
(7980, 4, 13, 'NEUTRAL_PLANET_FOUND', 'Після тривалих блукань по просторах всесвіту, сенсори експедиції засікли дивну активність у районі {@planet}. <br/> Підлетівши ближче, вчені виявили, що це невідома раніше планета інопланетян з уламками від бою. Мабуть хтось недавно розбив тут великий флот. На орбіті планети виявлені уламки: {@metal} металу і {@silicon} кремнію. Поспішайте, щоб забрати їх, оскільки планета не стабільна і скоро зруйнується, крім цього про планеті відомо комусь ще!', 0),
(7981, 4, 13, 'NEUTRAL_PLANET_DIE', 'Виявляється не даремно інопланетний флот так бився за цю планету. У її корі стали проявлятися небачені за силою гравітаційні аномалії і, перш ніж вчені встигли дослідити їх, планета {@planet} розвалилася на субматерію.', 0),
(7983, 4, 13, 'EXPEDITION_NEUTRAL_PLANET_SUBJ', 'Відкриття невідомої планети', 0),
(7984, 4, 1, 'NEUTRAL_PLANET_NAME', 'UFO-251', 0),
(7985, 4, 3, 'ANIGILATION_TIMER', 'Планета {@target_mission} самознищиться гравітаційної аномалією.', 0),
(7986, 4, 20, 'WRONG_ARTEFACT_PLANET', 'Розташований на іншій планеті', 0),
(7987, 4, 4, 'PACK_BUILDING_NOW', 'Запакувати поточний рівень в артефакт', 0),
(7988, 4, 20, 'OUTSTANDING_ARTEFACT_REQUIREMENTS', '', 0),
(7989, 4, 13, 'EXPEDITION_SENSOR_POOR_REPORT', 'Шпигунські зонди просканували шлейф луни темної матерії і виявили сліди {@visits} експедицій в секторі {@exp_sector}. Дослідники, порадившись, вирішили запропонувати Вам не літати в цей сектор кілька днів. Спробуйте знайти менш відвідані експедиціями сектора. Пошукова потужність склала {@exp_power}. Дослідники вивчали обраний сектор {@exp_hours} годин. Поточний результат експедиції стався з імовірністю {@exp_percent}%', 0),
(7990, 4, 12, 'BS_SHOW_NO_DESTROYED', 'показувати бої без втрат (грабежі ресурсів)', 0),
(7991, 4, 12, 'EXCH_LOT_MIN_PRICE', 'За партію', 0),
(7992, 4, 1, 'MENU_REFERAL', 'Реферали', 0),
(7993, 4, 12, 'BS_ALLIANCE_FILTER', 'Альянс', 0),
(7994, 4, 12, 'BS_ALLIANCE_FILTER_INFO', '', 0),
(7995, 4, 6, 'FLEET_CONSUMPTION', 'Флот', 0),
(7996, 4, 4, 'MOON_HYDROGEN_LAB', 'Місячний синтезатор водню', 0),
(7997, 4, 4, 'MOON_HYDROGEN_LAB_FULL_DESC', 'Місячний синтезатор видобуває водень з льоду з кратерів, розташованих на полюсах місяця. Це найтемніші і незвідані місця на місяці, туди ніколи не потрапляє світло з зірки. Вчені активно працюють над вивченням прихованих можливостей з видобутку водню на місяці. Енергію для синтезатора можуть дати захоплені в бою сонячні супутники.', 0),
(7998, 4, 5, 'MOON_HYDROGEN_LAB_DESC', 'Місячний синтезатор видобуває водень з льоду з кратерів, розташованих на полюсах місяця. Це найтемніші і незвідані місця. Енергію для синтезатора можуть дати захоплені в бою сонячні супутники.', 0),
