(8009, 4, 22, 'ACHIEVEMENT_BONUS', 'Нагорода', 0),
(8010, 4, 22, 'RECALC_ACHIEVEMENTS', 'Перерахувати', 0),
(8011, 4, 23, 'SN_OK_TITLE', 'Прийом платежів однокласники', 0),
(8012, 4, 23, 'SN_OK_DESC', 'Опис прийому платежів однокласників', 0),
(8013, 4, 23, 'SN_OK_CREDITS', '{@credit} Кредитів', 0),
(8014, 4, 1, 'USER_AGREEMENT', 'Угода', 0),
(8015, 4, 24, 'USER_AGREEMENT_PRE_TEXT', '', 0),
(8016, 4, 24, 'USER_AGREEMENT_POST_TEXT', '', 0),
(8017, 4, 1, 'TOP_MENU', 'Меню', 0),
(8018, 4, 1, 'TOP_MENU_PLANETS', 'Планети', 0),
(8019, 4, 1, 'TOP_MENU_BUY_CREDIT', 'Поповнити кредити', 0),
(8020, 4, 1, 'AGREE', 'Погодитися', 0),
(8021, 4, 8, 'SKIN_TYPE_MOBI', 'Мобільний', 0),
(8022, 4, 1, 'MENU_PLANET_OPTIONS', 'Планета', 0),
(8023, 4, 1, 'MENU_USER_AGREEMENT', 'Угода', 0),
(8024, 4, 24, 'USER_AGREEMENT_NEW_PRE_TEXT', '<span class=''true''> Щоб продовжити гру, підтвердіть Угода (кнопочка в кінці цієї сторінки). </span>', 0),
(8025, 4, 1, 'TW_UPCOMING_BLOCK', 'Скоро розпочнуться технічні роботи (ТР). Під час робіт Ви не зможете увійти в гру. ТР завершаться в {@tw_end_time} (час московський).', 0),
(8026, 4, 1, 'TW_UPCOMING', 'Скоро розпочнуться технічні роботи (ТР). Будь-які завершуються під час ТР завдання будуть припинені. Порядок поновлення завдань збережеться. ТР завершаться в {@tw_end_time} (час московський).', 0),
(8027, 4, 1, 'TW_IN_PROGRESS', 'В даний момент йдуть технічні роботи (ТР).', 0),
(8028, 4, 1, 'COUNTDOWN_TW', 'ТР', 0),
(8029, 4, 1, 'COUNTDOWN_WAIT', 'Виконується', 0),
(8030, 4, 1, 'MENU_NOTEPAD', 'Блокнот', 0),
(8031, 4, 1, 'NOTEPAD', 'Блокнот', 0),
(8032, 4, 4, 'REG_NO_AGREEMENT', 'Ви не погодилися з призначеним для користувача угодою.', 0),
(8033, 4, 4, 'REG_AGREE', 'Прочитав і згоден.', 0),
(8034, 4, 4, 'REG_AGREEMENT', 'Ознайомтесь з призначеним для користувача угодою.', 0),
(8035, 4, 4, 'TW_SIMULATOR', 'Йдуть технічні роботи, симуляція бою недоступна.', 0),
(8036, 4, 22, 'LOGIN', 'Ласкаво просимо.', 0),
(8037, 4, 22, 'LOGIN_DESC', 'Щоб отримати Ваші перші бонусні ресурси, натисніть кнопку Отримати бонус. Система Досягнень допоможе Вам пройти курс молодого бійця і стати грозою Миру OXSAR. Щоб виконати Досягнення, потрібно виконати всі його вимоги. Досягнення, які Ви приховали, завжди можна знайти вибравши в меню пункт Досягнення.', 0),
(8038, 4, 22, 'FIRST_METAL', 'Метал - основа всього.', 0),
(8039, 4, 22, 'FIRST_METAL_DESC', 'Для будівництва будівель, кораблів і оборони, а так само для дослідження деяких технологій потрібен метал. Він видобувається на руднику. Побудуйте свій перший рудник по видобутку металу.', 0),
(8040, 4, 22, 'FIRST_SILICON', 'Кремнієве речовина.', 0),
(8041, 4, 22, 'FIRST_SILICON_DESC', 'Кремній використовується для виробництва мікросхем, які необхідні вченим для роботи і використовуються практично в кожному приладі і будову. Побудуйте свій перший рудник по видобутку кремнію і почніть свій шлях розвитку високих технологій.', 0),
(8042, 4, 22, 'FIRST_HYDROGEN', 'Синя кров.', 0),
(8043, 4, 22, 'FIRST_HYDROGEN_DESC', 'У далекому майбутньому цивілізації відмовилися від нафти, як від основного джерела палива, тепер повсюдно використовується водень. На ньому літають кораблі і його споживає наукове обладнання. Побудуйте свій перший синтезатор водню і забезпечте свою планету паливом.', 0),
(8044, 4, 22, 'FIRST_SOLAR', 'Бережіть природу.', 0),
(8045, 4, 22, 'FIRST_SOLAR_DESC', 'Сонце - гігантська електростанція, треба просто навчиться добувати з нього енергію. Побудуйте Сонячну електростанцію і забезпечте теплом і енергією свою планету.', 0),
(8046, 4, 22, 'FIRST_ROBOT', 'Роботи, на роботу!', 0),
(8047, 4, 22, 'FIRST_ROBOT_DESC', 'Вчені встановили, що використання роботів прискорює строительсво будівель і кораблів. Побудуйте фабрику роботів, що б дізнатися чи це так.', 0),
(8048, 4, 22, 'STARTER', 'Міцний фундамент', 0),
(8049, 4, 22, 'STARTER_DESC', 'Перед тим як вийти в космос, обладнайте свою планету.', 0),
(8050, 4, 22, 'FIVE_ATTACKER', 'Залізні м&#39;язи.', 0),
(8051, 4, 22, 'FIVE_ATTACKER_DESC', 'Не всі планети відразу визнають у Вас свого повелителя. Побудуйте декілька кораблів атакуючого плану для початку Вашого переможного ходу по галактиці.', 0),
(8052, 4, 22, 'FIRST_ENERGY', 'Сонце - наш друг.', 0),
(8053, 4, 22, 'FIRST_ENERGY_DESC', 'Досліджуючи сонячну радіацію можна спробувати добути з неї енергію. Дослідіть енергетичну технологію для збільшення вироблення електрики.', 0),
(8054, 4, 22, 'TEN_TRANSPORT', 'Космічний далекобійник.', 0),
(8055, 4, 22, 'TEN_TRANSPORT_DESC', 'Для перевезень вантажів між планетами, а так само для збору ресурсів з інших планет найкраще підходять Перевезення. Ще транспорти можуть везти додаткові запаси палива, тим самим збільшуючи дальність польоту флоту.', 0),
(8056, 4, 22, 'FIRST_DEFFENCE', 'Кріпимо стіни.', 0),
(8057, 4, 22, 'FIRST_DEFFENCE_DESC', 'Галактика - небезпечне і суворе місце. Поки ваш флот борознить простори космосу, на вашу планету можуть напасти інші гравці. Змусьте їх заплатити за самовпевненість - почніть будувати оборону.', 0),
(8058, 4, 22, 'FIRST_ENGINE', 'Передполітна підготовка.', 0),
(8059, 4, 22, 'FIRST_ENGINE_DESC', 'Для переміщення в просторі вашим кораблям потрібні надійні і мощьние двигуни. Дослідивши свій перший двигун ви станете ще на крок ближче до підкорення космосу.', 0),
(8060, 4, 22, 'FIVE_ROCKET', 'Ми не одні, але ми захищені.', 0),
(8061, 4, 22, 'FIVE_ROCKET_DESC', 'Надійно захистіть свої тили - побудуйте ракетну оборону!', 0),
(8062, 4, 22, 'SIMULATE_BATTLE', 'Тактичний геній.', 0),
(8063, 4, 22, 'STATE_ASSAULT_SIMULATION', 'Провести симуляцію бою.', 0),
(8064, 4, 22, 'SIMULATE_BATTLE_DESC', 'Перемога в будь-якому битві на 80 відсотків складається з грамотного планування. Ваші вчені допоможуть вам у цьому, вони розробили систему для передбачення, що дозволить перевірити всі Ваші тактичні схеми. Знайдіть у меню Симулятор бою і спробуйте провести один бій в лабораторних умовах.', 0),
(8065, 4, 22, 'FIRST_RESS_EXCHANGE', 'Ринкова економіка.', 0),
(8066, 4, 22, 'STATE_RES_UPDATE_EXCHANGE', 'Обміняти ресурси в обміннику', 0),
(8067, 4, 22, 'FIRST_RESS_EXCHANGE_DESC', 'Для великих звершень не завжди вистачає ресурсів. Як добре, що у Вашій імперії відкрився Обмінник. Пошукайте його в меню. Обміняйте деяку кількість одних ресурсів на інші і продовжуйте своє сходження до влади над Світом.', 0),
(8068, 4, 22, 'FIRST_COMPUTER_TECH', 'Відкрити другий фронт.', 0),
(8069, 4, 22, 'FIRST_COMPUTER_TECH_DESC', 'Найчастіше для перемоги над супротивником його треба атакувати в декількох місцях одночасно. Для координації атакуючих флотів потрібні величезні обчислювальні потужності. Дослідіть комп&#39;ютерну технологію, щоб керувати великою кількістю флотів.', 0),
(8070, 4, 22, 'TUTORIAL_END', 'Кінець курсу молодого бійця.', 0),
(8071, 4, 22, 'TUTORIAL_END_DESC', 'Перед тим як закінчити курс молодого бійця, закінчите облаштовувати свою імперію.', 0),
(8072, 4, 13, 'MSG_CREDIT_EXCHANGE_RESERVE', 'Ви додали лот на біржу за {@credits} кредитів.', 0),
(8073, 4, 13, 'MSG_CREDIT_EXCHANGE_FROM_RESERVE', 'На Вашій біржі був виставлений лот, зароблена комісія склала {@credits} кредитів.', 0),
(8074, 4, 2, 'BIG_LOT_FLEET', 'У вас недостатньо кораблів.', 0),
(8075, 4, 2, 'BIG_LOT_COMISSION', 'У вас недостатньо кредитів для виставлення лота на біржу.', 0),
(8076, 4, 2, 'BIG_LOT_CANT_RESERV', 'У вас недостатньо ресурсів для виставлення лота на біржу. Спробуйте виставити лот знову.', 0),
(8077, 4, 1, 'MENU_SUPPORT', 'Регламент тих підтримки', 0),
(8078, 4, 2, 'BIG_LOT_ARTEFACT', 'Артефакт вже в польоті або на біржі.', 0),
(8079, 4, 1, 'MENU_ACHIEVEMENTS', 'Досягнення', 0),
(8080, 4, 18, 'BATTLE_REPORT_SUBJECT', 'Командування флоту отримало посилання на бойовий звіт від гравця {@username}', 0),
(8081, 4, 4, 'ASSAULT_REPORT_TITLE', 'Звіт про битву', 0),
(8082, 4, 1, 'EXCH_MAX_PRICE_ERR', 'Ціна лота не може бути такою високою.', 0),
(8083, 4, 18, 'MOON_ARTEFACT_CHANCE_LOW', 'Потенціал просторово-часового поля частково використано, в результаті бою він склав %s%%. Можлива поява артефакту з паралельного світу.', 0),
(8084, 4, 18, 'MOON_ARTEFACT_CHANCE_NONE', 'Потенціал просторово-часового поля використано, йде зарядка. Поява артефакту зараз неможливо.', 0),
(8085, 4, 22, 'MOON_BONUS_ONLY', 'Нагороду за це досягнення можна отримати тільки на місяці.', 0),
(8086, 4, 22, 'PLANET_BONUS_ONLY', 'Нагороду за це досягнення не можна отримати на місяці.', 0),
(8087, 4, 11, 'ARTEFACT_MESSAGES', 'Система артефактів', 0),
(8088, 4, 11, 'CREDIT_MESSAGES', 'Кредити', 0),
(8089, 4, 4, 'WRONG_LEAVE_PHRASE', 'Ви неправильно ввели фразу. Фраза чутлива до регістру.', 0),
(8090, 4, 4, 'LEAVE', 'ЗАЛИШИТИ', 0),
(8091, 4, 2, 'CANNOT_DELETE_HOME_PLANET', 'Не можна залишити головну планету.', 0),
(8092, 4, 3, 'PLANET_IS_NOT_FORMED_YET', 'Планета ще не сформувалася', 0),
(8093, 4, 1, 'UNFORMED_PLANET_NAME', 'Туманність', 0),
(8094, 4, 4, 'HOME_PLANET_REQUIRED', 'Ваші колоністи вже шукають у всесвіті відповідну планету для колонізації. Ви поки можете озирнутися, загляньте в чат, на біржу, ознайомтесь з меню гри (воно ліворуч). При бажанні, ігровий нік можна змінити в Налаштуваннях (в самому низу ігрового меню).', 0),
(8095, 4, 1, 'COLONIZE_RANDOM_PLANET', 'Колонізувати незвідані далі', 0),
(8096, 4, 3, 'FLEET_MESSAGE_COLONIZE_NEW_USER_PLANET', 'Ваш флот ({@fleet}) відправлений на завдання: {@mission}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.', 0),
(8097, 4, 14, 'ALLIANCE_FOUND_BLOCKED_BY_USER_POINTS', 'Ви не можете зараз створити альянс, тому у Вас дуже мало очок. Необхідно мати як мінімум {@min_points} очок, у Вас зараз {@user_points} очок.', 0),
(8098, 4, 7, 'EMAIL_DOMAIN_FAILED', 'На домен {@email_domain_failed} листи не доходять. Використовуйте будь ласка іншу поштову скриньку для реєстрації, наприклад, @ ya.ru, @ mail.ru, @ gmail.com і т.п.', 0),
(8099, 4, 23, 'SN_OK_CREDITS_STRING', '<span class=''confederation''> {@total} </span> кредитів <br/> ({@raw} <span class=''true''> + {@bonus} в подарунок </span>)', 0),
(8100, 4, 25, 'CHANGE_NAME_TITLE', 'Ласкаво просимо', 0),
(8101, 4, 25, 'ACHIV_BONUS_TITLE', 'Система досягнень', 0),
(8102, 4, 25, 'ACHIV_BONUS_DESC', '<p /> Щоб освоїти гру швидше, йди підказок Системи досягнень - Курс молодого бійця. Просто виконуй пропоновані вимоги і отримуй за це нагороди. <p /> Натисни зараз кнопку <b> Отримати бонус і приховати </b> (на неї вказує стрілка), щоб отримати твій перший бонус у грі.', 0),
(8103, 4, 25, 'MENU_ACHIEVEMENTS_TITLE', 'Досягнення', 0),
(8104, 4, 25, 'MENU_ACHIEVEMENTS_DESC', 'Якщо на досягненні натиснути кнопку <b> сховати </b> або <b> Отримати бонус і приховати </b>, досягнення більше не буде показуватися на всіх сторінках. Щоб подивитися приховані (згорнуті) досягнення перейди на сторінку Досягнення (на неї вказує стрілка).', 0),
(8105, 4, 25, 'MENU_ACHIEVEMENTS_PAGE_TITLE', 'Детальніше про досягнення', 0),
(8106, 4, 25, 'MENU_ACHIEVEMENTS_PAGE_DESC', 'Для отримання досягнень треба виконати певні вимоги. Їх ти побачиш відразу після списку нагород в описі досягнення. Зеленим відзначені виконані вимоги, червоним - невиконані.', 0),
(8107, 4, 25, 'MENU_BUILD_TITLE', 'Навчання будівництва будинків', 0),
(8108, 4, 25, 'MENU_BUILD_DESC', 'Щоб виконати досягнення &quot;Бережіть природу&quot;, необхідно побудувати Сонячну електростанцію (це будова, в грі їх також називають будівлі або споруди). Щоб побудувати Сонячну електростанцію, перейди на сторінку Будівлі.', 0),
(8109, 4, 25, 'BUILD_SOLAR_TITLE', 'Будівництво', 0),
(8110, 4, 25, 'BUILD_SOLAR_DESC', '<p /> Для того, щоб побудувати будинок, треба виконати всі вимоги для його споруди і мати необхідну кількість ресурсів. <p /> Сонячна електростанція відображається відразу за синтезатором водню. Натисни на Побудувати навпроти опису Сонячної електростанції. Прокрути сторінку трохи вниз, якщо кнопочка Побудувати не видно.', 0),
(8111, 4, 25, 'SHOW_ME_TUTORIAL_TITLE', 'Підказки', 0),
(8112, 4, 25, 'SHOW_ME_TUTORIAL_DESC ', '<p /> Підказки можна вимкнути, натиснувши у вікні підказки кнопку <b> сховати </b>. Для того, щоб знову показати підказки, потрібно натиснути на <b> Вопросик </b> (на нього зараз вказує стрілка). <p /> Натисни кнопку <b> Далі </b> для продовження знайомства з грою.', 0),
(8113, 4, 25, 'MENU_GALAXY_TITLE', 'Знайомство з галактикою', 0),
(8114, 4, 25, 'MENU_GALAXY_DESC', '<p /> Поки будується Сонячна електростанція, давай подивимося зоряну систему, де знаходиться твоя планета. Цікаво, чи є у тебе сусіди. Перейди на сторінку Галактика.', 0),
(8115, 4, 25, 'MENU_GALAXY_DESC_TITLE', 'Перегляд галактики', 0),
(8116, 4, 25, 'MENU_GALAXY_DESC_DESC', '<p /> Всесвіт OXSAR складається з галактик, які складаються з зоряних систем. У кожній системі можуть знаходиться до 30 планет. <p /> При перегляді галактики витрачається 10 водню!', 0),
(8117, 4, 25, 'MENU_CHAT_TITLE', 'Знайомство з чатом', 0),
(8118, 4, 25, 'MENU_CHAT_DESC', '<p /> Для спілкування між гравцями і допомоги новачкам в грі є чат. Давай подивимося, що там зараз відбувається. <p /> Перейди на сторінку Чату.', 0),
(8119, 4, 25, 'MENU_CHAT_DESC_TITLE', 'Чат', 0),
(8120, 4, 25, 'MENU_CHAT_DESC_DESC', '<p /> Є два види чату - Загальний і Чат альянсу. Загалом чаті можуть спілкуватися всі гравці. В чаті альянсу - тільки гравці конкретного альянсу. Ти можеш вступити в один з існуючих альянсів, щоб розвиватися і воювати спільно.', 0),
(8121, 4, 25, 'SOLARPLANT_BONUS_TITLE', 'Виконане досягнення', 0),
(8122, 4, 25, 'SOLARPLANT_BONUS_DESC', '<p /> При завершенні будівництва Сонячної електростанції ти виконав всі вимоги досягнення &quot;Бережіть природу&quot;. Нагорода: другий рівень Сонячної електростанції і 2 Сонячних супутника. Це забезпечить енергією твою планету на найближчий час. Саме час отримати нагороду.', 0),
(8123, 4, 25, 'MENU_FLEET_TITLE', 'Знайомство з Флотом', 0),
(8124, 4, 25, 'MENU_FLEET_DESC', 'Переглядати і відправляти свої кораблі в політ можна із сторінки флоту. <br /> Перейдіть туди.', 0);
INSERT INTO `na_phrases` (`phraseid`, `languageid`, `phrasegroupid`, `title`, `content`, `translated`) VALUES
(8125, 4, 25, 'MENU_FLEET_DESC_TITLE', 'Огляд флоту', 0),
(8126, 4, 25, 'MENU_FLEET_DESC_DESC', 'На сторінку флоту ви можете бачити всі свої кораблі на цій планеті і відповідно відправляти їх в атаку або експедицію, завантажувати ресурсами і транспортувати на інші планети або просто переміщати між вашими планетами.', 0),
(8127, 4, 25, 'MENU_SIMULATOR_TITLE', 'Симулятор бою', 0),
(8128, 4, 25, 'MENU_SIMULATOR_DESC', '<p /> Незабаром ти зможеш вийти в космос і нападати на інших гравців. Важлива складова перемоги над супротивником - прораховування шансів на успішний результат бою. Для цього тобі знадобитися Симулятор бою.', 0),
(8129, 4, 25, 'MENU_SIMULATOR_DESC_TITLE', 'Симуляція бою', 0),
(8130, 4, 25, 'MENU_SIMULATOR_DESC_DESC', 'Для того, щоб провести найпростішу симуляцію бою - введи атакуючий флот і обороняється та натисніть кнопку <b> Симулювати </b> в самому низу сторінки. Знання про те як симулювати бій допоможе тобі у проходженні курсу молодого бійця.', 0),
(8131, 4, 25, 'CONTINUE_ACHIV_TITLE', 'Курс молодого бійця', 0),
(8132, 4, 25, 'CONTINUE_ACHIV_DESC', '<p /> Тепер ти знаєш багато про гру. Продовжуй розвивати свою імперії слідуючи підказкам Курсу молодого бійця (просто виконуй необхідні вимоги в досягненнях) і дуже скоро ти вийдеш в космос з військовими кораблями і зможеш вести військові дії. <p /> Приємної гри.', 0),
(8133, 4, 25, 'PLANET_CREATION_WAIT_TITLE', 'Очікування створення планети', 0),
(8134, 4, 25, 'PLANET_CREATION_WAIT_DESC', 'Ваша планета створюється, почекайте трохи і обновіть сторінку.', 0),
(8135, 4, 25, 'SOLARPLANT_CONSTRUCTED_TITLE', 'Завершення будівництва', 0),
(8136, 4, 25, 'SOLARPLANT_CONSTRUCTED_DESC', '<p /> Сонячна електростанція, яку ти почав будувати деякий час тому, швидше за все вже вишикувалася. Давай перевіримо це. Перейди на сторінку Будівлі.', 0),
(8137, 4, 25, 'MENU_GALAXY_COORD_DESC', '<p /> Для перегляду різних галактик і систем, можна ввести потрібні кордінати в поля вводу. Координати планет відображаються [X: Y: Z], де X - номер галактики, Y - номер зоряної системи, Z - номер планети. <p /> Чим менше номер планети, тим ближче планета знаходиться на зірку, тим вище у неї може бути температура. Температура впливає на видобуток водню, чим вона більша, тим менше водню видобувається. Але зате більше виробляється енергії сонячними супутниками.', 0),
(8138, 4, 25, 'MENU_GALAXY_COORD_TITLE', 'Координати планет', 0),
(8139, 4, 8, 'RESEND_ACTIVATION_LABEL', 'Надіслати новий лист про активацію на e-mail', 0),
(8140, 4, 8, 'RESEND_ACTIVATION', 'Надіслати', 0),
(8141, 4, 1, 'PLEASE_ACTIVATE_ACCOUNT', 'Активація e-mail ще не виконана. Перевір будь ласка свою пошту, на неї було надіслано лист про активацію. Це потрібно зробити, щоб не втратити доступ в гру і мати можливість відновити забутий пароль або змінити поточний при необхідності. Якщо тобі не прийшов лист про активацію на e-mail, запити його заного на сторінці Налаштування. Якщо лист не прийде після кількох спроб, зміни емайл на інший також на сторінці Налаштування.', 0),
(8142, 4, 25, 'SOLAR_PLANT_WAIT_TITLE', 'Необхідно побудувати СЕС', 0),
(8143, 4, 25, 'SOLAR_PLANT_WAIT_DESC', '<p /> Для наступного кроку необхідно побудувати Сонячну електростанцію. Якщо ти вже запустив її будівництво, почекай завершення і натисни <b> Далі </b>. Інакше запусти будівництво прямо зараз.', 0),
(8144, 4, 18, 'SHIPYARD_POWER', 'Верф', 0),
(8145, 4, 18, 'DEFENSE_FACTORY_POWER', 'Обор. завод', 0),
(8146, 4, 12, 'EXCH_TITLE_EXISTS', 'Біржа з ??назвою {@exch_title} вже існує!', 0),
(8147, 4, 4, 'PLANET_TEMP_CREATOR_FULL_DESC', 'Дозволяє створити планетарний маяк - тимчасову карликову планету з місячної для дислокації кораблів. Будівлі на місяці будуються набагато швидше, ніж на звичайних місяцях, але вона може бути знищена Зірками Смерті в будь галактиці. Після знищення місяця на маяку, нову побудувати неможливо. Маяк саморуйнується гравітаційної аномалією цілком через 3 тижні (з усіма будівлями на ньому, якщо такі там є), флот також повинен бути прибраний до руйнування. Маяк - це планетарний комплекс, місяць або планету маяка можна залишити в будь-який час при необхідності. Щоб створити маяк, необхідно відправити артефакт в складі флоту з колонізатором на вільні координати.', 0),
(8148, 4, 4, 'PLANET_TEMP_CREATOR_DESC', 'Дозволяє створити тимчасову карликову планету з місяцем для точки дислокації строком на 3 тижні. На місяці маяка можна будуватися набагато швидше, ніж на звичайних місяцях, але вона може бути знищена. Щоб створити маяк, необхідно відправити артефакт в складі флоту з колонізатором на вільні координати.', 0),
(8149, 4, 4, 'PLANET_TEMP_CREATOR', 'Планетарний маяк', 0),
(8150, 4, 4, 'TRANSMITTER', 'Трансмітер', 0),
(8151, 4, 4, 'TRANSMITTER_DESC', 'Важкий транспортний корабель з величезною місткістю і масштабованої руховою установкою.', 0),
(8152, 4, 4, 'TRANSMITTER_FULL_DESC', 'Важкий транспортний корабель побудований на нових розробках у сфері сучасних двигунів і корпусних захисту. Застосування цих технологій дозволили створити прийнятний за виживання транспортний корабель з величезною місткістю і масштабованими швидкісними характеристиками. Унікальна рухова компановка дозволяє оновлювати двигуни багато разів, досягаючи небачених раніше швидкостей для ін транспортних кораблів в імперії.', 0),
(8153, 4, 1, 'ARTEFACT_NOT_BUYABLE', 'Не можна купити', 0),
(8154, 4, 13, 'TEMP_PLANET_DIE', 'Маяк {@planet} зруйнований гравітаційної аномалією.', 0),
(8155, 4, 13, 'TEMP_PLANET_DIE_SUBJ', 'Маяк зруйнувався', 0),
(8156, 4, 10, 'JUMP_SUCCESSFUL_HITCHED', 'Перевантаження системи при телепортації, щось пішло не так, але здається все в порядку.', 0),
(8157, 4, 13, 'RETREAT_TRANSPORT', '{@username} скасував Транспорт на {@planet_from} {@coords_from}. Ваш флот ({@fleet}) повертається на {@planet} {@coords}.', 0),
(8158, 4, 13, 'RETREAT_TRANSPORT_SUBJECT', 'Скасування транспорту', 0),
(8159, 4, 10, 'CONTROL_EVENT', 'Керувати', 0),
(8160, 4, 10, 'FLEET_MESSAGE_HOLDING_FUEL', 'Флот ({@fleet}) належить {@username} {@message} з {@planet} {@coords} знаходиться на орбіті {@target} {@targetcoords} {@target_username} {@target_message}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню. Паливо: {@fuel_hydrogen} водню.', 0),
(8161, 4, 10, 'UNLOAD_RESOURCES', 'Вивантажити', 0),
(8162, 4, 10, 'LOAD_RESOURCES', 'Завантажити', 0),
(8163, 4, 10, 'FLEET_MESSAGE_HOLDING', 'Флот ({@fleet}) належить {@username} {@message} з {@planet} {@coords} знаходиться на орбіті {@target} {@targetcoords} {@target_username} {@target_message}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.', 0),
(8164, 4, 1, 'STARGATE_JUMP', 'Телепортація', 0),
(8165, 4, 13, 'STARGATE_JUMP_REPORT', 'Ваш флот (%s) успішно переміщуватися на %s %s.', 0),
(8166, 4, 13, 'STARGATE_JUMP_REPORT_SUBJECT', 'Телепортація завершена успішно', 0),
(8167, 4, 4, 'IGLA_MORI', 'Голка Морі-колис', 0),
(8168, 4, 4, 'IGLA_MORI_DESC', 'Дозволяє активувати просторову воронку для переміщення флоту (у тому числі з вантажем) через міжгалактичні врата в режимі гіперполета. При цьому кожну годину звичайного польоту перетворюється в 10 секунд, споживання палива зменшується в 1000 разів. Щоб активувати гіпер політ, потрібно додати Голку до складу флоту при передислокації між місяцями з брамою.', 0),
(8169, 4, 4, 'IGLA_MORI_FULL_DESC', 'Голка Морі-колис пронизує простір і створює воронку з характеристиками, що дозволяють переміщатися флоту (у тому числі з вантажем) через міжгалактичні врата в режимі гіперполета. У цьому режимі флот проходить відстань, еквівалентну 1 годині звичайного польоту, за 10 секунд, споживання палива зменшується в 1000 разів. Довгий час робота цього артефакту залишалася не відомою, поки одній групі вчених не вдалося розшифрувати листування інопланетян у комп&#39;ютері захопленого корабля інопланетної раси. Назва артефакту було дано по іменах учених, розгадати його принцип. Міжзоряні врата після використання блокуються, як при телепортації. Щоб активувати гіпер політ, потрібно додати Голку до складу флоту при передислокації між місяцями з брамою.', 0),
(8170, 4, 13, 'SURVEILLANCE_DETECTED', 'Командування флоту виявило активність на частотах роботи сенсорної фаланги близько {@coords_planet}, планета була кимось просканувала.', 0),
(8171, 4, 13, 'SURVEILLANCE_DETECTED_SUBJ', 'Планета просканувала чужий сенсорної фалангою', 0),
(8172, 4, 13, 'ALIEN_HALTING_MSG', 'Командування флоту отримало повідомлення від інопланетної раси: Здраваствуйте, ми прилетіти з світів! Інопланетний флот зайняв позиції на орбіті {@coords_planet}.', 0),
(8173, 4, 13, 'ALIEN_HALTING_SUBJ', 'Контакт з інопланетною цивілізацією', 0),
(8174, 4, 3, 'FLEET_MESSAGE_ALIEN_HOLDING', 'Інопланетний флот ({@fleet}) знаходиться на орбіті {@target} {@targetcoords}.', 0),
(8175, 4, 3, 'FLEET_MESSAGE_ALIEN', 'Інопланетний флот ({@fleet}) досягає Ваших координат {@target} {@targetcoords}. Завдання: {@mission}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.', 0),
(8176, 4, 3, 'FLEET_MESSAGE_ALIEN_OTHER', 'Інопланетний флот ({@fleet}) полетів на координати {@target} {@targetcoords}. Завдання: {@mission}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.', 0),
(8177, 4, 3, 'FLEET_MESSAGE_ALIEN_OTHER_2', 'Інопланетний флот ({@fleet}) рухається на координати {@target} {@targetcoords}. Завдання: {@mission}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.', 0),
(8178, 4, 13, 'MSG_CREDIT_BUILDING_UNIT', 'Ви запустили будівництво ({@name}) за {@credits} кредитів.', 0),
(8179, 4, 13, 'MSG_CREDIT_RESEARCHING', 'Ви запустили вивчення ({@name}) за {@credits} кредитів.', 0),
(8180, 4, 13, 'MSG_CREDIT_ALIEN_GRAB', 'Командування флоту виявило злом системи зберігання кредитів, інопланетяни викрали {@credits} кредитів.', 0),
(8181, 4, 13, 'MSG_CREDIT_ALIEN_GIFT', 'Командування флоту отримало повідомлення від інопланетян: Дякую за гостіпріемстіство, під імяні благодарнасть прийміть дар {@credits} кредитів.', 0),
(8182, 4, 1, 'CONFIRM_BUILDING_USE_CREDIT', 'Для будівництва ({@name}) буде потрібно {@credit} кредитів.', 0),
(8183, 4, 1, 'CONFIRM_OK', 'OK', 0),
(8184, 4, 1, 'CONFIRM_CANCEL', 'Скасування', 0),
(8185, 4, 1, 'CONFIRM_TITLE_WARNING', 'Увага', 0),
(8186, 4, 1, 'EXCH_NEWLOT_FEATURED', 'Обрані біржі', 0),
(8187, 4, 1, 'EXCH_LOTS_FEATURED', 'Преміум пропозиції', 0),
(8188, 4, 1, 'PREMIUM', 'Преміум', 0),
(8189, 4, 1, 'CONFIRM_PREMIUN_LOT_USE_CREDIT', 'Підняти лот ({@name}) в список преміум за {@credit} кредитів?', 0),
(8190, 4, 13, 'MSG_CREDIT_EXCHANGE_PREMIUM_LOT', 'Ви підняли лот ({@name}) в список преміум за {@credits} кредитів.', 0),
(8191, 4, 1, 'PREMIUN_LIST_MAX_SIZE', 'Преміум пропозиції дешевше для покупців і вигідніше для продавців. Швидкість доставки в два рази швидше, паливо в два рази дешевше. Якість товару перевірено міжгалактичної асоціацією, гарантується відсутність подряпин і ушкоджень! Максимум показується {@count} лотів. Після виходу зі списку лот залишається у статусі преміум і може бути доданий до списку повторно.', 0),
(8192, 4, 1, 'CONFIRM_LOT_RECALL', 'Ви дійсно хочете зняти лот ({@name})?', 0),
(8193, 4, 1, 'EXCH_RECALL_AND_BAN', 'Забанити', 0),
(8194, 4, 1, 'CONFIRM_EXCH_RECALL_AND_BAN', 'Ви дійсно хочете Забанити продавця і зняти його лот ({@name})?', 0),
(8195, 4, 1, 'PREMIUN_LOT_SLOGAN', 'Ціна менше, доставка швидше.', 0),
(8196, 4, 1, 'PREMIUN_SELLER_INFO', 'Продавець преміум класу. Забезпечує швидку і дешеву доставку товару.', 0),
(8197, 4, 1, 'MSG_EXCH_LOT_BACK_RESOURSES', 'При закінченні дії лота ({@lot}) залишилися невитрачені ресурси, вони були повернуті назад на {@planet}. <br /> Вантаж: {@metal} металу, {@silicon} кремнію і {@hydrogen} водню.', 0),
(8198, 4, 1, 'MSG_EXCH_LOT_BACK_RESOURSES_SUBJ', 'Повернення невитрачених ресурсів', 0),
(8199, 4, 4, 'MOON_LAB', 'Місячна лабораторія', 0),
(8200, 4, 4, 'MOON_LAB_FULL_DESC', 'Місячна лабораторія (ЛЛ) - це найдосконаліше споруда на місяці та й мабуть у всій імперії, плід праці кращих учених. Кожен рівень ЛЛ 10-кратно підвищує рівень планетарної дослідної лабораторії, що бере участь в МІС. Це дає можливість проводити дослідження найбільш трудомістких і не досяжних без ЛЛ технологій. Крім цього кожен рівень ЛЛ дає можливість використовувати на місяці 10% потужності планетарної фабрики нанітов, що дозволяє будувати все більш грандіозні споруди. Але й це ще не все, вчені знайшли спосіб розширити за допомогою ЛЛ доступні поля на місяці для все більшої її забудови.', 0),
(8201, 4, 5, 'MOON_LAB_DESC', 'Місячна лабораторія багаторазово прискорює дослідження, робить доступною на місяці планетарну фабрику нанітов, додає вільні поля на місяці.', 0),
(8202, 4, 4, 'MOON_REPAIR_FACTORY_DESC', 'Місячний ремонтний ангар необхідний для ремонту пошкоджених та утилізації непотрібних юнітів.', 0),
(8203, 4, 4, 'MOON_REPAIR_FACTORY_FULL_DESC', 'Місячний ремонтний ангар необхідний для виконання двох операцій: 1 - ремонт пошкоджених кораблів і оборонних споруд, 2 - утилізація непотрібних кораблів і оборони для отримання ресурсів.', 0),
(8204, 4, 4, 'MOON_REPAIR_FACTORY', 'Місячний ремонтний ангар', 0),
(8205, 4, 1, 'PLANET_UNDER_ATTACK', 'Неможливо виконати завдання зараз. На Вашій планеті йде бій. Повторіть спробу через секунду.', 0),
(8207, 4, 10, 'EXPEDITION_WARNING', 'В експедиції можна знайти ресурси, флот, зустріти інопланетян і мн. інше. Але не забувайте, що експедиція завжди таїть небезпеку, в ній можна втратити флот. Не запускайте в експедицію флот, втрата якого буде значима для Вас!', 0),
(8208, 6, 1, 'ACCOUNT_WILL_BE_DELETED', 'Акаўнт будзе выдалены!', 0),
(8209, 6, 1, 'ADD_TO_BUDDYLIST', 'Дадаць у спіс сяброў', 0),
(8210, 6, 1, 'ALLIANCE', 'Альянс', 0),
(8211, 6, 1, 'ALLIANCE_ATTACK', 'Сумесная атака', 0),
(8212, 6, 1, 'ALLIANCE_DESTROY_ATTACK', 'Сумесна разбурыць пабудову', 0),
(8213, 6, 1, 'ATTACK', 'Атака', 0),
(8214, 6, 1, 'BACK', 'Назад', 0),
(8215, 6, 1, 'BASIC_PRODUCTION', 'Натуральнае вытворчасць', 0),
(8216, 6, 1, 'CHARACTERS', 'знакаў', 0),
(8217, 6, 1, 'COLONIZE', 'Каланізаваць', 0),
(8218, 6, 1, 'COLONY', 'Калонія', 0),
(8219, 6, 1, 'COMMIT', 'Ok', 0),
(8220, 6, 1, 'CONFIRM_PROCEEDING', 'Вы ўпэўненыя?', 0),
