(8223, 6, 1, 'EDIT', 'Змяніць', 0),
(8224, 6, 1, 'EMAIL', 'E-Mail', 0),
(8225, 6, 1, 'ENERGY', 'Энергія', 0),
(8226, 6, 1, 'ERROR', 'Памылка', 0),
(8227, 6, 1, 'EXTERN_LINK', 'Вы пакідаеце {config}pagetitle{/config}. Звярніце ўвагу, што {config}pagetitle{/config} не нясе адказнасці за ўтрыманне Вэб-конента.', 0),
