(8306, 6, 3, 'FLEET_MESSAGE_FORMATION', '<p> Сумесна з %s з %s %s: %s </p>', 0),
(8307, 6, 3, 'FLEET_MESSAGE_HOLDING_1', 'Ваш флот ({@fleet}) з {@planet} {@coords} знаходзіцца на арбіце {@target} {@targetcoords}. <br /> Груз: {@metal} металу, {@silicon} крэмнія і {@hydrogen} вадароду.', 0),
(8308, 6, 3, 'FLEET_MESSAGE_HOLDING_2', 'Чужы флот ({@fleet}) {@username} {@message} з {@planet} {@coords} знаходзіцца на арбіце {@target} {@targetcoords}.', 0),
(8309, 6, 3, 'FLEET_MESSAGE_OTHER', 'Чужы флот ({@fleet}) {@username} {@message} з {@planet} {@coords} дасягае Вашых каардынатаў {@target} {@targetcoords}. Заданне: {@mission}. <br /> Груз: {@metal} металу, {@silicon} крэмнія і {@hydrogen} вадароду.', 0),
(8310, 6, 3, 'FLEET_MESSAGE_OWN', 'Ваш флот ({@fleet}) з {@planet} {@coords} адпраўлены на {@target} {@targetcoords}. Заданне: {@mission}. <br /> Груз: {@metal} металу, {@silicon} крэмнія і {@hydrogen} вадароду.', 0),
(8311, 6, 3, 'FLEET_MESSAGE_RETURN', 'Ваш флот ({@fleet}) з {@planet} {@coords} вяртаецца на {@target} {@targetcoords}. Заданне: {@mission}. <br /> Груз: {@metal} металу, {@silicon} крэмнія і {@hydrogen} вадароду.', 0),
(8312, 6, 3, 'FLEET_MESSAGE_ROCKET_ATTACK', 'Вашы ракеты ({@rockets}) з {@planet} {@coords} дасягаюць {@target} {@targetcoords}.', 0),
(8313, 6, 3, 'FLEET_MESSAGE_ROCKET_ATTACK_FOREIGN', 'Варожыя ракеты ({@rockets}) {@username} {@message} з {@planet} {@coords} дасягаюць {@target} {@targetcoords}.', 0),
(8314, 6, 3, 'INVALID_PLANET_NAME', 'Назва планеты змяшчае недапушчальныя сімвалы.', 0),
(8315, 6, 3, 'NEW_PLANET_NAME', 'Новая назва планеты', 0),
