(8529, 6, 6, 'PROD_ONE_SOLAR_SATELLITE', 'Адзін спадарожнік здабывае: {@prodPerSat} энергіі', 0),
(8530, 6, 6, 'RESOURCE_PRODUCTION_FOR_PLANET', 'Вытворчасць рэсурсаў на планеце:', 0),
(8531, 6, 6, 'SHUT_DOWN', 'Выключыць', 0),
