(8535, 6, 7, 'ACCEPT_AGB', 'Уваходзячы, Вы аўтаматычна згаджаецеся з правіламі.', 0),
(8536, 6, 7, 'AGB', 'Палітыка / Правілы', 0),
(8537, 6, 7, 'BOARD', 'Форум', 0),
(8538, 6, 7, 'BOARD_DESC', 'Тут можна атрымаць адказы на ўсе ўзніклі пытанні.', 0),
(8539, 6, 7, 'CHANGE_PASSWORD', 'Змяніць пароль', 0),
(8540, 6, 7, 'DISCLAIMER', 'Зыходныя', 0),
(8541, 6, 7, 'EMAIL_CHECK', 'Калі ласка, увядзіце адрас электроннай пошты.', 0),
(8542, 6, 7, 'EMAIL_EXISTS', 'Такі E-Mail ужо зарэгістраваны.', 0),
(8543, 6, 7, 'EMAIL_INVALID', 'Адрас электроннай пошты з&#39;яўляецца несапраўдным.', 0),
(8544, 6, 7, 'EMAIL_NOT_FOUND', 'Уведзены e-mail не існуе.', 0),
(8545, 6, 7, 'ERROR_PASSWORD_CHANGED', 'Уведзены няслушныя дадзеныя. Пароль не можа быць зменены.', 0),
(8546, 6, 7, 'FORGOTTEN', 'забыліся?', 0),
(8548, 6, 7, 'INFOS_HELP', 'Дапамога', 0),
(8549, 6, 7, 'LOGIN', 'Увайсці', 0),
(8550, 6, 7, 'LOST_PW_HINT_1', 'Указанні', 0),
(8551, 6, 7, 'LOST_PW_HINT_2', 'Калі Вы забыліся імя карыстальніка, увядзіце E-Mail. Калі забыліся пароль, неабходна ўвесці імя карыстальніка і E-Mail.', 0),
(8552, 6, 7, 'LOST_PW_SUBJECT_1', '{config}pagetitle{/config}: Аднаўленне лагіна.', 0),
(8553, 6, 7, 'LOST_PW_SUBJECT_2', '{config}pagetitle{/config}: Аднаўленне пароля.', 0),
(8554, 6, 7, 'MAXIMUM_LOGIN_ATTEMPTS_REACHED', 'Дасягнута максімальную колькасць спробаў ўваходу.', 0),
(8555, 6, 7, 'NO_ACCESS', 'Несапраўдных сесія.', 0),
(8556, 6, 7, 'NO_ACTIVATION', 'Указаны карыстач яшчэ не актываваны.', 0),
(8557, 6, 7, 'OPEN_SOURCE', 'Open Source', 0),
(8558, 6, 7, 'PASSWORD_CHANGED', 'Пароль быў паспяхова зменены', 0),
(8559, 6, 7, 'PASSWORD_CHECK', 'Пароль павінен быць ад %d да %d сімвалаў.', 0),
(8560, 6, 7, 'PASSWORD_FORGOTTEN', 'Нагадаць пароль', 0),
(8561, 6, 7, 'PASSWORD_INVALID', 'Няправільны пароль.', 0),
(8562, 6, 7, 'PW_LOST_EMAIL_SUCCESS', 'Далейшыя інструкцыі Вы атрымаеце па электроннай пошце.', 0),
(8563, 6, 7, 'REGISTRATION', 'Рэгістрацыя', 0),
(8564, 6, 7, 'REGISTRATION_BANNED_FOR_IP', 'Вы толькі што зарэгістраваліся. Пачакайце {@minutes} хвілін і паспрабуйце зноў.', 0),
(8565, 6, 7, 'REGISTRATION_MAIL', 'Дзякуй {@regUsername} за рэгістрацыю ў {config}pagetitle{/config}! <br /> <br /> Ваш пароль: {@regPassword} <br /> <br /> Вам трэба актываваць уліковы запіс. Перайдзіце па спасылцы ніжэй для пацверджання або скапіюйце яе ў адрасны радок Вашага браўзэра: <br /> <br /> {@activationLink} <br /> <br /> З павагай, <br /> каманда {config}pagetitle{/config}', 0),
(8566, 6, 7, 'REQUEST_DATA', 'Адправіць', 0);
INSERT INTO `na_phrases` (`phraseid`, `languageid`, `phrasegroupid`, `title`, `content`, `translated`) VALUES
(8567, 6, 7, 'REQUEST_PASSWORD', 'Добры дзень, {@req_username}! <br /> <br /> Хто-то, магчыма Вы, на сайце {config}pagetitle{/config} запрасіў забыты пароль. Калі Вы сапраўды забыліся пароль, то для атрымання новага націсніце на спасылку ніжэй: <br /> <br /> {@new_pw_url} <br /> <br /> Калі Вы не запытвалі пароля, праігнаруйце гэты ліст. <br /> <br /> Запыт быў адпраўлены з IP-адрасы {@req_ipaddress}. <br /> <br /> Каб актываваць рахунак без змены пароля, націсніце на спасылку ніжэй: <br /> <br /> {@reactivate_url} <br /> <br /> З павагай, <br /> Ваша каманда {config}pagetitle{/config}', 0),
(8568, 6, 7, 'REQUEST_USERNAME', 'Добры дзень, {@req_username}! Хто-то, магчыма Вы, на сайце {config}pagetitle{/config} запыталі забыты лагін. Ваш Лагін: {@req_username} Калі Вы не забывалі свой лагін, раім Вам у наладах змяніць адрас электроннай пошты. Запыт быў адпраўлены з IP-адрасы {@req_ipaddress}. З павагай, Ваша каманда {config}pagetitle{/config}', 0),
(8569, 6, 7, 'RULES', 'Правілы', 0),
(8570, 6, 7, 'SCREENSHOTS', 'Скрыншоты', 0),
(8571, 6, 7, 'SCREENSHOT_GALAXY_BROWSER', 'Прадстаўленне Галактыкі', 0),
(8572, 6, 7, 'SCREENSHOT_MAIN_PAGE', 'Домашнаяя старонка', 0),
(8573, 6, 7, 'SIGN_IN', 'Увайсці', 0),
(8574, 6, 7, 'SIGN_UP', 'Рэгістравацца', 0),
(8575, 6, 7, 'START_UP_MESSAGE', 'Сардэчна запрашаем у {config}pagetitle{/config}! {config}pagetitle{/config} - гэта шматкарыстальніцкая касмічная онлайн гульня. Усе гульцы развіваюцца ў адзінай сусвету. Тут можна запрашаць сяброў і аб&#39;ядноўваць свае намаганні ў нападзе на ворагаў і абароне, выкарыстоўваць унікальную сістэму бою і ўласны сімулятар бітваў. Біржа дазволіць весці гандаль рэсурсамі, караблямі і артэфактамі з іншымі гульцамі, навуковыя даследаванні адкрыюць новыя тэхналогіі і больш дасканалыя сістэмы ўзбраення. Выкарыстоўваючы мноства стратэгій і тактык развіцця, ты зможаш пашыраць сваю імперыю і ўзмацняць уплыў на іншыя галактыкі ў імя галоўнай мэты - стаць гаспадаром {config}pagetitle{/config}. Каб развіццё імперыі ішло поўным ходам, лад шахты па здабычы рэсурсаў. Калі сканчаецца пабудова або назапашваецца патрэбную колькасць рэсурсаў, строй новыя будынкі ў меню <i> Пабудовы </i>. Аднак, не забывай пра Энергію. Без Энергіі ні адна шахта не зможа здабываць рэсурсы. Сістэма Дасягненняў дапаможа табе стаць навальніцай {config}pagetitle{/config}. Ідзі яе падказкамі і тваё развіццё пойдзе па аптымальным шляху. Любыя пытанні па гульні можна абмеркаваць у <i> чаце </i>, не саромейся, пытайся, там заўсёды гатовыя прыйсці на дапамогу. З павагай, твая каманда {config}pagetitle{/config}', 0),
(8576, 6, 7, 'START_UP_MESSAGE_SUBJECT', 'Сардэчна запрашаем, {@regUsername}!', 0),
(8577, 6, 7, 'SUCCESS_REGISTRATION', 'Вы паспяхова зарэгістраваліся ў Сусвеце. Для таго каб пачаць гуляць, зайдзіце ў свой паштовую скрыню, дачакайцеся атрымання лісты і вынікайце прыведзеных там інструкцыі. Сусвет чакае цябе, паспяшайцеся!', 0),
