(8802, 6, 13, 'RECYLCING_REPORT', 'Вашы %s перапрацоўшчыкаў здабылі %s рэсурсаў. На каардынатах было %s металу і %s крэмнію. Вы здабылі %s металу і %s крэмнію.', 0),
(8803, 6, 13, 'RECYLCING_REPORT_SUBJECT', 'Поле абломкаў: %s', 0),
(8804, 6, 13, 'ROCKET_ATTACK_MSG_ATTACKER', 'Ракетная атака на планету {@planet} {@coords} завяршылася паспяхова. Гулец {@defender} пазбавіўся {@lostunits} ачкоў пасля нападу {@rockets} межпланетыми ракетамі.', 0),
(8805, 6, 13, 'ROCKET_ATTACK_MSG_DEFENDER', 'Ваша планета {@planet} {@coords} была схільная ракетнай атацы. Гулец {@attacker} атакаваў {@rockets} ракетамі. Страты складаюць {@lostunits} ачкоў.', 0),
