(9059, 6, 1, 'MENU_REPAIR', 'Рамонт', 0),
(9060, 6, 4, 'REPAIR_FACTORY_DESC', 'Рамонтны ангар неабходны для рамонту пашкоджаных і ўтылізацыі непатрэбных юнітаў.', 0),
(9061, 6, 4, 'REPAIR_FACTORY_FULL_DESC', 'Рамонтны ангар неабходны для выканання дзвюх аперацый: 1 - рамонт пашкоджаных караблёў і абарончых збудаванняў, 2 - утылізацыя непатрэбных караблёў і абароны для атрымання рэсурсаў.', 0),
(9062, 6, 4, 'REPAIR_REQUIRED', 'Неабходна пабудаваць ангар.', 0),
