(9076, 6, 5, 'REPAIR_FREE', 'Свабодна', 0),
(9077, 6, 4, 'DEFENSE_FACTORY', 'Абаронны завод', 0),
(9078, 6, 4, 'DEFENSE_FACTORY_FULL_DESC', 'У абаронным заводзе вырабляюцца ўсе віды абарончых збудаванняў. Чым ён больш, тым хутчэй можна будаваць больш складаныя і больш буйныя абарончыя збудаванні. Акрамя гэтага кожны ўзровень завода павялічвае на 1% сілу шчытоў і на 0,1 ўзроўню маскіроўкі юнітаў, якія выконваюць бараніліся ролю ў бітве.', 0),
(9079, 6, 4, 'DEFENSE_FACTORY_REQUIRED', 'Неабходна пабудаваць абаронны завод.', 0),
(9080, 6, 5, 'DEFENSE_FACTORY_DESC', 'У абаронным заводзе вырабляюцца ўсе віды абарончых збудаванняў. Акрамя гэтага абаронны завод павялічвае сілу шчытоў і маскіроўку юнітаў, якія выконваюць бараніліся ролю ў бітве.', 0),
