(9120, 6, 18, 'UNIT_NOTHING_INFO', 'Траплення ў знішчаныя юніты, прамашкі і да т.п.', 0),
(9121, 6, 1, 'MENU_DISASSEMBLE', 'Утылізацыя', 0),
(9122, 6, 4, 'QUEUE_REPAIR_PREFIX', 'Рамонт', 0),
