(9124, 6, 5, 'DISASSEMBLE', 'Утылізаваць', 0),
(9125, 6, 4, 'LANCER_SHIP', 'Лансер', 0),
(9126, 6, 4, 'LANCER_SHIP_DESC', 'Хуткі і эфектыўны ваенны карабель, пабудаваны на самых сучасных тэхналогіях. Абсталяваны магутным узбраеннем для нанясення катастрафічных разбурэнняў праціўніку.', 0),
(9127, 6, 4, 'LANCER_SHIP_FULL_DESC', 'Хуткі і эфектыўны ваенны карабель, пабудаваны на самых сучасных тэхналогіях. Абсталяваны наймагутным узбраеннем, якое здольна наносіць катастрафічныя разбурэнні праціўніку. Для перазарадкі энергетычнай гарматы карабля патрабуецца некаторы час, таму карабель валодае дрэнны хуткастрэльнасцю. Карабель спраектаваны навукоўцамі, як дапаможны зброю пры нанясенні маштабнага ўдару ворагу, таму найбольш эфектыўны ў спалучэнні з астатнім флотам.', 0),
(9128, 6, 17, 'FRONT', 'Фронт', 0),
(9129, 6, 18, 'FRONT', 'Фронт', 0),
(9130, 6, 18, 'ATTACKER_LOST_RES', 'Страты атакавалага: %s (%s металу, %s крэмнія).', 0),
