INSERT INTO `na_phrases` (`phraseid`, `languageid`, `phrasegroupid`, `title`, `content`, `translated`) VALUES
(9132, 6, 18, 'ATTACKER_LOST_RES_4', 'Страты атакавалага: %s (%s металу, %s крэмнія, %s вадароду).', 0),
(9133, 6, 18, 'DEFENDER_LOST_RES_4', 'Страты абаранялых: %s (%s металу, %s крэмнія, %s вадароду).', 0),
(9134, 6, 18, 'HIDE_BATTLE_TEXT', 'Інфармацыя не даступная для прагляду.', 0),
(9135, 6, 18, 'ROCKET_ATTACK_TIME', 'Ракетная атака у %s гадзін:', 0),
(9136, 6, 11, 'ROCKET_ATTACK_REPORT', 'Справаздача аб ракетнай атацы', 0),
(9137, 6, 11, 'ASSAULT_REPORT_TURNS', 'Раўндаў', 0),
(9138, 6, 12, 'BS_USER_FILTER', 'Імя гульца', 0),
(9139, 6, 12, 'BS_USER_FILTER_INFO', '', 0),
(9140, 6, 6, 'DAILY_PRODUCTION', 'За дзень', 0),
(9141, 6, 6, 'MONTHLY_PRODUCTION', 'За месяц', 0),
(9142, 6, 6, 'WEEKLY_PRODUCTION', 'За тыдзень', 0),
(9143, 6, 1, 'PREV', 'Папярэд.', 0),
(9144, 6, 1, 'NEXT', 'Наступ.', 0),
(9145, 6, 1, 'RELATED_MSG', 'Паведамленні, звязаныя з гэтым гульцом.', 0),
(9146, 6, 13, 'EXPEDITION_XSKIRMISH', 'У час экспедыцыі Вашы караблі натыкнуліся на іншапланетны флот, які з&#39;явіўся з ніадкуль. Невядомая цывілізацыя апынулася варожая, завязалася бітва. Глядзіце справаздачу аб бітве ў раздзеле &#39;Баявыя справаздачы&#39;.', 0),
(9147, 6, 13, 'EXPEDITION_RESOURCE_DISCOVERY_1', 'Вашы даследнікі выявілі старыя і не рабочыя караблі, дрэйфуючыя ў космасе. Камандаванне распарадзілася забраць наяўныя ў трумах рэсурсы: {@metal} металу, {@silicon} крэмнія і {@hydrogen} вадароду.', 0),
(9148, 6, 13, 'EXPEDITION_SHIPS_DISCOVERY', 'Вашы даследнікі выявілі у пакоі ў адкрытым космасе флот, які апынуўся ў стане кансервацыі. Камандаванне распарадзілася прывесці знойдзеныя караблі на базу: {@new_ships}', 0),
(9149, 6, 13, 'EXPEDITION_NOTHING_1', 'Ваш флот доўга баразніў абшары сусвету, аднак сэнсары навукоўцаў так і не змаглі зафіксаваць нічога цікавага.', 0),
(9150, 6, 4, 'UNIT_A_CORVETTE', 'Карвет іншапланецян', 0),
(9151, 6, 4, 'UNIT_A_SCREEN', 'Шчытавы карабель іншапланецян', 0),
(9152, 6, 13, 'EXPEDITION_BATTLEFIELD_DISCOVERY', 'Вашы даследнікі выявілі сляды даўно отгремевшая бітвы. Сярод тон пакарабачанага металу ўдалося знайсці караблі, прыдатныя для далейшага выкарыстання: {@new_ships}', 0),
(9153, 6, 13, 'EXPEDITION_NOTHING_2', 'Вашы даследчыкі прайшлі міма звышновай зоркі і зрабілі цудоўныя фатаграфіі. Больш нічога цікавага ў абраным сектары яны не знайшлі.', 0),
(9154, 6, 13, 'EXPEDITION_LOST_1', 'На жаль сувязь з экспедыцыяй была страчана.', 0),
(9155, 6, 4, 'UNIT_A_PALADIN', 'Паладзін іншапланецян', 0),
(9156, 6, 4, 'UNIT_A_FRIGATE', 'Фрэгат іншапланецян', 0),
(9157, 6, 4, 'UNIT_A_TORPEDOCARIER', 'Торпедоносец іншапланецян', 0),
(9158, 6, 13, 'EXPEDITION_DELAY_RETURN', 'Вашы даследчыкі нічога не знайшлі, да таго ж яны заблудзіліся. На пошук шляху дадому спатрэбіцца на {@percent}% больш часу.', 0),
(9159, 6, 13, 'EXPEDITION_FAST_RETURN_1', 'Вашы даследчыкі нічога не знайшлі. На шчасце, яны выявілі па шляху стабільную чорную дзірку, праход праз якую дазволіць ім скараціць зваротны шлях на {@percent}%', 0),
(9160, 6, 13, 'EXPEDITION_SENSOR_REPORT', 'Шпіёнскія зонды прасканавалі шлейф рэха цёмнай матэрыі і выявілі сляды {@visits} экспедыцый у сектары {@exp_sector}. Пошукавая магутнасць экспедыцыі склала {@exp_power}. Даследнікі вывучалі выбраны сектар {@exp_hours} гадзін. Бягучы вынік экспедыцыі адбыўся з верагоднасцю {@exp_percent}%', 0),
(9161, 6, 1, 'RESEARCH_EXPO_TECH', 'Неабходна даследаваць экспедыцыйную тэхналогію', 0),
(9162, 6, 1, 'TOO_MANY_EXPOS', 'Узровень экспедыцыйнай тэхналогіі не дазваляе адпраўляць такая колькасць экспедыцый.', 0),
(9163, 6, 13, 'EXPEDITION_SENSOR_CLEAR_REPORT', 'Шпіёнскія зонды прасканавалі шлейф рэха цёмнай матэрыі і выявілі, што сектар {@exp_sector} ніхто не наведваў у бліжэйшыя дні - гэта вельмі добра! Даследнікі раяць Вам злятаць у гэты сектар яшчэ некалькі разоў для больш дбайнага яго вывучэння. Пошукавая магутнасць экспедыцыі склала {@exp_power}. Даследнікі вывучалі выбраны сектар {@exp_hours} гадзін. Бягучы вынік экспедыцыі адбыўся з верагоднасцю {@exp_percent}%', 0),
(9164, 6, 10, 'EXPEDITION_TIME', 'Час на даследаванні ў экспедыцыі', 0),
(9165, 6, 1, 'EXPEDITION', 'Экспедыцыя', 0),
(9166, 6, 13, 'EXPEDITION_SUBJECT', 'Справаздача экспедыцыі', 0),
(9167, 6, 13, 'EXPEDITION_SENSOR_SUBJECT', 'Дадзеныя з разведзонда', 0),
(9168, 6, 1, 'SENDER', 'Адпраўнік', 0),
(9169, 6, 1, 'RECIEVER', 'Атрымальнік', 0),
(9170, 6, 1, 'MENU_RESTRANSFERS', 'Перададзеныя рэсурсы', 0),
(9171, 6, 12, 'TRANSFERS_COUNT', 'Колькасць разгрузок', 0),
(9172, 6, 12, 'TOTAL_RES_TRANSFER', 'Сума рэсурсаў', 0),
(9173, 6, 12, 'RT_GROUP_RECIEVER', 'Групаваць па атрымальніку', 0),
(9174, 6, 12, 'RT_GROUP_SENDER', 'Групаваць па адпраўніку', 0),
(9175, 6, 12, 'RT_SEARCH_USER', 'Пошук па імя', 0),
(9176, 6, 13, 'EXPEDITION_FAST_RETURN_2', 'Вашы даследчыкі нічога не знайшлі. На шчасце, з кароны бліжэйшай зоркі зыходзіць струмень сонечнага ветру, які дазволіць ім скараціць час зваротнага шляху на {@percent}%', 0),
(9177, 6, 13, 'EXPEDITION_ASTEROID_DISCOVERY_NO_CARGO', 'Вашы даследчыкі знайшлі астероидное поле абломкаў: {@debrismetal} металу і {@debrissilicon} крэмнію. На жаль у экспедыцыі не было перапрацоўшчыкаў, каб сабраць рэсурсы з адкрытага космасу.', 0),
(9178, 6, 13, 'EXPEDITION_ASTEROID_DISCOVERY_1', 'Вашы даследчыкі знайшлі астероидное поле абломкаў: {@debrismetal} металу і {@debrissilicon} крэмнію. Перапрацоўшчыкі здабылі: {@metal} металу і {@silicon} крэмнію.', 0),
(9179, 6, 13, 'EXPEDITION_RESOURCE_DISCOVERY_2', 'Выдатная навіна: Вашы даследнікі выявілі неабжытаю планету з рэсурсамі: {@debrismetal} металу, {@debrissilicon} крэмнія і {@debrishydrogen} вадароду. Флот забраў: {@metal} металу, {@silicon} крэмнія і {@hydrogen} вадароду.', 0),
(9180, 6, 13, 'EXPEDITION_NOTHING_3', 'Вашы даследчыкі правялі ўвесь час, прадстаўленае на вывучэнне абранага сектара. Але яны не знайшлі нічога цікавага.', 0),
(9181, 6, 13, 'EXPEDITION_NOTHING_4', 'Ваш флот выявіў адну планету, які прыцягнуў увагу! Даследнікі знайшлі на ёй пацешных маленькіх звяркоў. Больш нічога выяўлена не было.', 0),
(9182, 6, 13, 'EXPEDITION_NOTHING_5', 'Вашы даследчыкі запеленгаваў на шляху прытрымлівання флот велізарных памераў іншапланетнага паходжання. Камандаванне прыняло рашэнне не рызыкаваць і вярнуцца на базу.', 0),
(9183, 6, 13, 'EXPEDITION_LOST_2', 'Сувязь з Вашымі даследнікамі страчана. Хутчэй за ўсё, яны больш не вернуцца ...', 0),
(9184, 6, 13, 'EXPEDITION_NOTHING_7', 'Вашы даследчыкі прайшлі міма велізарнай імглістасці антыматэрыі. Больш нічога выяўлена не было.', 0),
(9185, 6, 13, 'EXPEDITION_NOTHING_6', 'Вашы даследчыкі знайшлі на шляху руху нестабільную чорную дзірку. Камандаванне прыняло рашэнне не рызыкаваць і вярнуцца на базу.', 0),
(9186, 6, 13, 'EXPEDITION_ASTEROID_DISCOVERY_2', 'Вашы даследчыкі знайшлі даўно отгремевшая поле бітвы. Ад разбураных караблёў засталіся абломкі, якія можна сабраць: {@debrismetal} металу і {@debrissilicon} крэмнію. Перапрацоўшчыкі здабылі: {@metal} металу і {@silicon} крэмнію.', 0),
(9187, 6, 13, 'EXPEDITION_FAST_RETURN_3', 'Флот Вашай экспедыцыі патрапіў у поле дзеянні велізарнага магнітнага поля невядомага паходжання. На шчасце, гэта дазволіць ім скараціць час зваротнага шляху на {@percent}%', 0),
(9188, 6, 13, 'RETREAT_OTHER', '{@username} адмяніў Утрыманне на {@planet_from} {@coords_from}. Ваш флот ({@fleet}) вяртаецца на {@planet} {@coords}.', 0),
(9189, 6, 13, 'RETREAT_OTHER_SUBJECT', 'Адмена ўтрымання', 0),
(9190, 6, 6, 'HOURLY_PRODUCTION', 'За гадзіну', 0),
(9191, 6, 4, 'BALLISTICS_TECH', 'Балістычная тэхналогія', 0),
(9192, 6, 4, 'BALLISTICS_TECH_DESC', 'Балістычны аналізатар кіруе высокадакладным навядзеннем зброі, павялічваючы дакладнасць прамых трапленняў у юніты праціўніка.', 0),
(9193, 6, 4, 'BALLISTICS_TECH_FULL_DESC', 'Тэхналогія Балістычнага аналізу дазваляе кампутарным сістэмам пралічваць бой да яго пачатку на аснове прасторавага размяшчэння, тэхнічных характарыстык юнітаў і траекторый агнявых шляхоў і выпраменьванняў. Гэта робіць магчымым весці прыцэльны і высокадакладны агонь на ўсім працягу бою. Тэхналогія памяншае прамашкі і траплення ва ўжо знішчаныя юніты.', 0),
(9194, 6, 4, 'MASKING_TECH', 'Маскіровачную тэхналогія', 0),
(9195, 6, 4, 'MASKING_TECH_DESC', 'Тэхналогія радыё-лакацыйных маскіроўкі стварае перашкоды ў працы Балістычнага аналізатара і сістэм навядзення агню праціўніка.', 0),
(9196, 6, 4, 'MASKING_TECH_FULL_DESC', 'Тэхналогія радыё-лакацыйных маскіроўкі стварае перашкоды ў працы Балістычнага аналізатара і сістэм навядзення агню праціўніка. Гэтая тэхналогія павялічвае жывучасць сваіх юнітаў за кошт памяншэння дакладнасці стральбы агнявых гармат суперніка.', 0),
(9197, 6, 17, 'COST', 'Кошт', 0),
(9198, 6, 17, 'BALLISTICS_POWER', 'Балістыкі', 0),
(9199, 6, 4, 'SIM_TECH_LIST', 'Тэхналогіі', 0),
(9200, 6, 18, 'BALLISTICS_POWER', 'Балістыкі', 0),
(9201, 6, 18, 'MASKING_POWER', 'Маскіроўка', 0),
(9202, 6, 17, 'MASKING_POWER', 'Маскіроўка', 0),
(9203, 6, 4, 'REQUIRE_TIME_EXT', 'Час будаўніцтва', 0),
(9204, 6, 13, 'EXPEDITION_CREDITS_DISCOVERY_1', 'Вашы даследнікі выявілі поле бітвы. На жаль ўсе караблі не спраўныя і без рэсурсаў, але ў адным з ацалелых сейфаў даследчыкі знайшлі {@credits} крэдытаў. Віншуем, крэдыты ўжо перакладзены на Ваш рахунак. Флот вяртаецца на базу.', 0),
(9205, 6, 13, 'EXPEDITION_CREDITS_DISCOVERY_2', 'Экспедыцыйнае абсталяванне запеленгаваў дзіўны аб&#39;ект. Гэта апынулася Капітанская высечка невядомага карабля з які працуе пазыўныя прыладай. Рубка апынулася адрэзанай ад асноўнага карабля супер зброяй, даследчыкі здзіўлены, нічога падобнага яны не бачылі. У абсалютна цэлым сейфе даследчыкі знайшлі {@credits} крэдытаў. Віншуем, крэдыты ўжо перакладзены на Ваш рахунак. Флот вяртаецца на базу.', 0),
(9206, 6, 13, 'EXPEDITION_CREDITS_DISCOVERY_3', 'Экспедыцыйнае абсталяванне запеленгаваў дзіўны аб&#39;ект. Гэта апынуўся аднамесны пашкоджаны касмічны карабель з мёртвым істотай невядомай расы. Пад сядзеннем іншапланецяніна даследчыкі знайшлі {@credits} крэдытаў. Віншуем, крэдыты ўжо перакладзены на Ваш рахунак. Флот вяртаецца на базу.', 0),
(9207, 6, 13, 'EXPEDITION_CREDITS_DISCOVERY_4', 'Экспедыцыйнае абсталяванне запеленгаваў дзіўны аб&#39;ект. Гэта апынуўся мёртвы іншапланецянін-пілот, аб чым сведчыць яго экіпіроўка. Даследаванне паказала, што іншапланецянін памёр, знаходзячыся ў адкрытым космасе ў стане анабіёзу {@anabios_years} гадоў, калі сістэмы падтрымання жыццезабеспячэння выдаткавалі свае рэсурсы (мабыць яго выкінула ў адкрыты космас у нейкім бітве). У адзежы пілота выяўлены пазыўны маячок і {@credits} крэдытаў. Крэдыты ўжо перакладзены на Ваш рахунак. Флот вяртаецца на базу.', 0),
(9208, 6, 13, 'EXPEDITION_CREDITS_DISCOVERY_5', 'Экспедыцыйнае абсталяванне запеленгаваў дзіўны аб&#39;ект. Гэта апынуўся невялікі пашкоджаны карабель іншапланецян. Даследнікі ўважліва агледзелі яго і сёе што знайшлі: хітрыя іншапланецяне схавалі ў тайніку {@credits} крэдытаў. Віншуем, крэдыты ўжо перакладзены на Ваш рахунак. Флот вяртаецца на базу.', 0),
(9209, 6, 13, 'EXPEDITION_CREDITS_DISCOVERY_6', 'Вашы даследнікі выявілі поле бітвы. На жаль ўсе караблі не спраўныя і без рэсурсаў, але ў тайніку аднаго з караблёў ўважлівыя даследчыкі знайшлі {@credits} крэдытаў. Віншуем, крэдыты ўжо перакладзены на Ваш рахунак. Флот вяртаецца на базу.', 0),
(9210, 6, 4, 'ALIEN_TECH', 'Іншапланетная тэхналогія', 0),
(9211, 6, 4, 'ALIEN_TECH_DESC', 'Гэтая тэхналогія дазваляе рамантаваць іншапланетныя караблі.', 0),
(9212, 6, 4, 'ALIEN_TECH_FULL_DESC', 'Гэтая тэхналогія дазваляе рамантаваць іншапланетныя караблі.', 0),
(9213, 6, 4, 'UNIT_A_CORVETTE_DESC', 'Вельмі хуткі і эканамічны баявы карабель з добрым узбраеннем.', 0),
(9214, 6, 4, 'UNIT_A_SCREEN_DESC', 'Унікальны шчытавы карабель. Неперасягненая абароненасць дазваляе прымаць на сабе асноўны ўдар суперніка.', 0),
(9215, 6, 4, 'UNIT_A_PALADIN_DESC', 'Невялікі карабель агнявой падтрымкі. Абсталяваны высокадакладным зброяй і сістэмай маскіроўкі.', 0),
(9216, 6, 4, 'UNIT_A_FRIGATE_DESC', 'Велізарная агнявая моц і вялікая ўмяшчальнасць. Здольны наносіць разбуральныя ўдары праціўніку.', 0),
(9217, 6, 4, 'UNIT_A_TORPEDOCARIER_DESC', 'Хуткі карабель для нанясення раптоўнага ўдару. Абсталяваны магутным зброяй з сістэмай аўтаматычнага навядзення.', 0),
(9218, 6, 4, 'UNIT_A_CORVETTE_FULL_DESC', 'Вельмі хуткі і эканамічны баявы карабель з добрым узбраеннем.', 0),
(9219, 6, 4, 'UNIT_A_SCREEN_FULL_DESC', 'Унікальны шчытавы карабель. Неперасягненая абароненасць дазваляе прымаць на сабе асноўны ўдар суперніка.', 0),
(9220, 6, 4, 'UNIT_A_PALADIN_FULL_DESC', 'Невялікі карабель агнявой падтрымкі. Абсталяваны высокадакладным зброяй і сістэмай маскіроўкі.', 0),
(9221, 6, 4, 'UNIT_A_FRIGATE_FULL_DESC', 'Велізарная агнявая моц і вялікая ўмяшчальнасць. Здольны наносіць разбуральныя ўдары праціўніку.', 0),
(9222, 6, 4, 'UNIT_A_TORPEDOCARIER_FULL_DESC', 'Хуткі карабель для нанясення раптоўнага ўдару. Абсталяваны магутным зброяй з сістэмай аўтаматычнага навядзення.', 0),
