(9301, 6, 1, 'EXCH_LOT_DETAILS', 'Лот', 0),
(9302, 6, 4, 'UNIT_EXCH_SUPPORT_RANGE_DESC', 'Міжгалактычны спадарожнік павялічвае радыус дзеяння біржы. Прадаўцы могуць дадаваць лоты на продаж толькі ў выпадку знаходжання ў радыусе дзеянні.', 0),
(9303, 6, 4, 'UNIT_EXCH_SUPPORT_RANGE_FULL_DESC', 'Міжгалактычны спадарожнік - гэта велізарны аб&#39;ект, які верціцца на арбіце планеты. Ён практычна цалкам складаецца з высокатэхналагічнай апаратуры для падтрымання стабільнай і бесперабойнай сувязі з самымі далёкімі зорнымі сістэмамі ў сусвеце. Пры аб&#39;яднанні такіх спадарожнікаў ў групы, яны здольныя паляпшаць якасць сувязі шматкроць. Міжгалактычны спадарожнік неабходны для працы біржы. Кожны такі спадарожнік павялічвае радыус дзеяння міжгалактычнай біржы на падвойнае колькасць узроўняў кампутарнай тэхналогіі. Радыус дзеяння вымяраецца ў зорных сістэмах. Кожныя 300 сістэм павялічваюць радыус дзеяння на 1 галактыку. Прадаўцы могуць дадаваць лоты на продаж толькі ў выпадку знаходжання ў радыусе дзеянні біржы.', 0),
(9304, 6, 4, 'EXCHANGE_DESC', 'На міжгалактычнай біржы гульцы падаюць заяўкі на продаж тавараў.', 0),
(9305, 6, 4, 'EXCHANGE_FULL_DESC', 'Міжгалактычны біржа неабходная для ажыццяўлення гандлёвых здзелак у галактыках. Для нармальнага яе функцыянавання, неабходна стварыць і падтрымліваць у працоўным стане інфраструктуру з міжгалактычных спадарожнікаў і біржавых падстанцый.', 0),
(9306, 6, 1, 'EXCH_DISTANCE', 'Радыус дзеяння біржы (зв. сістэм)', 0),
(9307, 6, 1, 'EXCH_LOTS', 'Лотаў на біржы (занята / макс.)', 0),
(9308, 6, 1, 'EXCH_PURCHASE', 'Купля лота', 0),
(9309, 6, 1, 'BUY_SECCEED', 'Дзякуй за куплю на міжгалактычнай біржы!', 0),
(9310, 6, 1, 'DELIVERY_UNITS', 'Дастаўка набытага флоту', 0),
(9311, 6, 13, 'DELIVERY_UNITS_REPORT', 'Набыты флот (%s) дасягнуў планеты %s %s. <br /> Флот пакінуў груз: %s металу, %s крэмнія і %s вадароду.', 0),
(9312, 6, 13, 'DELIVERY_UNITS_REPORT_SUBJECT', 'Дастаўлены набыты флот', 0),
(9313, 6, 1, 'DELIVERY_RESOURSES', 'Дастаўка набытых рэсурсаў', 0),
(9314, 6, 3, 'FLEET_MESSAGE_DELIVERY_UNITS', 'Флот ({@fleet}) з {@planet} {@coords} дасягае каардынат {@target} {@targetcoords}. Заданне: {@mission}. <br /> Груз: {@metal} металу, {@silicon} крэмнія і {@hydrogen} вадароду.', 0),
(9315, 6, 3, 'FLEET_MESSAGE_OTHER_RES', 'Чужы флот ({@fleet}) {@username} {@message} з {@planet} {@coords} дасягае Вашых каардынатаў {@target} {@targetcoords}. Заданне: {@mission}. <br /> Груз: {@metal} металу, {@silicon} крэмнія і {@hydrogen} вадароду.', 0),
(9316, 6, 4, 'EXCH_OFFICE_DESC', 'Гандлёвае прадстаўніцтва неабходна для магчымасці прадаваць на міжгалактычнай біржы.', 0),
(9317, 6, 4, 'EXCH_OFFICE_FULL_DESC', 'Гандлёвае прадстаўніцтва неабходна для магчымасці прадаваць на міжгалактычнай біржы. Кожны ўзровень прадстаўніцтва павялічвае максімальную колькасць Вашых лотаў на 2.', 0),
(9318, 6, 4, 'UNIT_EXCH_SUPPORT_SLOT_DESC', 'Біржавая падстанцыя павялічвае максімальную колькасць лотаў, абслугоўванай біржай.', 0),
(9319, 6, 4, 'UNIT_EXCH_SUPPORT_SLOT_FULL_DESC', 'Біржавая падстанцыя павялічвае максімальную колькасць лотаў, абслугоўванай біржай.', 0),
(9320, 6, 3, 'FLEET_MESSAGE_DELIVERY_UNITS_SELLER', 'Флот ({@fleet}) з {@planet} {@coords} дасягае каардынат {@target} {@targetcoords}. Заданне: {@mission}. <br /> Груз: {@metal} металу, {@silicon} крэмнія і {@hydrogen} вадароду.', 0),
