(9357, 6, 20, 'FLAG_STATIC', 'Неперевозимый', 0),
(9358, 6, 20, 'FLAG_MOVABLE', 'Перавозіцца', 0),
(9359, 6, 4, 'ARTEFACTS_TECH', 'Вывучэнне артэфактаў', 0),
(9360, 6, 4, 'ARTEFACTS_TECH_DESC', 'Тэхналогія дазваляе актываваць артэфакты. Колькасць адначасова якія працуюць артэфактаў на ўсіх планетах павялічваецца з кожным узроўнем на 1.', 0),
(9361, 6, 4, 'ARTEFACTS_TECH_FULL_DESC', 'У даследаванні іншапланетных артэфактаў працуюць самыя лепшыя навуковыя падраздзяленні Вашай імперыі. Для вывучэння невядомых тэхналогій і механізмаў працы артэфактаў выкарыстоўваюцца лепшыя эўрыстычныя метады аналізу і супер кампутарныя тэхналогіі. Дадзеная тэхналогія дазваляе выкарыстоўваць артэфакты і падтрымліваць некаторыя з іх у працоўным стане некаторы час. Максімальная колькасць актываваных артэфактаў на ўсіх планетах абмежавана узроўнем гэтай тэхналогіі.', 0),
(9362, 6, 4, 'MERCHANTS_MARK', 'Знак гандляра', 0),
(9363, 6, 4, 'MERCHANTS_MARK_DESC', 'Памяншае камісію на біржы і пры абмене рэсурсаў з 20% да 3%', 0),
(9364, 6, 4, 'MERCHANTS_MARK_FULL_DESC', 'Дае магчымасць здзяйсняць пакупкі на біржы і абмен рэсурсаў са зніжанай камісіяй 3% замест 20%', 0),
(9365, 6, 4, 'CATALYST', 'Каталізатар', 0),
(9366, 6, 4, 'CATALYST_DESC', 'Павялічвае выпрацоўку рэсурсаў на 10%.', 0),
(9367, 6, 4, 'CATALYST_FULL_DESC', 'Універсальны каталізатар паскарае ход хімічных працэсаў пры сінтэзе металу, крэмнію і вадароду. На працягу тыдня выпрацоўка рэсурсаў на ўсіх планетах павялічваецца на 10%.', 0),
(9368, 6, 4, 'POWER_GENERATOR', 'Энерготранс', 0),
(9369, 6, 4, 'POWER_GENERATOR_DESC', 'Павялічвае выпрацоўку энергіі на 15%, а шчытоў тэхналогію - на 1 ўзровень.', 0),
(9370, 6, 4, 'POWER_GENERATOR_FULL_DESC', 'Дае прырост прадукцыйнасці ўсіх электрастанцый і спадарожнікаў на 15%. Павялічвае шчытоў тэхналогію на 1 ўзровень.', 0),
(9371, 6, 4, 'ATOMIC_DENSIFIER', 'Атамны ўшчыльняльнік', 0),
(9372, 6, 4, 'ATOMIC_DENSIFIER_DESC', 'Павялічвае ёмістасць сховішчаў на 15%, а бранявыя тэхналогію - на 1 ўзровень.', 0),
(9373, 6, 4, 'ATOMIC_DENSIFIER_FULL_DESC', 'Генеруе сілавое поле, сціскальныя рэчыва, што дазваляе сховішчаў змяшчаць больш рэсурсаў. На працягу тыдня ёмістасць сховішчаў рэсурсаў на ўсіх планетах павялічваецца на 15%. Павялічвае бранявыя тэхналогію на 1 ўзровень.', 0),
(9374, 6, 20, 'BUY_FOR_RESOURCES', 'Купіць за рэсурсы', 0),
(9375, 6, 20, 'BUY_FOR_CREDITS', 'Купіць за крэдыты', 0),
(9376, 6, 20, 'ARTEFACT_MARKET', 'Крама артэфактаў', 0),
(9377, 6, 1, 'OR', 'або', 0),
(9378, 6, 4, 'ANNIHILATION_ENGINE', 'Аннигиляционный модуль', 0),
(9379, 6, 4, 'ANNIHILATION_ENGINE_DESC', 'Пры падключэнні да любога тыпу рухавікоў павялічвае хуткасць флота ў палёце на 10%.', 0),
(9380, 6, 4, 'ANNIHILATION_ENGINE_FULL_DESC', 'Анігіляцыі - взаимоуничтожение часціцы і антычасцінка пры іх сутыкненні з вызваленнем велізарнай колькасці энергіі. Антыматэрыі вельмі складана сінтэзаваць і захоўваць, таму стварэнне эфектыўнага рухавіка, заснаванага на прынцыпе анігіляцыі, пакуль немагчыма. Аднак сярод абломкаў буйных іншапланетных караблёў былі знойдзены модулі рухавікоў, якія працуюць менавіта па такім прынцыпе. Некаторыя з іх знаходзяцца ў працоўным стане і могуць быць сумешчаныя з вядомымі тыпамі рухавікоў, даючы ім прырост прадукцыйнасці ў 10%.', 0),
(9381, 6, 4, 'SUPERCOMPUTER', 'Суперкампутар', 0),
(9382, 6, 4, 'SUPERCOMPUTER_DESC', 'Павышае ўзровень камп&#39;ютэрнай тэхналогіі на 1 і павялічвае хуткасць даследаванняў у два разы. Спрацоўвае для даследаванняў запушчаных пасля актывацыі суперкампутара. Пасля дэактывацыі, паскораныя даследаванні не запавольваюцца!', 0),
(9383, 6, 4, 'SUPERCOMPUTER_FULL_DESC', 'У адной з экспедыцый атрымалася захапіць унікальнае іншапланетнае прылада, якое пры падрабязным вывучэнні апынулася суперкампутарам іншапланецян. Суперкампутар атрымалася прывесці ў дзеянне і ўключыць у даследчую сетку. Ён валодае велізарнай вылічальнай магутнасцю і здольны кантраляваць дзеянні дадатковага флоту. Адначасова з гэтым Суперкампутар займаецца рашэннем найбольш складаных даследчых задач, памяншаючы час даследаванняў у 2 разы. Спрацоўвае для даследаванняў запушчаных пасля актывацыі суперкампутара. Пасля дэактывацыі, паскораныя даследаванні не запавольваюцца! Два суперкампутара павялічаць хуткасць даследаванняў у 4-е разы!', 0),
(9384, 1, 4, 'MAX_LEVEL', 'Максимальный уровень: {@level}', 1),
(9385, 1, 13, 'RECYLCING_REPORT_EXT', 'Ваш флот ({@fleet}) добыл {@res_all} ресурсов. На координатах было {@debrismetal} металла и {@debrissilicon} кремния. Вы добыли {@recycledmetal} металла и {@recycledsilicon} кремния.', 1),
(9386, 1, 13, 'RECYLCING_REPORT_SUBJECT_EXT', 'Поле обломков: {@coords}', 1),
(9387, 1, 1, 'MSG_ALIEN_RESOURSES_GIFT', 'Командование флота получило сообщение от инопланетян: Спасиба за гостиприемстиство, во имяни благодарнасть примите дар на {@planet}. <br /> Груз: {@metal} металла, {@silicon} кремния и {@hydrogen} водорода.', 1),
(9388, 1, 1, 'MSG_ALIEN_RESOURSES_GIFT_SUBJ', 'Инопланетяне подарили ресурсы', 1),
(9389, 1, 4, 'SHIP_TRANSPLANTATOR', 'Трансплантатор', 1),
(9390, 1, 4, 'SHIP_TRANSPLANTATOR_DESC', 'Трансплантатор - корабль чудовищной мощности для переработки огромных полей обломков, оставшихся после эпических сражений. Оснащен мощным вооружением и хорошей защитой, двигатели позволяют добираться до полей обломков быстрее обычных переработчиков. К сожалению, потребляет огромное количество топлива на полеты.', 1),
(9391, 1, 4, 'SHIP_TRANSPLANTATOR_FULL_DESC', 'Трансплантатор - корабль чудовищной мощности для сбора и переработки огромных астероидов, а также сбора обломков оставшихся после эпических сражений. Оснащен мощным вооружением, хорошо защищен от повреждений даже большими астероидными осколками, имеет усовершенствованную двигательную установку, которая позволяет этому чудовищу добираться до полей обломков быстрее обычных переработчиков. К сожалению, из за использования двигателей, работающих постоянно в форсированном режиме, потребляет огромное количество топлива на полеты. ', 1),
(9392, 1, 4, 'SHIP_COLLECTOR_FULL_DESC', 'Сборщик - корабль для сбора космического мусора в своей звездной системе и не далеко за ее пределами. Имеет навесные емкости для прикрепления собранного материала, супер экономичный двигатель и неплохую скорость.', 1),
(9393, 1, 4, 'SHIP_COLLECTOR_DESC', 'Сборщик - корабль для сбора космического мусора в своей звездной системе и не далеко за ее пределами.', 1),
(9394, 1, 4, 'SHIP_COLLECTOR', 'Сборщик', 1),
(9395, 1, 4, 'LARGE_PLANET_SHIELD', 'Большой планетарный щит', 1),
(9396, 1, 4, 'LARGE_PLANET_SHIELD_DESC', 'Дальнейшее развитие малого планетарного щита. Может сдерживать эпические атаки на планету. Имеет колоссальной мощности огневое излучение для разрушения Звезд смерти противника. Постоянно потребляет 500 энергии.', 1),
(9397, 1, 4, 'LARGE_PLANET_SHIELD_FULL_DESC', 'Дальнейшее развитие малого планетарного щита. Может сдерживать эпические атаки на планету. Защищает флот и оборону. Имеет колоссальной мощности огневое излучение для разрушения Звезд смерти противника. Возможное количество щитов зависит от уровня щитовой технологии. Каждые 4 уровня дают возможность строить один большой планетарный щит. Постоянно потребляет 500 энергии, щит выключить нельзя.', 1),
(9398, 1, 4, 'SMALL_PLANET_SHIELD', 'Малый планетарный щит', 1),
(9399, 1, 4, 'SMALL_PLANET_SHIELD_DESC', 'Малый планетарный щит защищает планету, поглощая грандиозные удары противника. Постоянно потребляет 100 энергии.', 1),
(9400, 1, 4, 'SMALL_PLANET_SHIELD_FULL_DESC', 'Малый планетарный щит защищает планету, поглощая грандиозные удары противника. Возможное количество щитов зависит от уровня щитовой технологии. Каждые 2 уровня дают возможность строить один малый планетарный щит. Постоянно потребляет 100 энергии, щит выключить нельзя.', 1),
(9401, 1, 4, 'BATTLE_NEUTRON_AFFECTOR_FULL_DESC', 'Увеличивает во время сражения силу атаки, щитов и брони на 1000% для всех юнитов всех игроков своей стороны. Снимает блокировку атаки на сильных игроков.', 1),
(9402, 1, 4, 'BATTLE_NEUTRON_AFFECTOR_DESC', 'Увеличивает во время сражения силу атаки, щитов и брони на 1000% для всех юнитов всех игроков своей стороны. Снимает блокировку атаки на сильных игроков.', 1),
(9403, 1, 4, 'BATTLE_NEUTRON_AFFECTOR', 'Нейтронный аффектор', 1),
(9404, 1, 4, 'PLANET_TELEPORTER', 'Линза пространства-Фрике', 1),
(9405, 1, 4, 'PLANET_TELEPORTER_DESC', 'Позволяет телепортировать планету и луну со всем содержимым на новые координаты, используя подпространство Фрике. Для этого необходимо отправить флот с луны (на которой есть межгалактические врата) с данным артефактом на координаты-назначения с заданием Телепортировать планетарную систему.', 1),
(9406, 1, 4, 'PLANET_TELEPORTER_FULL_DESC', 'Позволяет телепортировать планетарную систему (планету и луну) со всем содержимым на новые координаты, используя подпространство Фрике. Для этого необходимо отправить флот с луны (на которой есть межгалактические врата) с данным артефактом на координаты-назначения с заданием Телепортировать планетарную систему. Принцип работы: по прибытии флота с артефактом на нужные координаты, включаются врата, затягивая через Линзу пространства-Фрике планетарную систему целиком на новые координаты. Осуществить такое перемещение возможно раз в сутки. Флот, который летел на планету, прилетит на новые координаты, скрыться от атаки таким образом нельзя.', 1),
(9407, 1, 6, 'FLEET_STOCK_CONSUMPTION', 'Флот на бирже', 1),
(9408, 1, 1, 'TELEPORT_PLANET', 'Телепортировать планетарную систему', 1),
(9409, 1, 1, 'MSG_PLANET_TELEPORTED', 'Планетарная система успешно телепортирована с {@planet_old} на новые координаты {@planet_new}', 1),
(9410, 1, 1, 'MSG_PLANET_TELEPORTED_SUBJ', 'Планетарная система телепортирована', 1),
(9411, 1, 1, 'MSG_PLANET_NOT_TELEPORTED_SUBJ', 'Ошибка при телепортации планетарной системы', 1),
(9412, 1, 1, 'MSG_PLANET_NOT_TELEPORTED', 'Произошла ошибка при телепортации планетарной системы {@planet_old} на новые координаты {@planet_new}. Планета и луна остались на прежних координатах.', 1),
(9413, 1, 18, 'MOON_ARTEFACT_UNIVERSE_EMPTY', 'Потенциал пространственно-временного поля израсходован полностью. Появление артефакта сейчас невозможно.', 1),
(9414, 1, 1, 'EMAIL_CONFIRM', 'Нужно подтвердить емайл, проверьте почту', 0);
INSERT INTO `na_phrases` (`phraseid`, `languageid`, `phrasegroupid`, `title`, `content`, `translated`) VALUES
(9415, 1, 18, 'MOON_DESTROY_CHANCE', 'Шанс уничтожить луну составил: %s%%', 1),
(9416, 1, 18, 'ATTACKER_EXPLODE_CHANCE', 'Шанс для взрыва атакующего флота составил: %s%%', 1),
(9417, 1, 5, 'BUILDING_NOT_AVAIBLE_EXCHANGE_DISABLED', 'На реконструкции', 1),
(9418, 1, 1, 'SUSPENDED_FOR_TECHNICAL_REASONS', 'Приостановлено по техническим причинам', 1),
(9419, 1, 12, 'EXCH_LOT_DISCOUNT_PRICE', 'Цена лота для торговых союзов', 1),
(9420, 1, 1, 'MENU_PROFESSION', 'Профессия', 1),
(9421, 1, 1, 'PROFESSION_CHANGE_COST_INFO', 'Изменить профессию можно за {@cost} кредитов сейчас или бесплатно через {@days_remain} дней(я)', 1),
(9422, 1, 1, 'PROFESSION_CHANGE_NO_COST_INFO', 'Сейчас можно изменить профессию бесплатно. В следующий раз изменить можно будет через {@days_remain} дней(я) или за {@cost} кредитов в любое время', 1),
(9423, 1, 1, 'PROFESSION_SPECIALISATION', 'Специализация', 0),
(9424, 1, 1, 'PROFESSION_UNKNOWN', 'Универсал', 0),
(9425, 1, 1, 'PROFESSION_UNKNOWN_DESC', 'Универсал не имеет специализации, все постройки и исследования работают в нормальном режиме', 0),
(9426, 1, 1, 'PROFESSION_MINER', 'Шахтер', 0),
(9427, 1, 1, 'PROFESSION_MINER_DESC', 'Шахтер специализируется на добыче ресурсов', 0),
(9428, 1, 1, 'PROFESSION_ATTACKER_DESC', 'Специализируется на атаках', 0),
(9429, 1, 1, 'PROFESSION_ATTACKER', 'Атакер', 0),
(9430, 1, 1, 'PROFESSION_DEFENDER', 'Оборонщик', 0),
(9431, 1, 1, 'PROFESSION_DEFENDER_DESC', 'Специализируется на обороне', 0),
(9432, 1, 1, 'NO_CREDIT_TO_CHANGE_PROFESSION', 'У вас недостаточно кредитов, чтобы изменить профессию сейчас.', 1),
(9433, 1, 13, 'MSG_CREDIT_PROFESSION_CHANGED', 'Вы изменили профессию за {@credits} кредитов.', 1),
(9436, 1, 1, 'PROFESSION_TANK_DESC', 'Специализируется на пробивной мощи', 0),
(9437, 1, 1, 'PROFESSION_TANK', 'Танкист', 0),
(9438, 1, 1, 'USERNAME_WRONG_CHARS', 'Имя пользователя содержит недопустимые символы, измените его.', 1),
(9440, 1, 1, 'STOCK_ARTEFACT_NOT_FOUND', 'Артефакт не найден, продавец - читер!?', 1),
(9441, 1, 1, 'STOCK_ARTEFACT_USED', 'Артефакт бывший в употреблении, продавец - читер!?', 1),
(9442, 1, 1, 'STOCK_ARTEFACT_LIFETIME_NOT_FOUND', 'Неизвестно время действия артефакта', 1),
(9443, 1, 1, 'STOCK_ARTEFACT_LIFETIME_TOO_SHORT', 'Время существования артефакта слишком мало', 1),
(9444, 1, 1, 'STOCK_LOT_EXPIRED', 'Время существования лота истекло', 1),
(9445, 1, 1, 'STOCK_ARTEFACT_EXPIRED', 'Время существования артефакта истекло', 1),
(9446, 1, 4, 'SHIP_ARMORED_TERRAN', 'Броневик землян', 1),
(9447, 1, 4, 'SHIP_ARMORED_TERRAN_DESC', 'Осознав нарастающую угрозу из космоса и поняв что технологии инопланетян не будут доступны в обозримом будущем, ученые пошли другим путем. Был создан корабль невиданной броневой мощи. Новейшая многослойная сложноструктурированная броня и уникальное вооружение - главные преимущества Бронивика Землян.', 1),
(9448, 1, 4, 'SHIP_ARMORED_TERRAN_FULL_DESC', 'Осознав нарастающую угрозу из космоса и поняв что технологии инопланетян не будут доступны в обозримом будущем, ученые пошли другим путем. Был создан корабль невиданной броневой мощи. Новейшая многослойная сложноструктурированная броня и уникальное вооружение - главные преимущества Бронивика Землян.', 1),
(9449, 1, 4, 'BATTLE_ATTACK_POWER_10', 'Единство атаки x10', 1),
(9450, 1, 4, 'BATTLE_ATTACK_POWER_10_DESC', 'Увеличивает во время сражения силу атаки на 100% для всех юнитов всех игроков своей стороны.', 1),
(9451, 1, 4, 'BATTLE_ATTACK_POWER_10_FULL_DESC', 'Увеличивает во время сражения силу атаки на 100% для всех юнитов всех игроков своей стороны.', 1),
(9452, 1, 4, 'BATTLE_SHELL_POWER_10', 'Единство брони x10', 1),
(9453, 1, 4, 'BATTLE_SHELL_POWER_10_DESC', 'Увеличивает во время сражения силу брони на 100% для всех юнитов всех игроков своей стороны.', 1),
(9454, 1, 4, 'BATTLE_SHELL_POWER_10_FULL_DESC', 'Увеличивает во время сражения силу брони на 100% для всех юнитов всех игроков своей стороны.', 1),
(9455, 1, 4, 'BATTLE_SHIELD_POWER_10', 'Единство щитов x10', 1),
(9456, 1, 4, 'BATTLE_SHIELD_POWER_10_DESC', 'Увеличивает во время сражения силу щитов на 100% для всех юнитов всех игроков своей стороны.', 1),
(9457, 1, 4, 'BATTLE_SHIELD_POWER_10_FULL_DESC', 'Увеличивает во время сражения силу щитов на 100% для всех юнитов всех игроков своей стороны.', 1),
(9458, 1, 4, 'ANNIHILATION_ENGINE_10', 'Аннигиляционный модуль x10', 1),
(9459, 1, 4, 'ANNIHILATION_ENGINE_10_DESC', 'При подключении к любому типу двигателей увеличивает скорость флота в полете на 100%.', 1),
(9460, 1, 4, 'ANNIHILATION_ENGINE_10_FULL_DESC', 'Аннигиляция - взаимоуничтожение частицы и античастицы при их столкновении с высвобождением огромного количества энергии. Антиматерию крайне сложно синтезировать и хранить, поэтому создание эффективного двигателя, основанного на принципе аннигиляции, пока невозможно. Однако среди обломков крупных инопланетных кораблей были найдены модули двигателей, работающих именно по такому принципу. Некоторые из них находятся в рабочем состоянии и могут быть совмещены с известными типами двигателей, давая им прирост производительности в 100%.', 1),
(9461, 1, 1, 'CONFIRM_BUY_LOT_BIG_FUEL_COST', 'Цена топлива составляет: {fuel_cost}, суммарная стоимость лота: {total_cost}. Купить лот?', 1),
(9462, 1, 12, 'STAT_DM_POINTS', 'Доминатор', 1),
(9463, 1, 1, 'DM_POINTS', 'Доминатор', 1);
